var _wnPage = 0;
var _wnPerPage = 3;
var _wnTimer = null;

function _wnRelDate(dateStr) {
  var then = new Date(dateStr);
  var now  = new Date();
  var days = Math.floor((now - then) / 86400000);
  if (days === 0) return 'Today';
  if (days === 1) return 'Yesterday';
  if (days < 7)  return days + 'd ago';
  if (days < 30) return Math.floor(days/7) + 'w ago';
  if (days < 365) return Math.floor(days/30) + 'mo ago';
  return Math.floor(days/365) + 'y ago';
}

function _wnTagColor(type) {
  return {template:'var(--gold)',video:'#6366f1',lesson:'#0ea5e9',feature:'var(--emerald)',assessment:'#f59e0b',tool:'#8b5cf6'}[type] || 'var(--gold)';
}
function _wnIconBg(type) {
  return {template:'rgba(200,153,58,.10)',video:'rgba(99,102,241,.10)',lesson:'rgba(14,165,233,.10)',feature:'rgba(26,107,74,.10)',assessment:'rgba(245,158,11,.10)',tool:'rgba(139,92,246,.10)'}[type] || 'rgba(26,107,74,.08)';
}

function renderWhatsNew(page) {
  var grid = document.getElementById('whatsNewGrid');
  var dots = document.getElementById('whatsNewDots');
  var live = document.getElementById('whatsNewLive');
  if (!grid) return;
  _wnPage = page;

  var totalPages = Math.ceil(WHATS_NEW.length / _wnPerPage);
  var slice = WHATS_NEW.slice(page * _wnPerPage, page * _wnPerPage + _wnPerPage);

  // Update live timestamp
  var latest = WHATS_NEW[0];
  if (live) live.textContent = 'Last updated ' + _wnRelDate(latest.date);

  // Render cards
  grid.style.opacity = '0';
  grid.style.transform = 'translateY(6px)';
  setTimeout(function() {
    grid.innerHTML = slice.map(function(item, i) {
      var daysOld = Math.floor((new Date() - new Date(item.date)) / 86400000);
      var isNew = daysOld < 30;
      return '<div class="wn-card" onclick="WHATS_NEW[' + (page * _wnPerPage + i) + '].action()" title="Go to ' + item.title + '">'
        + '<div style="width:40px;height:40px;min-width:40px;border-radius:10px;background:' + _wnIconBg(item.type) + ';display:flex;align-items:center;justify-content:center;font-size:1.15rem;">' + item.icon + '</div>'
        + '<div style="flex:1;min-width:0;">'
        + '<div style="font-size:.65rem;font-weight:700;letter-spacing:.09em;text-transform:uppercase;color:' + _wnTagColor(item.type) + ';margin-bottom:.3rem;">'
        + item.tag + (isNew ? '<span class="wn-badge-new">NEW</span>' : '') + '</div>'
        + '<div style="font-size:.9rem;font-weight:700;color:var(--ink);margin-bottom:.2rem;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">' + item.title + '</div>'
        + '<div style="font-size:.76rem;color:var(--ink-light);display:flex;align-items:center;gap:.4rem;">'
        + '<span>' + item.desc + '</span>'
        + '<span style="margin-left:auto;font-family:\'DM Mono\',monospace;font-size:.65rem;color:var(--ink-pale);white-space:nowrap;">' + _wnRelDate(item.date) + '</span>'
        + '</div>'
        + '</div>'
        + '<div class="wn-arrow">→</div>'
        + '</div>';
    }).join('');

    grid.style.transition = 'opacity .28s ease, transform .28s ease';
    grid.style.opacity = '1';
    grid.style.transform = 'translateY(0)';
  }, 120);

  // Render dots
  if (dots) {
    dots.innerHTML = Array.from({length: totalPages}, function(_, i) {
      return '<button class="wn-dot' + (i === page ? ' active' : '') + '" onclick="renderWhatsNew(' + i + ');_wnResetTimer();" aria-label="Page ' + (i+1) + '"></button>';
    }).join('');
  }
}

function _wnResetTimer() {
  if (_wnTimer) clearInterval(_wnTimer);
  _wnTimer = setInterval(function() {
    var total = Math.ceil(WHATS_NEW.length / _wnPerPage);
    renderWhatsNew((_wnPage + 1) % total);
  }, 6000);
}

// Init on DOM ready
(function() {
  function _wnInit() {
    renderWhatsNew(0);
    _wnResetTimer();
  }
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', _wnInit);
  } else {
    _wnInit();
  }
})();



