        { q: 'A clean annual audit with no material findings demonstrates:', options: ['That the organization has no room for improvement', 'Financial integrity and management competence to funders and stakeholders', 'That all financial data is perfectly accurate', 'That the auditor approved all financial decisions made during the year'], correct: 1 },
        { q: 'Repeat audit findings — the same issue appearing in multiple consecutive years — are significant because:', options: ['They are normal for growing organizations', 'They signal that management has not genuinely addressed the root cause, damaging funder and board confidence', 'They require the organization to switch auditors', 'They are only significant if flagged as material by the auditor'], correct: 1 }
