// STATE
// ═══════════════════════════════════════════════
// Load saved progress from localStorage or initialize fresh
const progress = {};

// ═══════════════════════════════════════════════
// PROGRESS  — per sub-capability tracking
// key: capId_subIdx  e.g. "strategy_0"
// ═══════════════════════════════════════════════
var scProgress = {};   // { "strategy_0": { workbook, video, lessons:[...], templates:false, assessment:false } }

function initProgress() {
  var saved = {};
  try { saved = JSON.parse(localStorage.getItem('aljude_sc_progress') || '{}'); } catch(e) {}
  Object.keys(CAPABILITIES).forEach(function(key) {
    var cap = CAPABILITIES[key];
    (cap.subCapabilities || []).forEach(function(sub, i) {
      var pid = key + '_' + i;
      var s = saved[pid] || {};
      scProgress[pid] = {
        workbook:   s.workbook   || false,
        video:      s.video      || false,
        lessons:    s.lessons    || [false,false,false,false,false],
        templates:  s.templates  || false,
        assessment: s.assessment || false
      };
    });
  });
}

function saveProgress() {
  try { localStorage.setItem('aljude_sc_progress', JSON.stringify(scProgress)); } catch(e) {}
}

function getCapPct(capId) {
  var cap = CAPABILITIES[capId];
  if (!cap || !cap.subCapabilities || !cap.subCapabilities.length) return 0;
  var total = 0, done = 0;
  cap.subCapabilities.forEach(function(sub, i) {
    var sp = scProgress[capId + '_' + i] || {};
    total += 5; // workbook video templates assessment + at least 1 lesson
    if (sp.workbook)   done++;
    if (sp.video)      done++;
    if (sp.templates)  done++;
    if (sp.assessment) done++;
    var ld = (sp.lessons || []).filter(Boolean).length;
    if (ld > 0) done++;
  });
  return Math.round((done / total) * 100);
}

initProgress();

