// NAVIGATION
// ═══════════════════════════════════════════════
function setFloatingBack(label) {
  var fb = document.getElementById('floatingBackBtn');
  var fl = document.getElementById('floatingBackLabel');
  if (!fb) return;
  fb.style.display = 'flex';
  if (fl) fl.textContent = label || 'Back';
}

function hideFloatingBack() {
  var fb = document.getElementById('floatingBackBtn');
  if (fb) fb.style.display = 'none';
}

function goHome() {
  document.querySelectorAll('.page').forEach(function(p) { p.classList.remove('active'); });
  document.getElementById('home-page').classList.add('active');
  document.getElementById('navBackBtn').style.display = 'none';
  hideFloatingBack();
  document.querySelectorAll('.nav-menu li a').forEach(function(a) { a.classList.remove('active'); });
  currentCapId = null;
  currentSubCapIdx = null;
  updateAllProgress();
}

function showAboutPage() {
  document.querySelectorAll('.page').forEach(function(p) { p.classList.remove('active'); });
  document.getElementById('about-page').classList.add('active');
  document.getElementById('navBackBtn').style.display = 'none';
  document.querySelectorAll('.nav-menu li a').forEach(function(a) {
    a.classList.remove('active');
    if (a.getAttribute('onclick') && a.getAttribute('onclick').indexOf('showAboutPage') !== -1)
      a.classList.add('active');
  });
  currentCapId = null;
  currentSubCapIdx = null;
  window.scrollTo(0, 0);
}

function loadCapability(capId) {
  // Track where we came from so back button can return there
  var resultsVisible = document.getElementById('assessResults') && document.getElementById('assessResults').style.display !== 'none';
  var assessPageActive = document.getElementById('assessment-page') && document.getElementById('assessment-page').classList.contains('active');
  var mlDetailActive = document.getElementById('micro-lesson-detail-page') && document.getElementById('micro-lesson-detail-page').classList.contains('active');
  var mlListActive   = document.getElementById('micro-lessons-page') && document.getElementById('micro-lessons-page').classList.contains('active');
  var lpDetailActive = document.getElementById('learning-path-detail-page') && document.getElementById('learning-path-detail-page').classList.contains('active');
  var lpListActive   = document.getElementById('learning-paths-page') && document.getElementById('learning-paths-page').classList.contains('active');
  var wbDetailActive = document.getElementById('webinar-detail-page') && document.getElementById('webinar-detail-page').classList.contains('active');
  var successStoriesActive = document.getElementById('success-stories-page') && document.getElementById('success-stories-page').classList.contains('active');
  var resourceLibActive = document.getElementById('resource-library-page') && document.getElementById('resource-library-page').classList.contains('active');
  var categoriesActive = document.getElementById('categories-page') && document.getElementById('categories-page').classList.contains('active');
  var myLearningPathActive = document.getElementById('my-learning-path-page') && document.getElementById('my-learning-path-page').classList.contains('active');
  var trackDetailActive = document.getElementById('track-detail-page') && document.getElementById('track-detail-page').classList.contains('active');

  if (resultsVisible && assessPageActive) {
    navHistory.push({ pageId: 'assessment-page', label: '← My Results', capId: null, subIdx: null });
  } else if (categoriesActive) {
    navHistory.push({ pageId: 'categories-page', label: '← All Capabilities', capId: null, subIdx: null });
  } else if (myLearningPathActive) {
    navHistory.push({ pageId: 'my-learning-path-page', label: '← My Learning Path', capId: null, subIdx: null });
  } else if (trackDetailActive && currentTrackId) {
    navHistory.push({ pageId: 'improvement-tracks-page', label: '← Improvement Tracks', capId: null, subIdx: null });
    navHistory.push({ pageId: 'track-detail-page', label: '← Track: ' + (IMPROVEMENT_TRACKS.find(function(t){return t.id===currentTrackId;})||{title:'Track'}).title, capId: null, subIdx: null });
  } else if (successStoriesActive) {
    navHistory.push({ pageId: 'success-stories-page', label: '← Success Stories', capId: null, subIdx: null });
  } else if (resourceLibActive) {
    navHistory.push({ pageId: 'resource-library-page', label: '← Resource Library', capId: null, subIdx: null });
  } else if (mlDetailActive) {
    navHistory.push({ pageId: 'micro-lesson-detail-page', label: '← Micro Lesson', capId: null, subIdx: null });
  } else if (mlListActive) {
    navHistory.push({ pageId: 'micro-lessons-page', label: '← Micro Lessons', capId: null, subIdx: null });
  } else if (lpDetailActive) {
    navHistory.push({ pageId: 'learning-path-detail-page', label: '← Learning Path', capId: null, subIdx: null });
  } else if (lpListActive) {
    navHistory.push({ pageId: 'learning-paths-page', label: '← Learning Paths', capId: null, subIdx: null });
  } else if (wbDetailActive) {
    navHistory.push({ pageId: 'webinars-page',       label: '← Webinars', capId: null, subIdx: null });
    navHistory.push({ pageId: 'webinar-detail-page', label: '← Webinar',  capId: null, subIdx: null });
  }

  loadCapabilityNoHistory(capId);
  if (navHistory.length > 0) {
    document.getElementById('navBackLabel').textContent = navHistory[navHistory.length-1].label;
  }
  return false;
}

function loadCapabilityFromLP(capId, pathId) {
  // Set history: cap back → LP detail, LP detail back → LP list
  navHistory = [
    { pageId: 'learning-paths-page',      label: '← Learning Paths', capId: null,  subIdx: null },
    { pageId: 'learning-path-detail-page', label: '← Learning Path',  pathId: pathId, capId: null, subIdx: null }
  ];
  loadCapabilityNoHistory(capId);
  document.getElementById('navBackLabel').textContent = '← Learning Path';
  setFloatingBack('← Learning Path');
}

function loadCapabilityNoHistory(capId) {
  currentCapId = capId;
  currentSubCapIdx = null;
  var cap = CAPABILITIES[capId];
  if (!cap) return;
  document.querySelectorAll('.page').forEach(function(p) { p.classList.remove('active'); });
  document.getElementById('cap-page').classList.add('active');
  document.getElementById('navBackBtn').style.display = 'flex';
  var _lcnhLabel = navHistory.length > 0 ? navHistory[navHistory.length-1].label : '← All Capabilities';
  document.getElementById('navBackLabel').textContent = _lcnhLabel;
  setFloatingBack(_lcnhLabel);
  renderCategoryPage(cap);
  window.scrollTo(0, 0);
}

function openSubCapability(capId, subIdx) {
  // Track originating page for back nav
  var mlDetailActive      = document.getElementById('micro-lesson-detail-page') && document.getElementById('micro-lesson-detail-page').classList.contains('active');
  var lpDetailActive      = document.getElementById('learning-path-detail-page') && document.getElementById('learning-path-detail-page').classList.contains('active');
  var wbDetailActive      = document.getElementById('webinar-detail-page') && document.getElementById('webinar-detail-page').classList.contains('active');
  var workbooksActive     = document.getElementById('workbooks-page') && document.getElementById('workbooks-page').classList.contains('active');
  var videoGuidesActive   = document.getElementById('video-guides-page') && document.getElementById('video-guides-page').classList.contains('active');
  var capImproveActive    = document.getElementById('cap-improve-page') && document.getElementById('cap-improve-page').classList.contains('active');
  var capLearnMoreActive  = document.getElementById('cap-learn-more-page') && document.getElementById('cap-learn-more-page').classList.contains('active');
  var trackImproveActive  = document.getElementById('track-improve-page') && document.getElementById('track-improve-page').classList.contains('active');
  var trackLearnActive    = document.getElementById('track-learn-page') && document.getElementById('track-learn-page').classList.contains('active');

  var trackDetailActive   = document.getElementById('track-detail-page') && document.getElementById('track-detail-page').classList.contains('active');

  if (trackDetailActive) {
    navHistory.push({ pageId: 'track-detail-page', label: '← Track Overview', capId: null, subIdx: null });
  } else if (trackImproveActive) {
    navHistory.push({ pageId: 'track-improve-page', label: '← Track Improve', capId: null, subIdx: null });
  } else if (trackLearnActive) {
    navHistory.push({ pageId: 'track-learn-page', label: '← Track Learn', capId: null, subIdx: null });
  } else if (capImproveActive) {
    navHistory.push({ pageId: 'cap-improve-page', label: '← Improve', capId: null, subIdx: null });
  } else if (capLearnMoreActive) {
    navHistory.push({ pageId: 'cap-learn-more-page', label: '← ' + (CAPABILITIES[capId] ? CAPABILITIES[capId].title : 'Capability'), capId: capId, subIdx: null });
  } else if (workbooksActive) {
    navHistory.push({ pageId: 'workbooks-page', label: '← Workbooks', capId: null, subIdx: null });
  } else if (videoGuidesActive) {
    navHistory.push({ pageId: 'video-guides-page', label: '← Video Guides', capId: null, subIdx: null });
  } else if (mlDetailActive) {
    navHistory.push({ pageId: 'micro-lesson-detail-page', label: '← Micro Lesson', capId: null, subIdx: null });
  } else if (lpDetailActive) {
    navHistory.push({ pageId: 'learning-path-detail-page', label: '← Learning Path', capId: null, subIdx: null });
  } else if (wbDetailActive) {
    navHistory.push({ pageId: 'webinars-page',       label: '← Webinars', capId: null, subIdx: null });
    navHistory.push({ pageId: 'webinar-detail-page', label: '← Webinar',  capId: null, subIdx: null });
  }

  currentCapId     = capId;
  currentSubCapIdx = subIdx;
  var cap = CAPABILITIES[capId];
  if (!cap || !cap.subCapabilities || !cap.subCapabilities[subIdx]) return;
  document.querySelectorAll('.page').forEach(function(p) { p.classList.remove('active'); });
  document.getElementById('subcap-page').classList.add('active');
  document.getElementById('navBackBtn').style.display = 'flex';
  var _osubLabel = navHistory.length > 0 ? navHistory[navHistory.length-1].label : 'Back to ' + cap.title;
  document.getElementById('navBackLabel').textContent = _osubLabel;
  setFloatingBack(_osubLabel);
  renderSubCapPage(cap, subIdx);
  window.scrollTo(0, 0);
}

function backToCategory() {
  if (!currentCapId) { showCategoriesPage(); return; }
  currentSubCapIdx = null;
  document.querySelectorAll('.page').forEach(function(p) { p.classList.remove('active'); });
  document.getElementById('cap-page').classList.add('active');
  // Default back label to All Capabilities (not Home) since cap page lives under Capabilities
  var backLabel = navHistory.length > 0 ? navHistory[navHistory.length-1].label : '← All Capabilities';
  document.getElementById('navBackLabel').textContent = backLabel;
  document.getElementById('navBackBtn').style.display = 'flex';
  setFloatingBack(backLabel);
  renderCategoryPage(CAPABILITIES[currentCapId]);
  window.scrollTo(0, 0);
}

// ═══════════════════════════════════════════════
// CATEGORY PAGE  — hero + list of sub-capabilities
// ═══════════════════════════════════════════════
function renderCategoryPage(cap) {
  var cid  = cap.id;
  var subs = cap.subCapabilities || [];
  var doneCnt = 0;
  subs.forEach(function(sub, i) {
    var sp = scProgress[cid + '_' + i] || {};
    if (sp.workbook && sp.video && sp.templates && sp.assessment) doneCnt++;
  });
  var pct = subs.length ? Math.round((doneCnt / subs.length) * 100) : 0;

  var html = '';

  // Breadcrumb
  html += '<div style="display:flex;align-items:center;gap:.4rem;font-size:.78rem;color:var(--ink-light);margin-bottom:1.25rem;flex-wrap:wrap;">';
  html += '<span onclick="showCategoriesPage()" style="color:var(--emerald);cursor:pointer;font-weight:600;">All Capabilities</span>';
  html += '<span style="opacity:.4;">›</span>';
  html += '<span style="color:var(--ink-mid);font-weight:600;">' + cap.title + '</span>';
  html += '</div>';

  // Hero banner
  html += '<div style="background:linear-gradient(135deg,var(--emerald-dark),var(--emerald));border-radius:18px;padding:2.5rem 2rem;margin-bottom:2rem;color:white;">';
  html += '<div style="font-size:.72rem;font-weight:800;letter-spacing:.1em;text-transform:uppercase;opacity:.7;margin-bottom:.5rem;">' + cap.eyebrow + '</div>';
  html += '<div style="font-size:2rem;font-weight:900;font-family:\'Playfair Display\',serif;margin-bottom:.5rem;">' + cap.icon + ' ' + cap.title + '</div>';
  html += '<div style="font-size:.92rem;opacity:.85;line-height:1.6;max-width:600px;">' + cap.description + '</div>';
  html += '<div style="display:flex;gap:1rem;margin-top:1.25rem;flex-wrap:wrap;">';
  html += '<div style="background:rgba(255,255,255,.15);border-radius:10px;padding:.4rem .85rem;font-size:.78rem;font-weight:700;">&#128218; ' + subs.length + ' Capabilities</div>';
  html += '<div style="background:rgba(255,255,255,.15);border-radius:10px;padding:.4rem .85rem;font-size:.78rem;font-weight:700;">&#128211; Workbooks</div>';
  html += '<div style="background:rgba(255,255,255,.15);border-radius:10px;padding:.4rem .85rem;font-size:.78rem;font-weight:700;">&#127909; Videos</div>';
  html += '<div style="background:rgba(255,255,255,.15);border-radius:10px;padding:.4rem .85rem;font-size:.78rem;font-weight:700;">&#128196; Templates</div>';
  html += '</div>';
  html += '<div style="height:6px;background:rgba(255,255,255,.25);border-radius:3px;margin-top:1.25rem;overflow:hidden;">';
  html += '<div style="height:100%;background:white;border-radius:3px;width:' + pct + '%;transition:width .4s;"></div></div>';
  html += '<div style="font-size:.78rem;opacity:.75;margin-top:.4rem;" id="cat-progress-label-' + cid + '">' + doneCnt + ' of ' + subs.length + ' capabilities completed</div>';
  html += '</div>';

  // Learn About This Capability section
  if (cap.learnContent) {
    var lc = cap.learnContent;
    html += '<div style="background:white;border:1.5px solid var(--border);border-radius:16px;margin-bottom:1.5rem;overflow:hidden;">';
    html += '<div onclick="this.nextElementSibling.style.display=this.nextElementSibling.style.display===\'none\'?\'block\':\'none\';this.querySelector(\'.lc-chevron\').style.transform=this.nextElementSibling.style.display===\'none\'?\'rotate(0deg)\':\'rotate(180deg)\'" style="display:flex;align-items:center;justify-content:space-between;padding:1.1rem 1.5rem;cursor:pointer;background:linear-gradient(90deg,rgba(26,107,74,0.05),transparent);">';
    html += '<div style="display:flex;align-items:center;gap:.75rem;">';
    html += '<div style="width:34px;height:34px;border-radius:9px;background:var(--emerald-glow);border:1.5px solid rgba(26,107,74,0.2);display:flex;align-items:center;justify-content:center;font-size:.95rem;">&#128218;</div>';
    html += '<div><div style="font-size:.92rem;font-weight:700;color:var(--emerald-dark);">About This Capability</div><div style="font-size:.74rem;color:var(--ink-light);margin-top:.1rem;">Why it matters · What you will learn · Who it is for</div></div></div>';
    html += '<svg class="lc-chevron" style="width:18px;height:18px;color:var(--ink-pale);transition:transform .3s;transform:rotate(180deg)" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M5.293 7.293a1 1 0 011.414 0L10 10.586l3.293-3.293a1 1 0 111.414 1.414l-4 4a1 1 0 01-1.414 0l-4-4a1 1 0 010-1.414z"/></svg>';
    html += '</div>';
    html += '<div style="display:block;border-top:1px solid var(--border);padding:1.5rem;">';
    // Why it matters
    html += '<div style="margin-bottom:1.25rem;">';
    html += '<div style="font-size:.68rem;font-weight:800;text-transform:uppercase;letter-spacing:.1em;color:var(--gold);margin-bottom:.5rem;">&#9888; Why It Matters</div>';
    html += '<p style="font-size:.88rem;color:var(--ink-mid);line-height:1.75;background:var(--cream);padding:.85rem 1rem;border-radius:10px;border-left:3px solid var(--gold);">' + lc.why + '</p>';
    html += '</div>';
    // What you will learn
    html += '<div style="margin-bottom:1.25rem;">';
    html += '<div style="font-size:.68rem;font-weight:800;text-transform:uppercase;letter-spacing:.1em;color:var(--emerald);margin-bottom:.6rem;">&#127891; What You Will Learn</div>';
    html += '<div style="display:flex;flex-direction:column;gap:.45rem;">';
    lc.whatYouLearn.forEach(function(item) {
      html += '<div style="display:flex;align-items:flex-start;gap:.7rem;font-size:.86rem;color:var(--ink-mid);line-height:1.55;">';
      html += '<div style="width:20px;height:20px;min-width:20px;border-radius:50%;background:var(--emerald-glow);border:1.5px solid var(--emerald);display:flex;align-items:center;justify-content:center;margin-top:1px;"><svg viewBox=\'0 0 20 20\' fill=\'none\' style=\'width:11px;height:11px;\'><path d=\'M5 10l4 4 6-8\' stroke=\'#1A6B4A\' stroke-width=\'2.2\' stroke-linecap=\'round\' stroke-linejoin=\'round\'/></svg></div>';
      html += '<span>' + item + '</span></div>';
    });
    html += '</div></div>';
    // Two-col: who + insight
    html += '<div style="display:grid;grid-template-columns:1fr 1fr;gap:1rem;">';
    html += '<div style="background:rgba(200,153,58,0.06);border:1px solid rgba(200,153,58,0.2);border-radius:10px;padding:1rem;">';
    html += '<div style="font-size:.68rem;font-weight:800;text-transform:uppercase;letter-spacing:.1em;color:var(--gold);margin-bottom:.4rem;">&#128101; Who Is This For</div>';
    html += '<p style="font-size:.83rem;color:var(--ink-mid);line-height:1.65;">' + lc.whoIsItFor + '</p>';
    html += '</div>';
    html += '<div style="background:rgba(26,107,74,0.05);border:1px solid rgba(26,107,74,0.15);border-radius:10px;padding:1rem;">';
    html += '<div style="font-size:.68rem;font-weight:800;text-transform:uppercase;letter-spacing:.1em;color:var(--emerald);margin-bottom:.4rem;">&#128161; Key Insight</div>';
    html += '<p style="font-size:.83rem;color:var(--ink-mid);line-height:1.65;font-style:italic;">' + lc.keyInsight + '</p>';
    html += '</div>';
    html += '</div>';
    html += '</div></div>';
  }

  // Capability cards
  html += '<div style="display:flex;flex-direction:column;gap:.75rem;">';
  subs.forEach(function(sub, i) {
    var sp   = scProgress[cid + '_' + i] || {};
    var isDone = sp.workbook && sp.video && sp.templates && sp.assessment;
    var completedCount = (sp.workbook?1:0)+(sp.video?1:0)+(sp.templates?1:0)+(sp.assessment?1:0)+((sp.lessons||[]).filter(Boolean).length>0?1:0);
    html += '<div onclick="openSubCapability(\'' + cid + '\',' + i + ')" style="background:white;border:1.5px solid ' + (isDone ? '#6ee7b7' : 'var(--border)') + ';border-radius:14px;padding:1.25rem 1.5rem;display:flex;align-items:center;gap:1.25rem;cursor:pointer;transition:all .2s;box-shadow:0 2px 8px rgba(15,74,50,.04);" onmouseover="this.style.borderColor=\'var(--emerald)\';this.style.transform=\'translateY(-1px)\'" onmouseout="this.style.borderColor=\'' + (isDone ? '#6ee7b7' : 'var(--border)') + '\';this.style.transform=\'none\'">';
    html += '<div style="width:42px;height:42px;border-radius:11px;background:' + (isDone ? '#d1fae5' : 'var(--emerald-glow)') + ';border:1.5px solid ' + (isDone ? '#6ee7b7' : 'var(--emerald)') + ';display:flex;align-items:center;justify-content:center;font-size:.85rem;font-weight:800;color:' + (isDone ? '#065f46' : 'var(--emerald)') + ';flex-shrink:0;">' + (isDone ? '&#10003;' : (i + 1)) + '</div>';
    html += '<div style="flex:1;min-width:0;">';
    html += '<div style="font-size:.95rem;font-weight:700;color:var(--ink);margin-bottom:.2rem;">' + sub.title + '</div>';
    if (sub.outcome) html += '<div style="font-size:.8rem;color:var(--ink-light);line-height:1.4;margin-bottom:.45rem;">' + sub.outcome.replace(/📦\s*/,'') + '</div>';
    html += '<div style="display:flex;gap:.4rem;flex-wrap:wrap;">';
    html += '<span style="font-size:.68rem;font-weight:700;padding:.18rem .5rem;border-radius:20px;background:var(--cream);color:var(--ink-light);border:1px solid var(--border);">&#9201; ' + (sub.time || '60 min') + '</span>';
    html += '<span style="font-size:.68rem;font-weight:700;padding:.18rem .5rem;border-radius:20px;background:var(--cream);color:var(--ink-light);border:1px solid var(--border);">&#128211; Workbook</span>';
    html += '<span style="font-size:.68rem;font-weight:700;padding:.18rem .5rem;border-radius:20px;background:var(--cream);color:var(--ink-light);border:1px solid var(--border);">&#127909; Video Guide</span>';
    html += '<span style="font-size:.68rem;font-weight:700;padding:.18rem .5rem;border-radius:20px;background:var(--cream);color:var(--ink-light);border:1px solid var(--border);">&#128241; Micro Lessons</span>';
    html += '<span style="font-size:.68rem;font-weight:700;padding:.18rem .5rem;border-radius:20px;background:var(--cream);color:var(--ink-light);border:1px solid var(--border);">&#128196; Templates</span>';
    html += '<span style="font-size:.68rem;font-weight:700;padding:.18rem .5rem;border-radius:20px;background:var(--cream);color:var(--ink-light);border:1px solid var(--border);">&#127919; Assessment</span>';
    if (completedCount > 0) html += '<span style="font-size:.68rem;font-weight:700;padding:.18rem .5rem;border-radius:20px;background:#d1fae5;color:#065f46;border:1px solid #6ee7b7;">' + completedCount + '/5 done</span>';
    html += '</div></div>';
    html += '<div style="color:var(--ink-pale);font-size:1.4rem;flex-shrink:0;">&#8250;</div>';
    html += '</div>';
  });
  html += '</div>';

  document.getElementById('capPageInner').innerHTML = html;
}

// ═══════════════════════════════════════════════
// SUB-CAPABILITY DETAIL PAGE  — 5 tabs
// ═══════════════════════════════════════════════
// ── SAVE BUTTON HELPER ───────────────────────────────────────────────────────
function isSaved(id) {
  return savedItems.some(function(s){ return s.id === id; });
}

function toggleSaveItem(item) {
  if (!item) return;
  if (!currentUser) {
    showToast('Sign in to save items to your profile 🔒');
    openSignInModal();
    return;
  }
  var exists = savedItems.find(function(s){ return s.id === item.id; });
  if (exists) {
    savedItems = savedItems.filter(function(s){ return s.id !== item.id; });
    showToast('Removed from saved items');
  } else {
    savedItems.push(item);
    showToast('Saved to your profile 🔖');
  }
  // Update saved count in header
  var countEl = document.getElementById('profileSavedCount');
  if (countEl) countEl.textContent = savedItems.length;
  // Update all save buttons with this id
  var nowSaved = isSaved(item.id);
  document.querySelectorAll('[data-save-id="' + item.id + '"]').forEach(function(btn) {
    btn.textContent   = nowSaved ? 'Saved' : 'Save';
    btn.style.background  = nowSaved ? 'var(--emerald-glow)' : 'white';
    btn.style.color       = nowSaved ? 'var(--emerald)'      : 'var(--ink-light)';
    btn.style.borderColor = nowSaved ? 'rgba(26,107,74,.3)'  : 'var(--border)';
  });
}

// ── SAVE ITEM REGISTRY (avoids JSON-in-onclick quoting issues) ────────────────
window._saveRegistry = window._saveRegistry || {};

function renderSaveBtn(item) {
  // Store item in registry keyed by id
  window._saveRegistry[item.id] = item;
  var saved = isSaved(item.id);
  return '<button data-save-id="' + item.id + '" '
    + 'onclick="toggleSaveItem(window._saveRegistry[this.getAttribute(\'data-save-id\')])" '
    + 'style="display:inline-flex;align-items:center;gap:.35rem;padding:.42rem .9rem;border-radius:8px;font-size:.78rem;font-weight:700;cursor:pointer;font-family:inherit;transition:all .18s;'
    + 'background:' + (saved ? 'var(--emerald-glow)' : 'white') + ';'
    + 'color:' + (saved ? 'var(--emerald)' : 'var(--ink-light)') + ';'
    + 'border:1.5px solid ' + (saved ? 'rgba(26,107,74,.3)' : 'var(--border)') + ';">'
    + (saved ? 'Saved' : 'Save')
    + '</button>';
}

function renderSubCapPage(cap, subIdx) {
  var cid = cap.id;
  var sub = cap.subCapabilities[subIdx];
  var pid = cid + '_' + subIdx;
  if (!scProgress[pid]) scProgress[pid] = { workbook:false, video:false, lessons:[false,false,false,false,false], templates:false, assessment:false };
  var sp = scProgress[pid];

  var html = '';

  // Breadcrumb
  html += '<div style="display:flex;align-items:center;gap:.5rem;font-size:.8rem;color:var(--ink-light);margin-bottom:1.5rem;flex-wrap:wrap;">';
  html += '<span onclick="goHome()" style="color:var(--emerald);cursor:pointer;font-weight:600;">&#127968; Home</span>';
  html += '<span style="opacity:.4;">&#8250;</span>';
  html += '<span onclick="backToCategory()" style="color:var(--emerald);cursor:pointer;font-weight:600;">' + cap.icon + ' ' + cap.title + '</span>';
  html += '<span style="opacity:.4;">&#8250;</span>';
  html += '<span style="color:var(--ink);">' + sub.title + '</span>';
  html += '</div>';

  // Header
  html += '<div style="margin-bottom:1.5rem;">';
  html += '<div style="font-size:.72rem;font-weight:800;letter-spacing:.1em;text-transform:uppercase;color:var(--emerald);margin-bottom:.4rem;">' + cap.eyebrow + ' &rsaquo; Capability ' + (subIdx + 1) + '</div>';
  html += '<h1 style="font-size:1.55rem;font-weight:900;font-family:\'Playfair Display\',serif;color:var(--ink);margin:0 0 .4rem;line-height:1.25;">' + sub.title + '</h1>';
  if (sub.outcome) html += '<div style="font-size:.88rem;color:var(--ink-light);line-height:1.5;margin-bottom:.85rem;">' + sub.outcome.replace(/📦\s*/,'') + '</div>';
  html += '<div style="display:flex;gap:.5rem;flex-wrap:wrap;">';
  html += '<span style="font-size:.72rem;font-weight:700;padding:.25rem .65rem;border-radius:20px;background:var(--cream);color:var(--ink-light);border:1px solid var(--border);">&#9201; ' + (sub.time || '60 min') + '</span>';
  html += '<span style="font-size:.72rem;font-weight:700;padding:.25rem .65rem;border-radius:20px;background:var(--cream);color:var(--ink-light);border:1px solid var(--border);">&#127891; Free</span>';
  html += '<span style="font-size:.72rem;font-weight:700;padding:.25rem .65rem;border-radius:20px;background:var(--cream);color:var(--ink-light);border:1px solid var(--border);">&#127760; ' + cap.title + '</span>';
  html += '</div></div>';

  // Tab nav
  var tabs = [['workbook','&#128211; Workbook'],['video','&#127909; Video Guide'],['microlessons','&#128241; Micro Lessons'],['templates','&#128196; Templates'],['assessment','&#127919; Assessment']];
  html += '<div style="display:flex;gap:.3rem;border-bottom:2px solid var(--border);margin-bottom:1.5rem;overflow-x:auto;" id="sc-tabs-' + pid + '">';
  tabs.forEach(function(t, i) {
    html += '<button class="cap-tab-btn' + (i === 0 ? ' active' : '') + '" style="border-bottom:3px solid ' + (i === 0 ? 'var(--emerald)' : 'transparent') + ';margin-bottom:-2px;white-space:nowrap;" onclick="switchScTab(\'' + pid + '\',\'' + t[0] + '\',this)">' + t[1] + '</button>';
  });
  html += '</div>';

  // Tab panels
  html += '<div id="sc-panel-' + pid + '-workbook"    class="cap-tab-panel active">' + renderScWorkbook(cap, sub, pid, sp) + '</div>';
  html += '<div id="sc-panel-' + pid + '-video"       class="cap-tab-panel">'        + renderScVideo(cap, sub, pid, sp, subIdx) + '</div>';
  html += '<div id="sc-panel-' + pid + '-microlessons" class="cap-tab-panel">'       + renderScMicro(cap, sub, pid, sp, subIdx) + '</div>';
  html += '<div id="sc-panel-' + pid + '-templates"   class="cap-tab-panel">'        + renderScTemplates(cap, sub, pid, sp) + '</div>';
  html += '<div id="sc-panel-' + pid + '-assessment"  class="cap-tab-panel">'        + renderScAssessment(cap, sub, pid, sp, subIdx) + '</div>';

  document.getElementById('subcapInner').innerHTML = html;
}

function switchScTab(pid, tab, btn) {
  document.querySelectorAll('#sc-tabs-' + pid + ' .cap-tab-btn').forEach(function(b) {
    b.classList.remove('active');
    b.style.borderBottomColor = 'transparent';
  });
  document.querySelectorAll('[id^="sc-panel-' + pid + '-"]').forEach(function(p) { p.classList.remove('active'); });
  var panel = document.getElementById('sc-panel-' + pid + '-' + tab);
  if (panel) panel.classList.add('active');
  if (btn) { btn.classList.add('active'); btn.style.borderBottomColor = 'var(--emerald)'; }
}

// ── WORKBOOK ─────────────────────────────────────────────────────────────────
function renderScWorkbook(cap, sub, pid, sp) {
  var capId  = cap.id;
  var subIdx = parseInt(pid.split('_')[1], 10);
  var wb   = sub.workbook;
  var done = sp.workbook;
  var dc   = wb && wb.docContent ? wb.docContent : null;

  var html = '<div class="tab-section-title">&#128211; Workbook</div>';
  html += '<div class="tab-section-sub">' + sub.title + ' — Read the documentation, then complete each section below.</div>';

  html += '<div class="workbook-viewer"><div class="workbook-preview">';

  // ── Workbook header ──
  html += '<div class="wb-header">';
  html += '<div class="wb-title">' + sub.title + '</div>';
  html += '<div class="wb-subtitle">' + cap.title + ' Workbook &nbsp;|&nbsp; ALJUDE Capacity Building Platform</div>';
  html += '</div>';

  // ── Documentation block ──
  if (dc) {
    // Intro paragraph
    html += '<div class="wb-intro-text">' + dc.intro + '</div>';

    // Example box
    if (dc.example) {
      html += '<div class="wb-example-box">';
      html += '<div class="wb-example-label">&#128218; Practical Example</div>';
      html += dc.example;
      html += '</div>';
    }

    // Key takeaway
    if (dc.takeaway) {
      html += '<div class="wb-takeaway-box">';
      html += '<div class="wb-takeaway-label">&#128161; Key Takeaway</div>';
      html += dc.takeaway;
      html += '</div>';
    }

    // How to use this workbook banner
    html += '<div style="background:linear-gradient(90deg,rgba(26,107,74,0.08),rgba(26,107,74,0.03));border:1px solid rgba(26,107,74,0.18);border-radius:10px;padding:.85rem 1.1rem;margin-bottom:1.5rem;display:flex;align-items:center;gap:.75rem;">';
    html += '<div style="font-size:1.2rem;">&#9997;</div>';
    html += '<div style="font-size:.82rem;color:#1A6B4A;font-weight:600;">How to use this workbook: Read each prompt carefully, then write your answer in the lines below. There are no right or wrong answers — honest reflection produces the most useful results.</div>';
    html += '</div>';
  }

  // ── Workbook fields with inline guidance ──
  if (wb && wb.fields && wb.fields.length) {
    wb.fields.forEach(function(field, fi) {
      var fieldDoc = dc && dc.fieldDocs && dc.fieldDocs[fi] ? dc.fieldDocs[fi] : null;
      html += '<div class="wb-section">';
      html += '<div class="wb-section-title">&#128221; Section ' + (fi + 1) + '</div>';

      // Field guidance doc text
      if (fieldDoc) {
        html += '<div class="wb-doc-text">' + fieldDoc + '</div>';
      }

      html += '<div class="wb-field">';
      html += '<div class="wb-field-label">' + field.label + '</div>';
      html += '<div class="wb-field-lines">';
      for (var i = 0; i < (field.lines || 3); i++) html += '<div class="wb-line"></div>';
      html += '</div></div></div>';
    });
  } else {
    (sub.steps || []).forEach(function(step, i) {
      html += '<div class="wb-section">';
      html += '<div class="wb-section-title">Step ' + (i + 1) + ' — ' + step + '</div>';
      if (dc && dc.fieldDocs && dc.fieldDocs[i]) {
        html += '<div class="wb-doc-text">' + dc.fieldDocs[i] + '</div>';
      }
      html += '<div class="wb-field"><div class="wb-field-label">Your notes and actions:</div>';
      html += '<div class="wb-field-lines"><div class="wb-line"></div><div class="wb-line"></div><div class="wb-line"></div></div></div></div>';
    });
  }

  html += '</div></div>';

  html += '<div class="workbook-actions" style="margin-top:1rem;">';
  html += '<button class="btn btn-secondary" onclick="downloadWorkbook(\'' + capId + '\',' + subIdx + ',\'PDF\')">&#128196; Download PDF</button>';
  html += '<button class="btn btn-secondary" onclick="downloadWorkbook(\'' + capId + '\',' + subIdx + ',\'DOCX\')">&#128196; Download DOCX</button>';
  html += renderSaveBtn({ id:'wb_'+pid, type:'workbook', icon: cap.icon||'📓', title: sub.title + ' Workbook', subtitle: cap.title, capId: capId });
  html += '<button class="btn btn-complete ' + (done ? 'done' : '') + '" id="sc-wb-' + pid + '" onclick="markScProgress(\'' + pid + '\',\'workbook\')">' + (done ? '&#10003; Completed' : 'Mark as Complete') + '</button>';
  html += '</div>';
  return html;
}

// ── VIDEO ─────────────────────────────────────────────────────────────────────
function renderScVideo(cap, sub, pid, sp, idx) {
  var done = sp.video;
  var pool = [
    {src:'https://commondatastorage.googleapis.com/gtv-videos-bucket/sample/ForBiggerBlazes.mp4',         poster:'https://images.unsplash.com/photo-1460925895917-afdab827c52f?w=800&q=80'},
    {src:'https://commondatastorage.googleapis.com/gtv-videos-bucket/sample/SubaruOutbackOnStreetAndDirt.mp4', poster:'https://images.unsplash.com/photo-1542744173-8e7e53415bb0?w=800&q=80'},
    {src:'https://commondatastorage.googleapis.com/gtv-videos-bucket/sample/ElephantsDream.mp4',           poster:'https://images.unsplash.com/photo-1556761175-5973dc0f32e7?w=800&q=80'},
    {src:'https://commondatastorage.googleapis.com/gtv-videos-bucket/sample/BigBuckBunny.mp4',             poster:'https://images.unsplash.com/photo-1516321318423-f06f85e504b3?w=800&q=80'},
    {src:'https://commondatastorage.googleapis.com/gtv-videos-bucket/sample/ForBiggerEscapes.mp4',         poster:'https://images.unsplash.com/photo-1551288049-bebda4e38f71?w=800&q=80'},
    {src:'https://commondatastorage.googleapis.com/gtv-videos-bucket/sample/ForBiggerJoyrides.mp4',        poster:'https://images.unsplash.com/photo-1517048676732-d65bc937f952?w=800&q=80'},
    {src:'https://commondatastorage.googleapis.com/gtv-videos-bucket/sample/ForBiggerMeltdowns.mp4',       poster:'https://images.unsplash.com/photo-1454165804606-c3d57bc86b40?w=800&q=80'},
    {src:'https://commondatastorage.googleapis.com/gtv-videos-bucket/sample/ForBiggerFun.mp4',             poster:'https://images.unsplash.com/photo-1582213782179-e0d53f98f2ca?w=800&q=80'}
  ];
  var vid = pool[idx % pool.length];
  var steps = sub.steps || [];
  var html = '<div class="tab-section-title">&#127909; Video Guide</div>';
  html += '<div class="tab-section-sub">A complete walkthrough for: ' + sub.title + '</div>';
  html += '<div style="background:#000;border-radius:14px;overflow:hidden;margin-bottom:1.25rem;box-shadow:0 16px 48px rgba(0,0,0,.25);">';
  html += '<video controls preload="metadata" style="width:100%;display:block;max-height:400px;background:#000;" src="' + vid.src + '" poster="' + vid.poster + '" onplay="markScProgress(\'' + pid + '\',\'video\')">No HTML5 video support.</video>';
  html += '<div style="background:linear-gradient(135deg,var(--emerald-dark),var(--emerald));padding:.85rem 1.5rem;display:flex;align-items:center;gap:1rem;">';
  html += '<span style="background:rgba(255,255,255,.18);color:white;font-size:.68rem;font-weight:800;letter-spacing:.07em;text-transform:uppercase;padding:.2rem .55rem;border-radius:10px;flex-shrink:0;">Video Guide</span>';
  html += '<span style="color:white;font-weight:700;font-size:.9rem;flex:1;">' + sub.title + '</span>';
  html += '<span style="color:rgba(255,255,255,.65);font-size:.75rem;flex-shrink:0;">Free</span>';
  html += '</div></div>';
  if (steps.length) {
    html += '<div style="background:white;border-radius:12px;border:1px solid var(--border);padding:1.25rem;margin-bottom:1.25rem;">';
    html += '<div style="font-weight:800;font-size:.9rem;color:var(--ink);margin-bottom:.75rem;">We will show you how</div>';
    html += '<ol style="margin:0;padding-left:1.25rem;display:flex;flex-direction:column;gap:.5rem;">';
    steps.forEach(function(s) { html += '<li style="font-size:.87rem;color:var(--ink-light);line-height:1.5;">' + s + '</li>'; });
    html += '</ol></div>';
  }
  html += '<div style="margin-top:.75rem;display:flex;align-items:center;gap:.6rem;flex-wrap:wrap;">';
  html += renderSaveBtn({ id:'vid_'+pid, type:'lesson', icon:'🎬', title: sub.title + ' — Video Guide', subtitle: cap.title, capId: cap.id });
  html += '<button class="btn btn-complete ' + (done ? 'done' : '') + '" id="sc-vid-' + pid + '" onclick="markScProgress(\'' + pid + '\',\'video\')">' + (done ? '&#10003; Completed' : 'Mark as Complete') + '</button>';
  html += '</div>';
  return html;
}

// ── MICRO LESSONS ─────────────────────────────────────────────────────────────
function renderScMicro(cap, sub, pid, sp, idx) {
  var steps = sub.steps || [];
  var microPool = [
    {src:'https://commondatastorage.googleapis.com/gtv-videos-bucket/sample/ForBiggerBlazes.mp4',         poster:'https://images.unsplash.com/photo-1460925895917-afdab827c52f?w=400&q=80',dur:'4:30'},
    {src:'https://commondatastorage.googleapis.com/gtv-videos-bucket/sample/SubaruOutbackOnStreetAndDirt.mp4', poster:'https://images.unsplash.com/photo-1517048676732-d65bc937f952?w=400&q=80',dur:'6:15'},
    {src:'https://commondatastorage.googleapis.com/gtv-videos-bucket/sample/ElephantsDream.mp4',           poster:'https://images.unsplash.com/photo-1454165804606-c3d57bc86b40?w=400&q=80',dur:'5:00'},
    {src:'https://commondatastorage.googleapis.com/gtv-videos-bucket/sample/BigBuckBunny.mp4',             poster:'https://images.unsplash.com/photo-1551288049-bebda4e38f71?w=400&q=80',dur:'3:45'},
    {src:'https://commondatastorage.googleapis.com/gtv-videos-bucket/sample/ForBiggerEscapes.mp4',         poster:'https://images.unsplash.com/photo-1582213782179-e0d53f98f2ca?w=400&q=80',dur:'5:20'},
    {src:'https://commondatastorage.googleapis.com/gtv-videos-bucket/sample/ForBiggerJoyrides.mp4',        poster:'https://images.unsplash.com/photo-1515187029135-18ee286d815b?w=400&q=80',dur:'7:00'}
  ];
  var ld = (sp.lessons || []).filter(Boolean).length;
  var html = '<div class="tab-section-title">&#128241; Micro Lessons</div>';
  html += '<div class="tab-section-sub">' + steps.length + ' short focused lessons — one action step each.</div>';
  html += '<div style="display:flex;align-items:center;gap:.75rem;margin-bottom:1.25rem;">';
  html += '<div style="background:var(--emerald-glow);border:1px solid var(--emerald);border-radius:8px;padding:.4rem .9rem;font-size:.8rem;font-weight:700;color:var(--emerald);" id="sc-ml-count-' + pid + '">' + ld + '/' + steps.length + ' Completed</div>';
  html += '</div>';
  html += '<div class="micro-lessons-grid" id="sc-ml-grid-' + pid + '">';
  steps.forEach(function(step, i) {
    var lessDone = (sp.lessons || [])[i];
    var mv = microPool[(idx * 5 + i) % microPool.length];
    html += '<div class="ml-card ' + (lessDone ? 'completed' : '') + '" id="sc-ml-' + pid + '-' + i + '">';
    html += '<div class="ml-card-header" onclick="toggleScLesson(\'' + pid + '\',' + i + ')">';
    html += '<div class="ml-number" id="sc-ml-num-' + pid + '-' + i + '">' + (lessDone ? '&#10003;' : (i + 1)) + '</div>';
    html += '<div class="ml-info"><div class="ml-title">Step ' + (i + 1) + ': ' + step + '</div>';
    html += '<div class="ml-objective">Watch this lesson, then apply the step in your organization.</div></div>';
    html += '<span style="font-size:.7rem;color:var(--ink-pale);margin-right:.5rem;">' + mv.dur + '</span>';
    html += '<svg class="ml-chevron" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M5.293 7.293a1 1 0 011.414 0L10 10.586l3.293-3.293a1 1 0 111.414 1.414l-4 4a1 1 0 01-1.414 0l-4-4a1 1 0 010-1.414z"/></svg>';
    html += '</div>';
    html += '<div class="ml-body">';
    html += '<div style="background:#000;border-radius:10px;overflow:hidden;margin-bottom:1rem;box-shadow:0 4px 16px rgba(15,74,50,.15);">';
    html += '<video controls preload="none" poster="' + mv.poster + '" style="width:100%;display:block;max-height:220px;object-fit:cover;background:#000;" src="' + mv.src + '" onplay="markScLesson(\'' + pid + '\',' + i + ')">No HTML5 video.</video></div>';
    html += '<div class="ml-objective-box"><div class="ml-objective-box-label">Action Step</div><p>' + step + '</p></div>';
    html += '<div class="ml-complete-row" style="display:flex;align-items:center;gap:.6rem;flex-wrap:wrap;">';
    html += renderSaveBtn({ id:'ml_'+pid+'_'+i, type:'lesson', icon: cap.icon||'📚', title:'Step '+(i+1)+': '+step, subtitle: sub.title + ' · ' + cap.title, capId: cap.id });
    html += '<button class="btn btn-complete ' + (lessDone ? 'done' : '') + '" id="sc-ml-btn-' + pid + '-' + i + '" onclick="markScLesson(\'' + pid + '\',' + i + ')">' + (lessDone ? '&#10003; Completed' : 'Mark as Complete') + '</button></div>';
    html += '</div></div>';
  });
  html += '</div>';
  return html;
}

function toggleScLesson(pid, i) {
  var card = document.getElementById('sc-ml-' + pid + '-' + i);
  if (card) card.classList.toggle('open');
}

// ── TEMPLATES ─────────────────────────────────────────────────────────────────
function renderScTemplates(cap, sub, pid, sp) {
  var tpl  = sub.template;
  var done = sp.templates;
  var capId = cap.id;
  var html = '<div class="tab-section-title">&#128196; Templates</div>';
  html += '<div class="tab-section-sub">Ready-to-use tools for: ' + sub.title + '</div>';
  html += '<div class="templates-grid">';
  if (tpl) {
    // Store template data in a global registry so onclick can reference it safely
    var tplKey = pid + '_tpl';
    window._tplRegistry = window._tplRegistry || {};
    window._tplRegistry[tplKey] = { name: tpl.name||'', type: tpl.type||'DOCX', icon: tpl.icon||'📄', capTitle: cap.title||'', subTitle: sub.title||'' };
    html += '<div class="tpl-card ' + (done ? 'downloaded' : '') + '" id="sc-tpl-' + pid + '">';
    html += '<div class="tpl-header"><div class="tpl-file-icon">' + (tpl.icon || '&#128196;') + '</div>';
    html += '<div><div class="tpl-title">' + tpl.name + '</div><div class="tpl-type">' + tpl.type + ' Template</div></div></div>';
    html += '<div class="tpl-desc">A ready-to-use ' + tpl.type + ' template built specifically for this capability. Fully editable.</div>';
    html += '<div class="tpl-how-to"><div class="tpl-how-label">How to Use</div><div class="tpl-how"><p>Download, fill in your organization\'s details, and share with your team.</p></div></div>';
    html += '<div class="tpl-footer"><button class="btn btn-primary" onclick="markScProgress(\''+pid+'\',\'templates\');dlFromRegistry(\''+tplKey+'\')">Download ' + tpl.type + '</button>';
    html += renderSaveBtn({ id:'tpl_'+pid, type:'template', icon: tpl.icon||'📄', title: tpl.name, subtitle: cap.title, capId: capId });
    html += '<div class="tpl-downloaded-badge">Downloaded</div></div></div>';
  }
  // Checklist card — store steps in registry too
  var ckKey = pid + '_ck';
  window._tplRegistry = window._tplRegistry || {};
  window._tplRegistry[ckKey] = { title: sub.title||'', steps: sub.steps||[] };
  html += '<div class="tpl-card">';
  html += '<div class="tpl-header"><div class="tpl-file-icon">&#128203;</div>';
  html += '<div><div class="tpl-title">Implementation Checklist</div><div class="tpl-type">PDF</div></div></div>';
  html += '<div class="tpl-desc">A printable step-by-step checklist to track your team\'s progress through every stage of this capability.</div>';
  html += '<div class="tpl-how-to"><div class="tpl-how-label">How to Use</div><div class="tpl-how"><p>Print or share digitally. Check off each step as your team completes it.</p></div></div>';
  html += '<div class="tpl-footer"><button class="btn btn-primary" onclick="dlChecklistFromRegistry(\''+ckKey+'\')">Download PDF</button>';
  html += renderSaveBtn({ id:'ck_'+pid, type:'template', icon:'📋', title: sub.title + ' — Checklist', subtitle: cap.title, capId: capId });
  html += '</div></div>';
  html += '</div>';
  html += '<div style="background:linear-gradient(135deg,var(--emerald-dark),var(--emerald));border-radius:14px;padding:1.25rem 1.75rem;display:flex;align-items:center;justify-content:space-between;gap:1rem;flex-wrap:wrap;margin-top:1.5rem;">';
  html += '<div style="color:white;"><div style="font-weight:800;font-size:.95rem;margin-bottom:.2rem;">Full Template Pack</div><div style="font-size:.8rem;opacity:.85;">All templates for ' + cap.title + ', free forever</div></div>';
  html += '<button onclick="downloadFullPack(\''+capId+'\')" style="background:white;color:var(--emerald-dark);font-weight:800;font-size:.85rem;padding:.75rem 1.5rem;border-radius:10px;border:none;cursor:pointer;font-family:inherit;">Download All</button></div>';
  return html;
}

// ── ASSESSMENT ────────────────────────────────────────────────────────────────
function renderScAssessment(cap, sub, pid, sp, subIdx) {
  var questions = sub.quiz || [];
  var done = sp.assessment;
  var html = '<div class="tab-section-title">&#127919; Assessment</div>';
  html += '<div class="tab-section-sub">Test your understanding — score 70%+ to complete this capability.</div>';
  if (!questions.length) {
    html += '<div style="padding:2rem;text-align:center;color:var(--ink-light);background:white;border-radius:14px;border:1px solid var(--border);">No assessment questions for this capability yet.</div>';
    return html;
  }
  html += '<div class="assessment-inner">';
  html += '<div class="assessment-instructions"><div class="assessment-instructions-title">Instructions</div>';
  html += '<p>Select the best answer for each question. The last option is always the strongest response. Submit all answers to see your score.</p>';
  html += '<div class="assessment-meta-row">';
  html += '<div class="assessment-meta-item"><div class="key">Questions</div><div class="val">' + questions.length + '</div></div>';
  html += '<div class="assessment-meta-item"><div class="key">Passing Score</div><div class="val">70%</div></div>';
  html += '<div class="assessment-meta-item"><div class="key">Grading</div><div class="val">Auto-graded</div></div>';
  html += '</div></div>';
  html += '<div class="assessment-questions" id="sc-aq-' + pid + '">';
  questions.forEach(function(q, qi) {
    var opts = q.opts || q.options || [];
    html += '<div class="aq-card" id="sc-aqcard-' + pid + '-' + qi + '">';
    html += '<div class="aq-number">Question ' + (qi + 1) + ' of ' + questions.length + '</div>';
    html += '<div class="aq-question">' + q.q + '</div>';
    html += '<div class="aq-options">';
    opts.forEach(function(opt, oi) {
      var correct = opts.length - 1;  // last option is always best
      html += '<div class="aq-option" id="sc-aqopt-' + pid + '-' + qi + '-' + oi + '" onclick="selectScAnswer(\'' + pid + '\',' + qi + ',' + oi + ',' + correct + ')">';
      html += '<div class="aq-dot" id="sc-aqdot-' + pid + '-' + qi + '-' + oi + '"></div><span>' + opt + '</span></div>';
    });
    html += '</div></div>';
  });
  html += '</div>';
  html += '<div class="scoring-rubric"><div class="scoring-title">Scoring Guide</div><div class="scoring-levels">';
  html += '<div class="scoring-level"><div class="score-badge excellent">90-100%</div><p>Excellent — Strong mastery</p></div>';
  html += '<div class="scoring-level"><div class="score-badge good">70-89%</div><p>Proficient — Good understanding</p></div>';
  html += '<div class="scoring-level"><div class="score-badge needs">Below 70%</div><p>Needs Review — Revisit micro lessons</p></div>';
  html += '</div></div>';
  html += '<button class="btn btn-primary ' + (done ? 'done' : '') + '" id="sc-aq-submit-' + pid + '" onclick="submitScAssessment(\'' + pid + '\',\'' + cap.id + '\',' + subIdx + ',' + questions.length + ')" style="width:100%;justify-content:center;padding:.8rem;margin-top:1rem;">' + (done ? '&#10003; Assessment Passed' : 'Submit Assessment') + '</button>';
  html += '<div id="sc-aq-result-' + pid + '"></div>';
  html += '</div>';
  return html;
}

// ── INTERACTION HANDLERS ──────────────────────────────────────────────────────
function markScProgress(pid, type) {
  if (!scProgress[pid]) return;
  scProgress[pid][type] = true;
  var btn = document.getElementById('sc-' + (type==='workbook'?'wb':type==='video'?'vid':type==='templates'?'tpl':type) + '-' + pid);
  if (btn) { btn.textContent = '&#10003; Completed'; btn.innerHTML = '&#10003; Completed'; btn.classList.add('done'); }
  saveProgress();
  showToast(type.charAt(0).toUpperCase() + type.slice(1) + ' marked as complete!');
}

function markScLesson(pid, i) {
  if (!scProgress[pid]) return;
  if (!scProgress[pid].lessons) scProgress[pid].lessons = [];
  scProgress[pid].lessons[i] = true;
  var card = document.getElementById('sc-ml-' + pid + '-' + i);
  var btn  = document.getElementById('sc-ml-btn-' + pid + '-' + i);
  var num  = document.getElementById('sc-ml-num-' + pid + '-' + i);
  if (card) card.classList.add('completed');
  if (btn)  { btn.innerHTML = '&#10003; Completed'; btn.classList.add('done'); }
  if (num)  num.innerHTML = '&#10003;';
  var ld   = scProgress[pid].lessons.filter(Boolean).length;
  var cnt  = document.getElementById('sc-ml-count-' + pid);
  var steps = (function() { var parts = pid.split('_'); var cap = CAPABILITIES[parts[0]]; return cap && cap.subCapabilities && cap.subCapabilities[parts[1]] ? (cap.subCapabilities[parts[1]].steps||[]).length : 5; })();
  if (cnt) cnt.textContent = ld + '/' + steps + ' Completed';
  saveProgress();
  showToast('Lesson ' + (i + 1) + ' marked as complete!');
}

var scAnswerMap = {};
function selectScAnswer(pid, qi, oi, correct) {
  var key = pid + '_' + qi;
  if (scAnswerMap[key] !== undefined) return;
  scAnswerMap[key] = oi;
  document.querySelectorAll('[id^="sc-aqopt-' + pid + '-' + qi + '-"]').forEach(function(el) { el.classList.remove('selected'); });
  var opt = document.getElementById('sc-aqopt-' + pid + '-' + qi + '-' + oi);
  if (opt) opt.classList.add('selected');
}

function submitScAssessment(pid, capId, subIdx, totalQ) {
  var correct = 0;
  for (var qi = 0; qi < totalQ; qi++) {
    var key = pid + '_' + qi;
    if (scAnswerMap[key] === undefined) {
      showToast('Please answer all ' + totalQ + ' questions first.');
      return;
    }
    // last option is always the best answer
    var opts = document.querySelectorAll('[id^="sc-aqopt-' + pid + '-' + qi + '-"]');
    if (scAnswerMap[key] === opts.length - 1) correct++;
  }
  var score = Math.round((correct / totalQ) * 100);
  var passed = score >= 70;
  if (passed) {
    scProgress[pid].assessment = true;
    saveProgress();
    var submitBtn = document.getElementById('sc-aq-submit-' + pid);
    if (submitBtn) { submitBtn.innerHTML = '&#10003; Assessment Passed'; submitBtn.classList.add('done'); }
  }
  var resultEl = document.getElementById('sc-aq-result-' + pid);
  if (resultEl) {
    var capKeys = Object.keys(CAPABILITIES);
    var currentCapIdx = capKeys.indexOf(currentCapId);
    var currentSubList = CAPABILITIES[currentCapId] ? (CAPABILITIES[currentCapId].subCapabilities || []) : [];
    var hasNextSub  = (currentSubCapIdx + 1) < currentSubList.length;
    var hasNextCap  = (currentCapIdx + 1) < capKeys.length;
    var nextSubIdx  = currentSubCapIdx + 1;
    var nextCapId   = hasNextCap ? capKeys[currentCapIdx + 1] : null;
    var nextCap     = nextCapId ? CAPABILITIES[nextCapId] : null;

    var passActions = '';
    if (hasNextSub) {
      passActions = '<button onclick="openSubCapability(\'' + currentCapId + '\',' + nextSubIdx + ')" '
        + 'style="margin-top:.85rem;display:inline-flex;align-items:center;gap:.5rem;background:linear-gradient(135deg,#065f46,#059669);color:white;border:none;border-radius:10px;padding:.7rem 1.4rem;font-size:.88rem;font-weight:800;cursor:pointer;font-family:inherit;">'
        + '▶ Next: ' + currentSubList[nextSubIdx].title + '</button>';
    } else if (nextCap) {
      passActions = '<button onclick="loadCapability(\'' + nextCapId + '\')" '
        + 'style="margin-top:.85rem;display:inline-flex;align-items:center;gap:.5rem;background:linear-gradient(135deg,#065f46,#059669);color:white;border:none;border-radius:10px;padding:.7rem 1.4rem;font-size:.88rem;font-weight:800;cursor:pointer;font-family:inherit;">'
        + nextCap.icon + ' Proceed to ' + nextCap.title + ' →</button>';
    } else {
      passActions = '<button onclick="showDashboard()" '
        + 'style="margin-top:.85rem;display:inline-flex;align-items:center;gap:.5rem;background:linear-gradient(135deg,#065f46,#059669);color:white;border:none;border-radius:10px;padding:.7rem 1.4rem;font-size:.88rem;font-weight:800;cursor:pointer;font-family:inherit;">'
        + 'View My Profile →</button>';
    }

    var failActions = '<button onclick="retakeScAssessment(\'' + pid + '\')" '
      + 'style="margin-top:.85rem;display:inline-flex;align-items:center;gap:.5rem;background:white;color:#991b1b;border:2px solid #fca5a5;border-radius:10px;padding:.7rem 1.4rem;font-size:.88rem;font-weight:800;cursor:pointer;font-family:inherit;">'
      + 'Retake Assessment</button>';

    resultEl.innerHTML = '<div style="margin-top:1rem;padding:1.5rem;background:' + (passed ? '#d1fae5' : '#fef2f2') + ';border-radius:14px;border:1.5px solid ' + (passed ? '#6ee7b7' : '#fca5a5') + ';text-align:center;">'
      + '<div style="font-size:2rem;margin-bottom:.35rem;">' + (passed ? '🎉' : '😔') + '</div>'
      + '<div style="font-size:1.75rem;font-weight:900;color:' + (passed ? '#065f46' : '#991b1b') + ';font-family:\'DM Mono\',monospace;">' + score + '%</div>'
      + '<div style="font-size:.95rem;font-weight:800;color:' + (passed ? '#065f46' : '#991b1b') + ';margin-top:.3rem;">' + (passed ? '✓ Passed! Great work.' : '✗ Not quite — review and try again.') + '</div>'
      + '<div style="font-size:.8rem;color:' + (passed ? '#047857' : '#b91c1c') + ';margin-top:.3rem;">' + correct + ' of ' + totalQ + ' correct · ' + (passed ? 'Passing score: 70%' : 'Need 70% to pass') + '</div>'
      + (passed ? passActions : failActions)
      + '</div>';
  }
  showToast(passed ? 'Assessment passed! ' + score + '%' : 'Score: ' + score + '% — try again after reviewing.');
}

function retakeScAssessment(pid) {
  // Reset answers and result, scroll back to top of assessment panel
  scAnswerMap = scAnswerMap || {};
  Object.keys(scAnswerMap).forEach(function(k) { if (k.indexOf(pid) === 0) delete scAnswerMap[k]; });
  // Deselect all radio options visually
  document.querySelectorAll('[id^="sc-aqopt-' + pid + '-"]').forEach(function(opt) {
    opt.style.background   = '';
    opt.style.borderColor  = '';
    opt.style.color        = '';
    opt.style.fontWeight   = '';
  });
  var resultEl = document.getElementById('sc-aq-result-' + pid);
  if (resultEl) resultEl.innerHTML = '';
  var submitBtn = document.getElementById('sc-aq-submit-' + pid);
  if (submitBtn) { submitBtn.innerHTML = 'Submit Assessment'; submitBtn.classList.remove('done'); }
  scProgress[pid] && (scProgress[pid].assessment = false);
  document.getElementById('sc-panel-' + pid + '-assessment').scrollIntoView({ behavior:'smooth', block:'start' });
  showToast('Assessment reset — good luck! 💪');
}

// ── PROGRESS SYNC ─────────────────────────────────────────────────────────────
function updateAllProgress() {
  Object.keys(CAPABILITIES).forEach(function(key) {
    var pct = getCapPct(key);
    var bar   = document.getElementById('home-bar-' + key);
    var label = document.getElementById('home-label-' + key);
    if (bar)   bar.style.width = pct + '%';
    if (label) label.textContent = pct + '% complete';
  });
}

// ── HOME GRID ─────────────────────────────────────────────────────────────────
function renderHomeGrid() {
  var grid = document.getElementById('homeCapGrid');
  var badges = {
    strategy:   ['Strategic Planning','Workbooks','Video Guides'],
    programs:   ['Program Design','Workbooks','Video Guides'],
    leadership: ['Leadership Dev','Workbooks','Video Guides'],
    team:       ['Team Building','Workbooks','Video Guides'],
    systems:    ['Org Systems','Workbooks','Video Guides'],
    funding:    ['Funding Strategy','Workbooks','Video Guides'],
    comms:      ['Communications','Workbooks','Video Guides'],
    finance:    ['Financial Mgmt','Workbooks','Video Guides'],
  };
  var capKeys = Object.keys(CAPABILITIES);
  grid.innerHTML = capKeys.map(function(key) {
    var cap = CAPABILITIES[key];
    var pct = getCapPct(key);
    var bs  = badges[key] || [];
    return '<div class="cap-card" onclick="loadCapability(\'' + key + '\')">'
      + '<div class="cap-card-icon">' + cap.icon + '</div>'
      + '<h3>' + cap.title + '</h3>'
      + '<p>' + cap.description.substring(0, 90) + '\u2026</p>'
      + '<div class="cap-card-meta">' + bs.map(function(b) { return '<span class="cap-badge">' + b + '</span>'; }).join('') + '</div>'
      + '<div class="cap-progress-mini"><div class="cap-progress-mini-fill" id="home-bar-' + key + '" style="width:' + pct + '%"></div></div>'
      + '<div class="cap-progress-label" id="home-label-' + key + '">' + pct + '% complete</div>'
      + '</div>';
  }).join('');
}

renderHomeGrid();


// ── NAVIGATION HISTORY STACK ──────────────────────────────────────────────────
var navHistory = []; // each entry: { pageId, label, capId, subIdx }

function navBackAction() {
  if (navHistory.length > 0) {
    var prev = navHistory.pop();
    var newLabel = navHistory.length > 0 ? navHistory[navHistory.length-1].label : 'Back to Home';

    if (prev.pageId === 'assessment-page') {
      document.querySelectorAll('.page').forEach(function(p) { p.classList.remove('active'); });
      document.getElementById('assessment-page').classList.add('active');
      document.getElementById('assessProgress').style.display = 'none';
      document.getElementById('assessQuestionCard').innerHTML = '';
      document.getElementById('assessResults').style.display = 'block';
      window.scrollTo(0, 0);
      if (navHistory.length > 0) {
        document.getElementById('navBackBtn').style.display = 'flex';
        document.getElementById('navBackLabel').textContent = newLabel;
      } else {
        document.getElementById('navBackBtn').style.display = 'none';
      }
    } else if (prev.pageId === 'micro-lesson-detail-page') {
      // Restore the micro lesson detail page (it still has its content)
      document.querySelectorAll('.page').forEach(function(p) { p.classList.remove('active'); });
      document.getElementById('micro-lesson-detail-page').classList.add('active');
      document.getElementById('navBackBtn').style.display = 'flex';
      document.getElementById('navBackLabel').textContent = newLabel || '← Micro Lessons';
      setFloatingBack(newLabel || '← Micro Lessons');
      window.scrollTo(0, 0);
    } else if (prev.pageId === 'micro-lessons-page') {
      document.querySelectorAll('.page').forEach(function(p) { p.classList.remove('active'); });
      document.getElementById('micro-lessons-page').classList.add('active');
      renderMlFilters();
      renderMicroLessonsGrid(document.getElementById('mlSearchInput') ? document.getElementById('mlSearchInput').value : '');
      if (navHistory.length > 0) {
        document.getElementById('navBackBtn').style.display = 'flex';
        document.getElementById('navBackLabel').textContent = newLabel || 'Back to Home';
        setFloatingBack(newLabel || 'Back to Home');
      } else {
        document.getElementById('navBackBtn').style.display = 'flex';
        document.getElementById('navBackLabel').textContent = 'Back to Home';
        setFloatingBack('Back to Home');
      }
      window.scrollTo(0, 0);
    } else if (prev.pageId === 'learning-path-detail-page') {
      if (prev.pathId) {
        openLearningPath(prev.pathId);
      } else {
        document.querySelectorAll('.page').forEach(function(p) { p.classList.remove('active'); });
        document.getElementById('learning-path-detail-page').classList.add('active');
        document.getElementById('navBackBtn').style.display = 'flex';
        document.getElementById('navBackLabel').textContent = newLabel || '← Learning Paths';
        setFloatingBack(newLabel || '← Learning Paths');
        window.scrollTo(0, 0);
      }
    } else if (prev.pageId === 'learning-paths-page') {
      lpCurrentFilter = 'All';
      showPage('learning-paths-page', '← Back to Home');
      renderLpFilters();
      renderLearningPaths();
    } else if (prev.pageId === 'webinar-detail-page') {
      // Go back to the webinar detail page (it keeps its rendered content)
      document.querySelectorAll('.page').forEach(function(p) { p.classList.remove('active'); });
      document.getElementById('webinar-detail-page').classList.add('active');
      document.getElementById('navBackBtn').style.display = navHistory.length > 0 ? 'flex' : 'none';
      document.getElementById('navBackLabel').textContent = newLabel || '← Webinars';
      setFloatingBack(newLabel || '← Webinars');
      window.scrollTo(0, 0);
    } else if (prev.pageId === 'webinars-page') {
      showWebinarsPage();
    } else if (prev.pageId === 'tools-templates-page') {
      showToolsTemplatesPage();
    } else if (prev.pageId === 'workbooks-page') {
      showWorkbooksPage();
    } else if (prev.pageId === 'success-stories-page') {
      showSuccessStoriesPage();
    } else if (prev.pageId === 'resource-library-page') {
      showResourceLibraryPage();
    } else if (prev.pageId === 'video-guides-page') {
      showVideoGuidesPage();
    } else if (prev.pageId === 'improvement-tracks-page') {
      showImprovementTracksPage();
    } else if (prev.pageId === 'track-detail-page') {
      if (currentTrackId) openTrack(currentTrackId); else showImprovementTracksPage();
    } else if (prev.pageId === 'track-learn-page') {
      // Restore the learn page with its rendered content
      document.querySelectorAll('.page').forEach(function(p) { p.classList.remove('active'); });
      document.getElementById('track-learn-page').classList.add('active');
      document.getElementById('navBackBtn').style.display = navHistory.length > 0 ? 'flex' : 'none';
      if (navHistory.length > 0) {
        document.getElementById('navBackLabel').textContent = newLabel;
        setFloatingBack(newLabel);
      } else { hideFloatingBack(); }
      window.scrollTo(0, 0);
    } else if (prev.pageId === 'track-improve-page') {
      // Restore the improve page with its rendered content
      document.querySelectorAll('.page').forEach(function(p) { p.classList.remove('active'); });
      document.getElementById('track-improve-page').classList.add('active');
      document.getElementById('navBackBtn').style.display = navHistory.length > 0 ? 'flex' : 'none';
      if (navHistory.length > 0) {
        document.getElementById('navBackLabel').textContent = newLabel;
        setFloatingBack(newLabel);
      } else { hideFloatingBack(); }
      window.scrollTo(0, 0);
    } else if (prev.pageId === 'templates-page') {
      showPage('templates-page', 'Back to Home'); renderTemplatesPage();
    } else if (prev.pageId === 'my-learning-path-page') {
      showMyLearningPath();
    } else if (prev.pageId === 'categories-page') {
      showCategoriesPage();
    } else if (prev.pageId === 'cap-page' && prev.capId) {
      loadCapabilityNoHistory(prev.capId);
    } else if (prev.pageId === 'cap-learn-page') {
      // Restore the learn page — it keeps its rendered content
      document.querySelectorAll('.page').forEach(function(p) { p.classList.remove('active'); });
      document.getElementById('cap-learn-page').classList.add('active');
      if (navHistory.length > 0) {
        document.getElementById('navBackBtn').style.display = 'flex';
        document.getElementById('navBackLabel').textContent = newLabel;
        setFloatingBack(newLabel);
      } else {
        document.getElementById('navBackBtn').style.display = 'none';
        hideFloatingBack();
      }
      window.scrollTo(0, 0);
    } else if (prev.pageId === 'cap-learn-more-page') {
      // Restore the learn-more page — it keeps its rendered content
      document.querySelectorAll('.page').forEach(function(p) { p.classList.remove('active'); });
      document.getElementById('cap-learn-more-page').classList.add('active');
      if (navHistory.length > 0) {
        document.getElementById('navBackBtn').style.display = 'flex';
        document.getElementById('navBackLabel').textContent = newLabel;
        setFloatingBack(newLabel);
      } else {
        document.getElementById('navBackBtn').style.display = 'none';
        hideFloatingBack();
      }
      window.scrollTo(0, 0);
    } else if (prev.pageId === 'cap-improve-page') {
      // Restore the improve page — it keeps its rendered content
      document.querySelectorAll('.page').forEach(function(p) { p.classList.remove('active'); });
      document.getElementById('cap-improve-page').classList.add('active');
      if (navHistory.length > 0) {
        document.getElementById('navBackBtn').style.display = 'flex';
        document.getElementById('navBackLabel').textContent = newLabel;
        setFloatingBack(newLabel);
      } else {
        document.getElementById('navBackBtn').style.display = 'none';
        hideFloatingBack();
      }
      window.scrollTo(0, 0);
    } else {
      goHome();
    }
  } else if (currentCapId && currentSubCapIdx !== null) {
    backToCategory();
  } else if (currentCapId && currentSubCapIdx === null) {
    // On cap-page with no history — go back to All Capabilities
    showCategoriesPage();
  } else {
    goHome();
  }
}


function showPage(pageId, backLabel) {
  navHistory = []; // clear history on direct nav
  document.querySelectorAll('.page').forEach(function(p) { p.classList.remove('active'); });
  document.getElementById(pageId).classList.add('active');
  document.getElementById('navBackBtn').style.display = 'flex';
  document.getElementById('navBackLabel').textContent = backLabel || 'Back to Home';
  setFloatingBack(backLabel || 'Back to Home');
  currentCapId = null;
  currentSubCapIdx = null;
  window.scrollTo(0, 0);
}


function showCategoriesPage() {
  navHistory = [];
  document.querySelectorAll('.page').forEach(function(p) { p.classList.remove('active'); });
  document.getElementById('categories-page').classList.add('active');
  document.getElementById('navBackBtn').style.display = 'none';
  hideFloatingBack();
  currentCapId = null;
  currentSubCapIdx = null;
  updateCapStatsBar();
  renderCategoriesGrid();
  window.scrollTo(0, 0);
}

function showMyLearningPath() {
  // Push current page to history before navigating
  var categoriesActive = document.getElementById('categories-page') && document.getElementById('categories-page').classList.contains('active');
  var capPageActive = document.getElementById('cap-page') && document.getElementById('cap-page').classList.contains('active');
  if (categoriesActive) {
    navHistory = [{ pageId: 'categories-page', label: '← All Capabilities', capId: null, subIdx: null }];
  } else if (capPageActive && currentCapId) {
    navHistory = [
      { pageId: 'categories-page', label: '← All Capabilities', capId: null, subIdx: null },
      { pageId: 'cap-page', label: '← ' + (CAPABILITIES[currentCapId] ? CAPABILITIES[currentCapId].title : 'Capability'), capId: currentCapId, subIdx: null }
    ];
  } else {
    navHistory = [{ pageId: 'categories-page', label: '← All Capabilities', capId: null, subIdx: null }];
  }
  document.querySelectorAll('.page').forEach(function(p) { p.classList.remove('active'); });
  document.getElementById('my-learning-path-page').classList.add('active');
  document.getElementById('navBackBtn').style.display = 'flex';
  document.getElementById('navBackLabel').textContent = '← All Capabilities';
  setFloatingBack('← All Capabilities');
  currentCapId = null;
  currentSubCapIdx = null;
  updateCapStatsBar();
  renderMyLearningPath();
  window.scrollTo(0, 0);
}

function renderMyLearningPath() {
  var content = document.getElementById('mlpContent');
  if (!content) return;
  var capKeys = Object.keys(CAPABILITIES);
  var hasScores = capKeys.some(function(k){ return assessScores[k]; });

  if (!hasScores) {
    content.innerHTML = '<div style="background:linear-gradient(135deg,rgba(26,107,74,.06),rgba(26,107,74,.02));border:1.5px dashed rgba(26,107,74,.3);border-radius:16px;padding:2.5rem;text-align:center;">'
      + '<div style="font-size:2rem;margin-bottom:.85rem;">🎯</div>'
      + '<div style="font-weight:800;font-size:1.05rem;color:var(--emerald-dark);margin-bottom:.4rem;">Take the assessment first for a personalised recommendation</div>'
      + '<p style="font-size:.88rem;color:var(--ink-light);line-height:1.7;max-width:440px;margin:0 auto 1.5rem;">Your learning path is built from your assessment results. Take the full assessment or rate yourself on the Capabilities page.</p>'
      + '<div style="display:flex;gap:.75rem;justify-content:center;flex-wrap:wrap;">'
      + '<button onclick="showAssessmentPage()" style="background:var(--emerald);color:white;border:none;border-radius:10px;padding:.75rem 1.5rem;font-size:.88rem;font-weight:700;cursor:pointer;font-family:inherit;">Take Assessment →</button>'
      + '<button onclick="showCategoriesPage()" style="background:white;color:var(--emerald);border:1.5px solid rgba(26,107,74,.3);border-radius:10px;padding:.75rem 1.5rem;font-size:.88rem;font-weight:700;cursor:pointer;font-family:inherit;">Rate Capabilities</button>'
      + '</div></div>';
    return;
  }

  var sorted = capKeys.slice().sort(function(a,b){
    var sa = assessScores[a] || 6; var sb = assessScores[b] || 6;
    return sa - sb;
  });
  var accents = ['#dc2626','#f59e0b','#3b82f6','#8b5cf6','#0891b2','#059669','#d97706','#6366f1'];

  var html = '';
  sorted.forEach(function(key, i) {
    var cap   = CAPABILITIES[key];
    var s     = assessScores[key] || 0;
    var pct   = getCapPct(key);
    var accent = accents[i] || 'var(--emerald)';
    var subs  = (cap.subCapabilities || []).length;
    var tpls  = (cap.templates || []).length;
    var label = s ? getScoreLabel(s) : 'Not rated';
    var isGap  = s && s <= 2;
    var isStrong = s && s >= 4;

    html += '<div style="background:white;border:1.5px solid var(--border);border-radius:16px;overflow:hidden;margin-bottom:1rem;transition:all .2s;" onmouseover="this.style.borderColor=\'' + accent + '\'" onmouseout="this.style.borderColor=\'var(--border)\'">'
      + '<div style="height:4px;background:' + accent + ';"></div>'
      + '<div style="padding:1.35rem 1.5rem;display:flex;align-items:center;gap:1rem;flex-wrap:wrap;">'
      // Rank number
      + '<div style="width:42px;height:42px;min-width:42px;border-radius:10px;background:' + accent + '18;border:1.5px solid ' + accent + '30;display:flex;align-items:center;justify-content:center;font-family:\'DM Mono\',monospace;font-size:.92rem;font-weight:800;color:' + accent + ';flex-shrink:0;">' + (i+1) + '</div>'
      + '<div style="font-size:1.35rem;">' + cap.icon + '</div>'
      + '<div style="flex:1;min-width:0;">'
      + '<div style="font-weight:800;font-size:.97rem;color:var(--ink);">' + cap.title + '</div>'
      + '<div style="font-size:.75rem;color:var(--ink-light);margin-top:.15rem;">'
      + (s ? 'Score: <strong style="color:' + accent + '">' + s + '/5</strong> — ' + label : '<em>Not yet rated</em>')
      + ' &nbsp;·&nbsp; ' + subs + ' sub-capabilities &nbsp;·&nbsp; ' + tpls + ' templates</div>'
      + '</div>'
      // Progress
      + '<div style="display:flex;flex-direction:column;align-items:flex-end;gap:.3rem;flex-shrink:0;">'
      + (isGap ? '<span style="font-size:.65rem;font-weight:800;padding:.2rem .55rem;border-radius:20px;background:rgba(220,38,38,.1);color:#dc2626;border:1px solid rgba(220,38,38,.2);">Priority Gap</span>' : '')
      + (isStrong ? '<span style="font-size:.65rem;font-weight:800;padding:.2rem .55rem;border-radius:20px;background:rgba(22,163,74,.1);color:#16a34a;border:1px solid rgba(22,163,74,.2);">Strong Area</span>' : '')
      + '<div style="font-size:.7rem;color:var(--ink-light);">Module progress</div>'
      + '<div style="width:90px;height:6px;background:var(--border);border-radius:3px;overflow:hidden;">'
      + '<div style="height:100%;background:' + accent + ';width:' + pct + '%;border-radius:3px;"></div></div>'
      + '<div style="font-size:.68rem;color:var(--ink-pale);">' + pct + '% complete</div>'
      + '</div>'
      + '<button onclick="loadCapability(\'' + key + '\')" style="background:' + accent + ';color:white;border:none;border-radius:8px;padding:.55rem 1.1rem;font-size:.82rem;font-weight:700;cursor:pointer;font-family:inherit;white-space:nowrap;flex-shrink:0;">' + (pct===0?'Start →':'Continue →') + '</button>'
      + '</div></div>';
  });

  // Quick actions at bottom
  html += '<div style="display:grid;grid-template-columns:1fr 1fr;gap:1rem;margin-top:2rem;">'
    + '<div style="background:white;border:1.5px solid var(--border);border-radius:14px;padding:1.25rem;display:flex;align-items:center;gap:.85rem;cursor:pointer;transition:all .2s;" onclick="showRoadmapPage()" onmouseover="this.style.borderColor=\'var(--emerald)\'" onmouseout="this.style.borderColor=\'var(--border)\'">'
    + '<div style="font-size:1.75rem;">🗺️</div><div><div style="font-weight:800;font-size:.92rem;color:var(--ink);">90-Day Roadmap</div><div style="font-size:.78rem;color:var(--ink-light);">Week-by-week action plan</div></div></div>'
    + '<div style="background:white;border:1.5px solid var(--border);border-radius:14px;padding:1.25rem;display:flex;align-items:center;gap:.85rem;cursor:pointer;transition:all .2s;" onclick="showWeeklyChecklist()" onmouseover="this.style.borderColor=\'var(--emerald)\'" onmouseout="this.style.borderColor=\'var(--border)\'">'
    + '<div style="font-size:1.75rem;">✅</div><div><div style="font-weight:800;font-size:.92rem;color:var(--ink);">This Week\'s Checklist</div><div style="font-size:.78rem;color:var(--ink-light);">5 priority tasks right now</div></div></div>'
    + '</div>';

  content.innerHTML = html;
}

function showSearchPage() {
  showPage('search-page', 'Back to Home');
  document.getElementById('searchInput').focus();
  document.getElementById('searchResults').innerHTML = '';
}

// ── USER STATE ────────────────────────────────────────────────────────────────
var currentUser = null; // { firstName, lastName, email, org, role, country }
var savedItems = [];    // { id, type, icon, title, subtitle, capId }
var lessonFilter = 'all';
var savedFilter = 'all';

function showDashboard() {
  showPage('dashboard-page', 'Back to Home');
  renderProfile();
}

function renderProfile() {
  var locked   = document.getElementById('profileLocked');
  var unlocked = document.getElementById('profileUnlocked');
  if (!currentUser) {
    locked.style.display   = 'block';
    unlocked.style.display = 'none';
    return;
  }
  locked.style.display   = 'none';
  unlocked.style.display = 'block';

  // Header
  var initials = (currentUser.firstName[0] + (currentUser.lastName ? currentUser.lastName[0] : '')).toUpperCase();
  document.getElementById('profileAvatar').textContent = initials;
  document.getElementById('profileName').textContent   = currentUser.firstName + ' ' + (currentUser.lastName || '');
  document.getElementById('profileOrg').textContent    = (currentUser.role ? currentUser.role + ' · ' : '') + (currentUser.org || '');

  // Pre-fill account tab
  document.getElementById('accFirstName').value = currentUser.firstName || '';
  document.getElementById('accLastName').value  = currentUser.lastName  || '';
  document.getElementById('accEmail').value     = currentUser.email     || '';
  document.getElementById('accOrg').value       = currentUser.org       || '';

  // Stats
  var capKeys = Object.keys(CAPABILITIES);
  var allLessons = getAllLessons();
  var doneLessons = allLessons.filter(function(l){ return l.status === 'done'; });
  var overallScore = assessScores && Object.keys(assessScores).length
    ? Math.round((Object.values(assessScores).reduce(function(a,b){return a+b;},0) / (Object.keys(assessScores).length * 5)) * 100)
    : null;

  document.getElementById('profileOverallScore').textContent = overallScore !== null ? overallScore + '%' : '—';
  document.getElementById('profileLessonsCount').textContent = doneLessons.length;
  document.getElementById('profileSavedCount').textContent   = savedItems.length;

  // Render active tab
  switchProfileTab(document.querySelector('.profile-tab.active') ? document.querySelector('.profile-tab.active').id.replace('ptab-','') : 'progress');
}

function switchProfileTab(tab) {
  document.querySelectorAll('.profile-tab').forEach(function(b) { b.classList.remove('active'); });
  document.querySelectorAll('.profile-tab-content').forEach(function(c) { c.style.display = 'none'; });
  var btn = document.getElementById('ptab-' + tab);
  var content = document.getElementById('ptab-content-' + tab);
  if (btn) btn.classList.add('active');
  if (content) content.style.display = 'block';

  if (tab === 'progress')    renderProgressTab();
  if (tab === 'priorities')  renderPrioritiesTab();
  if (tab === 'lessons')     renderLessonsTab(lessonFilter);
  if (tab === 'saved')       renderSavedTab(savedFilter);
}

// ── PROGRESS TAB ──────────────────────────────────────────────────────────────
function renderProgressTab() {
  var capKeys = Object.keys(CAPABILITIES);
  var allLessons = getAllLessons();
  var doneLessons  = allLessons.filter(function(l){ return l.status==='done'; });
  var inProgLessons = allLessons.filter(function(l){ return l.status==='inprogress'; });
  var overallPct = Math.round(capKeys.map(function(k){return getCapPct(k);}).reduce(function(a,b){return a+b;},0) / capKeys.length);

  // Stat cards
  var stats = [
    { icon:'📊', label:'Overall Progress', value: overallPct + '%', color:'var(--emerald)' },
    { icon:'✅', label:'Lessons Completed', value: doneLessons.length + '/' + allLessons.length, color:'#16a34a' },
    { icon:'🔄', label:'In Progress',       value: inProgLessons.length, color:'#d97706' },
    { icon:'🏅', label:'Badges Earned',     value: capKeys.filter(function(k){return getCapPct(k)>=50;}).length, color:'#7c3aed' },
  ];
  var cards = document.getElementById('progressStatCards');
  if (cards) cards.innerHTML = stats.map(function(s) {
    return '<div style="background:white;border:1.5px solid var(--border);border-radius:14px;padding:1.25rem;text-align:center;">'
      + '<div style="font-size:1.5rem;margin-bottom:.4rem;">' + s.icon + '</div>'
      + '<div style="font-family:\'DM Mono\',monospace;font-size:1.5rem;font-weight:700;color:' + s.color + ';line-height:1;">' + s.value + '</div>'
      + '<div style="font-size:.72rem;color:var(--ink-light);margin-top:.3rem;">' + s.label + '</div>'
      + '</div>';
  }).join('');

  // Cap bars
  var bars = document.getElementById('progressCapBars');
  if (bars) bars.innerHTML = capKeys.map(function(key) {
    var cap = CAPABILITIES[key]; var pct = getCapPct(key);
    var color = pct >= 70 ? '#16a34a' : pct >= 30 ? '#d97706' : 'var(--border-dark)';
    return '<div style="display:flex;align-items:center;gap:1rem;">'
      + '<div style="width:180px;display:flex;align-items:center;gap:.5rem;flex-shrink:0;">'
      + '<span style="font-size:1rem;">' + cap.icon + '</span>'
      + '<span style="font-size:.82rem;font-weight:600;color:var(--ink);">' + cap.title + '</span></div>'
      + '<div style="flex:1;height:8px;background:var(--border);border-radius:4px;overflow:hidden;">'
      + '<div style="height:100%;background:' + color + ';border-radius:4px;width:' + pct + '%;transition:width .6s;"></div></div>'
      + '<div style="font-family:\'DM Mono\',monospace;font-size:.75rem;color:var(--ink-light);min-width:36px;text-align:right;">' + pct + '%</div>'
      + '<button onclick="loadCapability(\'' + key + '\')" style="background:var(--emerald-glow);border:1px solid rgba(26,107,74,.2);color:var(--emerald);border-radius:6px;padding:.3rem .65rem;font-size:.72rem;font-weight:700;cursor:pointer;font-family:inherit;">' + (pct===0?'Start':'Continue') + '</button>'
      + '</div>';
  }).join('');

  // Badges
  var badgesEl = document.getElementById('progressBadges');
  if (badgesEl) {
    var earned = capKeys.filter(function(k){return getCapPct(k)>=50;});
    if (!earned.length) {
      badgesEl.innerHTML = '<p style="font-size:.85rem;color:var(--ink-light);">Complete 50% of any module to earn your first badge.</p>';
    } else {
      badgesEl.innerHTML = earned.map(function(k) {
        var cap = CAPABILITIES[k]; var pct = getCapPct(k); var full = pct === 100;
        return '<div style="background:' + (full?'linear-gradient(135deg,var(--emerald-dark),var(--emerald))':'var(--emerald-glow)') + ';border:1.5px solid ' + (full?'transparent':'rgba(26,107,74,.2)') + ';border-radius:12px;padding:.75rem 1rem;display:flex;align-items:center;gap:.5rem;">'
          + '<span style="font-size:1.3rem;">' + cap.icon + '</span>'
          + '<div><div style="font-size:.78rem;font-weight:800;color:' + (full?'white':'var(--emerald)') + ';">' + cap.title.split(' ')[0] + '</div>'
          + '<div style="font-size:.65rem;color:' + (full?'rgba(255,255,255,.7)':'var(--ink-pale)') + ';">' + (full?'Completed':'50% done') + '</div></div>'
          + '</div>';
      }).join('');
    }
  }
}

// ── PRIORITIES TAB ────────────────────────────────────────────────────────────
function renderPrioritiesTab() {
  var hasPriorities = assessScores && Object.keys(assessScores).length === 8;
  var emptyEl = document.getElementById('prioritiesEmpty');
  var listEl  = document.getElementById('prioritiesList');
  var retakeEl = document.getElementById('prioritiesRetake');
  if (!hasPriorities) {
    emptyEl.style.display  = 'block';
    listEl.innerHTML       = '';
    retakeEl.style.display = 'none';
    return;
  }
  emptyEl.style.display  = 'none';
  retakeEl.style.display = 'block';
  var capKeys = Object.keys(CAPABILITIES);
  var sorted  = capKeys.slice().sort(function(a,b){ return assessScores[a]-assessScores[b]; });
  var accents = ['#dc2626','#f59e0b','#3b82f6','#8b5cf6','#0891b2','#059669','#d97706','#6366f1'];
  listEl.innerHTML = sorted.map(function(key, i) {
    var cap = CAPABILITIES[key]; var s = assessScores[key]; var pct = getCapPct(key);
    var accent = accents[i] || 'var(--emerald)';
    return '<div style="background:white;border:1.5px solid var(--border);border-radius:16px;overflow:hidden;transition:all .2s;" onmouseover="this.style.borderColor=\'' + accent + '\'" onmouseout="this.style.borderColor=\'var(--border)\'">'
      + '<div style="height:4px;background:' + accent + ';"></div>'
      + '<div style="padding:1.25rem 1.5rem;display:flex;align-items:center;gap:1rem;flex-wrap:wrap;">'
      + '<div style="width:38px;height:38px;min-width:38px;border-radius:10px;background:' + accent + '18;border:1.5px solid ' + accent + '30;display:flex;align-items:center;justify-content:center;font-family:\'DM Mono\',monospace;font-size:.85rem;font-weight:800;color:' + accent + ';">' + (i+1) + '</div>'
      + '<div style="font-size:1.3rem;">' + cap.icon + '</div>'
      + '<div style="flex:1;">'
      + '<div style="font-weight:800;font-size:.97rem;color:var(--ink);">' + cap.title + '</div>'
      + '<div style="font-size:.75rem;color:var(--ink-light);margin-top:.15rem;">Assessment score: ' + s + '/5 · ' + getScoreLabel(s) + '</div>'
      + '</div>'
      + '<div style="display:flex;flex-direction:column;align-items:flex-end;gap:.3rem;">'
      + '<div style="font-size:.72rem;font-weight:700;color:var(--ink-light);">Module progress</div>'
      + '<div style="width:80px;height:6px;background:var(--border);border-radius:3px;overflow:hidden;">'
      + '<div style="height:100%;background:' + accent + ';width:' + pct + '%;border-radius:3px;"></div></div>'
      + '<div style="font-size:.7rem;color:var(--ink-pale);">' + pct + '%</div>'
      + '</div>'
      + '<button onclick="loadCapability(\'' + key + '\')" style="background:' + accent + ';color:white;border:none;border-radius:8px;padding:.55rem 1rem;font-size:.8rem;font-weight:700;cursor:pointer;font-family:inherit;white-space:nowrap;">' + (pct===0?'Start Module →':'Continue →') + '</button>'
      + '</div></div>';
  }).join('');
}

// ── LESSONS TAB ───────────────────────────────────────────────────────────────
function getAllLessons() {
  var lessons = [];
  Object.keys(CAPABILITIES).forEach(function(key) {
    var cap = CAPABILITIES[key];
    (cap.microLessons || []).forEach(function(ml, i) {
      var prog = scProgress[key + '_' + i] || {};
      var status = prog.video ? 'done' : (prog.workbook ? 'inprogress' : 'notstarted');
      lessons.push({ capId: key, idx: i, icon: cap.icon, capTitle: cap.title, title: ml.title, objective: ml.objective, status: status });
    });
  });
  return lessons;
}

function filterLessonsTab(filter) {
  lessonFilter = filter;
  ['all','done','inprogress','notstarted'].forEach(function(f) {
    var btn = document.getElementById('lf-' + f);
    if (!btn) return;
    var active = f === filter;
    btn.style.background    = active ? 'var(--emerald)' : 'white';
    btn.style.color         = active ? 'white' : 'var(--ink-light)';
    btn.style.borderColor   = active ? 'var(--emerald)' : 'var(--border)';
  });
  renderLessonsTab(filter);
}

function renderLessonsTab(filter) {
  var list = document.getElementById('lessonsList');
  if (!list) return;
  var lessons = getAllLessons();
  var filtered = filter === 'all' ? lessons : lessons.filter(function(l){ return l.status === filter; });
  if (!filtered.length) {
    list.innerHTML = '<div style="text-align:center;padding:3rem;color:var(--ink-light);">No ' + filter + ' lessons yet.</div>';
    return;
  }
  var statusMeta = { done:{ icon:'✅', label:'Completed', color:'#16a34a' }, inprogress:{ icon:'🔄', label:'In Progress', color:'#d97706' }, notstarted:{ icon:'⭕', label:'Not Started', color:'var(--ink-pale)' } };
  list.innerHTML = filtered.map(function(l) {
    var sm = statusMeta[l.status];
    return '<div style="background:white;border:1.5px solid var(--border);border-radius:12px;padding:1rem 1.25rem;display:flex;align-items:center;gap:1rem;transition:all .15s;" onmouseover="this.style.borderColor=\'var(--emerald)\'" onmouseout="this.style.borderColor=\'var(--border)\'">'
      + '<div style="font-size:1.2rem;flex-shrink:0;">' + l.icon + '</div>'
      + '<div style="flex:1;min-width:0;">'
      + '<div style="font-weight:700;font-size:.9rem;color:var(--ink);">' + l.title + '</div>'
      + '<div style="font-size:.72rem;color:var(--ink-light);margin-top:.1rem;">' + l.capTitle + '</div>'
      + '</div>'
      + '<div style="display:flex;align-items:center;gap:.3rem;flex-shrink:0;">'
      + '<span style="font-size:.85rem;">' + sm.icon + '</span>'
      + '<span style="font-size:.72rem;font-weight:700;color:' + sm.color + ';">' + sm.label + '</span>'
      + '</div>'
      + '<button onclick="loadCapability(\'' + l.capId + '\')" style="background:var(--cream-dark);border:1px solid var(--border);color:var(--ink-mid);border-radius:7px;padding:.35rem .75rem;font-size:.75rem;font-weight:600;cursor:pointer;font-family:inherit;flex-shrink:0;">' + (l.status==='done'?'Review':'Go →') + '</button>'
      + '</div>';
  }).join('');
}

// ── SAVED ITEMS TAB ───────────────────────────────────────────────────────────
function saveItem(item) {
  var exists = savedItems.find(function(s){ return s.id === item.id; });
  if (!exists) {
    savedItems.push(item);
    showToast('Saved to your profile 🔖');
    document.getElementById('profileSavedCount').textContent = savedItems.length;
  } else {
    savedItems = savedItems.filter(function(s){ return s.id !== item.id; });
    showToast('Removed from saved items');
    document.getElementById('profileSavedCount').textContent = savedItems.length;
  }
}

function filterSavedTab(filter) {
  savedFilter = filter;
  ['all','template','tool','lesson'].forEach(function(f) {
    var btn = document.getElementById('sf-' + f);
    if (!btn) return;
    var active = f === filter;
    btn.style.background  = active ? 'var(--emerald)' : 'white';
    btn.style.color       = active ? 'white' : 'var(--ink-light)';
    btn.style.borderColor = active ? 'var(--emerald)' : 'var(--border)';
  });
  renderSavedTab(filter);
}

function renderSavedTab(filter) {
  var grid  = document.getElementById('savedGrid');
  var empty = document.getElementById('savedEmpty');
  if (!grid) return;

  // Auto-populate saved items from completed templates/workbooks
  var autoSaved = [];
  Object.keys(CAPABILITIES).forEach(function(key) {
    var cap = CAPABILITIES[key];
    (cap.templates || []).forEach(function(t, ti) {
      var prog = scProgress[key + '_t_' + ti];
      if (prog) autoSaved.push({ id:'tpl_'+key+'_'+ti, type:'template', icon: t.icon||'📄', title: t.name, subtitle: cap.title, capId: key });
    });
  });
  var allSaved = savedItems.concat(autoSaved.filter(function(a){ return !savedItems.find(function(s){ return s.id===a.id; }); }));
  var filtered = filter === 'all' ? allSaved : allSaved.filter(function(s){ return s.type === filter; });

  if (!filtered.length) {
    empty.style.display = 'block'; grid.innerHTML = ''; return;
  }
  empty.style.display = 'none';
  grid.innerHTML = filtered.map(function(item) {
    var typeColors = { template:'#1A6B4A', tool:'#2563eb', lesson:'#d97706' };
    var color = typeColors[item.type] || 'var(--ink)';
    return '<div style="background:white;border:1.5px solid var(--border);border-radius:16px;padding:1.25rem;transition:all .2s;" onmouseover="this.style.borderColor=\'' + color + '\';this.style.transform=\'translateY(-2px)\'" onmouseout="this.style.borderColor=\'var(--border)\';this.style.transform=\'\'">'
      + '<div style="display:flex;align-items:flex-start;justify-content:space-between;margin-bottom:.75rem;">'
      + '<div style="width:40px;height:40px;border-radius:10px;background:' + color + '15;display:flex;align-items:center;justify-content:center;font-size:1.2rem;">' + item.icon + '</div>'
      + '<button onclick="saveItem({id:\'' + item.id + '\',type:\'' + item.type + '\',icon:\'' + item.icon + '\',title:\'' + item.title.replace(/'/g,"\\'") + '\',subtitle:\'' + (item.subtitle||'').replace(/'/g,"\\'") + '\',capId:\'' + item.capId + '\'})" style="background:none;border:none;cursor:pointer;font-size:.8rem;color:var(--ink-pale);padding:.2rem;" title="Remove">✕</button>'
      + '</div>'
      + '<div style="font-size:.65rem;font-weight:700;letter-spacing:.1em;text-transform:uppercase;color:' + color + ';margin-bottom:.3rem;">' + item.type + '</div>'
      + '<div style="font-weight:700;font-size:.92rem;color:var(--ink);margin-bottom:.2rem;">' + item.title + '</div>'
      + '<div style="font-size:.75rem;color:var(--ink-light);margin-bottom:.85rem;">' + (item.subtitle||'') + '</div>'
      + '<button onclick="loadCapability(\'' + item.capId + '\')" style="width:100%;background:var(--cream-dark);border:1px solid var(--border);color:var(--ink-mid);border-radius:8px;padding:.5rem;font-size:.78rem;font-weight:600;cursor:pointer;font-family:inherit;">Open →</button>'
      + '</div>';
  }).join('');
}

// ── ACCOUNT ───────────────────────────────────────────────────────────────────
// ══ PERSISTENCE HELPERS ═══════════════════════════════════════════════════════
// All user data is stored under a per-email key so multiple accounts can coexist
// and data is restored exactly when the same email signs back in.

function _userKey(email) {
  return 'aljude_user_' + (email || '').toLowerCase().trim();
}

function _saveUserData() {
  if (!currentUser || !currentUser.email) return;
  var key = _userKey(currentUser.email);
  try {
    localStorage.setItem(key, JSON.stringify({
      profile:       currentUser,
      savedItems:    savedItems,
      assessScores:  assessScores,
      scProgress:    scProgress,
      capMiniScores: capMiniScores
    }));
  } catch(e) {}
  // Also remember who is currently logged in so we can restore on page reload
  try { localStorage.setItem('aljude_active_email', currentUser.email); } catch(e) {}
}

function _loadUserData(email) {
  try {
    var raw = localStorage.getItem(_userKey(email));
    if (!raw) return null;
    return JSON.parse(raw);
  } catch(e) { return null; }
}

function _applyUserData(data) {
  if (!data) return;
  if (data.savedItems)    savedItems    = data.savedItems;
  if (data.assessScores)  assessScores  = data.assessScores;
  if (data.capMiniScores) capMiniScores = data.capMiniScores;
  if (data.scProgress) {
    // Merge loaded progress into scProgress (keeps keys initialised by capability loader)
    Object.keys(data.scProgress).forEach(function(pid) {
      scProgress[pid] = data.scProgress[pid];
    });
  }
}

function _updateNavBtn() {
  var btn = document.getElementById('navSignInBtn');
  if (!btn) return;
  if (currentUser) {
    btn.textContent = currentUser.firstName;
    btn.onclick = function(){ showDashboard(); };
  } else {
    btn.textContent = 'Sign In';
    btn.onclick = function(){ openSignInModal(); };
  }
}

// ── Restore session on page load ──────────────────────────────────────────────
(function restoreSession() {
  try {
    var email = localStorage.getItem('aljude_active_email');
    if (!email) return;
    var data = _loadUserData(email);
    if (!data || !data.profile) return;
    currentUser  = data.profile;
    _applyUserData(data);
    // Defer nav update until DOM is ready
    if (document.readyState === 'loading') {
      document.addEventListener('DOMContentLoaded', _updateNavBtn);
    } else {
      _updateNavBtn();
    }
  } catch(e) {}
})();

// ── Patch saveProgress to also persist full user data ─────────────────────────
var _origSaveProgress = saveProgress;
saveProgress = function() {
  _origSaveProgress();   // keeps the global scProgress localStorage key working too
  _saveUserData();
};

// ── Patch toggleSaveItem to persist after every save/unsave ───────────────────
var _origToggleSaveItem = toggleSaveItem;
toggleSaveItem = function(item) {
  _origToggleSaveItem(item);
  _saveUserData();
};

// ══ AUTH FUNCTIONS ════════════════════════════════════════════════════════════

function saveAccountDetails() {
  if (!currentUser) return;
  var oldEmail = currentUser.email;
  currentUser.firstName = document.getElementById('accFirstName').value.trim() || currentUser.firstName;
  currentUser.lastName  = document.getElementById('accLastName').value.trim()  || currentUser.lastName;
  currentUser.email     = document.getElementById('accEmail').value.trim()     || currentUser.email;
  currentUser.org       = document.getElementById('accOrg').value.trim()       || currentUser.org;
  // If email changed, migrate data to new key and remove old
  if (oldEmail !== currentUser.email) {
    try { localStorage.removeItem(_userKey(oldEmail)); } catch(e) {}
    try { localStorage.setItem('aljude_active_email', currentUser.email); } catch(e) {}
  }
  _saveUserData();
  showToast('Profile updated ✓');
  document.getElementById('profileName').textContent = currentUser.firstName + ' ' + (currentUser.lastName||'');
  document.getElementById('profileOrg').textContent  = (currentUser.role||'') + ' · ' + (currentUser.org||'');
  _updateNavBtn();
}

function signOutUser() {
  _saveUserData(); // persist one final time before clearing memory
  currentUser  = null;
  savedItems   = [];
  assessScores = {};
  // Reset scProgress to fresh defaults (don't wipe localStorage — data stays for next login)
  Object.keys(scProgress).forEach(function(pid) {
    scProgress[pid] = { workbook:false, video:false, lessons:[false,false,false,false,false], templates:false, assessment:false };
  });
  try { localStorage.removeItem('aljude_active_email'); } catch(e) {}
  _updateNavBtn();
  showToast('Signed out. Your progress is saved for next time.');
  goHome();
}

function handleModalSignIn() {
  var email = (document.getElementById('modalEmail').value || '').trim();
  if (!email) { showToast('Please enter your email'); return; }
  // Load any previously saved data for this email
  var data = _loadUserData(email);
  if (data && data.profile) {
    currentUser = data.profile;
    _applyUserData(data);
    closeAuthModalDirect();
    showToast('Welcome back, ' + currentUser.firstName + '! 🎉');
  } else {
    // First time with this email — create a basic profile
    currentUser = { firstName: email.split('@')[0], lastName: '', email: email, org: '', role: '', country: '' };
    closeAuthModalDirect();
    showToast('Signed in! Complete your profile to personalise your experience.');
  }
  _updateNavBtn();
  _saveUserData();
  showDashboard();
}

function handleModalSignUp() {
  var inputs    = document.querySelectorAll('#signupPanel input, #signupPanel select');
  var firstName = (inputs[0] ? inputs[0].value : '').trim() || 'User';
  var lastName  = (inputs[1] ? inputs[1].value : '').trim();
  var email     = (inputs[2] ? inputs[2].value : '').trim();
  var org       = (inputs[3] ? inputs[3].value : '').trim();
  var role      = inputs[4] ? inputs[4].value : '';
  var country   = inputs[5] ? inputs[5].value : '';
  if (!email) { showToast('Please enter your email address'); return; }
  // Check if account already exists and merge
  var existing = _loadUserData(email);
  currentUser = existing && existing.profile
    ? Object.assign(existing.profile, { firstName: firstName||existing.profile.firstName, lastName: lastName||existing.profile.lastName, org: org||existing.profile.org, role: role||existing.profile.role, country: country||existing.profile.country })
    : { firstName: firstName, lastName: lastName, email: email, org: org, role: role, country: country };
  if (existing) _applyUserData(existing);
  closeAuthModalDirect();
  showToast('Welcome to ALJUDE Academy, ' + currentUser.firstName + '! 🎉');
  _updateNavBtn();
  _saveUserData();
  showDashboard();
}


