function showFullAssessment() {
  var section = document.getElementById('assessment-section');
  section.style.display = 'block';
  document.getElementById('problems-section').style.display = 'none';
  var capKeys = Object.keys(CAPABILITIES);
  var qHtml = capKeys.map(function(key) {
    var cap = CAPABILITIES[key];
    return '<div style="background:white;border:1.5px solid var(--border);border-radius:12px;padding:1.25rem;">'
      + '<div style="display:flex;align-items:center;gap:.75rem;margin-bottom:.75rem;">'
      + '<div style="font-size:1.3rem;">' + cap.icon + '</div>'
      + '<div style="font-weight:700;color:var(--ink);">' + cap.title + '</div></div>'
      + '<div style="display:flex;gap:.5rem;flex-wrap:wrap;">'
      + [1,2,3,4].map(function(score) {
        var labels = ['1 — Not started', '2 — Early stage', '3 — Developing', '4 — Strong'];
        return '<label style="flex:1;min-width:100px;">'
          + '<input type="radio" name="assess_' + key + '" value="' + score + '" style="margin-right:.3rem;">'
          + '<span style="font-size:.78rem;color:var(--ink-light);">' + labels[score-1] + '</span></label>';
      }).join('')
      + '</div></div>';
  }).join('');
  document.getElementById('assessment-questions-sh').innerHTML = qHtml;
  section.scrollIntoView({behavior:'smooth', block:'start'});
}

function submitFullAssessment() {
  var capKeys = Object.keys(CAPABILITIES);
  var scores = {};
  var allAnswered = true;
  capKeys.forEach(function(key) {
    var selected = document.querySelector('input[name="assess_' + key + '"]:checked');
    if (selected) scores[key] = parseInt(selected.value);
    else allAnswered = false;
  });
  if (!allAnswered) { showToast('Please rate all 8 areas first'); return; }
  var sorted = capKeys.slice().sort(function(a,b) { return scores[a] - scores[b]; });
  var html = '<div style="background:white;border:1.5px solid var(--border);border-radius:14px;padding:1.5rem;">'
    + '<div style="font-weight:800;font-size:1rem;color:var(--ink);margin-bottom:1rem;">📊 Your Organizational Heatmap</div>'
    + '<div style="display:flex;flex-direction:column;gap:.6rem;margin-bottom:1.25rem;">';
  capKeys.forEach(function(key) {
    var s = scores[key] || 0;
    var color = s<=1 ? '#dc2626' : s<=2 ? '#f59e0b' : s<=3 ? '#3b82f6' : '#16a34a';
    var pct = (s/4)*100;
    html += '<div style="display:flex;align-items:center;gap:.75rem;">'
      + '<div style="width:130px;font-size:.8rem;color:var(--ink-mid);">' + CAPABILITIES[key].icon + ' ' + CAPABILITIES[key].title + '</div>'
      + '<div style="flex:1;height:8px;background:var(--border);border-radius:4px;overflow:hidden;">'
      + '<div style="height:100%;background:' + color + ';border-radius:4px;width:' + pct + '%;transition:width .5s;"></div></div>'
      + '<div style="font-family:\'DM Mono\',monospace;font-size:.72rem;color:var(--ink-light);min-width:24px;">' + s + '/4</div></div>';
  });
  html += '</div>';
  html += '<div style="font-weight:800;font-size:.88rem;color:var(--ink);margin-bottom:.75rem;">🎯 Your Top Priorities</div>'
    + '<div style="display:flex;flex-direction:column;gap:.5rem;">';
  sorted.slice(0,3).forEach(function(key, i) {
    html += '<div onclick="loadCapability(\'' + key + '\')" style="background:var(--emerald-glow);border:1px solid rgba(26,107,74,.2);border-radius:8px;padding:.65rem 1rem;display:flex;align-items:center;gap:.75rem;cursor:pointer;" onmouseover="this.style.background=\'rgba(26,107,74,.1)\'" onmouseout="this.style.background=\'var(--emerald-glow)\'">'
      + '<div style="font-size:.72rem;font-weight:800;color:var(--emerald);min-width:20px;">' + (i+1) + '</div>'
      + '<div style="font-size:.88rem;font-weight:600;color:var(--emerald-dark);">' + CAPABILITIES[key].icon + ' ' + CAPABILITIES[key].title + '</div>'
      + '<svg style="width:14px;height:14px;color:var(--emerald);margin-left:auto;" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M7.293 14.707a1 1 0 010-1.414L10.586 10 7.293 6.707a1 1 0 011.414-1.414l4 4a1 1 0 010 1.414l-4 4a1 1 0 01-1.414 0z"/></svg>'
      + '</div>';
  });
  html += '</div></div>';
  document.getElementById('assessment-result-sh').innerHTML = html;
  document.getElementById('assessment-result-sh').scrollIntoView({behavior:'smooth', block:'start'});
}

// ── CATEGORIES GRID ───────────────────────────────────────────────────────────
function updateCapStatsBar() {
  var capKeys = Object.keys(CAPABILITIES);
  var assessed = capKeys.filter(function(k){ return assessScores[k]; });
  var strong   = assessed.filter(function(k){ return assessScores[k] >= 4; });
  var gaps     = assessed.filter(function(k){ return assessScores[k] <= 2; });
  var avg      = assessed.length ? (assessed.reduce(function(s,k){ return s + assessScores[k]; }, 0) / assessed.length).toFixed(1) : null;

  ['capStatAvg','mlpStatAvg'].forEach(function(id) {
    var el = document.getElementById(id);
    if (el) el.textContent = avg !== null ? avg + '/5' : '—';
  });
  ['capStatAssessed','mlpStatAssessed'].forEach(function(id) {
    var el = document.getElementById(id);
    if (el) el.textContent = assessed.length + '/8';
  });
  ['capStatStrong','mlpStatStrong'].forEach(function(id) {
    var el = document.getElementById(id);
    if (el) el.textContent = strong.length;
  });
  ['capStatGaps','mlpStatGaps'].forEach(function(id) {
    var el = document.getElementById(id);
    if (el) el.textContent = gaps.length;
  });
}

function setCapScore(key, score) {
  assessScores[key] = score;
  updateCapStatsBar();
  renderCategoriesGrid();
  showToast(CAPABILITIES[key].title + ' rated ' + score + '/5');
}

function getScoreColor(s) {
  if (!s) return 'var(--border-dark)';
  if (s <= 2) return '#dc2626';
  if (s === 3) return '#f59e0b';
  return '#16a34a';
}

function getScoreBg(s) {
  if (!s) return 'rgba(155,155,155,.08)';
  if (s <= 2) return 'rgba(220,38,38,.08)';
  if (s === 3) return 'rgba(245,158,11,.08)';
  return 'rgba(22,163,74,.08)';
}

function getScoreLabel(s) {
  if (!s) return 'Not rated';
  var labels = {1:'Critical gap',2:'Needs work',3:'Developing',4:'Capable',5:'Strong'};
  return labels[s] || '';
}

function renderCategoriesGrid() {
  var grid = document.getElementById('categoriesGrid');
  if (!grid) return;
  updateCapStatsBar();
  var keys = Object.keys(CAPABILITIES);
  var hasAnyScore = keys.some(function(k){ return assessScores[k]; });

  // ── NO SCORES YET: show CTA + default grid ──────────────────────────────────
  if (!hasAnyScore) {
    var ctaHtml = '<div style="background:linear-gradient(135deg,rgba(26,107,74,.06),rgba(26,107,74,.02));border:1.5px dashed rgba(26,107,74,.3);border-radius:16px;padding:2rem;text-align:center;margin-bottom:2rem;">'
      + '<div style="font-size:1.75rem;margin-bottom:.75rem;">🎯</div>'
      + '<div style="font-weight:800;font-size:1rem;color:var(--emerald-dark);margin-bottom:.4rem;">Score all 8 capabilities to see your profile</div>'
      + '<p style="font-size:.85rem;color:var(--ink-light);line-height:1.6;margin-bottom:1.25rem;max-width:420px;margin-left:auto;margin-right:auto;">Rate yourself on each area below (1–5), or take the full guided assessment to get a personalised action plan.</p>'
      + '<div style="display:flex;gap:.75rem;justify-content:center;flex-wrap:wrap;">'
      + '<button onclick="showAssessmentPage()" style="background:var(--emerald);color:white;border:none;border-radius:10px;padding:.7rem 1.5rem;font-size:.85rem;font-weight:700;cursor:pointer;font-family:inherit;">Take Full Assessment →</button>'
      + '<button onclick="showMyLearningPath()" style="background:white;color:var(--emerald);border:1.5px solid rgba(26,107,74,.3);border-radius:10px;padding:.7rem 1.5rem;font-size:.85rem;font-weight:700;cursor:pointer;font-family:inherit;">My Learning Path</button>'
      + '</div></div>';
    grid.innerHTML = ctaHtml + '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(320px,1fr));gap:1.25rem;">' + keys.map(function(key){ return buildCapCard(key); }).join('') + '</div>';
    return;
  }

  // ── SCORED VIEW ──────────────────────────────────────────────────────────────
  // Buckets:
  //   1. Priority Gaps Assessed  — score ≤ 2 AND capMiniScores set  (deep-assessed gaps)
  //   2. Priority Gaps           — score ≤ 2, capMiniScores NOT set  (flagged but not deep-assessed)
  //   3. Developing              — score 3
  //   4. Strong Areas            — score ≥ 4
  //   5. Not Yet Rated           — no assessScore
  var priorityGapsAssessed = [];
  var priorityGaps         = [];
  var developing           = [];
  var strong               = [];
  var unscored             = [];

  keys.forEach(function(k) {
    var s = assessScores[k];
    var deepAssessed = capMiniScores[k] && capMiniScores[k].length === 5;
    if (!s) {
      unscored.push(k);
    } else if (s <= 2 && deepAssessed) {
      priorityGapsAssessed.push(k);
    } else if (s <= 2) {
      priorityGaps.push(k);
    } else if (s === 3) {
      developing.push(k);
    } else {
      strong.push(k);
    }
  });

  // Sort within each bucket by score ascending
  function byScore(a, b) { return (assessScores[a] || 0) - (assessScores[b] || 0); }
  priorityGapsAssessed.sort(byScore);
  priorityGaps.sort(byScore);
  developing.sort(byScore);
  strong.sort(byScore);

  var html = '';

  // ── Section 1: Priority Gaps Assessed ────────────────────────────────────────
  if (priorityGapsAssessed.length) {
    html += '<div style="margin-bottom:2rem;">';
    // Section header — red alert bar
    html += '<div style="display:flex;align-items:center;gap:.75rem;background:linear-gradient(135deg,rgba(220,38,38,.08),rgba(220,38,38,.03));border:1.5px solid rgba(220,38,38,.25);border-radius:14px;padding:.85rem 1.25rem;margin-bottom:1rem;">';
    html += '<div style="width:36px;height:36px;min-width:36px;border-radius:10px;background:#dc2626;display:flex;align-items:center;justify-content:center;font-size:1.05rem;flex-shrink:0;">🎯</div>';
    html += '<div style="flex:1;min-width:0;">';
    html += '<div style="font-weight:800;font-size:.95rem;color:#dc2626;line-height:1.2;">Priority Gaps — Assessed</div>';
    html += '<div style="font-size:.78rem;color:#b91c1c;margin-top:.2rem;">These capabilities have been assessed in depth. Start here — your personalised improvement plan is ready.</div>';
    html += '</div>';
    html += '<span style="background:#dc2626;color:white;border-radius:20px;padding:.2rem .65rem;font-size:.72rem;font-weight:800;flex-shrink:0;">' + priorityGapsAssessed.length + ' ready</span>';
    html += '</div>';
    html += '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(320px,1fr));gap:1.25rem;">';
    priorityGapsAssessed.forEach(function(key) { html += buildCapCard(key, true); });
    html += '</div></div>';
  }

  // ── Section 2: Priority Gaps (flagged but not yet deep-assessed) ─────────────
  if (priorityGaps.length) {
    html += '<div style="margin-bottom:2rem;">';
    html += '<div style="display:flex;align-items:center;gap:.6rem;margin-bottom:.85rem;">';
    html += '<div style="width:8px;height:8px;border-radius:50%;background:#dc2626;flex-shrink:0;"></div>';
    html += '<div style="font-size:.72rem;font-weight:800;letter-spacing:.12em;text-transform:uppercase;color:#dc2626;">Priority Gaps</div>';
    html += '<div style="flex:1;height:1px;background:rgba(220,38,38,.2);"></div>';
    html += '<span style="font-size:.7rem;color:#dc2626;font-weight:600;">Assess these to unlock your action plan</span>';
    html += '</div>';
    html += '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(320px,1fr));gap:1.25rem;">';
    priorityGaps.forEach(function(key) { html += buildCapCard(key, false); });
    html += '</div></div>';
  }

  // ── Section 3: Developing ─────────────────────────────────────────────────────
  if (developing.length) {
    html += '<div style="margin-bottom:2rem;">';
    html += '<div style="display:flex;align-items:center;gap:.6rem;margin-bottom:.85rem;">';
    html += '<div style="width:8px;height:8px;border-radius:50%;background:#d97706;flex-shrink:0;"></div>';
    html += '<div style="font-size:.72rem;font-weight:800;letter-spacing:.12em;text-transform:uppercase;color:#d97706;">Developing</div>';
    html += '<div style="flex:1;height:1px;background:rgba(217,119,6,.2);"></div>';
    html += '</div>';
    html += '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(320px,1fr));gap:1.25rem;">';
    developing.forEach(function(key) { html += buildCapCard(key, false); });
    html += '</div></div>';
  }

  // ── Section 4: Strong Areas ───────────────────────────────────────────────────
  if (strong.length) {
    html += '<div style="margin-bottom:2rem;">';
    html += '<div style="display:flex;align-items:center;gap:.6rem;margin-bottom:.85rem;">';
    html += '<div style="width:8px;height:8px;border-radius:50%;background:var(--emerald);flex-shrink:0;"></div>';
    html += '<div style="font-size:.72rem;font-weight:800;letter-spacing:.12em;text-transform:uppercase;color:var(--emerald);">Strong Areas</div>';
    html += '<div style="flex:1;height:1px;background:rgba(26,107,74,.2);"></div>';
    html += '</div>';
    html += '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(320px,1fr));gap:1.25rem;">';
    strong.forEach(function(key) { html += buildCapCard(key, false); });
    html += '</div></div>';
  }

  // ── Section 5: Not Yet Rated ──────────────────────────────────────────────────
  if (unscored.length) {
    html += '<div style="margin-bottom:2rem;">';
    html += '<div style="display:flex;align-items:center;gap:.6rem;margin-bottom:.85rem;">';
    html += '<div style="width:8px;height:8px;border-radius:50%;background:var(--border-dark);flex-shrink:0;"></div>';
    html += '<div style="font-size:.72rem;font-weight:800;letter-spacing:.12em;text-transform:uppercase;color:var(--ink-light);">Not Yet Rated</div>';
    html += '<div style="flex:1;height:1px;background:var(--border);"></div>';
    html += '</div>';
    html += '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(320px,1fr));gap:1.25rem;">';
    unscored.forEach(function(key) { html += buildCapCard(key, false); });
    html += '</div></div>';
  }

  grid.innerHTML = html;
}

// ── CAP ASSESSMENT DATA (5 questions per capability) ─────────────────────────
var CAP_QUESTIONS = {
  strategy: [
    { q: 'Does your organization have a written strategic plan that is actively used to guide decisions?', opts: ['No written plan', 'A plan exists but rarely consulted', 'Occasionally referenced', 'Regularly used in planning', 'Fully integrated into all decisions'] },
    { q: 'How clearly defined are your organization\'s long-term goals and success metrics?', opts: ['Not defined', 'Vaguely articulated', 'Defined but not measured', 'Defined with some tracking', 'Clear, measured, and reviewed regularly'] },
    { q: 'How effectively does your leadership team align on strategic priorities?', opts: ['Frequent disagreement', 'Some alignment, often unclear', 'General consensus', 'Mostly aligned', 'Fully aligned with shared ownership'] },
    { q: 'How well does your organization respond to changes in the external environment?', opts: ['Reactive with no system', 'Ad hoc responses', 'Some scanning processes', 'Proactive with regular reviews', 'Systematic environmental scanning'] },
    { q: 'How clearly is strategy communicated and understood across the organization?', opts: ['Only known to leadership', 'Partially shared', 'Known but not internalized', 'Understood by most staff', 'Owned at every level of the org'] }
  ],
  programs: [
    { q: 'Do your programs have a clearly documented Theory of Change?', opts: ['No ToC exists', 'Informal understanding only', 'Draft ToC not yet validated', 'ToC exists but not reviewed', 'Documented, validated, and used'] },
    { q: 'How consistently do you measure outcomes (not just outputs) in your programs?', opts: ['We only count activities', 'Mostly outputs tracked', 'Some outcome indicators', 'Regular outcome measurement', 'Robust MEL system in place'] },
    { q: 'How well do your program designs reflect actual community or beneficiary needs?', opts: ['Based on assumptions', 'Occasional feedback gathered', 'Periodic needs assessments', 'Regular community input', 'Co-designed with beneficiaries'] },
    { q: 'How effective is your safeguarding and complaint management system?', opts: ['No system exists', 'Basic policy on paper', 'Policy with some implementation', 'Active system, mostly followed', 'Robust, tested, and audited'] },
    { q: 'How strong is your ability to produce evidence-based donor reports?', opts: ['Narrative only, no data', 'Limited data included', 'Some outcome evidence', 'Strong data with analysis', 'Compelling impact evidence'] }
  ],
  leadership: [
    { q: 'How clearly defined are leadership roles and decision-making authority?', opts: ['Very unclear', 'Somewhat unclear', 'Mostly defined', 'Clearly defined', 'Fully documented and followed'] },
    { q: 'How well does senior leadership model the organization\'s values?', opts: ['Not consistently', 'Occasionally', 'Somewhat', 'Most of the time', 'Consistently and visibly'] },
    { q: 'How effective is your leadership development and succession planning?', opts: ['No development efforts', 'Informal mentoring only', 'Some planned development', 'Regular development programs', 'Structured with succession plans'] },
    { q: 'How well does leadership manage organizational change?', opts: ['Change causes significant disruption', 'Often met with resistance', 'Change is managed adequately', 'Well communicated and planned', 'Change is embraced and led effectively'] },
    { q: 'How effectively does leadership give and receive feedback?', opts: ['Rarely happens', 'Only in formal reviews', 'Inconsistent practice', 'Regular structured feedback', 'Continuous feedback culture'] }
  ],
  team: [
    { q: 'How clear are roles, responsibilities, and expectations for each team member?', opts: ['Very unclear', 'Partially defined', 'Mostly documented', 'Clear and documented', 'Fully clear, updated regularly'] },
    { q: 'How strong is psychological safety in your team (ability to speak up without fear)?', opts: ['Very low — people stay silent', 'Some speak up, most do not', 'Moderate safety', 'Generally safe environment', 'High — everyone speaks up freely'] },
    { q: 'How effective are your team meetings and communication rhythms?', opts: ['Meetings are rare or unproductive', 'Some structure, often ineffective', 'Adequate but could improve', 'Generally effective', 'Well-structured and productive'] },
    { q: 'How well does your team manage conflict when it arises?', opts: ['Conflict is avoided or escalates', 'Handled reactively', 'Some resolution processes', 'Usually resolved constructively', 'Proactive conflict resolution culture'] },
    { q: 'How effective are your staff recognition and motivation practices?', opts: ['No recognition system', 'Rare informal recognition', 'Occasional recognition', 'Regular and meaningful', 'Systematic and valued by the team'] }
  ],
  systems: [
    { q: 'How strong are your HR systems (recruitment, onboarding, performance management)?', opts: ['Mostly informal', 'Some documented processes', 'Basic HR systems in place', 'Functional HR with some gaps', 'Comprehensive HR system'] },
    { q: 'How effective is your governance structure and board oversight?', opts: ['Board rarely engaged', 'Board meets but adds little value', 'Board is functional', 'Active board with good governance', 'Excellent governance, board adds strategic value'] },
    { q: 'How mature are your data and technology systems for program delivery?', opts: ['Paper-based, no systems', 'Basic spreadsheets only', 'Some digital tools in use', 'Integrated digital workflows', 'Robust data systems across all functions'] },
    { q: 'How well does your organization manage compliance and audit requirements?', opts: ['Not prepared', 'Reactive to requirements', 'Basic compliance in place', 'Generally compliant', 'Audit-ready and fully compliant'] },
    { q: 'How effective are your organizational risk management processes?', opts: ['No risk processes', 'Risks identified informally', 'Basic risk register exists', 'Active risk monitoring', 'Comprehensive risk management system'] }
  ],
  funding: [
    { q: 'How diversified is your organization\'s funding base?', opts: ['1–2 funders, 80%+ concentration', 'Some diversification, still high risk', 'Moderate diversification', 'Well diversified across types', 'Highly diversified with sustainable mix'] },
    { q: 'How strong is your grant writing and proposal development capacity?', opts: ['No capacity — we struggle', 'Basic proposals, low success rate', 'Adequate capacity', 'Strong proposals, good success rate', 'Excellent — high conversion rate'] },
    { q: 'How well do you manage donor relationships after a grant is secured?', opts: ['Minimal contact until next ask', 'Basic reporting only', 'Regular updates to key donors', 'Active stewardship program', 'Deep, long-term partner relationships'] },
    { q: 'How clear and compelling is your organization\'s case for support?', opts: ['Not clearly articulated', 'Generic and unfocused', 'Adequate but not distinctive', 'Strong and well-evidenced', 'Compelling, specific, and inspiring'] },
    { q: 'How actively do you explore and develop new funding streams?', opts: ['No exploration happening', 'Occasional, opportunistic', 'Some structured exploration', 'Active pipeline development', 'Strategic diversification plan in action'] }
  ],
  comms: [
    { q: 'How consistent is your organization\'s brand identity and messaging across channels?', opts: ['Very inconsistent', 'Somewhat inconsistent', 'Mostly consistent', 'Consistent with minor gaps', 'Fully consistent and recognizable'] },
    { q: 'How effectively do you communicate your impact to external stakeholders?', opts: ['Rarely communicate impact', 'Basic activity reports only', 'Some impact stories shared', 'Regular impact communications', 'Compelling, evidence-based impact narrative'] },
    { q: 'How active and strategic is your use of digital and social media channels?', opts: ['No digital presence', 'Inactive or inconsistent presence', 'Basic presence, low engagement', 'Active with moderate results', 'Strategic and high-impact digital presence'] },
    { q: 'How well-prepared is your organization to handle a communications crisis?', opts: ['No plan exists', 'Aware of need but unprepared', 'Basic plan outlined', 'Plan exists and tested somewhat', 'Comprehensive crisis communications plan'] },
    { q: 'How well do you use beneficiary stories ethically and effectively?', opts: ['Stories not used', 'Stories shared without clear process', 'Some consent and dignity practices', 'Good ethical storytelling practices', 'Exemplary ethical story collection and use'] }
  ],
  finance: [
    { q: 'How accurately and timely are your financial reports produced?', opts: ['Reports are often late or inaccurate', 'Mostly late, some errors', 'Adequate accuracy and timing', 'Usually timely and accurate', 'Always timely, accurate, and useful'] },
    { q: 'How robust are your financial controls and segregation of duties?', opts: ['One person handles all finance', 'Minimal controls in place', 'Basic controls with some gaps', 'Good controls, minor gaps', 'Strong, documented, and tested controls'] },
    { q: 'How well does your organization manage cash flow and operating reserves?', opts: ['Frequent cash crises', 'Cash flow issues occasionally', 'Adequate, no major crises', 'Good cash management with reserve', '3–6 month reserve, proactive management'] },
    { q: 'How well does your team understand and use financial information for decisions?', opts: ['Financial data rarely consulted', 'Only finance staff engage with it', 'Some leaders use financials', 'Most leaders are financially literate', 'Finance-driven culture across leadership'] },
    { q: 'How prepared is your organization for donor audits and financial compliance?', opts: ['Not prepared at all', 'Mostly unprepared', 'Somewhat prepared', 'Generally audit-ready', 'Always audit-ready, no findings'] }
  ]
};

// Storage for per-capability mini-assessment scores
var capMiniScores = {};

function openCapAssessModal(key) {
  var cap = CAPABILITIES[key];
  var questions = CAP_QUESTIONS[key] || [];
  if (!questions.length) return;

  var existing = capMiniScores[key] || [];
  var html = '<div style="position:fixed;inset:0;z-index:2000;background:rgba(0,0,0,0.55);backdrop-filter:blur(4px);display:flex;align-items:center;justify-content:center;padding:1rem;" id="capAssessOverlay">';
  html += '<div style="background:white;border-radius:20px;width:100%;max-width:560px;max-height:90vh;overflow-y:auto;box-shadow:0 24px 80px rgba(0,0,0,.25);animation:modalIn .25s ease;">';
  html += '<div style="position:sticky;top:0;background:linear-gradient(135deg,var(--emerald-dark),var(--emerald));border-radius:20px 20px 0 0;padding:1.5rem 1.75rem;z-index:1;">';
  html += '<div style="display:flex;align-items:center;justify-content:space-between;">';
  html += '<div><div style="font-size:.68rem;font-weight:800;letter-spacing:.12em;text-transform:uppercase;color:rgba(255,255,255,.7);margin-bottom:.3rem;">Capability Assessment</div>';
  html += '<div style="font-size:1.15rem;font-weight:800;color:white;">' + cap.icon + ' ' + cap.title + '</div></div>';
  html += '<button onclick="closeCapAssessModal()" style="width:34px;height:34px;border-radius:50%;background:rgba(255,255,255,.2);border:none;cursor:pointer;color:white;font-size:1.1rem;display:flex;align-items:center;justify-content:center;">✕</button>';
  html += '</div></div>';
  html += '<div style="padding:1.5rem 1.75rem;">';
  html += '<p style="font-size:.85rem;color:var(--ink-light);line-height:1.65;margin-bottom:1.5rem;">Rate your organization honestly on each area. Your answers will personalize your learning path for this capability.</p>';

  questions.forEach(function(item, qi) {
    var savedAns = existing[qi] !== undefined ? existing[qi] : -1;
    html += '<div style="margin-bottom:1.4rem;" id="capq-' + key + '-' + qi + '">';
    html += '<div style="font-size:.88rem;font-weight:700;color:var(--ink);margin-bottom:.65rem;line-height:1.5;">' + (qi+1) + '. ' + item.q + '</div>';
    html += '<div style="display:flex;flex-direction:column;gap:.4rem;">';
    item.opts.forEach(function(opt, oi) {
      var isSelected = savedAns === oi;
      html += '<label style="display:flex;align-items:center;gap:.65rem;padding:.6rem .85rem;border-radius:9px;border:1.5px solid '+(isSelected?'var(--emerald)':'var(--border)')+';background:'+(isSelected?'rgba(26,107,74,.05)':'white')+';cursor:pointer;transition:all .15s;" '
        + 'onmouseover="if(!this.querySelector(\'input\').checked){this.style.borderColor=\'var(--emerald)\';this.style.background=\'rgba(26,107,74,.03)\'}" '
        + 'onmouseout="if(!this.querySelector(\'input\').checked){this.style.borderColor=\'var(--border)\';this.style.background=\'white\'}">';
      html += '<input type="radio" name="capq-' + key + '-' + qi + '" value="' + oi + '" '+(isSelected?'checked':'')+' style="accent-color:var(--emerald);width:15px;height:15px;flex-shrink:0;" '
        + 'onchange="updateCapAssessOption(\''+key+'\','+qi+','+oi+',this.closest(\'label\'))">';
      html += '<span style="font-size:.82rem;color:var(--ink-mid);line-height:1.4;"><strong style="color:var(--emerald-dark);font-family:\'DM Mono\',monospace;font-size:.68rem;">' + (oi+1) + '</strong> — ' + opt + '</span>';
      html += '</label>';
    });
    html += '</div></div>';
  });

  html += '<div style="display:flex;gap:.75rem;justify-content:flex-end;margin-top:1.25rem;padding-top:1.25rem;border-top:1px solid var(--border);">';
  html += '<button onclick="closeCapAssessModal()" style="padding:.65rem 1.25rem;border-radius:9px;border:1.5px solid var(--border);background:white;color:var(--ink-light);font-size:.85rem;font-weight:600;cursor:pointer;font-family:inherit;">Cancel</button>';
  html += '<button onclick="submitCapAssess(\''+key+'\')" style="padding:.65rem 1.5rem;border-radius:9px;border:none;background:linear-gradient(135deg,var(--emerald-dark),var(--emerald));color:white;font-size:.85rem;font-weight:700;cursor:pointer;font-family:inherit;">Save Results</button>';
  html += '</div></div></div></div>';

  var overlay = document.createElement('div');
  overlay.innerHTML = html;
  document.body.appendChild(overlay.firstChild);
}

function updateCapAssessOption(key, qi, oi, lbl) {
  var container = document.getElementById('capq-' + key + '-' + qi);
  if (!container) return;
  container.querySelectorAll('label').forEach(function(l) {
    l.style.borderColor = 'var(--border)'; l.style.background = 'white';
  });
  lbl.style.borderColor = 'var(--emerald)'; lbl.style.background = 'rgba(26,107,74,.05)';
}

function closeCapAssessModal() {
  var el = document.getElementById('capAssessOverlay');
  if (el) el.remove();
}

function submitCapAssess(key) {
  var questions = CAP_QUESTIONS[key] || [];
  var answers = [];
  var allAnswered = true;
  questions.forEach(function(item, qi) {
    var radios = document.querySelectorAll('input[name="capq-' + key + '-' + qi + '"]');
    var chosen = -1;
    radios.forEach(function(r) { if (r.checked) chosen = parseInt(r.value, 10); });
    if (chosen === -1) allAnswered = false;
    answers.push(chosen);
  });

  if (!allAnswered) {
    showToast('Please answer all 5 questions to continue.');
    return;
  }

  capMiniScores[key] = answers;
  // Derive a 1–5 score: average of answers (0–4) mapped to 1–5
  var avg = answers.reduce(function(a,b){ return a+b; }, 0) / answers.length;
  var score = Math.round(avg) + 1; // 1–5
  setCapScore(key, score);

  closeCapAssessModal();
  showToast('Assessment saved! Score: ' + score + '/5 for ' + CAPABILITIES[key].title);
  renderCategoriesGrid();
}

function showCapLearnPage(key) {
  var cap = CAPABILITIES[key];
  if (!cap) return;
  var lc = cap.learnContent;
  var hasAssessed = capMiniScores[key] && capMiniScores[key].length === 5;

  // Push to nav history
  var categoriesActive      = document.getElementById('categories-page') && document.getElementById('categories-page').classList.contains('active');
  var myLearningPathActive  = document.getElementById('my-learning-path-page') && document.getElementById('my-learning-path-page').classList.contains('active');
  var capPageActive         = document.getElementById('cap-page') && document.getElementById('cap-page').classList.contains('active');
  if (categoriesActive) {
    navHistory.push({ pageId: 'categories-page', label: '← All Capabilities', capId: null, subIdx: null });
  } else if (myLearningPathActive) {
    navHistory.push({ pageId: 'my-learning-path-page', label: '← My Learning Path', capId: null, subIdx: null });
  } else if (capPageActive && currentCapId) {
    navHistory.push({ pageId: 'cap-page', label: '← ' + cap.title, capId: currentCapId, subIdx: null });
  } else {
    navHistory.push({ pageId: 'categories-page', label: '← All Capabilities', capId: null, subIdx: null });
  }

  document.querySelectorAll('.page').forEach(function(p) { p.classList.remove('active'); });
  document.getElementById('cap-learn-page').classList.add('active');
  document.getElementById('navBackBtn').style.display = 'flex';
  var backLabel = navHistory.length > 0 ? navHistory[navHistory.length-1].label : '← All Capabilities';
  document.getElementById('navBackLabel').textContent = backLabel;
  setFloatingBack(backLabel);

  renderCapLearnPage(key);
  window.scrollTo(0, 0);
}

function renderCapLearnPage(key) {
  var cap = CAPABILITIES[key];
  var lc = cap.learnContent;
  var hasAssessed = capMiniScores[key] && capMiniScores[key].length === 5;

  // ── Gather Learn-section data for this capability ──
  // 1. Micro Lessons from this capability
  var microLessons = (cap.microLessons || []).map(function(ml, i) {
    var regKey = 'ml_' + key + '_' + i;
    window._mlRegistry = window._mlRegistry || {};
    window._mlRegistry[regKey] = { icon: cap.icon, capTitle: cap.title, capId: key, lessonIdx: i, title: ml.title, objective: ml.objective, content: ml.content, activity: ml.activity };
    return { regKey: regKey, idx: i, title: ml.title, objective: ml.objective };
  });

  // 2. Learning Paths that include this capability
  var relatedPaths = (typeof LEARNING_PATHS !== 'undefined' ? LEARNING_PATHS : []).filter(function(p) {
    return p.caps && p.caps.indexOf(key) !== -1;
  });

  // 3. Webinars for this capability
  var relatedWebinars = (typeof WEBINARS !== 'undefined' ? WEBINARS : []).filter(function(w) {
    return w.capId === key;
  });

  var html = '';

  // Breadcrumb
  html += '<div style="display:flex;align-items:center;gap:.4rem;font-size:.78rem;color:var(--ink-light);margin-bottom:1.5rem;flex-wrap:wrap;">';
  html += '<span onclick="showCategoriesPage()" style="color:var(--emerald);cursor:pointer;font-weight:600;">All Capabilities</span>';
  html += '<span style="opacity:.4;">›</span>';
  html += '<span onclick="loadCapability(\''+key+'\')" style="color:var(--emerald);cursor:pointer;font-weight:600;">' + cap.icon + ' ' + cap.title + '</span>';
  html += '<span style="opacity:.4;">›</span>';
  html += '<span style="color:var(--ink);">' + (hasAssessed ? 'Suggested Learning' : 'Learning Content') + '</span>';
  html += '</div>';

  // Hero banner
  html += '<div style="background:linear-gradient(135deg,var(--emerald-dark),var(--emerald));border-radius:18px;padding:2.5rem 2rem;margin-bottom:2rem;color:white;position:relative;overflow:hidden;">';
  html += '<div style="position:absolute;inset:0;background:radial-gradient(ellipse 60% 80% at 90% 50%,rgba(200,153,58,.18) 0%,transparent 70%);pointer-events:none;"></div>';
  html += '<div style="position:relative;">';
  html += '<div style="font-size:.68rem;font-weight:800;letter-spacing:.14em;text-transform:uppercase;opacity:.7;margin-bottom:.4rem;">' + (hasAssessed ? '✨ Personalized for You' : 'Learning Content') + '</div>';
  html += '<div style="font-size:2rem;font-weight:900;font-family:\'Playfair Display\',serif;margin-bottom:.4rem;">' + cap.icon + ' ' + cap.title + '</div>';
  html += '<div style="font-size:.92rem;opacity:.85;line-height:1.6;max-width:580px;">' + (hasAssessed ? 'Learning resources from Micro Lessons, Learning Paths, and Webinars — matched to your assessment results.' : 'All learning resources for this capability from the platform\'s Learn section.') + '</div>';
  // Content counters
  html += '<div style="display:flex;gap:.75rem;margin-top:1.1rem;flex-wrap:wrap;">';
  html += '<div style="background:rgba(255,255,255,.15);border-radius:8px;padding:.35rem .8rem;font-size:.75rem;font-weight:700;">📺 ' + microLessons.length + ' Micro Lessons</div>';
  html += '<div style="background:rgba(255,255,255,.15);border-radius:8px;padding:.35rem .8rem;font-size:.75rem;font-weight:700;">🛤️ ' + relatedPaths.length + ' Learning Paths</div>';
  html += '<div style="background:rgba(255,255,255,.15);border-radius:8px;padding:.35rem .8rem;font-size:.75rem;font-weight:700;">🎙️ ' + relatedWebinars.length + ' Webinars</div>';
  html += '</div>';
  if (!hasAssessed) {
    html += '<div style="margin-top:1.1rem;">';
    html += '<button onclick="openCapAssessModal(\'' + key + '\')" style="background:rgba(255,255,255,.2);border:1.5px solid rgba(255,255,255,.4);color:white;border-radius:10px;padding:.55rem 1.25rem;font-size:.82rem;font-weight:700;cursor:pointer;font-family:inherit;">Take Assessment for Personalized Suggestions</button>';
    html += '</div>';
  }
  html += '</div></div>';

  if (hasAssessed) {
    // ── ASSESSED VIEW ──
    var answers = capMiniScores[key];
    var avgScore = answers.reduce(function(a,b){return a+b;},0) / answers.length;
    var levelLabel = avgScore < 1.5 ? 'Foundational' : avgScore < 2.5 ? 'Developing' : avgScore < 3.5 ? 'Established' : 'Advanced';
    var levelColor = avgScore < 1.5 ? '#DC2626' : avgScore < 2.5 ? '#D97706' : avgScore < 3.5 ? '#059669' : '#1A6B4A';
    var levelBg    = avgScore < 1.5 ? 'rgba(220,38,38,.05)' : avgScore < 2.5 ? 'rgba(217,119,6,.05)' : avgScore < 3.5 ? 'rgba(5,150,105,.05)' : 'rgba(26,107,74,.05)';

    // Score card
    html += '<div style="background:white;border:1.5px solid var(--border);border-radius:16px;padding:1.5rem;margin-bottom:1.75rem;display:flex;gap:1.25rem;align-items:center;flex-wrap:wrap;">';
    html += '<div style="background:'+levelBg+';border:2px solid '+levelColor+';border-radius:12px;padding:.85rem 1.25rem;text-align:center;flex-shrink:0;">';
    html += '<div style="font-family:\'DM Mono\',monospace;font-size:1.75rem;font-weight:800;color:'+levelColor+';">' + Math.round((avgScore/4)*100) + '%</div>';
    html += '<div style="font-size:.7rem;font-weight:800;letter-spacing:.08em;text-transform:uppercase;color:'+levelColor+';">' + levelLabel + '</div>';
    html += '</div>';
    html += '<div style="flex:1;min-width:180px;">';
    html += '<div style="font-size:.95rem;font-weight:800;color:var(--ink);margin-bottom:.25rem;">Your Assessment Score</div>';
    html += '<div style="font-size:.83rem;color:var(--ink-light);line-height:1.6;">Learning resources below are prioritized from your biggest gaps to your strongest areas.</div>';
    html += '<button onclick="openCapAssessModal(\''+key+'\')" style="margin-top:.6rem;background:none;border:1.5px solid var(--border);color:var(--ink-light);border-radius:7px;padding:.35rem .8rem;font-size:.73rem;font-weight:600;cursor:pointer;font-family:inherit;" onmouseover="this.style.borderColor=\'var(--emerald)\';this.style.color=\'var(--emerald)\'" onmouseout="this.style.borderColor=\'var(--border)\';this.style.color=\'var(--ink-light)\'">Retake Assessment</button>';
    html += '</div></div>';

    // Sort micro lessons: weak-area indices first (answers 0–1), then mid (2), then strong (3–4)
    var weakIdxs = [], midIdxs = [], strongIdxs = [];
    answers.forEach(function(ans, i) {
      if (i < microLessons.length) {
        if (ans <= 1) weakIdxs.push(i);
        else if (ans === 2) midIdxs.push(i);
        else strongIdxs.push(i);
      }
    });
    // Also include any extra micro lessons beyond Q count
    for (var ei = answers.length; ei < microLessons.length; ei++) { midIdxs.push(ei); }

    // ── Section: Priority Micro Lessons ──
    if (weakIdxs.length > 0) {
      html += _renderLearnSection('🎯 Priority Micro Lessons — Address Your Gaps', '#DC2626', 'rgba(220,38,38,.06)', 'rgba(220,38,38,.25)');
      weakIdxs.forEach(function(qi) {
        var ml = microLessons[qi];
        if (!ml) return;
        html += _renderMicroLessonCard(ml, true);
      });
      html += '</div>';
    }

    if (midIdxs.length > 0) {
      html += _renderLearnSection('📈 Developing Micro Lessons — Build on These', '#D97706', 'rgba(217,119,6,.05)', 'rgba(217,119,6,.2)');
      midIdxs.forEach(function(qi) {
        var ml = microLessons[qi];
        if (!ml) return;
        html += _renderMicroLessonCard(ml, false);
      });
      html += '</div>';
    }

    if (strongIdxs.length > 0) {
      html += _renderLearnSection('✅ Advanced Micro Lessons — Your Strengths', 'var(--emerald)', 'rgba(26,107,74,.04)', 'rgba(26,107,74,.18)');
      strongIdxs.forEach(function(qi) {
        var ml = microLessons[qi];
        if (!ml) return;
        html += _renderMicroLessonCard(ml, false);
      });
      html += '</div>';
    }

  } else {
    // ── UNASSESSED VIEW: all micro lessons ──
    if (microLessons.length > 0) {
      html += _renderLearnSection('Micro Lessons', 'var(--emerald)', 'rgba(26,107,74,.03)', 'var(--border)');
      microLessons.forEach(function(ml) {
        html += _renderMicroLessonCard(ml, false);
      });
      html += '</div>';
    }
  }

  // ── Learning Paths (always show, filtered) ──
  if (relatedPaths.length > 0) {
    html += '<div style="margin-bottom:1.75rem;">';
    html += '<div style="display:flex;align-items:center;gap:.6rem;margin-bottom:1rem;">';
    html += '<div style="width:8px;height:8px;border-radius:50%;background:#7c3aed;flex-shrink:0;"></div>';
    html += '<div style="font-size:.72rem;font-weight:800;text-transform:uppercase;letter-spacing:.12em;color:#7c3aed;">🛤️ Learning Paths That Include This Capability</div>';
    html += '</div>';
    relatedPaths.forEach(function(p) {
      html += '<div onclick="openLearningPath(\''+p.id+'\')" style="background:white;border:1.5px solid var(--border);border-radius:14px;padding:1.25rem 1.4rem;margin-bottom:.75rem;cursor:pointer;transition:all .2s;display:flex;align-items:center;gap:1.1rem;" onmouseover="this.style.borderColor=\''+p.color+'\';this.style.transform=\'translateY(-2px)\';this.style.boxShadow=\'0 6px 20px rgba(0,0,0,.07)\'" onmouseout="this.style.borderColor=\'var(--border)\';this.style.transform=\'\';this.style.boxShadow=\'\'">';
      html += '<div style="width:46px;height:46px;border-radius:12px;background:'+p.colorLight+';border:1.5px solid '+p.color+'33;display:flex;align-items:center;justify-content:center;font-size:1.35rem;flex-shrink:0;">' + p.icon + '</div>';
      html += '<div style="flex:1;min-width:0;">';
      html += '<div style="font-size:.92rem;font-weight:800;color:var(--ink);margin-bottom:.15rem;">' + p.title + '</div>';
      html += '<div style="font-size:.79rem;color:var(--ink-light);line-height:1.45;margin-bottom:.35rem;">' + p.tagline + '</div>';
      html += '<div style="display:flex;gap:.5rem;flex-wrap:wrap;">';
      html += '<span style="font-size:.67rem;font-weight:700;padding:.15rem .5rem;border-radius:20px;background:'+p.colorLight+';color:'+p.color+';border:1px solid '+p.color+'33;">'+p.level+'</span>';
      html += '<span style="font-size:.67rem;font-weight:700;padding:.15rem .5rem;border-radius:20px;background:var(--cream);color:var(--ink-light);border:1px solid var(--border);">⏱ '+p.duration+'</span>';
      html += '<span style="font-size:.67rem;font-weight:700;padding:.15rem .5rem;border-radius:20px;background:var(--cream);color:var(--ink-light);border:1px solid var(--border);">'+p.steps.length+' steps</span>';
      html += '</div></div>';
      html += '<div style="color:var(--ink-pale);font-size:1.2rem;flex-shrink:0;">›</div>';
      html += '</div>';
    });
    html += '</div>';
  }

  // ── Webinars ──
  if (relatedWebinars.length > 0) {
    html += '<div style="margin-bottom:1.75rem;">';
    html += '<div style="display:flex;align-items:center;gap:.6rem;margin-bottom:1rem;">';
    html += '<div style="width:8px;height:8px;border-radius:50%;background:#0ea5e9;flex-shrink:0;"></div>';
    html += '<div style="font-size:.72rem;font-weight:800;text-transform:uppercase;letter-spacing:.12em;color:#0ea5e9;">🎙️ Webinars</div>';
    html += '</div>';
    relatedWebinars.forEach(function(w) {
      var isRecorded = w.status === 'recorded';
      html += '<div onclick="openWebinar(\''+w.id+'\')" style="background:white;border:1.5px solid var(--border);border-radius:14px;padding:1.25rem 1.4rem;margin-bottom:.75rem;cursor:pointer;transition:all .2s;display:flex;align-items:center;gap:1.1rem;" onmouseover="this.style.borderColor=\'#0ea5e9\';this.style.transform=\'translateY(-2px)\';this.style.boxShadow=\'0 6px 20px rgba(0,0,0,.07)\'" onmouseout="this.style.borderColor=\'var(--border)\';this.style.transform=\'\';this.style.boxShadow=\'\'">';
      html += '<div style="width:46px;height:46px;border-radius:12px;background:rgba(14,165,233,.08);border:1.5px solid rgba(14,165,233,.2);display:flex;align-items:center;justify-content:center;font-size:1.35rem;flex-shrink:0;">' + w.icon + '</div>';
      html += '<div style="flex:1;min-width:0;">';
      html += '<div style="font-size:.92rem;font-weight:800;color:var(--ink);margin-bottom:.15rem;">' + w.title + '</div>';
      html += '<div style="font-size:.79rem;color:var(--ink-light);margin-bottom:.35rem;">' + w.speaker + ' · ' + w.role + '</div>';
      html += '<div style="display:flex;gap:.5rem;flex-wrap:wrap;">';
      html += '<span style="font-size:.67rem;font-weight:700;padding:.15rem .5rem;border-radius:20px;background:'+(isRecorded?'rgba(14,165,233,.08)':'rgba(22,163,74,.08)')+';color:'+(isRecorded?'#0ea5e9':'#16a34a')+';border:1px solid '+(isRecorded?'rgba(14,165,233,.2)':'rgba(22,163,74,.2)') +';">'+(isRecorded?'🎬 Recorded':'🔴 Upcoming')+'</span>';
      html += '<span style="font-size:.67rem;font-weight:700;padding:.15rem .5rem;border-radius:20px;background:var(--cream);color:var(--ink-light);border:1px solid var(--border);">⏱ '+w.duration+'</span>';
      html += '</div></div>';
      html += '<div style="color:var(--ink-pale);font-size:1.2rem;flex-shrink:0;">›</div>';
      html += '</div>';
    });
    html += '</div>';
  }

  // Footer CTA
  html += '<div style="margin-top:2rem;background:linear-gradient(135deg,var(--emerald-dark),var(--emerald));border-radius:16px;padding:1.75rem;display:flex;align-items:center;justify-content:space-between;gap:1.25rem;flex-wrap:wrap;">';
  html += '<div><div style="font-size:1rem;font-weight:800;color:white;margin-bottom:.25rem;">Explore all resources</div><div style="font-size:.85rem;color:rgba(255,255,255,.75);">Open the full ' + cap.title + ' module for workbooks, video guides, and templates.</div></div>';
  html += '<button onclick="loadCapability(\''+key+'\')" style="background:white;color:var(--emerald-dark);border:none;border-radius:10px;padding:.75rem 1.5rem;font-size:.88rem;font-weight:800;cursor:pointer;font-family:inherit;white-space:nowrap;">Open Full Module →</button>';
  html += '</div>';

  document.getElementById('capLearnPageInner').innerHTML = html;
}

function _renderLearnSection(label, color, bgColor, borderColor) {
  return '<div style="margin-bottom:1.75rem;">'
    + '<div style="display:flex;align-items:center;gap:.6rem;margin-bottom:1rem;">'
    + '<div style="width:8px;height:8px;border-radius:50%;background:'+color+';flex-shrink:0;"></div>'
    + '<div style="font-size:.72rem;font-weight:800;text-transform:uppercase;letter-spacing:.12em;color:'+color+';">'+label+'</div>'
    + '</div>';
}

function _renderMicroLessonCard(ml, isPriority) {
  var borderStyle = isPriority ? 'rgba(220,38,38,.3)' : 'var(--border)';
  var bgStyle = isPriority ? 'rgba(220,38,38,.02)' : 'white';
  return '<div onclick="openMicroLesson(\''+ml.regKey+'\')" style="background:'+bgStyle+';border:1.5px solid '+borderStyle+';border-radius:14px;padding:1.2rem 1.4rem;margin-bottom:.75rem;cursor:pointer;transition:all .2s;display:flex;align-items:flex-start;gap:1rem;" '
    + 'onmouseover="this.style.borderColor=\'var(--emerald)\';this.style.transform=\'translateY(-2px)\';this.style.boxShadow=\'0 6px 20px rgba(0,0,0,.07)\'" '
    + 'onmouseout="this.style.borderColor=\''+borderStyle+'\';this.style.transform=\'\';this.style.boxShadow=\'\'">'
    + '<div style="width:36px;height:36px;min-width:36px;border-radius:9px;background:rgba(14,165,233,.1);border:1.5px solid rgba(14,165,233,.25);display:flex;align-items:center;justify-content:center;font-size:.95rem;">📺</div>'
    + '<div style="flex:1;min-width:0;">'
    + '<div style="font-size:.92rem;font-weight:700;color:var(--ink);margin-bottom:.2rem;">' + ml.title + '</div>'
    + '<div style="font-size:.79rem;color:var(--ink-light);line-height:1.5;">' + (ml.objective || '') + '</div>'
    + '</div>'
    + '<div style="color:var(--ink-pale);font-size:1.2rem;flex-shrink:0;margin-top:.1rem;">›</div>'
    + '</div>';
}

function closeCapLearnModal() {
  var el = document.getElementById('capLearnOverlay');
  if (el) el.remove();
}

// ═══════════════════════════════════════════════
// CAP IMPROVE PAGE
// ═══════════════════════════════════════════════
function showCapImprovePage(key) {
  var cap = CAPABILITIES[key];
  if (!cap) return;

  // Push history
  var categoriesActive     = document.getElementById('categories-page') && document.getElementById('categories-page').classList.contains('active');
  var myLearningPathActive = document.getElementById('my-learning-path-page') && document.getElementById('my-learning-path-page').classList.contains('active');
  var capPageActive        = document.getElementById('cap-page') && document.getElementById('cap-page').classList.contains('active');
  if (categoriesActive) {
    navHistory.push({ pageId: 'categories-page', label: '← All Capabilities', capId: null, subIdx: null });
  } else if (myLearningPathActive) {
    navHistory.push({ pageId: 'my-learning-path-page', label: '← My Learning Path', capId: null, subIdx: null });
  } else if (capPageActive && currentCapId) {
    navHistory.push({ pageId: 'cap-page', label: '← ' + cap.title, capId: currentCapId, subIdx: null });
  } else {
    navHistory.push({ pageId: 'categories-page', label: '← All Capabilities', capId: null, subIdx: null });
  }

  document.querySelectorAll('.page').forEach(function(p) { p.classList.remove('active'); });
  document.getElementById('cap-improve-page').classList.add('active');
  document.getElementById('navBackBtn').style.display = 'flex';
  var backLabel = navHistory.length > 0 ? navHistory[navHistory.length - 1].label : '← All Capabilities';
  document.getElementById('navBackLabel').textContent = backLabel;
  setFloatingBack(backLabel);

  renderCapImprovePage(key);
  window.scrollTo(0, 0);
}

function renderCapImprovePage(key) {
  var cap = CAPABILITIES[key];
  var hasAssessed = capMiniScores[key] && capMiniScores[key].length === 5;

  // ── Gather Improve-section data for this capability ──

  // 1. Templates — from cap.templates[]
  var templates = cap.templates || [];

  // 2. Workbooks — from cap.subCapabilities[].workbook
  var workbooks = (cap.subCapabilities || []).map(function(sub, i) {
    return sub.workbook ? { idx: i, title: sub.title, intro: sub.workbook.intro || '', time: sub.time || '60 min' } : null;
  }).filter(Boolean);

  // 3. Success Stories — filtered by caps[] including this key
  var stories = (typeof SUCCESS_STORIES !== 'undefined' ? SUCCESS_STORIES : []).filter(function(s) {
    return s.caps && s.caps.indexOf(key) !== -1;
  });

  // 4. Improvement Tracks that include this capability
  var relatedTracks = (typeof IMPROVEMENT_TRACKS !== 'undefined' ? IMPROVEMENT_TRACKS : []).filter(function(t) {
    return t.capabilities && t.capabilities.indexOf(key) !== -1;
  });

  // 5. Roadmap milestones linked to this capability
  var roadmapItems = [];
  if (typeof ROADMAP_PHASES !== 'undefined') {
    ROADMAP_PHASES.forEach(function(phase) {
      phase.milestones.forEach(function(m) {
        if (m.action && m.action.indexOf("'" + key + "'") !== -1) {
          roadmapItems.push({ phase: phase.label, phaseTitle: phase.title, phaseColor: phase.color, icon: m.icon, title: m.title, desc: m.desc, action: m.action, cta: m.cta });
        }
      });
    });
  }

  // 6. Weekly Checklist tasks linked to this capability
  var checklistItems = [];
  if (typeof WEEKLY_TASKS !== 'undefined') {
    [1, 2, 3].forEach(function(p) {
      var phaseName = p === 1 ? 'Phase 1 · Days 1–30' : p === 2 ? 'Phase 2 · Days 31–60' : 'Phase 3 · Days 61–90';
      (WEEKLY_TASKS[p] || []).forEach(function(t) {
        if (t.action && t.action.indexOf("'" + key + "'") !== -1) {
          checklistItems.push({ phase: phaseName, icon: t.icon, title: t.title, desc: t.desc, action: t.action });
        }
      });
    });
  }

  var html = '';

  // Breadcrumb
  html += '<div style="display:flex;align-items:center;gap:.4rem;font-size:.78rem;color:var(--ink-light);margin-bottom:1.5rem;flex-wrap:wrap;">';
  html += '<span onclick="showCategoriesPage()" style="color:var(--emerald);cursor:pointer;font-weight:600;">All Capabilities</span>';
  html += '<span style="opacity:.4;">›</span>';
  html += '<span onclick="navHistory.push({pageId:\'cap-improve-page\',label:\'← Improve\',capId:null,subIdx:null});loadCapability(\'' + key + '\')" style="color:var(--emerald);cursor:pointer;font-weight:600;">' + cap.icon + ' ' + cap.title + '</span>';
  html += '<span style="opacity:.4;">›</span>';
  html += '<span style="color:var(--ink);">' + (hasAssessed ? 'Your Improvement Plan' : 'Improve') + '</span>';
  html += '</div>';

  // Hero banner
  html += '<div style="background:linear-gradient(135deg,#3730a3,#6366f1);border-radius:18px;padding:2.5rem 2rem;margin-bottom:2rem;color:white;position:relative;overflow:hidden;">';
  html += '<div style="position:absolute;inset:0;background:radial-gradient(ellipse 60% 80% at 85% 50%,rgba(200,153,58,.2) 0%,transparent 65%);pointer-events:none;"></div>';
  html += '<div style="position:relative;">';
  html += '<div style="font-size:.68rem;font-weight:800;letter-spacing:.14em;text-transform:uppercase;opacity:.7;margin-bottom:.4rem;">' + (hasAssessed ? '🚀 Your Improvement Plan' : 'Improve This Capability') + '</div>';
  html += '<div style="font-size:2rem;font-weight:900;font-family:\'Playfair Display\',serif;margin-bottom:.4rem;">' + cap.icon + ' ' + cap.title + '</div>';
  html += '<div style="font-size:.92rem;opacity:.85;line-height:1.6;max-width:580px;">' + (hasAssessed ? 'Improvement resources from Workbooks, Templates, Roadmap, and Success Stories — tailored to your assessment gaps.' : 'All practical improvement resources for this capability from the platform\'s Improve section.') + '</div>';
  // Content counters
  html += '<div style="display:flex;gap:.75rem;margin-top:1.1rem;flex-wrap:wrap;">';
  html += '<div style="background:rgba(255,255,255,.15);border-radius:8px;padding:.35rem .8rem;font-size:.75rem;font-weight:700;">📒 ' + workbooks.length + ' Workbooks</div>';
  html += '<div style="background:rgba(255,255,255,.15);border-radius:8px;padding:.35rem .8rem;font-size:.75rem;font-weight:700;">🛠️ ' + templates.length + ' Templates</div>';
  html += '<div style="background:rgba(255,255,255,.15);border-radius:8px;padding:.35rem .8rem;font-size:.75rem;font-weight:700;">🏆 ' + stories.length + ' Success Stories</div>';
  html += '<div style="background:rgba(255,255,255,.15);border-radius:8px;padding:.35rem .8rem;font-size:.75rem;font-weight:700;">🗺️ ' + relatedTracks.length + ' Improvement Tracks</div>';
  html += '</div>';
  if (!hasAssessed) {
    html += '<div style="margin-top:1.1rem;">';
    html += '<button onclick="openCapAssessModal(\'' + key + '\')" style="background:rgba(255,255,255,.2);border:1.5px solid rgba(255,255,255,.4);color:white;border-radius:10px;padding:.55rem 1.25rem;font-size:.82rem;font-weight:700;cursor:pointer;font-family:inherit;">Take Assessment for a Personalized Plan</button>';
    html += '</div>';
  }
  html += '</div></div>';

  // ══════════════════════════════════════════
  // ASSESSED VIEW — prioritize by gap areas
  // ══════════════════════════════════════════
  if (hasAssessed) {
    var answers = capMiniScores[key];
    var avgScore = answers.reduce(function(a, b) { return a + b; }, 0) / answers.length;
    var levelLabel = avgScore < 1.5 ? 'Foundational' : avgScore < 2.5 ? 'Developing' : avgScore < 3.5 ? 'Established' : 'Advanced';
    var levelColor = avgScore < 1.5 ? '#DC2626' : avgScore < 2.5 ? '#D97706' : avgScore < 3.5 ? '#059669' : '#1A6B4A';
    var levelBg    = avgScore < 1.5 ? 'rgba(220,38,38,.05)' : avgScore < 2.5 ? 'rgba(217,119,6,.05)' : avgScore < 3.5 ? 'rgba(5,150,105,.05)' : 'rgba(26,107,74,.05)';

    var weakIdxs = [], strongIdxs = [];
    answers.forEach(function(ans, i) { if (ans <= 1) weakIdxs.push(i); else if (ans >= 3) strongIdxs.push(i); });

    // Score card
    html += '<div style="background:white;border:1.5px solid var(--border);border-radius:16px;padding:1.5rem;margin-bottom:1.75rem;display:flex;gap:1.25rem;align-items:center;flex-wrap:wrap;">';
    html += '<div style="background:' + levelBg + ';border:2px solid ' + levelColor + ';border-radius:12px;padding:.85rem 1.25rem;text-align:center;flex-shrink:0;">';
    html += '<div style="font-family:\'DM Mono\',monospace;font-size:1.75rem;font-weight:800;color:' + levelColor + ';">' + Math.round((avgScore / 4) * 100) + '%</div>';
    html += '<div style="font-size:.7rem;font-weight:800;letter-spacing:.08em;text-transform:uppercase;color:' + levelColor + ';">' + levelLabel + '</div>';
    html += '</div>';
    html += '<div style="flex:1;min-width:180px;">';
    html += '<div style="font-size:.95rem;font-weight:800;color:var(--ink);margin-bottom:.25rem;">Your Improvement Priority</div>';
    html += '<div style="font-size:.83rem;color:var(--ink-light);line-height:1.6;">Resources below are ordered from your most critical gaps. Start with workbooks and templates in the red sections.</div>';
    html += '<button onclick="openCapAssessModal(\'' + key + '\')" style="margin-top:.6rem;background:none;border:1.5px solid var(--border);color:var(--ink-light);border-radius:7px;padding:.35rem .8rem;font-size:.73rem;font-weight:600;cursor:pointer;font-family:inherit;" onmouseover="this.style.borderColor=\'#6366f1\';this.style.color=\'#6366f1\'" onmouseout="this.style.borderColor=\'var(--border)\';this.style.color=\'var(--ink-light)\'">Retake Assessment</button>';
    html += '</div></div>';

    // ── Priority Workbooks (matching gap areas) ──
    var priorityWorkbooks = weakIdxs.map(function(i) { return workbooks[i]; }).filter(Boolean);
    var otherWorkbooks    = workbooks.filter(function(wb) { return weakIdxs.indexOf(wb.idx) === -1; });

    if (priorityWorkbooks.length > 0) {
      html += _renderImproveSection('📒 Priority Workbooks — Address Your Biggest Gaps', '#DC2626', 'rgba(220,38,38,.06)', 'rgba(220,38,38,.25)');
      priorityWorkbooks.forEach(function(wb) { html += _renderWorkbookCard(key, wb, true); });
      html += '</div>';
    }
    if (otherWorkbooks.length > 0) {
      html += _renderImproveSection('📒 Additional Workbooks', 'var(--emerald)', 'rgba(26,107,74,.03)', 'var(--border)');
      otherWorkbooks.forEach(function(wb) { html += _renderWorkbookCard(key, wb, false); });
      html += '</div>';
    }

    // ── Priority Templates ──
    // Map weak area question numbers to template indices (use all if short)
    var priorityTpls = weakIdxs.map(function(i) { return templates[i]; }).filter(Boolean);
    var otherTpls    = templates.filter(function(t, i) { return weakIdxs.indexOf(i) === -1; });

    if (priorityTpls.length > 0) {
      html += _renderImproveSection('🛠️ Priority Templates — Ready-to-Use Tools', '#DC2626', 'rgba(220,38,38,.04)', 'rgba(220,38,38,.2)');
      priorityTpls.forEach(function(tpl) { html += _renderTemplateCard(tpl, key, true); });
      html += '</div>';
    }
    if (otherTpls.length > 0) {
      html += _renderImproveSection('🛠️ More Templates', '#D97706', 'rgba(217,119,6,.04)', 'rgba(217,119,6,.2)');
      otherTpls.forEach(function(tpl) { html += _renderTemplateCard(tpl, key, false); });
      html += '</div>';
    }

  } else {
    // ══════════════════════════════════════════
    // UNASSESSED VIEW — show all Improve content
    // ══════════════════════════════════════════

    // Workbooks
    if (workbooks.length > 0) {
      html += _renderImproveSection('📒 Workbooks', 'var(--emerald)', 'rgba(26,107,74,.03)', 'var(--border)');
      workbooks.forEach(function(wb) { html += _renderWorkbookCard(key, wb, false); });
      html += '</div>';
    }

    // Templates
    if (templates.length > 0) {
      html += _renderImproveSection('🛠️ Tools & Templates', '#D97706', 'rgba(217,119,6,.04)', 'rgba(217,119,6,.2)');
      templates.forEach(function(tpl) { html += _renderTemplateCard(tpl, key, false); });
      html += '</div>';
    }
  }

  // ── Improvement Tracks (always shown) ──
  if (relatedTracks.length > 0) {
    html += '<div style="margin-bottom:1.75rem;">';
    html += '<div style="display:flex;align-items:center;gap:.6rem;margin-bottom:1rem;">';
    html += '<div style="width:8px;height:8px;border-radius:50%;background:#6366f1;flex-shrink:0;"></div>';
    html += '<div style="font-size:.72rem;font-weight:800;text-transform:uppercase;letter-spacing:.12em;color:#6366f1;">🗺️ Improvement Tracks That Include This Capability</div>';
    html += '</div>';
    relatedTracks.forEach(function(t) {
      html += '<div onclick="openTrack(\'' + t.id + '\')" style="background:white;border:1.5px solid var(--border);border-radius:14px;padding:1.25rem 1.4rem;margin-bottom:.75rem;cursor:pointer;transition:all .2s;display:flex;align-items:flex-start;gap:1.1rem;" onmouseover="this.style.borderColor=\'' + t.accentColor + '\';this.style.transform=\'translateY(-2px)\';this.style.boxShadow=\'0 6px 20px rgba(0,0,0,.07)\'" onmouseout="this.style.borderColor=\'var(--border)\';this.style.transform=\'\';this.style.boxShadow=\'\'">';
      html += '<div style="width:46px;height:46px;border-radius:12px;background:' + t.accentLight + ';border:1.5px solid ' + t.accentColor + '33;display:flex;align-items:center;justify-content:center;font-size:1.35rem;flex-shrink:0;">' + t.icon + '</div>';
      html += '<div style="flex:1;min-width:0;">';
      html += '<div style="font-size:.92rem;font-weight:800;color:var(--ink);margin-bottom:.15rem;">' + t.title + '</div>';
      html += '<div style="font-size:.79rem;color:var(--ink-light);line-height:1.45;margin-bottom:.4rem;">' + t.tagline + '</div>';
      html += '<div style="display:flex;gap:.5rem;flex-wrap:wrap;">';
      html += '<span style="font-size:.67rem;font-weight:700;padding:.15rem .5rem;border-radius:20px;background:' + t.accentLight + ';color:' + t.accentColor + ';border:1px solid ' + t.accentColor + '33;">' + t.difficulty + '</span>';
      html += '<span style="font-size:.67rem;font-weight:700;padding:.15rem .5rem;border-radius:20px;background:var(--cream);color:var(--ink-light);border:1px solid var(--border);">⏱ ' + t.duration + '</span>';
      html += '<span style="font-size:.67rem;font-weight:700;padding:.15rem .5rem;border-radius:20px;background:var(--cream);color:var(--ink-light);border:1px solid var(--border);">' + t.weeks.length + ' week plan</span>';
      html += '</div></div>';
      html += '<div style="color:var(--ink-pale);font-size:1.2rem;flex-shrink:0;margin-top:.2rem;">›</div>';
      html += '</div>';
    });
    html += '</div>';
  }

  // ── 90-Day Roadmap Milestones ──
  if (roadmapItems.length > 0) {
    html += '<div style="margin-bottom:1.75rem;">';
    html += '<div style="display:flex;align-items:center;gap:.6rem;margin-bottom:1rem;">';
    html += '<div style="width:8px;height:8px;border-radius:50%;background:var(--emerald);flex-shrink:0;"></div>';
    html += '<div style="font-size:.72rem;font-weight:800;text-transform:uppercase;letter-spacing:.12em;color:var(--emerald);">🗺️ 90-Day Roadmap Milestones</div>';
    html += '</div>';
    roadmapItems.forEach(function(m) {
      // Wrap action to preserve improve-page in nav history before navigating away
      var safeAction = 'navHistory.push({pageId:\'cap-improve-page\',label:\'← Improve\',capId:null,subIdx:null});' + m.action;
      html += '<div onclick="' + safeAction + '" style="background:white;border:1.5px solid var(--border);border-radius:14px;padding:1.1rem 1.35rem;margin-bottom:.65rem;cursor:pointer;transition:all .2s;display:flex;align-items:center;gap:1rem;" onmouseover="this.style.borderColor=\'var(--emerald)\';this.style.background=\'rgba(26,107,74,.03)\'" onmouseout="this.style.borderColor=\'var(--border)\';this.style.background=\'white\'">';
      html += '<div style="font-size:1.3rem;flex-shrink:0;">' + m.icon + '</div>';
      html += '<div style="flex:1;min-width:0;">';
      html += '<div style="font-size:.68rem;font-weight:700;letter-spacing:.08em;text-transform:uppercase;color:var(--ink-pale);margin-bottom:.15rem;">' + m.phase + '</div>';
      html += '<div style="font-size:.9rem;font-weight:700;color:var(--ink);">' + m.title + '</div>';
      html += '<div style="font-size:.78rem;color:var(--ink-light);margin-top:.1rem;">' + m.desc + '</div>';
      html += '</div>';
      html += '<div style="font-size:.8rem;font-weight:700;color:var(--emerald);white-space:nowrap;flex-shrink:0;">' + m.cta + '</div>';
      html += '</div>';
    });
    html += '</div>';
  }

  // ── Weekly Checklist Tasks ──
  if (checklistItems.length > 0) {
    html += '<div style="margin-bottom:1.75rem;">';
    html += '<div style="display:flex;align-items:center;gap:.6rem;margin-bottom:1rem;">';
    html += '<div style="width:8px;height:8px;border-radius:50%;background:#059669;flex-shrink:0;"></div>';
    html += '<div style="font-size:.72rem;font-weight:800;text-transform:uppercase;letter-spacing:.12em;color:#059669;">✅ This Week\'s Checklist Tasks</div>';
    html += '</div>';
    checklistItems.forEach(function(t) {
      // Wrap action to preserve improve-page in nav history before navigating away
      var safeAction = 'navHistory.push({pageId:\'cap-improve-page\',label:\'← Improve\',capId:null,subIdx:null});' + t.action;
      html += '<div style="background:white;border:1.5px solid var(--border);border-radius:14px;padding:1.1rem 1.35rem;margin-bottom:.65rem;display:flex;align-items:center;gap:1rem;">';
      html += '<div style="font-size:1.3rem;flex-shrink:0;">' + t.icon + '</div>';
      html += '<div style="flex:1;min-width:0;">';
      html += '<div style="font-size:.68rem;font-weight:700;letter-spacing:.08em;text-transform:uppercase;color:var(--ink-pale);margin-bottom:.15rem;">' + t.phase + '</div>';
      html += '<div style="font-size:.9rem;font-weight:700;color:var(--ink);">' + t.title + '</div>';
      html += '<div style="font-size:.78rem;color:var(--ink-light);margin-top:.1rem;">' + t.desc + '</div>';
      html += '</div>';
      html += '<button onclick="' + safeAction + '" style="background:rgba(5,150,105,.1);border:1px solid rgba(5,150,105,.25);color:#059669;border-radius:8px;padding:.4rem .8rem;font-size:.75rem;font-weight:700;cursor:pointer;font-family:inherit;white-space:nowrap;flex-shrink:0;">Go →</button>';
      html += '</div>';
    });
    html += '</div>';
  }

  // ── Success Stories ──
  if (stories.length > 0) {
    html += '<div style="margin-bottom:1.75rem;">';
    html += '<div style="display:flex;align-items:center;gap:.6rem;margin-bottom:1rem;">';
    html += '<div style="width:8px;height:8px;border-radius:50%;background:var(--gold);flex-shrink:0;"></div>';
    html += '<div style="font-size:.72rem;font-weight:800;text-transform:uppercase;letter-spacing:.12em;color:var(--gold);">🏆 Success Stories</div>';
    html += '</div>';
    stories.forEach(function(s) {
      html += '<div style="background:white;border:1.5px solid var(--border);border-radius:14px;padding:1.35rem 1.5rem;margin-bottom:.85rem;">';
      html += '<div style="display:flex;align-items:flex-start;gap:.85rem;margin-bottom:.85rem;">';
      html += '<div style="font-size:1.65rem;flex-shrink:0;">' + s.icon + '</div>';
      html += '<div style="flex:1;min-width:0;">';
      html += '<div style="font-size:.92rem;font-weight:800;color:var(--ink);margin-bottom:.15rem;">' + s.title + '</div>';
      html += '<div style="font-size:.75rem;color:var(--ink-light);">' + s.org + ' · ' + s.country + ' · ' + s.size + ' · ' + s.duration + '</div>';
      html += '</div></div>';
      // Challenge / Action / Result
      html += '<div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:.75rem;margin-bottom:.85rem;">';
      html += '<div style="background:rgba(220,38,38,.04);border:1px solid rgba(220,38,38,.15);border-radius:9px;padding:.75rem .85rem;">';
      html += '<div style="font-size:.62rem;font-weight:800;text-transform:uppercase;letter-spacing:.1em;color:#DC2626;margin-bottom:.3rem;">Challenge</div>';
      html += '<div style="font-size:.78rem;color:var(--ink-mid);line-height:1.55;">' + s.challenge + '</div></div>';
      html += '<div style="background:rgba(217,119,6,.04);border:1px solid rgba(217,119,6,.15);border-radius:9px;padding:.75rem .85rem;">';
      html += '<div style="font-size:.62rem;font-weight:800;text-transform:uppercase;letter-spacing:.1em;color:#D97706;margin-bottom:.3rem;">Action</div>';
      html += '<div style="font-size:.78rem;color:var(--ink-mid);line-height:1.55;">' + s.action + '</div></div>';
      html += '<div style="background:rgba(5,150,105,.04);border:1px solid rgba(5,150,105,.15);border-radius:9px;padding:.75rem .85rem;">';
      html += '<div style="font-size:.62rem;font-weight:800;text-transform:uppercase;letter-spacing:.1em;color:#059669;margin-bottom:.3rem;">Result</div>';
      html += '<div style="font-size:.78rem;color:var(--ink-mid);line-height:1.55;">' + s.result + '</div></div>';
      html += '</div>';
      // Quote
      html += '<div style="background:rgba(200,153,58,.07);border:1px solid rgba(200,153,58,.2);border-radius:9px;padding:.8rem 1rem;">';
      html += '<p style="font-size:.82rem;color:var(--ink-mid);line-height:1.6;font-style:italic;">"' + s.quote + '"</p>';
      html += '</div></div>';
    });
    html += '</div>';
  }

  // Footer CTA
  html += '<div style="margin-top:2rem;background:linear-gradient(135deg,#3730a3,#6366f1);border-radius:16px;padding:1.75rem;display:flex;align-items:center;justify-content:space-between;gap:1.25rem;flex-wrap:wrap;">';
  html += '<div><div style="font-size:1rem;font-weight:800;color:white;margin-bottom:.25rem;">Ready to start improving?</div>';
  html += '<div style="font-size:.85rem;color:rgba(255,255,255,.75);">Open the full ' + cap.title + ' module to work through all sub-capabilities.</div></div>';
  html += '<button onclick="navHistory.push({pageId:\'cap-improve-page\',label:\'← Improve\',capId:null,subIdx:null});loadCapability(\'' + key + '\')" style="background:white;color:#3730a3;border:none;border-radius:10px;padding:.75rem 1.5rem;font-size:.88rem;font-weight:800;cursor:pointer;font-family:inherit;white-space:nowrap;">Open Full Module →</button>';
  html += '</div>';

  document.getElementById('capImprovePageInner').innerHTML = html;
}

function _renderImproveSection(label, color, bgColor, borderColor) {
  return '<div style="margin-bottom:1.75rem;">'
    + '<div style="display:flex;align-items:center;gap:.6rem;margin-bottom:1rem;">'
    + '<div style="width:8px;height:8px;border-radius:50%;background:' + color + ';flex-shrink:0;"></div>'
    + '<div style="font-size:.72rem;font-weight:800;text-transform:uppercase;letter-spacing:.12em;color:' + color + ';">' + label + '</div>'
    + '</div>';
}

function _renderWorkbookCard(key, wb, isPriority) {
  var border = isPriority ? 'rgba(220,38,38,.3)' : 'var(--border)';
  var bg     = isPriority ? 'rgba(220,38,38,.02)' : 'white';
  return '<div onclick="openSubCapability(\'' + key + '\',' + wb.idx + ')" '
    + 'style="background:' + bg + ';border:1.5px solid ' + border + ';border-radius:14px;padding:1.2rem 1.4rem;margin-bottom:.75rem;cursor:pointer;transition:all .2s;display:flex;align-items:flex-start;gap:1rem;" '
    + 'onmouseover="this.style.borderColor=\'var(--emerald)\';this.style.transform=\'translateY(-2px)\';this.style.boxShadow=\'0 6px 20px rgba(0,0,0,.07)\'" '
    + 'onmouseout="this.style.borderColor=\'' + border + '\';this.style.transform=\'\';this.style.boxShadow=\'\'">'
    + '<div style="width:38px;height:38px;min-width:38px;border-radius:10px;background:rgba(200,153,58,.1);border:1.5px solid rgba(200,153,58,.3);display:flex;align-items:center;justify-content:center;font-size:1rem;flex-shrink:0;">📒</div>'
    + '<div style="flex:1;min-width:0;">'
    + '<div style="font-size:.92rem;font-weight:700;color:var(--ink);margin-bottom:.2rem;">' + wb.title + ' Workbook</div>'
    + '<div style="font-size:.78rem;color:var(--ink-light);line-height:1.5;margin-bottom:.35rem;">' + (wb.intro ? wb.intro.substring(0, 120) + '…' : '') + '</div>'
    + '<span style="font-size:.67rem;font-weight:700;padding:.15rem .5rem;border-radius:20px;background:var(--cream);color:var(--ink-light);border:1px solid var(--border);">⏱ ' + wb.time + '</span>'
    + '</div>'
    + '<div style="color:var(--ink-pale);font-size:1.2rem;flex-shrink:0;margin-top:.1rem;">›</div>'
    + '</div>';
}

function _renderTemplateCard(tpl, capKey, isPriority) {
  // Register in _tplRegistry so openTemplateDetail and downloadTemplatePDF work
  var categoryMap = { strategy:'Strategy', programs:'Programs', leadership:'HR', team:'HR', systems:'Operations', funding:'Fundraising', comms:'Communications', finance:'Finance' };
  window._tplRegistry = window._tplRegistry || {};
  var cap = CAPABILITIES[capKey] || {};
  var tplKey = 'tt_' + tpl.name.replace(/[^a-zA-Z0-9]/g, '_');
  window._tplRegistry[tplKey] = {
    name: tpl.name, type: tpl.type, icon: tpl.icon || '📄',
    desc: tpl.desc || '', howTo: tpl.howTo || '',
    category: categoryMap[capKey] || 'Strategy',
    capId: capKey, capTitle: cap.title || ''
  };

  var tc = (_tplTypeColors || {})[tpl.type] || '#6b7280';
  var tb = (_tplTypeBg    || {})[tpl.type] || 'rgba(107,114,128,.08)';
  var borderCol = isPriority ? 'rgba(220,38,38,.25)' : 'var(--border)';

  return '<div style="background:white;border:1.5px solid ' + borderCol + ';border-radius:14px;overflow:hidden;margin-bottom:.75rem;transition:all .2s;" '
    + 'onmouseover="this.style.borderColor=\'var(--emerald)\';this.style.transform=\'translateY(-1px)\';this.style.boxShadow=\'0 4px 16px rgba(0,0,0,.06)\'" '
    + 'onmouseout="this.style.borderColor=\'' + borderCol + '\';this.style.transform=\'\';this.style.boxShadow=\'\'">'
    // colour accent top bar
    + '<div style="height:3px;background:' + tc + ';"></div>'
    + '<div style="padding:1.1rem 1.35rem;display:flex;align-items:center;gap:1rem;cursor:pointer;" onclick="openTemplateDetail(\'' + tplKey + '\')">'
    // icon
    + '<div style="width:46px;height:46px;min-width:46px;border-radius:12px;background:' + tb + ';border:1.5px solid ' + tc + '33;display:flex;align-items:center;justify-content:center;font-size:1.25rem;flex-shrink:0;">' + (tpl.icon || '📄') + '</div>'
    // text
    + '<div style="flex:1;min-width:0;">'
    + '<div style="font-size:.92rem;font-weight:800;color:var(--ink);margin-bottom:.2rem;">' + tpl.name + '</div>'
    + '<div style="font-size:.79rem;color:var(--ink-light);line-height:1.5;margin-bottom:.4rem;">' + (tpl.desc || '') + '</div>'
    + '<span style="font-size:.68rem;font-weight:800;padding:.2rem .55rem;border-radius:5px;background:' + tb + ';color:' + tc + ';border:1px solid ' + tc + '33;">' + tpl.type + '</span>'
    + '</div>'
    + '<div style="color:var(--ink-pale);font-size:1.2rem;flex-shrink:0;">›</div>'
    + '</div>'
    // action row — View narrower, PDF wider (matches T&T page proportions)
    + '<div style="padding:.6rem 1.35rem .9rem;display:flex;gap:.5rem;border-top:1px solid var(--border);">'
    + '<button onclick="event.stopPropagation();openTemplateDetail(\'' + tplKey + '\')" style="flex:2;background:var(--cream);color:var(--emerald-dark);border:1.5px solid var(--border);border-radius:9px;padding:.55rem .5rem;font-size:.8rem;font-weight:700;cursor:pointer;font-family:inherit;transition:all .18s;" onmouseover="this.style.background=\'var(--cream-dark)\'" onmouseout="this.style.background=\'var(--cream)\'">View</button>'
    + '<button onclick="event.stopPropagation();downloadTemplatePDF(\'' + tplKey + '\')" style="flex:3;background:#dc2626;color:white;border:none;border-radius:9px;padding:.55rem .5rem;font-size:.8rem;font-weight:700;cursor:pointer;font-family:inherit;transition:all .18s;" onmouseover="this.style.background=\'#b91c1c\'" onmouseout="this.style.background=\'#dc2626\'">PDF</button>'
    + '</div>'
    + '</div>';
}

// ═══════════════════════════════════════════════
// CAP LEARN MORE PAGE  (from card "Learn More" button)
// Mirrors the full capability page (renderCategoryPage) but
// launched from the grid card, with proper back-nav.
// ═══════════════════════════════════════════════
function showCapLearnMorePage(key) {
  var cap = CAPABILITIES[key];
  if (!cap) return;

  // detect originating page for back nav
  var categoriesActive     = document.getElementById('categories-page')     && document.getElementById('categories-page').classList.contains('active');
  var myLPActive           = document.getElementById('my-learning-path-page') && document.getElementById('my-learning-path-page').classList.contains('active');
  if (categoriesActive) {
    navHistory.push({ pageId: 'categories-page', label: '← All Capabilities', capId: null, subIdx: null });
  } else if (myLPActive) {
    navHistory.push({ pageId: 'my-learning-path-page', label: '← My Learning Path', capId: null, subIdx: null });
  } else {
    navHistory.push({ pageId: 'categories-page', label: '← All Capabilities', capId: null, subIdx: null });
  }

  document.querySelectorAll('.page').forEach(function(p) { p.classList.remove('active'); });
  document.getElementById('cap-learn-more-page').classList.add('active');
  document.getElementById('navBackBtn').style.display = 'flex';
  var backLabel = navHistory[navHistory.length - 1].label;
  document.getElementById('navBackLabel').textContent = backLabel;
  setFloatingBack(backLabel);

  renderCapLearnMorePage(key);
  window.scrollTo(0, 0);
}

function renderCapLearnMorePage(key) {
  var cap = CAPABILITIES[key];
  var cid  = cap.id;
  var subs = cap.subCapabilities || [];

  // compute completion
  var doneCnt = 0;
  subs.forEach(function(sub, i) {
    var sp = scProgress[cid + '_' + i] || {};
    if (sp.workbook && sp.video && sp.templates && sp.assessment) doneCnt++;
  });
  var pct = subs.length ? Math.round((doneCnt / subs.length) * 100) : 0;

  var html = '';

  // ── Breadcrumb ──
  html += '<div style="display:flex;align-items:center;gap:.4rem;font-size:.78rem;color:var(--ink-light);margin-bottom:1.25rem;flex-wrap:wrap;">';
  html += '<span onclick="showCategoriesPage()" style="color:var(--emerald);cursor:pointer;font-weight:600;">All Capabilities</span>';
  html += '<span style="opacity:.4;">›</span>';
  html += '<span style="color:var(--ink-mid);font-weight:600;">' + cap.title + '</span>';
  html += '</div>';

  // ── Hero banner (matches renderCategoryPage exactly) ──
  html += '<div style="background:linear-gradient(135deg,var(--emerald-dark),var(--emerald));border-radius:18px;padding:2.5rem 2rem;margin-bottom:2rem;color:white;">';
  html += '<div style="font-size:.72rem;font-weight:800;letter-spacing:.1em;text-transform:uppercase;opacity:.7;margin-bottom:.5rem;">' + cap.eyebrow + '</div>';
  html += '<div style="font-size:2rem;font-weight:900;font-family:\'Playfair Display\',serif;margin-bottom:.5rem;">' + cap.icon + ' ' + cap.title + '</div>';
  html += '<div style="font-size:.92rem;opacity:.85;line-height:1.6;max-width:600px;">' + cap.description + '</div>';
  html += '<div style="display:flex;gap:1rem;margin-top:1.25rem;flex-wrap:wrap;">';
  html += '<div style="background:rgba(255,255,255,.15);border-radius:10px;padding:.4rem .85rem;font-size:.78rem;font-weight:700;">&#128218; ' + subs.length + ' Capabilities</div>';
  html += '<div style="background:rgba(255,255,255,.15);border-radius:10px;padding:.4rem .85rem;font-size:.78rem;font-weight:700;">&#128211; Workbooks</div>';
  html += '<div style="background:rgba(255,255,255,.15);border-radius:10px;padding:.4rem .85rem;font-size:.78rem;font-weight:700;">&#127909; Videos</div>';
  html += '<div style="background:rgba(255,255,255,.15);border-radius:10px;padding:.4rem .85rem;font-size:.78rem;font-weight:700;">&#128196; Templates</div>';
  html += '</div>';
  html += '<div style="height:6px;background:rgba(255,255,255,.25);border-radius:3px;margin-top:1.25rem;overflow:hidden;">';
  html += '<div style="height:100%;background:white;border-radius:3px;width:' + pct + '%;transition:width .4s;"></div></div>';
  html += '<div style="font-size:.78rem;opacity:.75;margin-top:.4rem;">' + doneCnt + ' of ' + subs.length + ' capabilities completed</div>';
  html += '</div>';

  // ── About This Capability accordion ──
  if (cap.learnContent) {
    var lc = cap.learnContent;
    html += '<div style="background:white;border:1.5px solid var(--border);border-radius:16px;margin-bottom:1.5rem;overflow:hidden;">';
    html += '<div onclick="var body=this.nextElementSibling;var open=body.style.display!==\'none\';body.style.display=open?\'none\':\'block\';this.querySelector(\'.lm-chev\').style.transform=open?\'rotate(0deg)\':\'rotate(180deg)\'" style="display:flex;align-items:center;justify-content:space-between;padding:1.1rem 1.5rem;cursor:pointer;background:linear-gradient(90deg,rgba(26,107,74,0.05),transparent);">';
    html += '<div style="display:flex;align-items:center;gap:.75rem;">';
    html += '<div style="width:34px;height:34px;border-radius:9px;background:var(--emerald-glow);border:1.5px solid rgba(26,107,74,0.2);display:flex;align-items:center;justify-content:center;font-size:.95rem;">&#128218;</div>';
    html += '<div><div style="font-size:.92rem;font-weight:700;color:var(--emerald-dark);">About This Capability</div><div style="font-size:.74rem;color:var(--ink-light);margin-top:.1rem;">Why it matters · What you will learn · Who it is for</div></div>';
    html += '</div>';
    html += '<svg class="lm-chev" style="width:18px;height:18px;color:var(--ink-pale);transition:transform .3s;transform:rotate(180deg)" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M5.293 7.293a1 1 0 011.414 0L10 10.586l3.293-3.293a1 1 0 111.414 1.414l-4 4a1 1 0 01-1.414 0l-4-4a1 1 0 010-1.414z"/></svg>';
    html += '</div>';

    html += '<div style="display:block;border-top:1px solid var(--border);padding:1.5rem;">';
    // Why it matters
    html += '<div style="margin-bottom:1.25rem;">';
    html += '<div style="font-size:.68rem;font-weight:800;text-transform:uppercase;letter-spacing:.1em;color:var(--gold);margin-bottom:.5rem;">&#9888; Why It Matters</div>';
    html += '<p style="font-size:.88rem;color:var(--ink-mid);line-height:1.75;background:var(--cream);padding:.85rem 1rem;border-radius:10px;border-left:3px solid var(--gold);">' + lc.why + '</p>';
    html += '</div>';
    // What you will learn
    html += '<div style="margin-bottom:1.25rem;">';
    html += '<div style="font-size:.68rem;font-weight:800;text-transform:uppercase;letter-spacing:.1em;color:var(--emerald);margin-bottom:.6rem;">&#127891; What You Will Learn</div>';
    html += '<div style="display:flex;flex-direction:column;gap:.45rem;">';
    lc.whatYouLearn.forEach(function(item) {
      html += '<div style="display:flex;align-items:flex-start;gap:.7rem;font-size:.86rem;color:var(--ink-mid);line-height:1.55;">';
      html += '<div style="width:20px;height:20px;min-width:20px;border-radius:50%;background:var(--emerald-glow);border:1.5px solid var(--emerald);display:flex;align-items:center;justify-content:center;margin-top:1px;"><svg viewBox="0 0 20 20" fill="none" style="width:11px;height:11px;"><path d="M5 10l4 4 6-8" stroke="#1A6B4A" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round"/></svg></div>';
      html += '<span>' + item + '</span></div>';
    });
    html += '</div></div>';
    // Who + insight grid
    html += '<div style="display:grid;grid-template-columns:1fr 1fr;gap:1rem;">';
    html += '<div style="background:rgba(200,153,58,0.06);border:1px solid rgba(200,153,58,0.2);border-radius:10px;padding:1rem;">';
    html += '<div style="font-size:.68rem;font-weight:800;text-transform:uppercase;letter-spacing:.1em;color:var(--gold);margin-bottom:.4rem;">&#128101; Who Is This For</div>';
    html += '<p style="font-size:.83rem;color:var(--ink-mid);line-height:1.65;">' + lc.whoIsItFor + '</p>';
    html += '</div>';
    html += '<div style="background:rgba(26,107,74,0.05);border:1px solid rgba(26,107,74,0.15);border-radius:10px;padding:1rem;">';
    html += '<div style="font-size:.68rem;font-weight:800;text-transform:uppercase;letter-spacing:.1em;color:var(--emerald);margin-bottom:.4rem;">&#128161; Key Insight</div>';
    html += '<p style="font-size:.83rem;color:var(--ink-mid);line-height:1.65;font-style:italic;">' + lc.keyInsight + '</p>';
    html += '</div>';
    html += '</div>';
    html += '</div></div>';
  }

  // ── Sub-capabilities list (clickable → openSubCapability) ──
  html += '<div style="display:flex;flex-direction:column;gap:.75rem;">';
  subs.forEach(function(sub, i) {
    var sp   = scProgress[cid + '_' + i] || {};
    var isDone = sp.workbook && sp.video && sp.templates && sp.assessment;
    var completedCount = (sp.workbook?1:0)+(sp.video?1:0)+(sp.templates?1:0)+(sp.assessment?1:0)+((sp.lessons||[]).filter(Boolean).length>0?1:0);
    html += '<div onclick="openSubCapability(\'' + cid + '\',' + i + ')" style="background:white;border:1.5px solid ' + (isDone ? '#6ee7b7' : 'var(--border)') + ';border-radius:14px;padding:1.25rem 1.5rem;display:flex;align-items:center;gap:1.25rem;cursor:pointer;transition:all .2s;box-shadow:0 2px 8px rgba(15,74,50,.04);" onmouseover="this.style.borderColor=\'var(--emerald)\';this.style.transform=\'translateY(-1px)\'" onmouseout="this.style.borderColor=\'' + (isDone ? '#6ee7b7' : 'var(--border)') + '\';this.style.transform=\'none\'">';
    html += '<div style="width:42px;height:42px;border-radius:11px;background:' + (isDone ? '#d1fae5' : 'var(--emerald-glow)') + ';border:1.5px solid ' + (isDone ? '#6ee7b7' : 'var(--emerald)') + ';display:flex;align-items:center;justify-content:center;font-size:.85rem;font-weight:800;color:' + (isDone ? '#065f46' : 'var(--emerald)') + ';flex-shrink:0;">' + (isDone ? '&#10003;' : (i + 1)) + '</div>';
    html += '<div style="flex:1;min-width:0;">';
    html += '<div style="font-size:.95rem;font-weight:700;color:var(--ink);margin-bottom:.2rem;">' + sub.title + '</div>';
    if (sub.outcome) html += '<div style="font-size:.8rem;color:var(--ink-light);line-height:1.4;margin-bottom:.45rem;">' + sub.outcome.replace(/📦\s*/,'') + '</div>';
    html += '<div style="display:flex;gap:.4rem;flex-wrap:wrap;">';
    html += '<span style="font-size:.68rem;font-weight:700;padding:.18rem .5rem;border-radius:20px;background:var(--cream);color:var(--ink-light);border:1px solid var(--border);">&#9201; ' + (sub.time || '60 min') + '</span>';
    html += '<span style="font-size:.68rem;font-weight:700;padding:.18rem .5rem;border-radius:20px;background:var(--cream);color:var(--ink-light);border:1px solid var(--border);">&#128211; Workbook</span>';
    html += '<span style="font-size:.68rem;font-weight:700;padding:.18rem .5rem;border-radius:20px;background:var(--cream);color:var(--ink-light);border:1px solid var(--border);">&#127909; Video Guide</span>';
    html += '<span style="font-size:.68rem;font-weight:700;padding:.18rem .5rem;border-radius:20px;background:var(--cream);color:var(--ink-light);border:1px solid var(--border);">&#128241; Micro Lessons</span>';
    html += '<span style="font-size:.68rem;font-weight:700;padding:.18rem .5rem;border-radius:20px;background:var(--cream);color:var(--ink-light);border:1px solid var(--border);">&#128196; Templates</span>';
    html += '<span style="font-size:.68rem;font-weight:700;padding:.18rem .5rem;border-radius:20px;background:var(--cream);color:var(--ink-light);border:1px solid var(--border);">&#127919; Assessment</span>';
    if (completedCount > 0) html += '<span style="font-size:.68rem;font-weight:700;padding:.18rem .5rem;border-radius:20px;background:#d1fae5;color:#065f46;border:1px solid #6ee7b7;">' + completedCount + '/5 done</span>';
    html += '</div></div>';
    html += '<div style="color:var(--ink-pale);font-size:1.4rem;flex-shrink:0;">&#8250;</div>';
    html += '</div>';
  });
  html += '</div>';

  // ── Footer CTA ──
  html += '<div style="margin-top:2rem;background:linear-gradient(135deg,var(--emerald-dark),var(--emerald));border-radius:16px;padding:1.75rem;display:flex;align-items:center;justify-content:space-between;gap:1.25rem;flex-wrap:wrap;">';
  html += '<div><div style="font-size:1rem;font-weight:800;color:white;margin-bottom:.25rem;">Ready to dive in?</div>';
  html += '<div style="font-size:.85rem;color:rgba(255,255,255,.75);">Open the full ' + cap.title + ' module with workbooks, videos, and templates.</div></div>';
  html += '<button onclick="loadCapability(\'' + key + '\')" style="background:white;color:var(--emerald-dark);border:none;border-radius:10px;padding:.75rem 1.5rem;font-size:.88rem;font-weight:800;cursor:pointer;font-family:inherit;white-space:nowrap;">Open Full Module →</button>';
  html += '</div>';

  document.getElementById('capLearnMorePageInner').innerHTML = html;
}

function buildCapCard(key, isPriorityAssessed) {
  var cap   = CAPABILITIES[key];
  var score = assessScores[key] || 0;
  var pct   = getCapPct(key);
  var sc    = getScoreColor(score);
  var sb    = getScoreBg(score);
  var subs  = (cap.subCapabilities || []).length;
  var tpls  = (cap.templates || []).length;
  var hasAssessed = capMiniScores[key] && capMiniScores[key].length === 5;

  // Priority assessed cards get a red left-accent border and subtle red tint
  var borderStyle   = isPriorityAssessed ? '1.5px solid rgba(220,38,38,.35)' : '1.5px solid var(--border)';
  var hoverBorder   = isPriorityAssessed ? '#dc2626' : 'var(--emerald)';
  var hoverShadow   = isPriorityAssessed ? '0 8px 28px rgba(220,38,38,.14)' : '0 8px 28px rgba(26,107,74,.12)';
  var topBarColor   = isPriorityAssessed ? '#dc2626' : (score ? sc : 'var(--border)');
  var priorityBadge = isPriorityAssessed
    ? '<div style="display:flex;align-items:center;gap:.3rem;background:rgba(220,38,38,.1);border:1px solid rgba(220,38,38,.3);border-radius:20px;padding:.2rem .6rem;margin-bottom:.6rem;">'
      + '<div style="width:6px;height:6px;border-radius:50%;background:#dc2626;animation:pulse 1.5s ease-in-out infinite;"></div>'
      + '<span style="font-size:.65rem;font-weight:800;color:#dc2626;letter-spacing:.06em;">PRIORITY GAP — ACTION PLAN READY</span>'
      + '</div>'
    : '';

  return '<div onclick="loadCapability(\'' + key + '\')" style="background:white;border:' + borderStyle + ';border-radius:16px;overflow:hidden;display:flex;flex-direction:column;cursor:pointer;transition:all .2s;" '
    + 'onmouseover="this.style.borderColor=\'' + hoverBorder + '\';this.style.boxShadow=\'' + hoverShadow + '\';this.style.transform=\'translateY(-2px)\'" '
    + 'onmouseout="this.style.borderColor=\'' + (isPriorityAssessed ? 'rgba(220,38,38,.35)' : 'var(--border)') + '\';this.style.boxShadow=\'\';this.style.transform=\'\'">'
    // Colored top bar
    + '<div style="height:4px;background:' + topBarColor + ';transition:background .3s;"></div>'
    + '<div style="padding:1.35rem 1.35rem 1rem;flex:1;">'
    // Priority badge (only for assessed priority gaps)
    + priorityBadge
    // Header row
    + '<div style="display:flex;align-items:flex-start;justify-content:space-between;gap:.5rem;margin-bottom:.85rem;">'
    + '<div style="display:flex;align-items:center;gap:.65rem;">'
    + '<div style="width:46px;height:46px;min-width:46px;border-radius:12px;background:' + sb + ';border:1.5px solid ' + sc + '33;display:flex;align-items:center;justify-content:center;font-size:1.35rem;">' + cap.icon + '</div>'
    + '<div><div style="font-weight:800;font-size:.95rem;color:var(--ink);line-height:1.25;">' + cap.title + '</div>'
    + '<div style="font-size:.7rem;color:var(--ink-pale);margin-top:.15rem;">' + subs + ' sub-capabilities · ' + tpls + ' templates</div></div></div>'
    // Score badge
    + (hasAssessed ? '<div style="min-width:46px;text-align:center;"><div style="font-family:\'DM Mono\',monospace;font-size:1rem;font-weight:800;color:' + sc + ';">' + score + '/5</div><div style="font-size:.6rem;color:' + sc + ';font-weight:600;">' + getScoreLabel(score) + '</div></div>' : '')
    + '</div>'
    // Description
    + '<p style="font-size:.82rem;color:var(--ink-light);line-height:1.6;margin-bottom:.85rem;">' + (cap.description || '').substring(0, 120) + '…</p>'
    // Progress bar
    + '<div style="margin-bottom:.85rem;">'
    + '<div style="display:flex;justify-content:space-between;font-size:.65rem;color:var(--ink-pale);margin-bottom:.3rem;"><span>Module progress</span><span>' + pct + '%</span></div>'
    + '<div style="height:5px;background:var(--border);border-radius:3px;overflow:hidden;">'
    + '<div style="height:100%;background:' + (isPriorityAssessed ? '#dc2626' : 'var(--emerald)') + ';border-radius:3px;width:' + pct + '%;transition:width .5s;"></div></div>'
    + '</div>'
    + '</div>'
    // Footer with Assess + Learn + Improve buttons
    + '<div style="padding:.75rem 1.1rem 1rem;border-top:1px solid ' + (isPriorityAssessed ? 'rgba(220,38,38,.15)' : 'var(--border)') + ';">'
    + '<div onclick="event.stopPropagation();" style="display:flex;align-items:center;gap:.4rem;flex-wrap:wrap;">'
    // Assess button
    + '<button onclick="openCapAssessModal(\'' + key + '\')" style="display:inline-flex;align-items:center;gap:.3rem;padding:.38rem .75rem;border-radius:7px;font-size:.73rem;font-weight:700;cursor:pointer;font-family:inherit;transition:all .18s;background:' + (hasAssessed ? 'rgba(26,107,74,.08)' : 'linear-gradient(135deg,var(--emerald-dark),var(--emerald))') + ';color:' + (hasAssessed ? 'var(--emerald)' : 'white') + ';border:' + (hasAssessed ? '1.5px solid rgba(26,107,74,.25)' : 'none') + ';" onmouseover="this.style.opacity=\'.85\'" onmouseout="this.style.opacity=\'1\'">'
    + (hasAssessed ? 'Assessed' : 'Assess') + '</button>'
    // Learn button
    + '<button onclick="showCapLearnPage(\'' + key + '\')" style="display:inline-flex;align-items:center;gap:.3rem;padding:.38rem .75rem;border-radius:7px;font-size:.73rem;font-weight:700;cursor:pointer;font-family:inherit;transition:all .18s;background:' + (hasAssessed ? 'rgba(200,153,58,.1)' : 'white') + ';color:' + (hasAssessed ? 'var(--gold)' : 'var(--ink-light)') + ';border:1.5px solid ' + (hasAssessed ? 'rgba(200,153,58,.35)' : 'var(--border)') + ';" onmouseover="this.style.borderColor=\'var(--gold)\';this.style.color=\'var(--gold)\'" onmouseout="this.style.borderColor=\'' + (hasAssessed ? 'rgba(200,153,58,.35)' : 'var(--border)') + '\';this.style.color=\'' + (hasAssessed ? 'var(--gold)' : 'var(--ink-light)') + '\'">'
    + (hasAssessed ? 'Learn' : 'Learn') + '</button>'
    // Improve button
    + '<button onclick="showCapImprovePage(\'' + key + '\')" style="display:inline-flex;align-items:center;gap:.3rem;padding:.38rem .75rem;border-radius:7px;font-size:.73rem;font-weight:700;cursor:pointer;font-family:inherit;transition:all .18s;background:' + (isPriorityAssessed ? 'rgba(220,38,38,.08)' : (hasAssessed ? 'rgba(99,102,241,.1)' : 'white')) + ';color:' + (isPriorityAssessed ? '#dc2626' : (hasAssessed ? '#6366f1' : 'var(--ink-light)')) + ';border:1.5px solid ' + (isPriorityAssessed ? 'rgba(220,38,38,.3)' : (hasAssessed ? 'rgba(99,102,241,.3)' : 'var(--border)')) + ';" onmouseover="this.style.borderColor=\'' + (isPriorityAssessed ? '#dc2626' : '#6366f1') + '\';this.style.color=\'' + (isPriorityAssessed ? '#dc2626' : '#6366f1') + '\'" onmouseout="this.style.borderColor=\'' + (isPriorityAssessed ? 'rgba(220,38,38,.3)' : (hasAssessed ? 'rgba(99,102,241,.3)' : 'var(--border)')) + '\';this.style.color=\'' + (isPriorityAssessed ? '#dc2626' : (hasAssessed ? '#6366f1' : 'var(--ink-light)')) + '\'">'
    + (isPriorityAssessed ? 'Improve Now' : (hasAssessed ? 'Improve' : 'Improve')) + '</button>'
    + '<button onclick="showCapLearnMorePage(\'' + key + '\')" style="margin-left:auto;display:inline-flex;align-items:center;gap:.3rem;padding:.38rem .85rem;border-radius:7px;font-size:.73rem;font-weight:700;cursor:pointer;font-family:inherit;transition:all .18s;background:linear-gradient(135deg,var(--emerald-dark),var(--emerald));color:white;border:none;white-space:nowrap;flex-shrink:0;" onmouseover="this.style.opacity=\'.85\'" onmouseout="this.style.opacity=\'1\'">Learn More →</button>'
    + '</div>'
    + '</div></div>';
}

function populateNavCategoriesDropdown() {
  var container = document.getElementById('navCategoriesDropdown');
  if (!container || !window.CAPABILITIES) return;
  if (container.children.length > 0) return; // already populated
  container.innerHTML = Object.keys(CAPABILITIES).map(function(key) {
    var cap = CAPABILITIES[key];
    return '<a href="#" onclick="loadCapability(\'' + key + '\');closeAllDropdowns();return false;" '
      + 'style="display:flex;align-items:center;gap:.75rem;padding:.6rem .75rem;border-radius:8px;text-decoration:none;color:var(--ink);transition:background .15s;" '
      + 'onmouseover="this.style.background=\'var(--cream-dark)\'" onmouseout="this.style.background=\'transparent\'">'
      + '<span style="font-size:1.1rem;flex-shrink:0;">' + cap.icon + '</span>'
      + '<span style="font-size:.88rem;font-weight:600;color:var(--ink);">' + cap.title + '</span>'
      + '</a>';
  }).join('');
}

// Run after all scripts
window.addEventListener('load', populateNavCategoriesDropdown);
setTimeout(populateNavCategoriesDropdown, 0);


// ── SEARCH ENGINE ─────────────────────────────────────────────────────────────
function runSearch(query) {
  var input = document.getElementById('searchInput');
  if (input && query !== undefined) input.value = query;
  query = (query || (input ? input.value : '')).toLowerCase().trim();
  var results = document.getElementById('searchResults');
  if (!results) return;
  if (!query) { results.innerHTML = ''; return; }

  var hits = [];
  Object.keys(CAPABILITIES).forEach(function(key) {
    var cap = CAPABILITIES[key];
    // Match capability title/description
    if (cap.title.toLowerCase().indexOf(query) >= 0 || cap.description.toLowerCase().indexOf(query) >= 0) {
      hits.push({ type: 'capability', icon: cap.icon, title: cap.title, subtitle: cap.eyebrow + ' · ' + (cap.subCapabilities ? cap.subCapabilities.length : 5) + ' sub-capabilities', action: function(k) { return function() { loadCapability(k); }; }(key) });
    }
    // Match sub-capabilities
    (cap.subCapabilities || []).forEach(function(sub, i) {
      if ((sub.title || '').toLowerCase().indexOf(query) >= 0 || (sub.outcome || '').toLowerCase().indexOf(query) >= 0) {
        hits.push({ type: 'sub', icon: cap.icon, title: sub.title, subtitle: cap.title + ' · Sub-capability ' + (i+1), action: function(k,idx) { return function() { openSubCapability(k, idx); }; }(key, i) });
      }
    });
    // Match templates
    (cap.templates || []).forEach(function(t) {
      if ((t.name || '').toLowerCase().indexOf(query) >= 0) {
        hits.push({ type: 'template', icon: t.icon || '📄', title: t.name, subtitle: cap.title + ' · ' + t.type + ' Template', action: function(k) { return function() { loadCapability(k); }; }(key) });
      }
    });
  });

  if (!hits.length) {
    results.innerHTML = '<div style="text-align:center;padding:3rem;color:var(--ink-light);"><div style="font-size:2rem;margin-bottom:.75rem;">🔍</div><div style="font-size:.92rem;">No results for "' + query + '"</div><div style="font-size:.8rem;margin-top:.4rem;">Try different keywords like "strategy", "fundraising", or "budget"</div></div>';
    return;
  }

  var typeLabels = { capability: '📚 Capability', sub: '🎯 Sub-Capability', template: '📄 Template' };
  results.innerHTML = '<div style="font-size:.78rem;font-weight:600;color:var(--ink-light);margin-bottom:.75rem;">' + hits.length + ' result' + (hits.length>1?'s':'') + ' for "' + query + '"</div>'
    + hits.map(function(h) {
      return '<div style="background:white;border:1.5px solid var(--border);border-radius:12px;padding:1rem 1.25rem;display:flex;align-items:center;gap:1rem;cursor:pointer;transition:all .2s;" onmouseover="this.style.borderColor=\'var(--emerald)\';this.style.transform=\'translateX(3px)\'" onmouseout="this.style.borderColor=\'var(--border)\';this.style.transform=\'\'" onclick="(' + h.action + ')()">'
        + '<div style="font-size:1.3rem;">' + h.icon + '</div>'
        + '<div style="flex:1;">'
        + '<div style="font-size:.65rem;font-weight:700;letter-spacing:.08em;text-transform:uppercase;color:var(--gold);margin-bottom:.2rem;">' + (typeLabels[h.type] || h.type) + '</div>'
        + '<div style="font-size:.9rem;font-weight:700;color:var(--ink);">' + h.title + '</div>'
        + '<div style="font-size:.75rem;color:var(--ink-light);margin-top:.15rem;">' + h.subtitle + '</div>'
        + '</div>'
        + '<svg style="width:16px;height:16px;color:var(--ink-pale);" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M7.293 14.707a1 1 0 010-1.414L10.586 10 7.293 6.707a1 1 0 011.414-1.414l4 4a1 1 0 010 1.414l-4 4a1 1 0 01-1.414 0z"/></svg>'
        + '</div>';
    }).join('');
}

// ── DASHBOARD ─────────────────────────────────────────────────────────────────
// ── PLANS GRID ────────────────────────────────────────────────────────────────
function renderPlansGrid() {
  var grid = document.getElementById('plansGrid');
  if (!grid) return;
  var planData = Object.keys(CAPABILITIES).map(function(key) {
    var cap = CAPABILITIES[key];
    var tasks = (cap.subCapabilities || []).slice(0,3).map(function(sub) { return sub.title; });
    return { key: key, cap: cap, tasks: tasks };
  });
  grid.innerHTML = planData.map(function(p) {
    var pct = getCapPct(p.key);
    return '<div style="background:white;border:1.5px solid var(--border);border-radius:16px;padding:1.5rem;transition:all .2s;" onmouseover="this.style.borderColor=\'var(--emerald)\';this.style.boxShadow=\'0 8px 24px rgba(26,107,74,.1)\'" onmouseout="this.style.borderColor=\'var(--border)\';this.style.boxShadow=\'\'">'
      + '<div style="display:flex;align-items:center;gap:.6rem;margin-bottom:.75rem;">'
      + '<div style="font-size:1.5rem;">' + p.cap.icon + '</div>'
      + '<div><div style="font-weight:800;font-size:.95rem;color:var(--emerald-dark);">' + p.cap.title + '</div>'
      + '<div style="font-size:.72rem;color:var(--ink-light);">30-Day Plan</div></div></div>'
      + '<div style="font-size:.82rem;color:var(--ink-light);line-height:1.55;margin-bottom:1rem;">' + p.cap.description.substring(0,90) + '…</div>'
      + '<div style="display:flex;flex-direction:column;gap:.4rem;margin-bottom:1rem;">'
      + p.tasks.map(function(t,i) {
        return '<div style="display:flex;align-items:center;gap:.5rem;font-size:.78rem;color:var(--ink-light);">'
          + '<div style="width:16px;height:16px;border-radius:4px;border:1.5px solid var(--border);flex-shrink:0;"></div>'
          + 'Week ' + (i+1) + ': ' + t.substring(0,50) + (t.length>50?'…':'') + '</div>';
      }).join('')
      + '</div>'
      + '<button onclick="loadCapability(\'' + p.key + '\')" style="width:100%;background:linear-gradient(135deg,var(--emerald-dark),var(--emerald));color:white;border:none;border-radius:8px;padding:.6rem;font-size:.82rem;font-weight:700;cursor:pointer;font-family:inherit;">'
      + (pct > 0 ? 'Continue Plan' : 'Start 30-Day Plan') + '</button>'
      + '</div>';
  }).join('');
}

// ── AUTH HANDLERS (demo) ──────────────────────────────────────────────────────

function toggleMobileMenu() {
  var menu = document.getElementById('navCenter');
  if (menu) menu.classList.toggle('mobile-open');
}

// ── DROPDOWN MEGA NAV ─────────────────────────────────────────────────────────
function toggleDropdown(itemId) {
  var item = document.getElementById(itemId);
  if (!item) return;
  var wasOpen = item.classList.contains('open');
  closeAllDropdowns();
  if (!wasOpen) {
    item.classList.add('open');
    if (itemId === 'navCategoriesItem') populateNavCategoriesDropdown();
  }
}
function closeAllDropdowns() {
  document.querySelectorAll('.nav-item.open').forEach(function(el) { el.classList.remove('open'); });
}
document.addEventListener('click', function(e) {
  if (!e.target.closest('.nav-item')) closeAllDropdowns();
});

// ── AUTH MODAL ────────────────────────────────────────────────────────────────
function openSignInModal() {
  document.getElementById('authModal').classList.add('open');
  switchModalTab('signin');
}
function openSignUpModal() {
  document.getElementById('authModal').classList.add('open');
  switchModalTab('signup');
}
function closeAuthModal(e) {
  if (e.target === document.getElementById('authModal')) closeAuthModalDirect();
}
function closeAuthModalDirect() {
  document.getElementById('authModal').classList.remove('open');
}
function switchModalTab(tab) {
  document.getElementById('signinTab').classList.toggle('active', tab==='signin');
  document.getElementById('signupTab').classList.toggle('active', tab==='signup');
  document.getElementById('signinPanel').classList.toggle('active', tab==='signin');
  document.getElementById('signupPanel').classList.toggle('active', tab==='signup');
}

// Redirect old sign-in page functions to modal
function showSignIn() { openSignInModal(); }
function showSignUp() { openSignUpModal(); }

// ── AI ADVISOR ────────────────────────────────────────────────────────────────
var currentAIMode = 'general';
var aiModePrompts = {
  general: 'You are a helpful capacity-building advisor for NGOs and nonprofits in the Arab region. Give practical, actionable advice. Keep responses concise and structured.',
  onepager: 'You are helping an NGO create a compelling one-pager. Ask what their program/organization does and give structured feedback on messaging, clarity, and fundability.',
  mission: 'You are helping an NGO write or refine their mission statement. Ask about their work, beneficiaries, and intended change — then draft 2-3 mission statement options.',
  logic: 'You are helping an NGO build a Theory of Change / Logic Model. Ask about their inputs, activities, outputs, outcomes, and impact — then structure it clearly.',
  proposal: 'You are helping an NGO write a grant proposal. Ask about the program, target population, problem being solved, and funder — then help draft key sections.'
};
var aiConversationHistory = [];

function setAIMode(mode) {
  currentAIMode = mode;
  document.querySelectorAll('[id^="aiMode-"]').forEach(function(btn) {
    var isActive = btn.id === 'aiMode-' + mode;
    btn.style.background = isActive ? 'var(--emerald)' : 'white';
    btn.style.color = isActive ? 'white' : 'var(--ink-light)';
    btn.style.borderColor = isActive ? 'var(--emerald)' : 'var(--border)';
  });
  aiConversationHistory = [];
  var msgs = document.getElementById('aiChatMessages');
  var modeLabels = { general:'general questions', onepager:'reviewing one-pagers', mission:'mission statements', logic:'Theory of Change / Logic Models', proposal:'grant proposals' };
  msgs.innerHTML = '<div style="display:flex;gap:.75rem;align-items:flex-start;"><div style="width:30px;height:30px;border-radius:50%;background:var(--emerald-glow);border:1.5px solid var(--emerald);display:flex;align-items:center;justify-content:center;font-size:.8rem;flex-shrink:0;">🤖</div><div style="background:var(--cream);border:1px solid var(--border);border-radius:12px 12px 12px 3px;padding:.85rem 1rem;font-size:.88rem;color:var(--ink-mid);line-height:1.65;max-width:80%;">I\'m now in <strong>' + (modeLabels[mode]||mode) + '</strong> mode. How can I help you?</div></div>';
}

function sendAISuggestion(text) {
  var input = document.getElementById('aiInput');
  if (input) input.value = text;
  sendAIMessage();
}

function sendAIMessage() {
  var input = document.getElementById('aiInput');
  var text = (input ? input.value : '').trim();
  if (!text) return;
  if (input) input.value = '';

  var msgs = document.getElementById('aiChatMessages');
  // User bubble
  msgs.innerHTML += '<div style="display:flex;gap:.75rem;align-items:flex-start;justify-content:flex-end;">'
    + '<div style="background:linear-gradient(135deg,var(--emerald-dark),var(--emerald));color:white;border-radius:12px 12px 3px 12px;padding:.85rem 1rem;font-size:.88rem;line-height:1.65;max-width:80%;">' + escHtml(text) + '</div>'
    + '<div style="width:30px;height:30px;border-radius:50%;background:var(--gold-pale);border:1.5px solid var(--gold);display:flex;align-items:center;justify-content:center;font-size:.8rem;flex-shrink:0;">👤</div>'
    + '</div>';

  // Typing indicator
  var typingId = 'typing-' + Date.now();
  msgs.innerHTML += '<div id="' + typingId + '" style="display:flex;gap:.75rem;align-items:flex-start;">'
    + '<div style="width:30px;height:30px;border-radius:50%;background:var(--emerald-glow);border:1.5px solid var(--emerald);display:flex;align-items:center;justify-content:center;font-size:.8rem;flex-shrink:0;">🤖</div>'
    + '<div style="background:var(--cream);border:1px solid var(--border);border-radius:12px;padding:.85rem 1rem;font-size:.88rem;color:var(--ink-pale);">Thinking…</div></div>';
  msgs.scrollTop = msgs.scrollHeight;

  aiConversationHistory.push({ role: 'user', content: text });

  var systemPrompt = aiModePrompts[currentAIMode] || aiModePrompts.general;
  var messages = [{ role: 'user', content: '(system context) ' + systemPrompt + ' You are embedded in the ALJUDE Academy capacity-building platform for NGOs in the Arab region. Keep answers practical and under 300 words unless asked for more detail.' }].concat(
    aiConversationHistory.length > 1
      ? [{ role: 'assistant', content: 'Understood. I am ready to help.' }].concat(aiConversationHistory.slice(0, -1))
      : []
  ).concat([{ role: 'user', content: text }]);

  fetch('https://api.groq.com/openai/v1/chat/completions', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': 'Bearer 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'
    },
    body: JSON.stringify({
      model: 'llama-3.3-70b-versatile',
      max_tokens: 1000,
      messages: [
        { role: 'system', content: systemPrompt + ' You are the ALJUDE Academy AI Advisor — a specialist in NGO capacity building for organizations in the Arab region. Be practical, warm, and concise (under 300 words unless asked for more).' }
      ].concat(aiConversationHistory)
    })
  })
  .then(function(r) { return r.json(); })
  .then(function(data) {
    var reply = (data.choices && data.choices[0] && data.choices[0].message && data.choices[0].message.content)
      ? data.choices[0].message.content
      : (data.error ? 'Error: ' + data.error.message : 'I couldn\'t process that. Please try again.');
    aiConversationHistory.push({ role: 'assistant', content: reply });
    var typingEl = document.getElementById(typingId);
    if (typingEl) typingEl.outerHTML = '<div style="display:flex;gap:.75rem;align-items:flex-start;">'
      + '<div style="width:30px;height:30px;border-radius:50%;background:var(--emerald-glow);border:1.5px solid var(--emerald);display:flex;align-items:center;justify-content:center;font-size:.8rem;flex-shrink:0;">🤖</div>'
      + '<div style="background:var(--cream);border:1px solid var(--border);border-radius:12px 12px 12px 3px;padding:.85rem 1rem;font-size:.88rem;color:var(--ink-mid);line-height:1.7;max-width:80%;">' + reply.replace(/\n\n/g,'<br><br>').replace(/\n/g,'<br>').replace(/\*\*(.*?)\*\*/g,'<strong>$1</strong>').replace(/\*(.*?)\*/g,'<em>$1</em>') + '</div></div>';
    msgs.scrollTop = msgs.scrollHeight;
  })
  .catch(function(err) {
    var typingEl = document.getElementById(typingId);
    if (typingEl) typingEl.outerHTML = '<div style="display:flex;gap:.75rem;align-items:flex-start;">'
      + '<div style="width:30px;height:30px;border-radius:50%;background:var(--emerald-glow);border:1.5px solid var(--emerald);display:flex;align-items:center;justify-content:center;font-size:.8rem;flex-shrink:0;">🤖</div>'
      + '<div style="background:#fef2f2;border:1px solid #fca5a5;border-radius:12px 12px 12px 3px;padding:.85rem 1rem;font-size:.88rem;color:#991b1b;line-height:1.65;max-width:80%;">Connection error. Please check your internet and try again.</div></div>';
    msgs.scrollTop = msgs.scrollHeight;
  });
}

function clearAIChat() {
  aiConversationHistory = [];
  document.getElementById('aiChatMessages').innerHTML = '<div style="display:flex;gap:.75rem;align-items:flex-start;"><div style="width:30px;height:30px;border-radius:50%;background:var(--emerald-glow);border:1.5px solid var(--emerald);display:flex;align-items:center;justify-content:center;font-size:.8rem;flex-shrink:0;">🤖</div><div style="background:var(--cream);border:1px solid var(--border);border-radius:12px 12px 12px 3px;padding:.85rem 1rem;font-size:.88rem;color:var(--ink-mid);line-height:1.65;max-width:80%;">Chat cleared. How can I help you?</div></div>';
}

