      + '<div><div style="font-size:.68rem;font-weight:700;letter-spacing:.1em;text-transform:uppercase;color:rgba(255,255,255,.75);">' + phase.label + '</div>'
      + '<div style="font-size:1.1rem;font-weight:800;color:white;">' + phase.title + '</div></div>'
      + '<div style="margin-left:auto;background:rgba(255,255,255,.2);border-radius:8px;padding:.3rem .7rem;font-size:.78rem;font-weight:700;color:white;">' + phase.milestones.length + ' milestones</div>'
      + '</div>'
