        return '<div style="display:flex;align-items:center;gap:1rem;padding:1rem 1.25rem;background:var(--cream);border:1px solid var(--border);border-radius:12px;cursor:pointer;transition:all .2s;" onclick="' + m.action + '" onmouseover="this.style.borderColor=\'var(--emerald)\';this.style.background=\'white\'" onmouseout="this.style.borderColor=\'var(--border)\';this.style.background=\'var(--cream)\'">'
          + '<div style="font-size:1.4rem;flex-shrink:0;">' + m.icon + '</div>'
          + '<div style="flex:1;"><div style="font-weight:700;font-size:.92rem;color:var(--ink);">' + m.title + '</div><div style="font-size:.78rem;color:var(--ink-light);margin-top:.15rem;">' + m.desc + '</div></div>'
          + '<div style="font-size:.8rem;font-weight:700;color:var(--emerald);white-space:nowrap;">' + m.cta + '</div>'
          + '</div>';
