// ── WEEKLY CHECKLIST ──────────────────────────────────────────────────────────
var currentPhase = 1;
var checklistDone = {};
var WEEKLY_TASKS = {
  1: [
    { icon:'📊', title:'Take the Organizational Assessment', desc:'Score your NGO across all 8 capability areas to find your gaps', action:'showAssessmentPage()' },
    { icon:'📄', title:'Read your Strategy capability overview', desc:'Understand what strategic planning means for your NGO stage', action:"loadCapability('strategy')" },
    { icon:'🎯', title:'Write your 3 biggest organizational challenges', desc:'Be specific — this becomes your learning plan', action:'showAIAdvisor()' },
    { icon:'🤝', title:'Share the platform with one team member', desc:'Capacity building works better as a team activity', action:'showTeamPage()' },
    { icon:'📅', title:'Book 30 min weekly for learning', desc:'Block time in your calendar — consistency beats intensity', action:'showPlansPage()' },
  ],
  2: [
    { icon:'⚙️', title:'Map one core organizational process', desc:'Document how a key workflow currently works end-to-end', action:"loadCapability('systems')" },
    { icon:'💰', title:'Review your last 3 months of financial reports', desc:'Identify the biggest gap vs. best-practice controls', action:"loadCapability('finance')" },
    { icon:'👥', title:'Rate your leadership team alignment', desc:'Use the Leadership assessment to find your score', action:"loadCapability('leadership')" },
    { icon:'📋', title:'Create or update your HR policy document', desc:'Even a 2-page version is better than none', action:"loadCapability('team')" },
    { icon:'📊', title:'Compare progress to your Phase 1 baseline', desc:'What has changed since you started? What has not?', action:'showDashboard()' },
  ],
  3: [
    { icon:'📣', title:'Audit your communications materials', desc:'Website, one-pager, social media — are they consistent?', action:"loadCapability('comms')" },
    { icon:'🎯', title:'Define your Q4 organizational priorities', desc:'3 goals, 3 owners, 3 deadlines', action:"loadCapability('strategy')" },
    { icon:'🤖', title:'Ask the AI Advisor about your top challenge', desc:'Get instant personalized guidance on your current priority', action:'showAIAdvisor()' },
    { icon:'📥', title:'Download and use one template this week', desc:'Move from learning to doing with a ready-made tool', action:'showPage(\'templates-page\',\'Back to Home\');renderTemplatesPage()' },
    { icon:'🔄', title:'Re-take the full assessment', desc:'See your before vs. after scores across all 8 capabilities', action:'showAssessmentPage()' },
  ]
};

function selectPhase(phase) {
  currentPhase = phase;
  checklistDone = {};
  [1,2,3].forEach(function(p) {
    var btn = document.getElementById('phaseBtn'+p);
    if (!btn) return;
    var isActive = p === phase;
    btn.style.background = isActive ? 'var(--emerald)' : 'white';
    btn.style.color = isActive ? 'white' : 'var(--ink-light)';
    btn.style.borderColor = isActive ? 'var(--emerald)' : 'var(--border)';
  });
  renderWeeklyTasks();
}

function renderWeeklyTasks() {
  var container = document.getElementById('weeklyTasks');
  if (!container) return;
  var tasks = WEEKLY_TASKS[currentPhase] || [];
  container.innerHTML = tasks.map(function(task, i) {
    var isDone = checklistDone[i];
    return '<div id="checkTask-' + i + '" style="background:white;border:1.5px solid ' + (isDone?'var(--emerald)':'var(--border)') + ';border-radius:14px;padding:1rem 1.25rem;display:flex;align-items:center;gap:1rem;transition:all .2s;" onmouseover="this.style.boxShadow=\'0 4px 16px rgba(26,107,74,.08)\'" onmouseout="this.style.boxShadow=\'\'">'
      + '<div onclick="toggleChecklistTask(' + i + ')" style="width:26px;height:26px;min-width:26px;border-radius:6px;border:2px solid ' + (isDone?'var(--emerald)':'var(--border-dark)') + ';background:' + (isDone?'var(--emerald)':'white') + ';display:flex;align-items:center;justify-content:center;cursor:pointer;flex-shrink:0;transition:all .2s;">'
      + (isDone ? '<svg viewBox="0 0 20 20" fill="white" style="width:14px;height:14px;"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>' : '') + '</div>'
      + '<div style="font-size:1.2rem;">' + task.icon + '</div>'
      + '<div style="flex:1;">'
      + '<div style="font-size:.92rem;font-weight:700;color:var(--ink);' + (isDone?'text-decoration:line-through;opacity:.6;':'') + '">' + task.title + '</div>'
      + '<div style="font-size:.78rem;color:var(--ink-light);margin-top:.15rem;">' + task.desc + '</div>'
      + '</div>'
      + '<button onclick="' + task.action + '" style="background:var(--emerald-glow);border:1px solid rgba(26,107,74,.2);color:var(--emerald);border-radius:8px;padding:.4rem .8rem;font-size:.75rem;font-weight:700;cursor:pointer;font-family:inherit;white-space:nowrap;">Go →</button>'
      + '</div>';
  }).join('');
  updateChecklistProgress();
}

function toggleChecklistTask(i) {
  checklistDone[i] = !checklistDone[i];
  renderWeeklyTasks();
}

function updateChecklistProgress() {
  var tasks = WEEKLY_TASKS[currentPhase] || [];
  var done = Object.values(checklistDone).filter(Boolean).length;
  var pct = tasks.length ? Math.round((done/tasks.length)*100) : 0;
  var prog = document.getElementById('checklistProgress');
  var bar = document.getElementById('checklistBar');
  if (prog) prog.textContent = done + ' / ' + tasks.length + ' done';
  if (bar) bar.style.width = pct + '%';
}

function showWeeklyChecklist() {
  showPage('checklist-page', 'Back to Home');
  renderWeeklyTasks();
}

// ── TEMPLATES PAGE ────────────────────────────────────────────────────────────
var templateFilters = ['All', 'Strategy', 'Programs', 'Finance', 'Fundraising', 'HR', 'Communications'];
var currentTemplateFilter = 'All';

function renderTemplatesPage() {
  // Filter buttons
  var filterContainer = document.getElementById('templateFilterBtns');
  if (filterContainer) {
    filterContainer.innerHTML = templateFilters.map(function(f) {
      var isActive = f === currentTemplateFilter;
      return '<button onclick="filterTemplates(\'' + f + '\')" id="tplFilter-' + f + '" style="padding:.45rem 1rem;border-radius:20px;font-size:.8rem;font-weight:700;cursor:pointer;font-family:inherit;border:1.5px solid ' + (isActive?'var(--emerald)':'var(--border)') + ';background:' + (isActive?'var(--emerald)':'white') + ';color:' + (isActive?'white':'var(--ink-light)') + ';transition:all .18s;">' + f + '</button>';
    }).join('');
  }

  // Collect all templates from CAPABILITIES
  var allTemplates = [];
  var categoryMap = { strategy:'Strategy', programs:'Programs', leadership:'HR', team:'HR', systems:'Strategy', funding:'Fundraising', comms:'Communications', finance:'Finance' };
  Object.keys(CAPABILITIES).forEach(function(key) {
    var cap = CAPABILITIES[key];
    var cat = categoryMap[key] || 'Strategy';
    (cap.templates || []).forEach(function(t) {
      allTemplates.push({ name: t.name, type: t.type, icon: t.icon||'📄', desc: t.desc||'', category: cat, capId: key, capTitle: cap.title });
    });
  });

  var filtered = currentTemplateFilter === 'All' ? allTemplates : allTemplates.filter(function(t) { return t.category === currentTemplateFilter; });
  var grid = document.getElementById('templatesPageGrid');
  if (!grid) return;
  if (!filtered.length) { grid.innerHTML = '<div style="text-align:center;padding:3rem;color:var(--ink-light);">No templates in this category yet.</div>'; return; }
  grid.innerHTML = filtered.map(function(t) {
    var tplKey = 'page_' + t.name.replace(/\s+/g,'_');
    window._tplRegistry = window._tplRegistry || {};
    window._tplRegistry[tplKey] = { name: t.name, type: t.type, icon: t.icon, capTitle: t.capTitle, subTitle: t.name };
    return '<div class="tpl-card" style="background:white;border:1.5px solid var(--border);border-radius:16px;padding:1.5rem;transition:all .2s;" onmouseover="this.style.borderColor=\'var(--emerald)\';this.style.boxShadow=\'0 6px 20px rgba(26,107,74,.1)\'" onmouseout="this.style.borderColor=\'var(--border)\';this.style.boxShadow=\'\'">'
      + '<div style="display:flex;align-items:center;gap:.85rem;margin-bottom:.85rem;">'
      + '<div style="width:42px;height:42px;border-radius:11px;background:var(--emerald-glow);display:flex;align-items:center;justify-content:center;font-size:1.2rem;">' + t.icon + '</div>'
      + '<div><div style="font-weight:800;font-size:.92rem;color:var(--ink);">' + t.name + '</div>'
      + '<div style="font-size:.72rem;color:var(--ink-pale);margin-top:.1rem;">' + t.type + ' · ' + t.capTitle + '</div></div></div>'
      + '<div style="font-size:.82rem;color:var(--ink-light);line-height:1.55;margin-bottom:1rem;">' + (t.desc||'A ready-to-use template for your organization.').substring(0,100) + '…</div>'
      + '<div style="display:flex;gap:.5rem;flex-wrap:wrap;align-items:center;">'
      + '<button onclick="dlFromRegistry(\'' + tplKey + '\')" style="flex:1;min-width:100px;background:var(--emerald);color:white;border:none;border-radius:8px;padding:.55rem;font-size:.8rem;font-weight:700;cursor:pointer;font-family:inherit;">Download ' + t.type + '</button>'
      + renderSaveBtn({ id:'page_tpl_'+tplKey, type:'template', icon:t.icon, title:t.name, subtitle:t.capTitle, capId:t.capId })
      + '<button onclick="loadCapability(\'' + t.capId + '\')" style="background:var(--cream-dark);border:1px solid var(--border);color:var(--ink-mid);border-radius:8px;padding:.55rem .85rem;font-size:.8rem;font-weight:600;cursor:pointer;font-family:inherit;">View Module</button>'
      + '</div></div>';
  }).join('');
}

function filterTemplates(filter) {
  currentTemplateFilter = filter;
  renderTemplatesPage();
}



// ── FULL ASSESSMENT PAGE ──────────────────────────────────────────────────────
// ── ASSESSMENT ENGINE ─────────────────────────────────────────────────────────
var assessScores = {};
var assessCurrentIdx = 0;
var assessKeys = [];

var ASSESS_QUESTIONS = {
  strategy:   { q: 'How would you rate your NGO\'s strategic planning?',   hints: ['No written strategy','Have a basic mission statement','Have a multi-year plan','Strategy guides decisions','Full strategy with KPIs & reviews'] },
  programs:   { q: 'How well-designed and documented are your programs?',   hints: ['Programs are informal','Some program docs exist','Programs have clear goals','ToC & M&E in place','Rigorous design & learning system'] },
  leadership: { q: 'How strong is your leadership and governance?',         hints: ['Leadership is ad hoc','Some leadership structures','Board & ED roles defined','Strong governance practices','Exemplary leadership & succession plan'] },
  team:       { q: 'How effective is your team and HR system?',             hints: ['No HR policies','Basic job descriptions exist','Recruitment & appraisal in place','Strong team culture & retention','Best-practice HR & volunteer system'] },
  systems:    { q: 'How organized are your operations and systems?',        hints: ['Everything is informal','Some processes documented','Key workflows are standardized','Digital tools & data management','Fully systematized operations'] },
  funding:    { q: 'How developed is your fundraising strategy?',           hints: ['Reactive fundraising only','1–2 funding sources','Diversified funding plan','Strong pipeline & donor relations','Fully diversified & sustainable funding'] },
  comms:      { q: 'How strong is your communications and brand?',          hints: ['No consistent messaging','Basic website/social present','Brand guide & content plan','Strong storytelling & visibility','Award-winning communications'] },
  finance:    { q: 'How sound are your financial management practices?',    hints: ['No formal financial controls','Basic bookkeeping','Budget & monthly reports','Strong controls & audit-ready','Best-practice financial governance'] }
};

function showAssessmentPage() {
  showPage('assessment-page', 'Back to Home');
  assessKeys = Object.keys(CAPABILITIES);
  assessCurrentIdx = 0;
  assessScores = {};
  document.getElementById('assessResults').style.display = 'none';
  document.getElementById('assessProgress').style.display = 'block';
  renderAssessQuestion();
}

function renderAssessQuestion() {
  var key = assessKeys[assessCurrentIdx];
  var cap = CAPABILITIES[key];
  var q = ASSESS_QUESTIONS[key] || { q: 'How would you rate your ' + cap.title + ' capability?', hints: ['Not started','Early stage','Developing','Established','Strong'] };
  var pct = ((assessCurrentIdx) / assessKeys.length) * 100;

  document.getElementById('assessCurrentQ').textContent = assessCurrentIdx + 1;
  document.getElementById('assessCapLabel').textContent = cap.icon + ' ' + cap.title;
  document.getElementById('assessProgressBar').style.width = pct + '%';

  var isLast = assessCurrentIdx === assessKeys.length - 1;

  var card = document.getElementById('assessQuestionCard');
  card.innerHTML = '<div style="background:white;border:1.5px solid var(--border);border-radius:20px;padding:2rem;animation:fadeIn .3s ease;">'
    + '<div style="font-size:2.5rem;margin-bottom:1rem;">' + cap.icon + '</div>'
    + '<div style="font-family:\'DM Mono\',monospace;font-size:.65rem;font-weight:600;letter-spacing:.12em;text-transform:uppercase;color:var(--gold);margin-bottom:.5rem;">' + cap.title + '</div>'
    + '<div style="font-size:1.1rem;font-weight:700;color:var(--ink);line-height:1.4;margin-bottom:1.75rem;">' + q.q + '</div>'
    + '<div style="display:flex;flex-direction:column;gap:.6rem;">'
    + [1,2,3,4,5].map(function(score) {
        var hint = q.hints[score-1] || '';
        var isSelected = assessScores[key] === score;
        return '<button onclick="selectAssessScore(\'' + key + '\',' + score + ')" id="assessBtn_' + key + '_' + score + '" '
          + 'style="display:flex;align-items:center;gap:1rem;padding:.85rem 1.1rem;border-radius:12px;border:1.5px solid ' + (isSelected ? 'var(--emerald)' : 'var(--border)') + ';background:' + (isSelected ? 'var(--emerald-glow)' : 'white') + ';cursor:pointer;font-family:inherit;text-align:left;transition:all .15s;width:100%;" '
          + 'onmouseover="if(!this.classList.contains(\'selected\')){this.style.borderColor=\'var(--emerald)\';this.style.background=\'var(--cream-dark)\'}" '
          + 'onmouseout="if(!this.classList.contains(\'selected\')){this.style.borderColor=\'var(--border)\';this.style.background=\'white\'}">'
          + '<div style="width:28px;height:28px;min-width:28px;border-radius:50%;background:' + (isSelected ? 'var(--emerald)' : 'var(--border)') + ';display:flex;align-items:center;justify-content:center;font-family:\'DM Mono\',monospace;font-size:.75rem;font-weight:700;color:' + (isSelected ? 'white' : 'var(--ink-light)') + ';transition:all .15s;">' + score + '</div>'
          + '<div>'
          + '<div style="font-size:.9rem;font-weight:700;color:var(--ink);">' + getScoreLabel(score) + '</div>'
          + '<div style="font-size:.78rem;color:var(--ink-light);margin-top:.1rem;">' + hint + '</div>'
          + '</div>'
          + (isSelected ? '<div style="margin-left:auto;color:var(--emerald);font-size:1rem;">✓</div>' : '')
          + '</button>';
      }).join('')
    + '</div>'
    // Navigation row — Back always visible, Next button always present
    + '<div style="display:flex;gap:.75rem;margin-top:1.5rem;">'
    + '<button onclick="assessBack()" style="padding:.75rem 1.5rem;border-radius:10px;border:1.5px solid var(--border);background:white;color:' + (assessCurrentIdx > 0 ? 'var(--ink-light)' : 'var(--border)') + ';font-size:.88rem;font-weight:600;cursor:' + (assessCurrentIdx > 0 ? 'pointer' : 'default') + ';font-family:inherit;pointer-events:' + (assessCurrentIdx > 0 ? 'auto' : 'none') + ';">← Back</button>'
    + '<button onclick="assessNext()" id="assessNextBtn" style="flex:1;padding:.85rem;border-radius:10px;border:none;background:' + (assessScores[key] ? 'linear-gradient(135deg,var(--emerald-dark),var(--emerald))' : 'var(--border)') + ';color:' + (assessScores[key] ? 'white' : 'var(--ink-pale)') + ';font-size:.92rem;font-weight:700;cursor:' + (assessScores[key] ? 'pointer' : 'default') + ';font-family:inherit;transition:all .2s;">' + (isLast ? 'See My Results →' : 'Next →') + '</button>'
    + '</div>'
    + '</div>';
}

function getScoreLabel(score) {
  return {1:'Not started',2:'Early stage',3:'Developing',4:'Established',5:'Strong'}[score];
}

function selectAssessScore(key, score) {
  assessScores[key] = score;
  updateCapStatsBar();
  renderAssessQuestion();
  // Auto-advance after a short pause so user sees the selection highlight
  var isLast = assessCurrentIdx === assessKeys.length - 1;
  clearTimeout(window._assessAutoTimer);
  window._assessAutoTimer = setTimeout(function() {
    if (isLast) {
      showAssessResults();
    } else {
      assessCurrentIdx++;
      renderAssessQuestion();
    }
  }, 420);
}

function assessBack() {
  if (assessCurrentIdx > 0) {
    clearTimeout(window._assessAutoTimer);
    assessCurrentIdx--;
    renderAssessQuestion();
  }
}

function assessNext() {
  var key = assessKeys[assessCurrentIdx];
  if (!assessScores[key]) { showToast('Please select a rating to continue'); return; }
  clearTimeout(window._assessAutoTimer);
  assessCurrentIdx++;
  if (assessCurrentIdx >= assessKeys.length) {
    showAssessResults();
  } else {
    renderAssessQuestion();
  }
}

function showAssessResults() {
  document.getElementById('assessProgress').style.display = 'none';
  document.getElementById('assessQuestionCard').innerHTML = '';
  var results = document.getElementById('assessResults');
  results.style.display = 'block';
  _saveUserData(); // persist assessment scores

  var capKeys = Object.keys(CAPABILITIES);
  var sorted = capKeys.slice().sort(function(a,b) { return assessScores[a] - assessScores[b]; });
  var total = capKeys.reduce(function(s,k){ return s + (assessScores[k]||0); }, 0);
  var overall = Math.round((total / (capKeys.length * 5)) * 100);
  var overallColor = overall >= 70 ? '#16a34a' : overall >= 40 ? '#d97706' : '#dc2626';
  var overallLabel = overall >= 70 ? 'Strong Foundation' : overall >= 40 ? 'Developing' : 'Needs Focus';

  results.innerHTML = '<div style="animation:fadeIn .4s ease;">'
    // Score hero
    + '<div style="background:linear-gradient(135deg,var(--emerald-dark),var(--emerald));border-radius:20px;padding:2rem;text-align:center;margin-bottom:1.5rem;">'
    + '<div style="font-size:.8rem;font-weight:700;color:rgba(255,255,255,.7);margin-bottom:.5rem;letter-spacing:.08em;text-transform:uppercase;">Your Overall Capacity Score</div>'
    + '<div style="font-family:\'Cormorant Garamond\',serif;font-size:5rem;font-weight:700;color:white;line-height:1;">' + overall + '%</div>'
    + '<div style="font-size:.92rem;font-weight:700;color:rgba(255,255,255,.85);margin-top:.35rem;">' + overallLabel + '</div>'
    + '</div>'

    // Breakdown bars
    + '<div style="background:white;border:1.5px solid var(--border);border-radius:16px;padding:1.5rem;margin-bottom:1.25rem;">'
    + '<div style="font-weight:800;font-size:.95rem;color:var(--ink);margin-bottom:1.1rem;">📊 Capability Breakdown</div>'
    + '<div style="display:flex;flex-direction:column;gap:.8rem;">'
    + capKeys.map(function(key) {
        var s = assessScores[key] || 0;
        var pct = (s / 5) * 100;
        var color = s <= 1 ? '#dc2626' : s <= 2 ? '#f59e0b' : s <= 3 ? '#3b82f6' : '#16a34a';
        return '<div>'
          + '<div style="display:flex;justify-content:space-between;margin-bottom:.3rem;">'
          + '<span style="font-size:.82rem;font-weight:600;color:var(--ink);">' + CAPABILITIES[key].icon + '  ' + CAPABILITIES[key].title + '</span>'
          + '<span style="font-family:\'DM Mono\',monospace;font-size:.75rem;font-weight:700;color:' + color + ';">' + s + '/5 · ' + getScoreLabel(s) + '</span>'
          + '</div>'
          + '<div style="height:7px;background:var(--border);border-radius:4px;overflow:hidden;">'
          + '<div style="height:100%;background:' + color + ';border-radius:4px;width:' + pct + '%;transition:width .7s ease;"></div>'
          + '</div></div>';
      }).join('')
    + '</div></div>'

    // Top priorities
    + '<div style="background:white;border:1.5px solid var(--border);border-radius:16px;padding:1.5rem;margin-bottom:1.25rem;">'
    + '<div style="font-weight:800;font-size:.95rem;color:var(--ink);margin-bottom:.25rem;">🎯 Your Top 3 Priority Areas</div>'
    + '<div style="font-size:.8rem;color:var(--ink-light);margin-bottom:1rem;">Start with these — they\'ll have the biggest impact.</div>'
    + '<div style="display:flex;flex-direction:column;gap:.6rem;">'
    + sorted.slice(0,3).map(function(key, i) {
        var s = assessScores[key];
        var accents = ['#dc2626','#f59e0b','#3b82f6'];
        return '<div onclick="loadCapability(\'' + key + '\')" style="display:flex;align-items:center;gap:1rem;padding:1rem 1.1rem;border:1.5px solid var(--border);border-radius:12px;cursor:pointer;transition:all .18s;" onmouseover="this.style.borderColor=\'' + accents[i] + '\';this.style.transform=\'translateX(4px)\'" onmouseout="this.style.borderColor=\'var(--border)\';this.style.transform=\'\'">'
          + '<div style="width:30px;height:30px;min-width:30px;border-radius:8px;background:' + accents[i] + ';display:flex;align-items:center;justify-content:center;font-weight:800;font-size:.85rem;color:white;">' + (i+1) + '</div>'
          + '<div style="flex:1;">'
          + '<div style="font-weight:700;font-size:.92rem;color:var(--ink);">' + CAPABILITIES[key].icon + ' ' + CAPABILITIES[key].title + '</div>'
          + '<div style="font-size:.75rem;color:var(--ink-light);margin-top:.1rem;">Current score: ' + s + '/5 · ' + getScoreLabel(s) + '</div>'
          + '</div>'
          + '<div style="font-size:.8rem;font-weight:700;color:var(--emerald);">Start →</div>'
          + '</div>';
      }).join('')
    + '</div></div>'

    // Action buttons
    + '<div style="display:flex;gap:.75rem;flex-wrap:wrap;">'
    + '<button onclick="loadCapability(\'' + sorted[0] + '\')" style="flex:1;min-width:200px;background:linear-gradient(135deg,var(--emerald-dark),var(--emerald));color:white;border:none;border-radius:10px;padding:.85rem;font-size:.88rem;font-weight:700;cursor:pointer;font-family:inherit;">Start Top Priority →</button>'
    + '<button onclick="showRoadmapPage()" style="flex:1;min-width:200px;background:white;border:1.5px solid var(--border);color:var(--ink-mid);border-radius:10px;padding:.85rem;font-size:.88rem;font-weight:600;cursor:pointer;font-family:inherit;">View 90-Day Roadmap</button>'
    + '</div>'
    + '<button onclick="showAssessmentPage()" style="width:100%;margin-top:.75rem;background:none;border:none;color:var(--ink-pale);font-size:.78rem;cursor:pointer;font-family:inherit;padding:.5rem;">Retake assessment</button>'
    + '</div>';

  results.scrollIntoView({ behavior: 'smooth', block: 'start' });
}

