// ── Progress tracking stored in memory ──────────────────────────────────────
var _lpProgress = {}; // { pathId: { completed: [stepIdx,...] } }

function getLpProgress(pathId) {
  if (!_lpProgress[pathId]) _lpProgress[pathId] = { completed: [] };
  return _lpProgress[pathId];
}
function toggleLpStep(pathId, stepIdx) {
  var p = getLpProgress(pathId);
  var i = p.completed.indexOf(stepIdx);
  if (i >= 0) p.completed.splice(i,1);
  else p.completed.push(stepIdx);
  // Re-render the checklist and progress bar inline
  renderLpChecklist(pathId);
  renderLpProgressBar(pathId);
}
function isLpStepDone(pathId, stepIdx) {
  return getLpProgress(pathId).completed.indexOf(stepIdx) >= 0;
}

var lpCurrentFilter = 'All';

function showLearningPathsPage() {
  lpCurrentFilter = 'All';
  showPage('learning-paths-page', '← Back to Home');
  renderLpFilters();
  renderLearningPaths();
}

function renderLpFilters() {
  var container = document.getElementById('lpFilterBtns');
  if (!container) return;
  var levels = ['All','Foundation','Intermediate','Advanced'];
  container.innerHTML = levels.map(function(f) {
    var isActive = f === lpCurrentFilter;
    return '<button onclick="filterLPs(\''+f+'\')" style="padding:.45rem 1.1rem;border-radius:20px;font-size:.8rem;font-weight:700;cursor:pointer;font-family:inherit;border:1.5px solid '+(isActive?'var(--emerald)':'var(--border)')+';background:'+(isActive?'var(--emerald)':'white')+';color:'+(isActive?'white':'var(--ink-light)')+';transition:all .18s;">'+f+'</button>';
  }).join('');
}

function filterLPs(f) {
  lpCurrentFilter = f;
  renderLpFilters();
  renderLearningPaths();
}

function renderLearningPaths() {
  var grid = document.getElementById('learningPathsGrid');
  if (!grid) return;
  var filtered = lpCurrentFilter === 'All' ? LEARNING_PATHS : LEARNING_PATHS.filter(function(p){ return p.level === lpCurrentFilter; });

  grid.innerHTML = filtered.map(function(path) {
    var prog = getLpProgress(path.id);
    var done = prog.completed.length;
    var total = path.steps.length;
    var pct = total > 0 ? Math.round((done/total)*100) : 0;
    var statusLabel = done === 0 ? 'Not started' : done === total ? '✓ Complete' : 'In progress';
    var statusColor = done === 0 ? 'var(--ink-pale)' : done === total ? path.color : '#d97706';

    return '<div style="background:white;border:1.5px solid var(--border);border-radius:18px;overflow:hidden;transition:all .22s;cursor:pointer;display:flex;flex-direction:column;" onclick="openLearningPath(\''+path.id+'\')" onmouseover="this.style.borderColor=\''+path.color+'\';this.style.boxShadow=\'0 10px 32px rgba(0,0,0,.10)\';this.style.transform=\'translateY(-3px)\'" onmouseout="this.style.borderColor=\'var(--border)\';this.style.boxShadow=\'\';this.style.transform=\'\'">'
      // Coloured top band
      + '<div style="height:5px;background:linear-gradient(90deg,'+path.color+','+path.color+'88);"></div>'
      // Card header
      + '<div style="padding:1.5rem 1.5rem 1.1rem;border-bottom:1px solid var(--border);background:'+path.colorLight+';">'
      + '<div style="display:flex;align-items:flex-start;justify-content:space-between;margin-bottom:.8rem;">'
      + '<span style="font-size:2rem;">'+path.icon+'</span>'
      + '<span style="font-size:.65rem;font-weight:800;padding:.28rem .7rem;border-radius:20px;background:white;color:'+path.color+';border:1.5px solid '+path.color+';">'+path.level+'</span>'
      + '</div>'
      + '<div style="font-weight:900;font-size:1.05rem;color:var(--ink);margin-bottom:.18rem;line-height:1.3;">'+path.title+'</div>'
      + '<div style="font-size:.75rem;color:var(--ink-light);margin-bottom:.6rem;">For '+path.role+'</div>'
      // Tags
      + '<div style="display:flex;flex-wrap:wrap;gap:.3rem;">'
      + path.tags.map(function(t){ return '<span style="font-size:.62rem;font-weight:700;padding:.15rem .5rem;background:rgba(0,0,0,.06);border-radius:4px;color:var(--ink-mid);">'+t+'</span>'; }).join('')
      + '</div></div>'
      // Body
      + '<div style="padding:1.25rem 1.5rem;flex:1;display:flex;flex-direction:column;">'
      + '<p style="font-size:.82rem;color:var(--ink-light);line-height:1.65;margin-bottom:1rem;">'+path.tagline+'</p>'
      // Stats row
      + '<div style="display:flex;gap:1.25rem;margin-bottom:1rem;flex-wrap:wrap;">'
      + '<span style="font-size:.73rem;font-weight:700;color:var(--ink-light);">⏱ '+path.totalTime+'</span>'
      + '<span style="font-size:.73rem;font-weight:700;color:var(--ink-light);">📚 '+total+' lessons</span>'
      + '<span style="font-size:.73rem;font-weight:700;color:var(--ink-light);">📅 '+path.duration+'</span>'
      + '</div>'
      // Progress bar
      + '<div style="margin-bottom:1rem;">'
      + '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:.35rem;">'
      + '<span style="font-size:.68rem;font-weight:700;color:'+statusColor+';">'+statusLabel+'</span>'
      + '<span style="font-size:.68rem;color:var(--ink-pale);">'+done+' / '+total+' done</span>'
      + '</div>'
      + '<div style="height:5px;background:var(--border);border-radius:3px;overflow:hidden;">'
      + '<div style="height:100%;width:'+pct+'%;background:'+path.color+';border-radius:3px;transition:width .4s;"></div>'
      + '</div></div>'
      // First 3 steps preview
      + '<div style="display:flex;flex-direction:column;gap:.3rem;margin-bottom:1.25rem;flex:1;">'
      + path.steps.slice(0,3).map(function(s,i){
          var done_s = isLpStepDone(path.id, i);
          return '<div style="display:flex;align-items:center;gap:.55rem;font-size:.78rem;color:'+(done_s?path.color:'var(--ink-mid)')+';">'
            + '<div style="width:18px;height:18px;min-width:18px;border-radius:50%;background:'+(done_s?path.color:path.colorLight)+';border:1.5px solid '+path.color+';display:flex;align-items:center;justify-content:center;flex-shrink:0;">'
            + (done_s?'<svg viewBox="0 0 20 20" fill="none" style="width:9px;height:9px;"><path d="M5 10l4 4 6-8" stroke="white" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"/></svg>':'<span style="font-size:.58rem;font-weight:800;color:'+path.color+';">'+(i+1)+'</span>')
            + '</div>'
            + '<span style="'+(done_s?'text-decoration:line-through;opacity:.6;':'')+'">'+s.title+'</span></div>';
        }).join('')
      + (total > 3 ? '<div style="font-size:.73rem;color:var(--ink-pale);padding-left:1.5rem;">+'+(total-3)+' more…</div>' : '')
      + '</div>'
      + '<button style="width:100%;background:'+path.color+';color:white;border:none;border-radius:10px;padding:.75rem;font-size:.85rem;font-weight:800;cursor:pointer;font-family:inherit;margin-top:auto;" onclick="event.stopPropagation();openLearningPath(\''+path.id+'\')">'+(done===0?'Start Path →':done===total?'Review Path →':'Continue Path →')+'</button>'
      + '</div></div>';
  }).join('');
}

function openLearningPath(pathId) {
  var path = LEARNING_PATHS.find(function(p){ return p.id === pathId; });
  if (!path) return;

  var capLearnActive = document.getElementById('cap-learn-page') && document.getElementById('cap-learn-page').classList.contains('active');

  var trackLearnActiveLp = document.getElementById('track-learn-page') && document.getElementById('track-learn-page').classList.contains('active');
  if (trackLearnActiveLp) {
    navHistory.push({ pageId: 'track-learn-page', label: '← Track Learn', capId: null, subIdx: null });
  } else if (capLearnActive) {
    // preserve existing history stack, push learn page on top
    navHistory.push({ pageId: 'cap-learn-page', label: '← Learn', capId: null, subIdx: null });
  } else {
    navHistory = [{ pageId:'learning-paths-page', label:'← Learning Paths', capId:null, subIdx:null }];
  }

  document.querySelectorAll('.page').forEach(function(p){ p.classList.remove('active'); });
  document.getElementById('learning-path-detail-page').classList.add('active');
  document.getElementById('navBackBtn').style.display = 'flex';
  var _lpBackLabel = navHistory.length > 0 ? navHistory[navHistory.length - 1].label : '← Learning Paths';
  document.getElementById('navBackLabel').textContent = _lpBackLabel;
  setFloatingBack(_lpBackLabel);
  currentCapId = null; currentSubCapIdx = null;
  window.scrollTo(0,0);

  renderLpDetailPage(pathId);
}

function renderLpDetailPage(pathId) {
  var path = LEARNING_PATHS.find(function(p){ return p.id === pathId; });
  if (!path) return;
  var container = document.getElementById('lpDetailInner');
  if (!container) return;
  var prog = getLpProgress(pathId);
  var done = prog.completed.length;
  var total = path.steps.length;
  var pct = total > 0 ? Math.round((done/total)*100) : 0;

  var html = '';
  // Breadcrumb
  html += '<div style="display:flex;align-items:center;gap:.5rem;font-size:.8rem;color:var(--ink-light);margin-bottom:1.75rem;flex-wrap:wrap;">';
  html += '<span onclick="goHome()" style="color:var(--emerald);cursor:pointer;font-weight:600;">Home</span><span style="opacity:.4;">›</span>';
  html += '<span onclick="showLearningPathsPage()" style="color:var(--emerald);cursor:pointer;font-weight:600;">Learning Paths</span><span style="opacity:.4;">›</span>';
  html += '<span style="color:var(--ink);">'+path.title+'</span></div>';

  // ── HERO ──────────────────────────────────────────────────────────────────
  html += '<div style="background:linear-gradient(135deg,'+path.color+','+path.color+'bb);border-radius:20px;padding:2rem 2rem 1.75rem;margin-bottom:1.75rem;">';
  html += '<div style="display:flex;align-items:center;gap:.85rem;margin-bottom:.85rem;">';
  html += '<span style="font-size:2.75rem;">'+path.icon+'</span>';
  html += '<div>';
  html += '<div style="font-size:.6rem;font-weight:700;letter-spacing:.14em;text-transform:uppercase;color:rgba(255,255,255,.65);margin-bottom:.15rem;">Learning Path · '+path.level+'</div>';
  html += '<div style="font-size:.82rem;color:rgba(255,255,255,.8);">For '+path.role+'</div>';
  html += '</div></div>';
  html += '<h1 style="font-family:\'Cormorant Garamond\',serif;font-size:clamp(1.7rem,4vw,2.5rem);font-weight:600;color:white;line-height:1.2;margin-bottom:.6rem;">'+path.title+'</h1>';
  html += '<p style="font-size:.88rem;color:rgba(255,255,255,.85);line-height:1.7;margin-bottom:1.1rem;">'+path.description+'</p>';
  html += '<div style="display:flex;gap:.75rem;flex-wrap:wrap;">';
  html += '<span style="font-size:.78rem;font-weight:700;padding:.3rem .85rem;background:rgba(255,255,255,.2);border-radius:20px;color:white;">⏱ '+path.totalTime+'</span>';
  html += '<span style="font-size:.78rem;font-weight:700;padding:.3rem .85rem;background:rgba(255,255,255,.2);border-radius:20px;color:white;">📚 '+total+' lessons</span>';
  html += '<span style="font-size:.78rem;font-weight:700;padding:.3rem .85rem;background:rgba(255,255,255,.2);border-radius:20px;color:white;">📅 '+path.duration+'</span>';
  html += '<span style="font-size:.78rem;font-weight:700;padding:.3rem .85rem;background:rgba(255,255,255,.2);border-radius:20px;color:white;">🆓 Free access</span>';
  html += '</div></div>';

  // ── PROGRESS BAR ─────────────────────────────────────────────────────────
  html += '<div id="lpProgressSection_'+pathId+'" style="background:white;border:1.5px solid var(--border);border-radius:14px;padding:1.25rem 1.5rem;margin-bottom:1.5rem;">';
  html += '<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:.75rem;">';
  html += '<div style="font-size:.68rem;font-weight:800;text-transform:uppercase;letter-spacing:.1em;color:var(--ink-pale);">Your Progress</div>';
  html += '<div style="font-size:.8rem;font-weight:800;color:'+path.color+';" id="lpProgressLabel_'+pathId+'">'+done+' of '+total+' lessons complete</div>';
  html += '</div>';
  html += '<div style="height:8px;background:var(--cream);border-radius:4px;overflow:hidden;margin-bottom:.6rem;">';
  html += '<div id="lpProgressBar_'+pathId+'" style="height:100%;width:'+pct+'%;background:linear-gradient(90deg,'+path.color+','+path.color+'99);border-radius:4px;transition:width .4s;"></div>';
  html += '</div>';
  html += '<div style="display:flex;gap:.5rem;">';
  path.steps.forEach(function(s,i){
    var d = isLpStepDone(pathId,i);
    html += '<div style="flex:1;height:4px;border-radius:2px;background:'+(d?path.color:'var(--border)')+';transition:background .3s;" title="'+s.title+'"></div>';
  });
  html += '</div></div>';

  // ── TWO-COLUMN LAYOUT ─────────────────────────────────────────────────────
  html += '<div class="lp-layout">';

  // ── LEFT COLUMN ───────────────────────────────────────────────────────────
  html += '<div>';

  // What you'll achieve
  html += '<div style="background:white;border:1.5px solid var(--border);border-radius:14px;padding:1.4rem 1.5rem;margin-bottom:1.25rem;">';
  html += '<div style="font-size:.65rem;font-weight:800;text-transform:uppercase;letter-spacing:.1em;color:var(--gold);margin-bottom:1rem;">🏆 What You Will Achieve</div>';
  html += '<div style="display:grid;grid-template-columns:1fr 1fr;gap:.65rem;">';
  path.outcomes.forEach(function(o){
    html += '<div style="display:flex;align-items:flex-start;gap:.6rem;font-size:.83rem;color:var(--ink-mid);line-height:1.5;">';
    html += '<div style="width:20px;height:20px;min-width:20px;border-radius:50%;background:'+path.colorLight+';border:1.5px solid '+path.color+';display:flex;align-items:center;justify-content:center;margin-top:1px;flex-shrink:0;"><svg viewBox="0 0 20 20" fill="none" style="width:9px;height:9px;"><path d="M5 10l4 4 6-8" stroke="'+path.color+'" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"/></svg></div>';
    html += '<span>'+o+'</span></div>';
  });
  html += '</div></div>';

  // What you'll build
  html += '<div style="background:'+path.colorLight+';border:1.5px solid '+path.color+'33;border-radius:14px;padding:1.2rem 1.5rem;margin-bottom:1.25rem;">';
  html += '<div style="font-size:.65rem;font-weight:800;text-transform:uppercase;letter-spacing:.1em;color:'+path.color+';margin-bottom:.5rem;">🛠 What You Will Build</div>';
  html += '<p style="font-size:.85rem;color:var(--ink-mid);line-height:1.7;margin:0;">'+path.whatYouWillBuild+'</p>';
  html += '</div>';

  // Lesson checklist
  html += '<div style="background:white;border:1.5px solid var(--border);border-radius:14px;overflow:hidden;margin-bottom:1.25rem;" id="lpChecklist_'+pathId+'">';
  html += '<div style="padding:1.1rem 1.5rem;border-bottom:1px solid var(--border);display:flex;align-items:center;justify-content:space-between;">';
  html += '<div style="font-size:.65rem;font-weight:800;text-transform:uppercase;letter-spacing:.1em;color:var(--ink-pale);">📋 Lessons & Checklist</div>';
  html += '<span style="font-size:.72rem;color:var(--ink-pale);">Click a lesson to mark complete</span>';
  html += '</div>';
  html += '<div id="lpStepList_'+pathId+'">';
  path.steps.forEach(function(step, i){
    var isDone = isLpStepDone(pathId,i);
    var isAction = step.type === 'action';
    html += '<div style="display:flex;align-items:stretch;border-bottom:1px solid var(--cream);transition:background .15s;" onmouseover="this.style.background=\'var(--cream)\'" onmouseout="this.style.background=\'\'">';
    // Checkbox column
    html += '<div onclick="toggleLpStep(\''+pathId+'\','+i+')" style="width:52px;min-width:52px;display:flex;align-items:center;justify-content:center;cursor:pointer;padding:.75rem 0;border-right:1px solid var(--cream);">';
    html += '<div id="lpCheck_'+pathId+'_'+i+'" style="width:22px;height:22px;border-radius:50%;border:2px solid '+(isDone?path.color:'var(--border)')+';background:'+(isDone?path.color:'white')+';display:flex;align-items:center;justify-content:center;transition:all .2s;flex-shrink:0;">';
    if (isDone) html += '<svg viewBox="0 0 20 20" fill="none" style="width:11px;height:11px;"><path d="M5 10l4 4 6-8" stroke="white" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"/></svg>';
    html += '</div></div>';
    // Content column
    html += '<div style="flex:1;padding:.85rem 1.1rem;cursor:pointer;" onclick="loadCapabilityFromLP(\''+step.capId+'\',\''+pathId+'\')">';
    html += '<div style="display:flex;align-items:center;gap:.5rem;margin-bottom:.2rem;">';
    if (isAction) html += '<span style="font-size:.58rem;font-weight:800;letter-spacing:.06em;text-transform:uppercase;background:'+path.color+';color:white;padding:.12rem .45rem;border-radius:3px;">Action</span>';
    html += '<div style="font-weight:800;font-size:.88rem;color:'+(isDone?'var(--ink-pale)':'var(--ink)')+';line-height:1.3;'+(isDone?'text-decoration:line-through;':'')+'">' + step.title + '</div>';
    html += '</div>';
    html += '<div style="font-size:.77rem;color:var(--ink-light);line-height:1.5;margin-bottom:.4rem;">'+step.desc+'</div>';
    html += '<div style="display:flex;align-items:center;gap:.85rem;">';
    html += '<span style="font-size:.68rem;font-weight:700;color:var(--ink-pale);">⏱ '+step.time+'</span>';
    html += '<span style="font-size:.68rem;font-weight:700;color:'+path.color+';">Open Lesson →</span>';
    html += '</div></div>';
    html += '</div>';
  });
  html += '</div></div>'; // close checklist

  // Related capabilities chips
  html += '<div style="background:white;border:1.5px solid var(--border);border-radius:14px;padding:1.2rem 1.5rem;margin-bottom:1.25rem;">';
  html += '<div style="font-size:.65rem;font-weight:800;text-transform:uppercase;letter-spacing:.1em;color:var(--ink-pale);margin-bottom:.75rem;">🔗 Capability Areas Covered</div>';
  html += '<div style="display:flex;flex-wrap:wrap;gap:.5rem;">';
  var capColors2 = {strategy:'#16a34a',programs:'#2563eb',leadership:'#d97706',team:'#7c3aed',systems:'#0891b2',funding:'#dc2626',comms:'#db2777',finance:'#065f46'};
  var capNames2  = {strategy:'Strategic Planning',programs:'Program Design',leadership:'Leadership Dev.',team:'Team Effectiveness',systems:'Org. Systems',funding:'Funding Strategy',comms:'Communications',finance:'Financial Mgmt'};
  path.caps.forEach(function(c){
    html += '<button onclick="loadCapabilityFromLP(\''+c+'\',\''+pathId+'\')" style="font-size:.75rem;font-weight:700;padding:.35rem .9rem;border-radius:20px;border:1.5px solid '+(capColors2[c]||'var(--emerald)')+';color:'+(capColors2[c]||'var(--emerald)')+';background:'+(capColors2[c]||'var(--emerald)')+'11;cursor:pointer;font-family:inherit;transition:all .18s;" onmouseover="this.style.background=\''+(capColors2[c]||'var(--emerald)')+'\';this.style.color=\'white\'" onmouseout="this.style.background=\''+(capColors2[c]||'var(--emerald)')+'11\';this.style.color=\''+(capColors2[c]||'var(--emerald)')+'\'">'+((capNames2[c])||c)+'</button>';
  });
  html += '</div></div>';

  html += '</div>'; // close left column

  // ── RIGHT SIDEBAR ─────────────────────────────────────────────────────────
  html += '<div style="position:sticky;top:80px;display:flex;flex-direction:column;gap:1.1rem;">';

  // Start / Continue CTA
  var firstIncomplete = -1;
  for (var si=0; si<path.steps.length; si++) { if (!isLpStepDone(pathId,si)){ firstIncomplete=si; break; } }
  html += '<div style="background:linear-gradient(135deg,'+path.color+','+path.color+'bb);border-radius:16px;padding:1.4rem;margin-bottom:1.1rem;text-align:center;">';
  html += '<div style="color:white;font-weight:800;font-size:1rem;margin-bottom:.35rem;">'+(done===0?'Ready to start?':done===total?'Path Complete! 🎉':'Keep going!')+'</div>';
  html += '<div style="color:rgba(255,255,255,.8);font-size:.78rem;margin-bottom:1rem;">'+(done===0?'Begin with Lesson 1':done===total?'All '+total+' lessons done':''+done+' of '+total+' lessons done')+'</div>';
  if (done < total) {
    var nextIdx = firstIncomplete >= 0 ? firstIncomplete : 0;
    html += '<button onclick="loadCapabilityFromLP(\''+path.steps[nextIdx].capId+'\',\''+pathId+'\')" style="width:100%;background:white;color:'+path.color+';font-weight:900;font-size:.9rem;padding:.85rem;border-radius:10px;border:none;cursor:pointer;font-family:inherit;">'+(done===0?'Start Lesson 1 →':'Continue: Lesson '+(nextIdx+1)+' →')+'</button>';
  } else {
    html += '<button onclick="showLearningPathsPage()" style="width:100%;background:white;color:'+path.color+';font-weight:900;font-size:.9rem;padding:.85rem;border-radius:10px;border:none;cursor:pointer;font-family:inherit;">Explore Other Paths →</button>';
  }
  html += '</div>';

  // Tools You Will Use — clickable with Word/PDF download
  html += '';
  html += '<div style="background:white;border:1.5px solid var(--border);border-radius:14px;padding:1.25rem;margin-bottom:1.1rem;">';
  html += '<div style="font-size:.62rem;font-weight:800;text-transform:uppercase;letter-spacing:.1em;color:var(--ink-pale);margin-bottom:.85rem;">📦 Tools You Will Use</div>';
  html += '<div style="display:flex;flex-direction:column;gap:.45rem;">';
  path.steps.forEach(function(s, si) {
    var toolId  = 'lp-tool-' + pathId + '-' + si;
    var safeTool = encodeURIComponent(s.tool);
    html += '<div style="position:relative;" id="wrap-' + toolId + '">';
    html += '<div class="lp-tool-row" data-toolid="' + toolId + '" onclick="toggleToolMenu(this.dataset.toolid)">';
    html += '<span style="font-size:.85rem;flex-shrink:0;">📄</span>';
    html += '<span style="flex:1;line-height:1.35;">' + s.tool + '</span>';
    html += '<span style="font-size:.65rem;color:var(--emerald);font-weight:700;margin-left:.3rem;">↓</span>';
    html += '</div>';
    html += '<div id="' + toolId + '" style="display:none;position:absolute;right:0;top:calc(100% + 2px);z-index:500;background:white;border:1.5px solid var(--border);border-radius:10px;box-shadow:0 8px 24px rgba(0,0,0,.12);overflow:hidden;min-width:175px;">';
    html += '<div class="lp-tool-dl-btn" data-tool="' + safeTool + '" data-fmt="docx" data-tid="' + toolId + '" onclick="downloadTool(decodeURIComponent(this.dataset.tool),this.dataset.fmt);toggleToolMenu(this.dataset.tid)">';
    html += '<span>📝</span><span>Download as Word</span>';
    html += '</div>';
    html += '<div style="height:1px;background:var(--border);margin:0 .75rem;"></div>';
    html += '<div class="lp-tool-dl-btn" data-tool="' + safeTool + '" data-fmt="pdf" data-tid="' + toolId + '" onclick="downloadTool(decodeURIComponent(this.dataset.tool),this.dataset.fmt);toggleToolMenu(this.dataset.tid)">';
    html += '<span>📕</span><span>Download as PDF</span>';
    html += '</div>';
    html += '</div>';
    html += '</div>';
  });
  html += '</div></div>';

  // Quick path summary
  html += '<div style="background:var(--cream);border-radius:14px;padding:1.1rem 1.25rem;">';
  html += '<div style="font-size:.62rem;font-weight:800;text-transform:uppercase;letter-spacing:.1em;color:var(--ink-pale);margin-bottom:.75rem;">📊 Path Summary</div>';
  var rows = [['Level',path.level],['Duration',path.duration],['Total Time',path.totalTime],['Lessons',total+' modules'],['Format','Self-paced']];
  rows.forEach(function(r){
    html += '<div style="display:flex;justify-content:space-between;font-size:.78rem;padding:.3rem 0;border-bottom:1px solid var(--border);">';
    html += '<span style="color:var(--ink-light);">'+r[0]+'</span><span style="font-weight:700;color:var(--ink);">'+r[1]+'</span>';
    html += '</div>';
  });
  html += '</div>';

  html += '</div>'; // close sidebar
  html += '</div>'; // close two-col grid

  container.innerHTML = html;
  window.scrollTo(0,0);
}

function renderLpChecklist(pathId) {
  var path = LEARNING_PATHS.find(function(p){ return p.id === pathId; });
  if (!path) return;
  // Re-render just the step list items
  var listEl = document.getElementById('lpStepList_'+pathId);
  if (!listEl) return;
  var html = '';
  path.steps.forEach(function(step,i){
    var isDone = isLpStepDone(pathId,i);
    var isAction = step.type === 'action';
    html += '<div style="display:flex;align-items:stretch;border-bottom:1px solid var(--cream);transition:background .15s;" onmouseover="this.style.background=\'var(--cream)\'" onmouseout="this.style.background=\'\'">';
    html += '<div onclick="toggleLpStep(\''+pathId+'\','+i+')" style="width:52px;min-width:52px;display:flex;align-items:center;justify-content:center;cursor:pointer;padding:.75rem 0;border-right:1px solid var(--cream);">';
    html += '<div style="width:22px;height:22px;border-radius:50%;border:2px solid '+(isDone?path.color:'var(--border)')+';background:'+(isDone?path.color:'white')+';display:flex;align-items:center;justify-content:center;transition:all .2s;">';
    if (isDone) html += '<svg viewBox="0 0 20 20" fill="none" style="width:11px;height:11px;"><path d="M5 10l4 4 6-8" stroke="white" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"/></svg>';
    html += '</div></div>';
    html += '<div style="flex:1;padding:.85rem 1.1rem;cursor:pointer;" onclick="loadCapabilityFromLP(\''+step.capId+'\',\''+pathId+'\')">';
    html += '<div style="display:flex;align-items:center;gap:.5rem;margin-bottom:.2rem;">';
    if (isAction) html += '<span style="font-size:.58rem;font-weight:800;letter-spacing:.06em;text-transform:uppercase;background:'+path.color+';color:white;padding:.12rem .45rem;border-radius:3px;">Action</span>';
    html += '<div style="font-weight:800;font-size:.88rem;color:'+(isDone?'var(--ink-pale)':'var(--ink)')+';line-height:1.3;'+(isDone?'text-decoration:line-through;':'')+'">'+step.title+'</div>';
    html += '</div>';
    html += '<div style="font-size:.77rem;color:var(--ink-light);line-height:1.5;margin-bottom:.4rem;">'+step.desc+'</div>';
    html += '<div style="display:flex;gap:.85rem;"><span style="font-size:.68rem;font-weight:700;color:var(--ink-pale);">⏱ '+step.time+'</span><span style="font-size:.68rem;font-weight:700;color:'+path.color+';">Open Lesson →</span></div>';
    html += '</div></div>';
  });
  listEl.innerHTML = html;
}

function renderLpProgressBar(pathId) {
  var path = LEARNING_PATHS.find(function(p){ return p.id===pathId; });
  if (!path) return;
  var prog = getLpProgress(pathId);
  var done = prog.completed.length, total = path.steps.length;
  var pct = total>0?Math.round((done/total)*100):0;
  var bar = document.getElementById('lpProgressBar_'+pathId);
  var lbl = document.getElementById('lpProgressLabel_'+pathId);
  if (bar) bar.style.width = pct+'%';
  if (lbl) lbl.textContent = done+' of '+total+' lessons complete';
  // Update step indicator dots in hero progress bar
  var sect = document.getElementById('lpProgressSection_'+pathId);
  if (sect) {
    var dots = sect.querySelectorAll('div[title]');
    path.steps.forEach(function(s,i){
      if (dots[i]) dots[i].style.background = isLpStepDone(pathId,i)?path.color:'var(--border)';
    });
  }
}

