// ── PDF DOWNLOAD ─────────────────────────────────────────────────────────────
function downloadTemplatePDF(key) {
  var t = (window._tplRegistry || {})[key];
  if (!t) { showToast('Template not found'); return; }
  var tc = _tplTypeColors[t.type] || '#1a6b4a';
  var preview = buildTemplatePreview(t);

  var printWin = window.open('', '_blank', 'width=920,height=700');
  if (!printWin) { showToast('Allow pop-ups to download PDF'); return; }

  var css = [
    '* { box-sizing:border-box; margin:0; padding:0; }',
    'body { font-family: Outfit, sans-serif; background:#fff; color:#1a1a1a; padding:2.5rem; max-width:900px; margin:0 auto; }',
    '.hdr { border-bottom:3px solid '+tc+'; padding-bottom:1.35rem; margin-bottom:2rem; display:flex; justify-content:space-between; align-items:flex-start; gap:1rem; }',
    '.org { font-size:.62rem; font-weight:700; letter-spacing:.12em; text-transform:uppercase; color:'+tc+'; margin-bottom:.3rem; }',
    '.title { font-size:1.55rem; font-weight:800; color:#0f4a32; margin-bottom:.25rem; line-height:1.2; }',
    '.meta { font-size:.75rem; color:#6b6b6b; margin-bottom:.4rem; }',
    '.badge { background:'+tc+'; color:white; font-size:.65rem; font-weight:800; padding:.25rem .65rem; border-radius:5px; display:inline-block; }',
    '.section { margin-bottom:1.5rem; }',
    '.sec-lbl { font-size:.65rem; font-weight:800; text-transform:uppercase; letter-spacing:.1em; color:'+tc+'; border-left:3px solid '+tc+'; padding-left:.55rem; margin-bottom:.55rem; }',
    '.desc { background:#f9fafb; border:1px solid #e5e7eb; border-radius:8px; padding:1rem; font-size:.88rem; line-height:1.75; color:#374151; }',
    '.howto { background:#fffbeb; border:1px solid #fde68a; border-radius:8px; padding:1rem; font-size:.88rem; line-height:1.75; color:#78350f; }',
    '.howto-lbl { font-size:.62rem; font-weight:800; text-transform:uppercase; color:#d97706; letter-spacing:.1em; margin-bottom:.4rem; }',
    '.preview { border:1.5px solid #e5e7eb; border-radius:10px; padding:1.5rem; }',
    '.preview-lbl { font-size:.6rem; font-weight:700; text-transform:uppercase; letter-spacing:.1em; color:#9ca3af; margin-bottom:1rem; border-bottom:1px solid #f3f4f6; padding-bottom:.5rem; }',
    '.footer { margin-top:2rem; padding-top:.85rem; border-top:1px solid #e5e7eb; display:flex; justify-content:space-between; font-size:.7rem; color:#9ca3af; }',
    'table { width:100%; border-collapse:collapse; font-size:.78rem; border-radius:8px; overflow:hidden; }',
    'th { background:'+tc+'; color:white; padding:.45rem .7rem; text-align:left; font-weight:700; }',
    'td { padding:.38rem .7rem; border-bottom:1px solid #e5e7eb; }',
    'tr:nth-child(even) td { background:#f9fafb; }',
    '@media print { body { padding:1.25rem; } @page { margin:1.5cm; size:A4 portrait; } }'
  ].join('\n');

  var doc = '<!DOCTYPE html><html><head>'
    + '<meta charset="UTF-8"><title>' + t.name + '</title>'
    + '<link href="https://fonts.googleapis.com/css2?family=Outfit:wght@400;600;700;800&display=swap" rel="stylesheet">'
    + ''
    + '</head><body>'
    // Header
    + '<div class="hdr"><div>'
    + '<div class="org">ALJUDE ACADEMY · ' + t.category.toUpperCase() + '</div>'
    + '<div class="title">' + t.name + '</div>'
    + '<div class="meta">Organisation: ___________________________ &nbsp;&nbsp; Date: _______________ &nbsp;&nbsp; Prepared by: _______________</div>'
    + '<span class="badge">' + t.type + ' Template &nbsp;·&nbsp; Free for NGO use</span>'
    + '</div></div>'
    // About
    + '<div class="section"><div class="sec-lbl">About This Template</div>'
    + '<div class="desc">' + t.desc + '</div></div>'
    // How to
    + (t.howTo ? '<div class="section"><div class="howto"><div class="howto-lbl">💡 How To Use This Template</div>' + t.howTo + '</div></div>' : '')
    // Preview
    + '<div class="section"><div class="preview"><div class="preview-lbl">Document Content Preview</div>'
    + preview
    + '</div></div>'
    // Footer
    + '<div class="footer">'
    + '<span>ALJUDE Academy · Free Capacity Building Platform for NGOs</span>'
    + '<span>Downloaded: ' + new Date().toLocaleDateString('en-GB', {day:'2-digit',month:'short',year:'numeric'}) + '</span>'
    + '</div>'
    + '</body></html>';

  printWin.document.write(doc);
  printWin.document.close();
  setTimeout(function() { printWin.focus(); printWin.print(); }, 900);
  showToast('PDF ready — ' + t.name);
}


