function showWorkbooksPage() {
  showPage('workbooks-page', 'Back to Home');
  renderWorkbooksGrid();
}

function renderWorkbooksGrid() {
  var grid = document.getElementById('workbooksGrid');
  if (!grid) return;
  var workbooks = [];
  Object.keys(CAPABILITIES).forEach(function(key) {
    var cap = CAPABILITIES[key];
    (cap.subCapabilities || []).forEach(function(sub, i) {
      if (sub.workbook) {
        workbooks.push({ capId:key, subIdx:i, icon:cap.icon, capTitle:cap.title, title:sub.workbook.title||sub.title, subtitle:sub.workbook.subtitle||'', intro:sub.workbook.intro||'' });
      }
    });
  });
  grid.innerHTML = workbooks.map(function(wb) {
    return '<div style="background:white;border:1.5px solid var(--border);border-radius:16px;overflow:hidden;transition:all .2s;" onmouseover="this.style.borderColor=\'var(--emerald)\';this.style.boxShadow=\'0 6px 20px rgba(26,107,74,.1)\'" onmouseout="this.style.borderColor=\'var(--border)\';this.style.boxShadow=\'\'">'
      + '<div style="background:linear-gradient(135deg,var(--emerald-dark),var(--emerald));padding:1.25rem 1.5rem;display:flex;align-items:center;gap:.75rem;">'
      + '<span style="font-size:1.5rem;">'+wb.icon+'</span>'
      + '<div><div style="font-family:\'DM Mono\',monospace;font-size:.62rem;font-weight:500;letter-spacing:.12em;text-transform:uppercase;color:rgba(255,255,255,.65);margin-bottom:.15rem;">'+wb.capTitle+'</div>'
      + '<div style="font-weight:700;font-size:.95rem;color:white;">'+wb.title+'</div></div>'
      + '</div>'
      + '<div style="padding:1.25rem 1.5rem;">'
      + (wb.subtitle ? '<div style="font-size:.78rem;font-weight:700;color:var(--gold);margin-bottom:.5rem;">'+wb.subtitle+'</div>' : '')
      + '<p style="font-size:.82rem;color:var(--ink-light);line-height:1.6;margin-bottom:1rem;">'+(wb.intro||'A structured workbook to guide your team through analysis and planning.').substring(0,130)+'…</p>'
      + '<div style="display:flex;gap:.5rem;flex-wrap:wrap;">'
      + '<button onclick="downloadWorkbook(\''+wb.capId+'\','+wb.subIdx+',\'PDF\')" style="flex:1;background:var(--emerald);color:white;border:none;border-radius:8px;padding:.55rem;font-size:.78rem;font-weight:700;cursor:pointer;font-family:inherit;">PDF</button>'
      + '<button onclick="downloadWorkbook(\''+wb.capId+'\','+wb.subIdx+',\'Word\')" style="flex:1;background:white;color:var(--emerald);border:1.5px solid rgba(26,107,74,.35);border-radius:8px;padding:.55rem;font-size:.78rem;font-weight:700;cursor:pointer;font-family:inherit;">Word</button>'
      + '<button onclick="openSubCapability(\''+wb.capId+'\','+wb.subIdx+')" style="flex:1;background:var(--cream);color:var(--ink-mid);border:1.5px solid var(--border);border-radius:8px;padding:.55rem;font-size:.78rem;font-weight:700;cursor:pointer;font-family:inherit;">Open →</button>'
      + '</div></div></div>';
  }).join('');
}

