var SUCCESS_STORIES = [
  { id:'ss1', icon:'🌍', org:'Al-Noor Foundation', country:'Jordan', size:'12 staff', category:'Strategy', title:'From Reactive to Strategic: A 6-Month Transformation', challenge:'Al-Noor had been operating for 7 years without a written strategy. Every funding opportunity caused a direction change, spreading the team thin and confusing donors.', action:'Used the Strategic Planning workbook to run a 2-day staff retreat. Built a 3-year strategy with 5 clear goals and quarterly reviews.', result:'Secured a €120,000 multi-year grant from a European donor who cited the clarity of their strategy. Staff turnover dropped 40%.', caps:['strategy'], duration:'6 months', quote:'For the first time, we could tell a donor exactly where we\'re going and why. That changed everything.' },
  { id:'ss2', icon:'💧', org:'Maeen Water Initiative', country:'Lebanon', size:'8 staff', category:'Funding', title:'Breaking Free from Single-Donor Dependency', challenge:'95% of funding came from one INGO partner. When that partner signalled a phase-out, the organization faced potential closure.', action:'Completed the Funding Strategy module in full. Built a prospect list of 30 donors, submitted 8 proposals in 6 months.', result:'Diversified to 4 active funders within 12 months. Now has a 6-month operational reserve for the first time.', caps:['funding'], duration:'12 months', quote:'We went from one phone call away from shutdown to our most financially stable year ever.' },
  { id:'ss3', icon:'👩‍🎓', org:'Tatweer Youth Center', country:'Palestine', size:'20 staff', category:'Programs', title:'Impact Evidence That Changed Donor Conversations', challenge:'A major donor cut funding after a review showed "no clear impact evidence." The team was delivering real change but had no way to prove it.', action:'Built a full MEL framework using the Program Design workbook. Introduced beneficiary surveys, monthly data reviews, and a learning log.', result:'Reapplied to the same donor 8 months later with a data-rich report. Funding was reinstated and increased 30%.', caps:['programs'], duration:'8 months', quote:'The MEL system showed us things about our own programs we didn\'t know. It made us better, not just more fundable.' },
  { id:'ss4', icon:'🏥', org:'Shifa Community Clinic', country:'Iraq', size:'35 staff', category:'Team', title:'Reducing Burnout and Staff Turnover by 50%', challenge:'Annual staff turnover was running at 60%. Exit interviews pointed to poor management, unclear expectations, and lack of recognition.', action:'All managers completed the Team Effectiveness module. Introduced team charters, monthly 1-on-1s, and a recognition system.', result:'Turnover dropped to 28% in year one and 15% in year two. Patient satisfaction scores improved alongside staff wellbeing.', caps:['team','leadership'], duration:'18 months', quote:'We stopped losing our best people. The team charter meeting alone changed how we talked to each other.' },
  { id:'ss5', icon:'📊', org:'Bayan Research Institute', country:'Jordan', size:'6 staff', category:'Finance', title:'Passing a Donor Audit for the First Time', challenge:'Failed a financial audit from a Gulf-based donor due to weak financial controls. Grant was placed under monitoring and future funding was threatened.', action:'The Finance Director completed all Financial Management sub-capabilities and rebuilt the financial control system from scratch.', result:'Passed a follow-up audit 6 months later with zero findings. The monitoring status was lifted and a renewal grant was approved.', caps:['finance'], duration:'6 months', quote:'The workbook sections on internal controls were exactly what our auditor flagged. It was like a cheat sheet for fixing the problem.' },
  { id:'ss6', icon:'📣', org:'Hikayat Storytelling Collective', country:'Egypt', size:'4 staff', category:'Communications', title:'Tripling Social Media Reach Through Brand Clarity', challenge:'The organization had powerful beneficiary stories but inconsistent messaging, three conflicting "looks," and almost no social media engagement.', action:'Built a brand guide and content calendar using the Communications module. Trained all staff on ethical storytelling with consent protocols.', result:'Social media reach tripled in 4 months. A partner INGO shared their content, leading to a new program partnership worth $45,000.', caps:['comms'], duration:'4 months', quote:'We had the stories. We just didn\'t know how to tell them consistently. Now our voice is unmistakable.' }
];

var currentSuccessFilter = 'All';
var successCategories = ['All','Strategy','Funding','Programs','Team','Finance','Communications'];

function showSuccessStoriesPage() {
  showPage('success-stories-page', 'Back to Home');
  renderSuccessFilters();
  renderSuccessStories();
}

function renderSuccessFilters() {
  var container = document.getElementById('successFilterBtns');
  if (!container) return;
  container.innerHTML = successCategories.map(function(f) {
    var isActive = f === currentSuccessFilter;
    return '<button onclick="filterSuccessStories(\''+f+'\')" style="padding:.45rem 1rem;border-radius:20px;font-size:.8rem;font-weight:700;cursor:pointer;font-family:inherit;border:1.5px solid '+(isActive?'var(--emerald)':'var(--border)')+';background:'+(isActive?'var(--emerald)':'white')+';color:'+(isActive?'white':'var(--ink-light)')+';transition:all .18s;">'+f+'</button>';
  }).join('');
}

function filterSuccessStories(f) {
  currentSuccessFilter = f;
  renderSuccessFilters();
  renderSuccessStories();
}

function renderSuccessStories() {
  var grid = document.getElementById('successStoriesGrid');
  if (!grid) return;
  var filtered = currentSuccessFilter === 'All' ? SUCCESS_STORIES : SUCCESS_STORIES.filter(function(s) { return s.category === currentSuccessFilter; });
  grid.innerHTML = filtered.map(function(s) {
    return '<div style="background:white;border:1.5px solid var(--border);border-radius:16px;overflow:hidden;transition:all .2s;" onmouseover="this.style.borderColor=\'var(--emerald)\';this.style.boxShadow=\'0 6px 20px rgba(26,107,74,.1)\'" onmouseout="this.style.borderColor=\'var(--border)\';this.style.boxShadow=\'\'">'
      + '<div style="padding:1.5rem 1.5rem 1.25rem;border-bottom:1px solid var(--border);">'
      + '<div style="display:flex;align-items:center;gap:.75rem;margin-bottom:.75rem;"><span style="font-size:1.75rem;">'+s.icon+'</span>'
      + '<div><div style="font-weight:800;font-size:.95rem;color:var(--ink);">'+s.org+'</div>'
      + '<div style="font-size:.75rem;color:var(--ink-light);">📍 '+s.country+' · '+s.size+' · '+s.duration+'</div></div></div>'
      + '<div style="font-weight:700;font-size:1rem;color:var(--emerald-dark);line-height:1.3;margin-bottom:.5rem;">'+s.title+'</div>'
      + '<span style="font-size:.7rem;font-weight:700;padding:.2rem .6rem;border-radius:20px;background:var(--emerald-glow);color:var(--emerald);border:1px solid rgba(26,107,74,.25);">'+s.category+'</span>'
      + '</div>'
      + '<div style="padding:1.25rem 1.5rem;display:flex;flex-direction:column;gap:.85rem;">'
      + '<div><div style="font-size:.68rem;font-weight:800;text-transform:uppercase;letter-spacing:.09em;color:var(--gold);margin-bottom:.3rem;">Challenge</div><p style="font-size:.83rem;color:var(--ink-mid);line-height:1.6;">'+s.challenge+'</p></div>'
      + '<div><div style="font-size:.68rem;font-weight:800;text-transform:uppercase;letter-spacing:.09em;color:var(--emerald);margin-bottom:.3rem;">What They Did</div><p style="font-size:.83rem;color:var(--ink-mid);line-height:1.6;">'+s.action+'</p></div>'
      + '<div style="background:var(--cream);border-radius:10px;padding:.9rem 1rem;border-left:3px solid var(--emerald);">'
      + '<div style="font-size:.68rem;font-weight:800;text-transform:uppercase;letter-spacing:.09em;color:var(--emerald);margin-bottom:.3rem;">Result</div>'
      + '<p style="font-size:.83rem;color:var(--ink-mid);line-height:1.6;font-weight:600;">'+s.result+'</p></div>'
      + '<div style="background:rgba(200,153,58,.07);border:1px solid rgba(200,153,58,.2);border-radius:10px;padding:.85rem 1rem;">'
      + '<p style="font-size:.82rem;color:var(--ink-mid);line-height:1.6;font-style:italic;">"'+s.quote+'"</p></div>'
      + '<button onclick="loadCapability(\''+s.caps[0]+'\')" style="width:100%;background:var(--emerald);color:white;border:none;border-radius:8px;padding:.6rem;font-size:.82rem;font-weight:700;cursor:pointer;font-family:inherit;">Explore This Capability →</button>'
      + '</div></div>';
  }).join('');
}

