var RL_GUIDES = [
  { id:'g1', icon:'🗺️', title:'Strategic Planning: A 10-Step Process for Arab Region NGOs', category:'Strategy', readTime:'20 min read', featured:true, description:'A proven 10-step strategic planning process adapted for Arab region NGOs, including stakeholder analysis, environmental scanning, SWOT, and goal-setting frameworks that survive real-world pressure.', tags:['Strategy','Planning','Leadership'], capId:'strategy', keyPoints:['Start with an environmental scan before setting any goals','Mission statements must be specific enough to guide real decisions','Strategy is choosing what NOT to do as much as what to do','Review strategy quarterly, not just annually'] },
  { id:'g2', icon:'📊', title:'Theory of Change: A Practical Primer', category:'Programs', readTime:'8 min read', featured:false, description:'Clear explanation of theory of change with real examples from Arab region NGOs and a step-by-step process for building your own. Includes the difference between outputs, outcomes, and impact.', tags:['MEL','Programs','Impact'], capId:'programs', keyPoints:['Theory of change is not a diagram — it is a set of testable assumptions','Outputs are what you do; outcomes are the changes that result','Every assumption in your theory is a risk to be managed','Participatory approaches produce more accurate and more owned ToCs'] },
  { id:'g3', icon:'📖', title:'NGO Governance Fundamentals', category:'Governance', readTime:'12 min read', featured:false, description:'A comprehensive guide to nonprofit board structure, fiduciary duties, conflict of interest policies, and effective board-ED relationships. Includes a board effectiveness self-assessment.', tags:['Board','Governance','Leadership'], capId:'leadership', keyPoints:['Boards govern; staff manage — confusion here is the root of most board dysfunction','Fiduciary duty means acting in the best interest of the mission, not personal interests','A good board chair is the single most important factor in board effectiveness','Meeting frequency does not determine board quality — agenda quality does'] },
  { id:'g4', icon:'📣', title:'Ethical Storytelling in the Humanitarian Sector', category:'Communications', readTime:'14 min read', featured:true, description:'A practical guide to collecting and sharing beneficiary stories with dignity, informed consent, and cultural sensitivity. Includes sample consent forms, interview frameworks, and publication guidelines.', tags:['Comms','Ethics','Storytelling'], capId:'comms', keyPoints:['Informed consent is not a signature — it is an ongoing conversation','Avoid the "poverty porn" trap: show agency, not just suffering','Ask: would this person be proud to share this story about themselves?','Stories must reflect the complexity of lives, not simplify for donor comfort'] },
  { id:'g5', icon:'📈', title:'Nonprofit Financial Ratios Explained', category:'Finance', readTime:'10 min read', featured:false, description:'Explains the 8 most important financial health ratios for nonprofits, how to calculate them, what your numbers mean for sustainability, and how to present them to boards and donors.', tags:['Finance','Sustainability','Reporting'], capId:'finance', keyPoints:['Program expense ratio: aim for 65-85% — below 65% signals overhead; above 85% may signal under-investment in infrastructure','Three-month reserve is the minimum threshold for operational resilience','Donor concentration ratio: no single donor should exceed 30% of revenue','Liquidity ratio measures how many months of operations you can cover without new income'] },
  { id:'g6', icon:'🤝', title:'Partnership Agreements: What NGOs Must Include', category:'Operations', readTime:'7 min read', featured:false, description:'Essential clauses for NGO partnership agreements, MoUs, and sub-grant agreements. Covers governance, financial management, reporting requirements, intellectual property, and exit arrangements.', tags:['Legal','Partnerships','Finance'], capId:'systems', keyPoints:['Define decision-making authority explicitly — "joint decision" without a process creates deadlock','Include a financial management clause specifying who holds accounts and who can authorize payments','Specify IP ownership for any tools, content, or research produced jointly','Always include an exit clause with a minimum notice period and wind-down responsibilities'] },
  { id:'g7', icon:'🌐', title:'Digital Tools for Small NGOs: A Curated Guide', category:'Operations', readTime:'9 min read', featured:false, description:'Curated guide to free and low-cost digital tools for project management, financial tracking, MEL data collection, and communication for small nonprofits. Includes comparison tables and setup tips.', tags:['Digital','Tools','Operations'], capId:'systems', keyPoints:['Choose tools your team will actually use over the most feature-rich option','Free tiers of Notion, Trello, and Google Workspace cover 80% of small NGO needs','Kobo Toolbox is the gold standard for field data collection in resource-limited settings','Before adding any tool, ask: does this replace something, or just add complexity?'] },
  { id:'g8', icon:'🧭', title:'Staff Wellbeing in High-Pressure NGOs', category:'HR', readTime:'11 min read', featured:false, description:'Research-backed strategies for reducing burnout, building resilience, and creating psychologically safe workplaces in resource-constrained organizations. Includes a team wellbeing audit.', tags:['Wellbeing','HR','Team'], capId:'team', keyPoints:['Burnout in NGOs is structural, not individual — fix systems, not just symptoms','Psychological safety is the single strongest predictor of team performance and retention','Transparency about constraints reduces anxiety more than optimistic messaging','Regular 1:1s are the most cost-effective wellbeing intervention available to managers'] },
  { id:'g9', icon:'💰', title:'Winning Grants: What Donors Actually Look For', category:'Funding', readTime:'16 min read', featured:true, description:'A candid guide to what institutional donors prioritize when reviewing proposals — written from the perspective of former donor program officers. Covers the 12 most common rejection reasons.', tags:['Grants','Fundraising','Donors'], capId:'funding', keyPoints:['Funders fund organizations they trust, not just projects they like — credibility is built before you apply','Your problem statement must demonstrate you understand the issue better than the donor does','Theory of change is the section most proposals fail — it must be logical, specific, and testable','Budget narrative is the second most common rejection reason after weak theory of change'] },
  { id:'g10', icon:'🔧', title:'Building Organizational Systems That Survive Growth', category:'Operations', readTime:'13 min read', featured:false, description:'How to design HR, finance, and operations systems that scale with your organization without creating bureaucracy. Includes a five-domain infrastructure assessment framework.', tags:['Systems','Growth','Operations'], capId:'systems', keyPoints:['Systems exist to protect your mission, not to create paperwork','The right time to build a system is before you desperately need it','Simplicity is a design principle — every additional step reduces compliance','Systematize what is repeated; customize what is exceptional'] },
  { id:'g11', icon:'🌍', title:'MEL for Advocacy and Systems Change Programs', category:'Programs', readTime:'12 min read', featured:false, description:'How to design monitoring, evaluation, and learning systems for programs where change is long-term, non-linear, and difficult to attribute — including advocacy, policy, and behavior change programs.', tags:['MEL','Advocacy','Evaluation'], capId:'programs', keyPoints:['Systems change cannot be measured quarterly — design for learning, not attribution','Most Significant Change methodology is powerful for capturing unintended outcomes','Process indicators are essential when outcome evidence is unavailable','Contribution analysis is more honest than attribution for complex change programs'] },
  { id:'g12', icon:'🏛️', title:'Board Recruitment: How to Build the Board You Need', category:'Governance', readTime:'10 min read', featured:false, description:'A practical guide to identifying board skill gaps, creating compelling board member profiles, recruiting strategically, and onboarding new members effectively. Includes a board skills matrix.', tags:['Board','Governance','Recruitment'], capId:'leadership', keyPoints:['A skills matrix reveals whether your board has what your strategy requires','The best board candidates are busy people — your pitch must respect their time','Board recruitment is relationship-building before it is asking','Onboarding determines whether new board members become contributors or passengers'] }
];

