var RL_GLOSSARY = [
  { term:'Theory of Change', abbr:'ToC', category:'MEL', definition:'A detailed description of how and why a desired change is expected to happen in a particular context. It maps the causal pathway from inputs and activities through outputs and outcomes to long-term impact, and makes explicit the assumptions at each stage.' },
  { term:'Logic Model', abbr:'', category:'MEL', definition:'A visual representation of a program\'s theory of change showing the relationship between inputs, activities, outputs, outcomes, and impact. Often presented as a simple flow diagram. Less detailed than a full theory of change but more accessible for stakeholders.' },
  { term:'Results-Based Management', abbr:'RBM', category:'MEL', definition:'A management approach that focuses on performance and achievement of results — outputs, outcomes, and impacts — rather than activities and inputs. Requires clear indicators, baselines, targets, and regular data review to enable adaptive management.' },
  { term:'MEAL', abbr:'', category:'MEL', definition:'Monitoring, Evaluation, Accountability, and Learning. An expansion of the MEL framework that adds an explicit accountability component — ensuring that programs are accountable to beneficiaries and communities, not just donors.' },
  { term:'Key Performance Indicator', abbr:'KPI', category:'MEL', definition:'A quantifiable metric used to measure progress toward a specific goal or objective. Good KPIs are SMART (Specific, Measurable, Achievable, Relevant, Time-bound), have a baseline and a target, and are reviewed on a regular cycle.' },
  { term:'Baseline', abbr:'', category:'MEL', definition:'The initial measurement of an indicator before a program or intervention begins. Baselines are essential for measuring change — without knowing where you started, you cannot measure how far you have come. Establishing baselines is often underinvested.' },
  { term:'Cost-Effectiveness Analysis', abbr:'CEA', category:'Finance', definition:'A method of comparing the relative costs and outcomes of different programs or approaches. Expressed as cost per unit of outcome achieved (e.g., cost per beneficiary, cost per student enrolled). Increasingly required by institutional donors.' },
  { term:'Unrestricted Funds', abbr:'', category:'Finance', definition:'Income that can be used by the organization for any purpose at the discretion of leadership. Unrestricted funds provide organizational flexibility and are essential for covering core costs, emergency responses, and strategic investments not covered by specific grants.' },
  { term:'Restricted Funds', abbr:'', category:'Finance', definition:'Income designated by the donor for a specific purpose, program, or time period. Organizations must spend restricted funds only as designated. Tracking restricted funds requires careful accounting to ensure compliance with donor conditions.' },
  { term:'Liquidity Ratio', abbr:'', category:'Finance', definition:'A measure of an organization\'s ability to meet short-term financial obligations. Calculated as current assets divided by current liabilities. A ratio above 1.5 is generally considered healthy for nonprofits.' },
  { term:'Reserve Fund', abbr:'', category:'Finance', definition:'Unrestricted funds set aside to protect organizational continuity during periods of reduced income or unexpected expenditure. Best practice is to maintain a reserve equivalent to 3–6 months of core operating costs.' },
  { term:'Overhead Ratio', abbr:'', category:'Finance', definition:'The percentage of total expenditure spent on administration and fundraising (as opposed to programs). Sometimes called the "overhead myth ratio." Most credible watchdogs recommend evaluating overhead in context rather than treating low overhead as inherently virtuous.' },
  { term:'Due Diligence', abbr:'', category:'Funding', definition:'The process by which a funder or partner investigates an organization before committing resources. Typically covers legal registration, governance, financial management, programmatic capacity, and safeguarding policies. Strong due diligence readiness signals organizational maturity.' },
  { term:'Call for Proposals', abbr:'CFP', category:'Funding', definition:'A formal invitation from a donor or grant-maker for organizations to submit project proposals for funding. Also called Request for Proposals (RFP) or Expression of Interest (EoI). CFPs typically specify eligible applicants, geographic focus, thematic priorities, and submission requirements.' },
  { term:'No-Cost Extension', abbr:'NCE', category:'Funding', definition:'An extension to the implementation period of a grant without additional funding. NCEs are requested when a program needs more time to achieve its objectives due to implementation delays, context changes, or unforeseen challenges. Most donors allow one NCE per grant.' },
  { term:'Co-Financing', abbr:'', category:'Funding', definition:'Contributions to a project\'s budget from sources other than the primary donor — including the implementing organization\'s own funds, other grants, or in-kind contributions. Many institutional donors require a co-financing percentage as a sign of organizational commitment.' },
  { term:'Capacity Building', abbr:'', category:'General', definition:'Investments in the knowledge, skills, systems, and tools that enable an organization to perform its mission more effectively. True capacity building addresses root causes of organizational weakness, not just symptoms, and produces sustainable improvements that outlast the intervention.' },
  { term:'Safeguarding', abbr:'', category:'HR', definition:'The policies, systems, and practices that protect vulnerable people — particularly children and adults at risk — from abuse, exploitation, and harm by staff, volunteers, or partners. Robust safeguarding includes prevention, reporting, investigation, and remediation components.' },
  { term:'PSEA', abbr:'', category:'HR', definition:'Prevention of Sexual Exploitation and Abuse. A specific safeguarding framework addressing the most serious forms of abuse in humanitarian and development contexts. Increasingly required by institutional donors as a prerequisite for funding eligibility.' },
  { term:'Whistleblowing Policy', abbr:'', category:'HR', definition:'A formal mechanism allowing staff, volunteers, or partners to report concerns about misconduct, fraud, or policy violations — with protection from retaliation. An effective whistleblowing policy includes multiple reporting channels and a clear investigation process.' },
  { term:'Psychological Safety', abbr:'', category:'Team', definition:'A team climate in which members feel safe to speak up, take risks, share concerns, and challenge ideas without fear of punishment or humiliation. Research by Amy Edmondson at Harvard shows psychological safety is the single strongest predictor of team learning and performance.' },
  { term:'RACI Matrix', abbr:'', category:'Operations', definition:'A responsibility assignment framework that clarifies who is Responsible (does the work), Accountable (owns the outcome), Consulted (provides input), and Informed (kept updated) for each task or decision. Prevents confusion, duplication, and decision paralysis.' },
  { term:'Stakeholder Mapping', abbr:'', category:'Strategy', definition:'The process of identifying all parties affected by or influencing an organization\'s work, assessing their power and interest, and designing differentiated engagement strategies for each group. Essential for both program design and organizational strategy.' },
  { term:'PESTLE Analysis', abbr:'', category:'Strategy', definition:'A structured environmental scanning framework covering Political, Economic, Social, Technological, Legal, and Environmental factors. Used to identify external trends and forces that may create opportunities or threats for an organization\'s mission and operations.' },
  { term:'Strategic Plan', abbr:'', category:'Strategy', definition:'A document that defines an organization\'s direction over a multi-year period, typically 3–5 years. A good strategic plan includes mission reaffirmation, environmental analysis, strategic priorities, measurable goals, implementation responsibilities, and a review cycle.' },
  { term:'Fiduciary Duty', abbr:'', category:'Governance', definition:'The legal and ethical obligation of board members to act in the best interests of the organization and its mission. Includes the duties of care (make informed decisions), loyalty (avoid conflicts of interest), and obedience (follow the organization\'s mission and legal requirements).' }
];

var currentResLibTab = 'guides';
var currentResLibFilter = 'All';
var resLibSearchVal = '';
var currentGlossaryLetter = 'All';

function showResourceLibraryPage() {
  showPage('resource-library-page', 'Back to Home');
  currentResLibTab = 'guides';
  currentResLibFilter = 'All';
  resLibSearchVal = '';
  renderResourceLibrary();
}

function switchResLibTab(tab) {
  currentResLibTab = tab;
  currentResLibFilter = 'All';
  resLibSearchVal = '';
  currentGlossaryLetter = 'All';
  renderResourceLibrary();
}

function filterResourceLibrary(val) {
  resLibSearchVal = val;
  renderResourceLibrary();
}

function filterResLibCat(cat) {
  currentResLibFilter = cat;
  renderResourceLibrary();
}

function filterGlossaryLetter(letter) {
  currentGlossaryLetter = letter;
  renderResourceLibrary();
}

function openResourceModal(type, id) {
  var item = null;
  if (type === 'guide') item = RL_GUIDES.find(function(g){return g.id===id;});
  else if (type === 'checklist') item = RL_CHECKLISTS.find(function(c){return c.id===id;});
  else if (type === 'swipe') item = RL_SWIPEFILES.find(function(s){return s.id===id;});
  if (!item) return;

  var modal = document.getElementById('resLibModal');
  if (!modal) {
    modal = document.createElement('div');
    modal.id = 'resLibModal';
    modal.style.cssText = 'display:none;position:fixed;inset:0;z-index:3000;background:rgba(4,12,8,.88);backdrop-filter:blur(8px);overflow-y:auto;';
    modal.addEventListener('click', function(e){if(e.target===modal) closeResLibModal();});
    document.body.appendChild(modal);
  }

  var accentColor = type==='guide'?'var(--emerald)':type==='checklist'?'#2563eb':'#9333ea';
  var accentBg = type==='guide'?'rgba(26,107,74,.08)':type==='checklist'?'rgba(37,99,235,.08)':'rgba(147,51,234,.08)';
  var typeLabel = type==='guide'?'Guide & Article':type==='checklist'?'Checklist':'Swipe File';

  var innerHtml = '<div style="max-width:720px;margin:2rem auto;padding:0 1rem 5rem;">'
    + '<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:1.25rem;">'
    + '<button onclick="closeResLibModal()" style="display:flex;align-items:center;gap:.4rem;background:rgba(255,255,255,.1);border:1px solid rgba(255,255,255,.2);color:rgba(255,255,255,.8);border-radius:8px;padding:.45rem .85rem;font-size:.8rem;font-weight:600;cursor:pointer;font-family:inherit;">← Back to Library</button>'
    + '<button onclick="closeResLibModal()" style="background:rgba(255,255,255,.1);border:1px solid rgba(255,255,255,.2);color:rgba(255,255,255,.8);width:34px;height:34px;border-radius:50%;font-size:1rem;cursor:pointer;line-height:1;">✕</button>'
    + '</div>'
    + '<div style="background:#fff;border-radius:20px;overflow:hidden;">'
    + '<div style="background:linear-gradient(135deg,var(--emerald-dark),var(--emerald));padding:2rem 2rem 1.5rem;">'
    + '<div style="display:flex;align-items:center;gap:.6rem;margin-bottom:.75rem;">'
    + '<span style="font-size:2rem;">' + item.icon + '</span>'
    + '<span style="background:rgba(255,255,255,.2);color:white;font-size:.68rem;font-weight:700;letter-spacing:.06em;text-transform:uppercase;padding:.2rem .65rem;border-radius:20px;">' + typeLabel + '</span>'
    + '</div>'
    + '<h2 style="font-family:\'Cormorant Garamond\',serif;font-size:1.6rem;font-weight:700;color:white;line-height:1.3;margin-bottom:.5rem;">' + item.title + '</h2>'
    + (item.readTime ? '<div style="font-size:.78rem;color:rgba(255,255,255,.7);">📖 ' + item.readTime + '</div>' : '')
    + (item.items ? '<div style="font-size:.78rem;color:rgba(255,255,255,.7);">✅ ' + item.items + ' items</div>' : '')
    + '</div>'
    + '<div style="padding:1.75rem 2rem;">'
    + '<p style="font-size:.92rem;color:var(--ink-light);line-height:1.75;margin-bottom:1.5rem;">' + item.description + '</p>';

  if (type === 'guide' && item.keyPoints) {
    innerHtml += '<div style="background:var(--cream);border-radius:14px;padding:1.25rem 1.5rem;margin-bottom:1.5rem;">'
      + '<div style="font-size:.72rem;font-weight:700;letter-spacing:.1em;text-transform:uppercase;color:var(--emerald);margin-bottom:.85rem;">Key Takeaways</div>';
    item.keyPoints.forEach(function(pt) {
      innerHtml += '<div style="display:flex;gap:.75rem;margin-bottom:.6rem;align-items:flex-start;">'
        + '<span style="color:var(--emerald);font-size:1rem;flex-shrink:0;margin-top:.05rem;">✦</span>'
        + '<span style="font-size:.86rem;color:var(--ink-mid);line-height:1.6;">' + pt + '</span></div>';
    });
    innerHtml += '</div>';
  }

  if ((type === 'checklist' || type === 'swipe') && item.sections) {
    var sectionLabel = type==='checklist' ? 'Checklist Sections' : 'What\'s Included';
    innerHtml += '<div style="background:var(--cream);border-radius:14px;padding:1.25rem 1.5rem;margin-bottom:1.5rem;">'
      + '<div style="font-size:.72rem;font-weight:700;letter-spacing:.1em;text-transform:uppercase;color:'+accentColor+';margin-bottom:.85rem;">' + sectionLabel + '</div>';
    var listItems = item.sections || item.templates || [];
    listItems.forEach(function(s, i) {
      innerHtml += '<div style="display:flex;gap:.75rem;margin-bottom:.5rem;align-items:flex-start;">'
        + '<span style="min-width:22px;height:22px;border-radius:50%;background:'+accentColor+';color:#fff;font-size:.62rem;font-weight:800;display:flex;align-items:center;justify-content:center;flex-shrink:0;margin-top:.05rem;">'+(i+1)+'</span>'
        + '<span style="font-size:.85rem;color:var(--ink-mid);line-height:1.6;">' + s + '</span></div>';
    });
    innerHtml += '</div>';
  }

  if (type === 'swipe' && item.templates && !item.sections) {
    innerHtml += '<div style="background:var(--cream);border-radius:14px;padding:1.25rem 1.5rem;margin-bottom:1.5rem;">'
      + '<div style="font-size:.72rem;font-weight:700;letter-spacing:.1em;text-transform:uppercase;color:'+accentColor+';margin-bottom:.85rem;">Templates Included</div>';
    item.templates.forEach(function(t, i) {
      innerHtml += '<div style="display:flex;gap:.75rem;margin-bottom:.5rem;align-items:flex-start;">'
        + '<span style="min-width:22px;height:22px;border-radius:50%;background:'+accentColor+';color:#fff;font-size:.62rem;font-weight:800;display:flex;align-items:center;justify-content:center;flex-shrink:0;margin-top:.05rem;">'+(i+1)+'</span>'
        + '<span style="font-size:.85rem;color:var(--ink-mid);line-height:1.6;">' + t + '</span></div>';
    });
    innerHtml += '</div>';
  }

  innerHtml += '<div style="display:flex;gap:.75rem;flex-wrap:wrap;">'
    + '<button onclick="loadCapability(\''+item.capId+'\');closeResLibModal();" style="flex:1;min-width:160px;background:var(--emerald);color:white;border:none;border-radius:10px;padding:.75rem 1.25rem;font-size:.85rem;font-weight:700;cursor:pointer;font-family:inherit;">Go to Capability →</button>'
    + '<button onclick="downloadResourceAsPDF(\''+type+'\',\''+item.id+'\')" style="flex:1;min-width:130px;background:#f0faf5;color:var(--emerald);border:1.5px solid rgba(26,107,74,.3);border-radius:10px;padding:.75rem 1.25rem;font-size:.85rem;font-weight:700;cursor:pointer;font-family:inherit;">PDF</button>'
    + '<button onclick="downloadResourceAsDoc(\''+type+'\',\''+item.id+'\')" style="flex:1;min-width:130px;background:#eff6ff;color:#2563eb;border:1.5px solid rgba(37,99,235,.3);border-radius:10px;padding:.75rem 1.25rem;font-size:.85rem;font-weight:700;cursor:pointer;font-family:inherit;">Word</button>'
    + '</div>'
    + '</div></div></div>';

  modal.innerHTML = innerHtml;
  modal.style.display = 'block';
  document.body.style.overflow = 'hidden';
}

function closeResLibModal() {
  var modal = document.getElementById('resLibModal');
  if (modal) modal.style.display = 'none';
  document.body.style.overflow = '';
}

// ── Resource Library Download Helpers ─────────────────────────────────────────

function _getResItem(type, id) {
  if (type === 'guide')     return RL_GUIDES.find(function(g){return g.id===id;});
  if (type === 'checklist') return RL_CHECKLISTS.find(function(c){return c.id===id;});
  if (type === 'swipe')     return RL_SWIPEFILES.find(function(s){return s.id===id;});
  return null;
}

function _buildResLibSections(type, item) {
  // Build sections array compatible with downloadToolAsPDF / downloadToolAsDocx
  var sections = [];
  var typeLabel = type==='guide' ? 'Guide & Article' : type==='checklist' ? 'Checklist' : 'Swipe File';

  // Section 1: Overview
  var overviewContent = item.description + '\n\n';
  if (item.readTime)  overviewContent += 'Reading time: ' + item.readTime + '\n';
  if (item.items)     overviewContent += 'Total items: ' + item.items + '\n';
  overviewContent += 'Capability area: ' + (item.capId ? item.capId.charAt(0).toUpperCase() + item.capId.slice(1) : '') + '\n';
  overviewContent += 'Tags: ' + (item.tags||[]).join(', ');
  sections.push({ title: 'Overview', content: overviewContent });

  // Section 2: Key content based on type
  if (type === 'guide' && item.keyPoints && item.keyPoints.length) {
    sections.push({
      title: 'Key Takeaways',
      content: item.keyPoints.map(function(pt, i){ return (i+1) + '. ' + pt; }).join('\n\n')
    });
    // Application section
    sections.push({
      title: 'Applying This in Your Organization',
      content: 'Reflection questions:\n\n1. Which of the key takeaways above is most relevant to your current situation?\n_______________________________________________\n\n2. What specific action will you take based on this guide?\n_______________________________________________\n\n3. Who else in your team needs to read this?\n_______________________________________________\n\n4. What is your target date to implement the primary recommendation?\n_______________________________________________\n\nNotes:\n_______________________________________________\n_______________________________________________\n_______________________________________________'
    });
  }

  if (type === 'checklist' && item.sections && item.sections.length) {
    sections.push({
      title: 'Checklist Sections',
      content: item.sections.map(function(s, i){ return (i+1) + '. ' + s; }).join('\n\n')
    });
    // Full checklist content
    var checkContent = '';
    item.sections.forEach(function(sec) {
      var numItems = parseInt(sec.match(/\((\d+)/)) || 5;
      checkContent += sec + '\n';
      for (var j = 1; j <= numItems; j++) {
        checkContent += '  \u25a1  Item ' + j + ': _______________________________________________\n';
      }
      checkContent += '\n';
    });
    checkContent += '\nOverall Status:\n  \u25a1 Complete    \u25a1 In Progress    \u25a1 Not Started\n\nCompleted by: _______________  Date: _______________\nReviewed by: _______________  Next review: _______________';
    sections.push({ title: 'Full Checklist', content: checkContent });
  }

  if (type === 'swipe') {
    var listItems = item.templates || item.sections || [];
    if (listItems.length) {
      sections.push({
        title: 'Templates & Formats Included',
        content: listItems.map(function(t, i){ return (i+1) + '. ' + t; }).join('\n\n')
      });
      // Template workspace
      var workContent = 'Use the space below to adapt each template for your organization:\n\n';
      listItems.slice(0, 4).forEach(function(t, i) {
        workContent += 'Template ' + (i+1) + ': ' + t + '\n';
        workContent += '_______________________________________________\n';
        workContent += '_______________________________________________\n';
        workContent += '_______________________________________________\n\n';
      });
      sections.push({ title: 'My Adapted Templates', content: workContent });
    }
  }

  // Final section: Action plan
  sections.push({
    title: 'My Action Plan',
    content: 'Based on this resource, I will:\n\nAction 1: _______________________________________________\nOwner: _______________  By when: _______________\n\nAction 2: _______________________________________________\nOwner: _______________  By when: _______________\n\nAction 3: _______________________________________________\nOwner: _______________  By when: _______________\n\nShare this with: _______________________________________________\nReview progress on: _______________________________________________'
  });

  return sections;
}

function downloadResourceAsPDF(type, id) {
  var item = _getResItem(type, id);
  if (!item) { showToast('Resource not found.'); return; }
  var sections = _buildResLibSections(type, item);
  var typeLabel = type==='guide' ? 'Guide' : type==='checklist' ? 'Checklist' : 'Swipe File';
  var data = { subtitle: typeLabel + ' · ALJUDE Academy Resource Library · ' + (item.tags||[]).join(', '), sections: sections };
  downloadToolAsPDF(item.title, data);
  showToast(item.title + ' downloading as PDF…');
}

function downloadResourceAsDoc(type, id) {
  var item = _getResItem(type, id);
  if (!item) { showToast('Resource not found.'); return; }
  var sections = _buildResLibSections(type, item);
  var typeLabel = type==='guide' ? 'Guide' : type==='checklist' ? 'Checklist' : 'Swipe File';
  var data = { subtitle: typeLabel + ' · ALJUDE Academy Resource Library · ' + (item.tags||[]).join(', '), sections: sections };
  downloadToolAsDocx(item.title, data);
}

function renderResourceLibrary() {
  // Render tab buttons
  var tabsEl = document.getElementById('resLibTabs');
  if (tabsEl) {
    var tabs = [
      {id:'guides', label:'📖 Guides & Articles', count: RL_GUIDES.length},
      {id:'checklists', label:'✅ Checklists', count: RL_CHECKLISTS.length},
      {id:'swipe', label:'🗂️ Swipe Files', count: RL_SWIPEFILES.length},
      {id:'glossary', label:'📘 Glossary', count: RL_GLOSSARY.length}
    ];
    tabsEl.innerHTML = tabs.map(function(t) {
      var isActive = currentResLibTab === t.id;
      return '<button onclick="switchResLibTab(\''+t.id+'\')" style="display:flex;align-items:center;gap:.45rem;padding:.6rem 1.15rem;border-radius:10px;font-size:.83rem;font-weight:700;cursor:pointer;font-family:inherit;border:1.5px solid '+(isActive?'var(--emerald)':'var(--border)')+';background:'+(isActive?'var(--emerald)':'white')+';color:'+(isActive?'white':'var(--ink-light)')+';transition:all .18s;">'
        + t.label
        + '<span style="background:'+(isActive?'rgba(255,255,255,.3)':'var(--cream-dark)')+';color:'+(isActive?'white':'var(--ink-light)')+';font-size:.65rem;font-weight:800;padding:.1rem .4rem;border-radius:20px;">' + t.count + '</span>'
        + '</button>';
    }).join('');
  }

  // Render search bar
  var searchEl = document.getElementById('resLibSearch');
  if (searchEl) searchEl.value = resLibSearchVal;

  var content = document.getElementById('resLibContent');
  if (!content) return;

  if (currentResLibTab === 'glossary') {
    renderGlossary(content);
    return;
  }

  // Category filters for current tab
  var data = currentResLibTab === 'guides' ? RL_GUIDES : currentResLibTab === 'checklists' ? RL_CHECKLISTS : RL_SWIPEFILES;
  var cats = ['All'];
  data.forEach(function(item) { if (cats.indexOf(item.category) < 0) cats.push(item.category); });

  var filterHtml = '<div style="display:flex;gap:.5rem;flex-wrap:wrap;margin-bottom:1.5rem;">'
    + cats.map(function(cat) {
      var isActive = currentResLibFilter === cat;
      return '<button onclick="filterResLibCat(\''+cat+'\')" style="padding:.35rem .8rem;border-radius:20px;font-size:.75rem;font-weight:700;cursor:pointer;font-family:inherit;border:1.5px solid '+(isActive?'var(--emerald)':'var(--border)')+';background:'+(isActive?'var(--emerald)':'white')+';color:'+(isActive?'white':'var(--ink-light)')+';transition:all .18s;">'+cat+'</button>';
    }).join('')
    + '</div>';

  var filtered = data.filter(function(item) {
    var matchCat = currentResLibFilter === 'All' || item.category === currentResLibFilter;
    var matchSearch = !resLibSearchVal || item.title.toLowerCase().indexOf(resLibSearchVal.toLowerCase()) >= 0 || item.description.toLowerCase().indexOf(resLibSearchVal.toLowerCase()) >= 0;
    return matchCat && matchSearch;
  });

  var typeKey = currentResLibTab === 'guides' ? 'guide' : currentResLibTab === 'checklists' ? 'checklist' : 'swipe';
  var accentColor = typeKey==='guide'?'var(--emerald)':typeKey==='checklist'?'#2563eb':'#9333ea';
  var featuredItems = filtered.filter(function(i){return i.featured;});
  var regularItems = filtered.filter(function(i){return !i.featured;});

  var gridHtml = '';

  // Featured strip (guides only)
  if (currentResLibTab === 'guides' && featuredItems.length && !resLibSearchVal && currentResLibFilter === 'All') {
    gridHtml += '<div style="margin-bottom:2rem;">'
      + '<div style="font-size:.72rem;font-weight:700;letter-spacing:.12em;text-transform:uppercase;color:var(--gold);margin-bottom:.85rem;">⭐ Featured Reads</div>'
      + '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(300px,1fr));gap:1rem;">'
      + featuredItems.map(function(r) { return renderResCard(r, typeKey, accentColor, true); }).join('')
      + '</div></div>'
      + '<div style="font-size:.72rem;font-weight:700;letter-spacing:.12em;text-transform:uppercase;color:var(--ink-light);margin-bottom:.85rem;">All Resources</div>';
  }

  if (!filtered.length) {
    gridHtml += '<div style="text-align:center;padding:3rem;color:var(--ink-light);">No resources found. Try adjusting your filter or search.</div>';
  } else {
    var itemsToShow = (currentResLibTab === 'guides' && !resLibSearchVal && currentResLibFilter === 'All') ? regularItems : filtered;
    gridHtml += '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(290px,1fr));gap:1rem;">'
      + itemsToShow.map(function(r) { return renderResCard(r, typeKey, accentColor, false); }).join('')
      + '</div>';
  }

  content.innerHTML = filterHtml + gridHtml;
}

function renderResCard(r, typeKey, accentColor, isFeatured) {
  var borderColor = isFeatured ? 'var(--gold)' : 'var(--border)';
  var accentBg = typeKey==='guide'?'rgba(26,107,74,.07)':typeKey==='checklist'?'rgba(37,99,235,.07)':'rgba(147,51,234,.07)';
  var typeLabel = typeKey==='guide'?'Guide':typeKey==='checklist'?'Checklist':'Swipe File';
  var metaInfo = r.readTime ? '📖 '+r.readTime : r.items ? '✅ '+r.items+' items' : '';
  var ctaLabel = typeKey==='guide'?'Read Article →':typeKey==='checklist'?'View Checklist →':'Get Templates →';

  return '<div style="background:white;border:1.5px solid '+borderColor+';border-radius:16px;padding:1.35rem;transition:all .2s;display:flex;flex-direction:column;" onmouseover="this.style.borderColor=\''+accentColor+'\';this.style.boxShadow=\'0 6px 24px rgba(26,107,74,.1)\';this.style.transform=\'translateY(-2px)\'" onmouseout="this.style.borderColor=\''+borderColor+'\';this.style.boxShadow=\'\';this.style.transform=\'\'">'
    + '<div style="cursor:pointer;" onclick="openResourceModal(\''+typeKey+'\',\''+r.id+'\')">'
    + '<div style="display:flex;align-items:flex-start;gap:.75rem;margin-bottom:.85rem;">'
    + '<div style="width:44px;height:44px;min-width:44px;border-radius:12px;background:'+accentBg+';display:flex;align-items:center;justify-content:center;font-size:1.25rem;">'+r.icon+'</div>'
    + '<div style="flex:1;">'
    + '<div style="display:flex;align-items:center;gap:.45rem;margin-bottom:.3rem;flex-wrap:wrap;">'
    + '<span style="font-size:.62rem;font-weight:800;letter-spacing:.06em;text-transform:uppercase;color:'+accentColor+';background:'+accentBg+';padding:.18rem .5rem;border-radius:5px;">'+typeLabel+'</span>'
    + (isFeatured ? '<span style="font-size:.62rem;font-weight:800;letter-spacing:.06em;text-transform:uppercase;color:var(--gold);background:rgba(200,153,58,.1);padding:.18rem .5rem;border-radius:5px;">Featured</span>' : '')
    + '</div>'
    + '<div style="font-weight:800;font-size:.9rem;color:var(--ink);line-height:1.35;">'+r.title+'</div>'
    + '</div></div>'
    + '<p style="font-size:.81rem;color:var(--ink-light);line-height:1.65;flex:1;margin-bottom:.85rem;">'+r.description.substring(0,150)+'…</p>'
    + (metaInfo ? '<div style="font-size:.72rem;color:var(--ink-pale);margin-bottom:.7rem;">'+metaInfo+'</div>' : '')
    + '<div style="display:flex;flex-wrap:wrap;gap:.3rem;margin-bottom:.85rem;">'
    + r.tags.map(function(tag) { return '<span style="font-size:.65rem;font-weight:600;padding:.15rem .5rem;border-radius:20px;background:'+accentBg+';color:'+accentColor+';border:1px solid '+accentColor.replace(')',',0.2)').replace('var(','rgba(26,107,74,')+';">'+tag+'</span>'; }).join('')
    + '</div>'
    + '<div style="font-size:.8rem;font-weight:700;color:'+accentColor+';margin-bottom:.85rem;">'+ctaLabel+'</div>'
    + '</div>'
    + '<div style="display:flex;gap:.5rem;padding-top:.85rem;border-top:1px solid var(--border);">'
    + '<button onclick="event.stopPropagation();downloadResourceAsPDF(\''+typeKey+'\',\''+r.id+'\')" style="flex:1;background:'+accentBg+';color:'+accentColor+';border:1.5px solid '+accentColor.replace('var(--emerald)','rgba(26,107,74,.25)').replace('#2563eb','rgba(37,99,235,.25)').replace('#9333ea','rgba(147,51,234,.25)')+';border-radius:8px;padding:.45rem .5rem;font-size:.75rem;font-weight:700;cursor:pointer;font-family:inherit;transition:all .15s;" onmouseover="this.style.opacity=\'.8\'" onmouseout="this.style.opacity=\'1\'">PDF</button>'
    + '<button onclick="event.stopPropagation();downloadResourceAsDoc(\''+typeKey+'\',\''+r.id+'\')" style="flex:1;background:#eff6ff;color:#2563eb;border:1.5px solid rgba(37,99,235,.25);border-radius:8px;padding:.45rem .5rem;font-size:.75rem;font-weight:700;cursor:pointer;font-family:inherit;transition:all .15s;" onmouseover="this.style.opacity=\'.8\'" onmouseout="this.style.opacity=\'1\'">Word</button>'
    + '</div>'
    + '</div>';
}

function renderGlossary(container) {
  var alphabet = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ'.split('');
  var usedLetters = {};
  RL_GLOSSARY.forEach(function(g) { usedLetters[g.term[0].toUpperCase()] = true; });

  var letterNavHtml = '<div style="display:flex;flex-wrap:wrap;gap:.35rem;margin-bottom:1.75rem;">'
    + '<button onclick="filterGlossaryLetter(\'All\')" style="padding:.3rem .75rem;border-radius:20px;font-size:.75rem;font-weight:700;cursor:pointer;font-family:inherit;border:1.5px solid '+(currentGlossaryLetter==='All'?'var(--emerald)':'var(--border)')+';background:'+(currentGlossaryLetter==='All'?'var(--emerald)':'white')+';color:'+(currentGlossaryLetter==='All'?'white':'var(--ink-light)')+';">All</button>'
    + alphabet.map(function(l) {
      var hasItems = usedLetters[l];
      var isActive = currentGlossaryLetter === l;
      if (!hasItems) return '<span style="padding:.3rem .55rem;font-size:.75rem;font-weight:700;color:var(--ink-pale);opacity:.35;">'+l+'</span>';
      return '<button onclick="filterGlossaryLetter(\''+l+'\')" style="padding:.3rem .55rem;border-radius:8px;font-size:.75rem;font-weight:700;cursor:pointer;font-family:inherit;border:1.5px solid '+(isActive?'var(--emerald)':'var(--border)')+';background:'+(isActive?'var(--emerald)':'white')+';color:'+(isActive?'white':'var(--ink-light)')+';">'+l+'</button>';
    }).join('')
    + '</div>';

  var filtered = RL_GLOSSARY.filter(function(g) {
    var matchLetter = currentGlossaryLetter === 'All' || g.term[0].toUpperCase() === currentGlossaryLetter;
    var matchSearch = !resLibSearchVal || g.term.toLowerCase().indexOf(resLibSearchVal.toLowerCase()) >= 0 || g.definition.toLowerCase().indexOf(resLibSearchVal.toLowerCase()) >= 0;
    return matchLetter && matchSearch;
  }).sort(function(a, b) { return a.term.localeCompare(b.term); });

  // Group by letter
  var groups = {};
  filtered.forEach(function(g) {
    var letter = g.term[0].toUpperCase();
    if (!groups[letter]) groups[letter] = [];
    groups[letter].push(g);
  });

  var catColors = {MEL:'#16a34a', Finance:'#2563eb', Funding:'#9333ea', HR:'#dc2626', Team:'#ea580c', Operations:'#0891b2', Strategy:'#7c3aed', Governance:'#854d0e', General:'#6b7280'};

  var listHtml = '';
  Object.keys(groups).sort().forEach(function(letter) {
    listHtml += '<div style="margin-bottom:2rem;">'
      + '<div style="font-family:\'Cormorant Garamond\',serif;font-size:2rem;font-weight:700;color:var(--emerald);margin-bottom:.85rem;border-bottom:2px solid var(--border);padding-bottom:.4rem;">'+letter+'</div>'
      + groups[letter].map(function(g) {
        var catColor = catColors[g.category] || '#6b7280';
        return '<div style="background:white;border:1.5px solid var(--border);border-radius:14px;padding:1.25rem 1.35rem;margin-bottom:.75rem;transition:border-color .2s;" onmouseover="this.style.borderColor=\'var(--emerald)\'" onmouseout="this.style.borderColor=\'var(--border)\'">'
          + '<div style="display:flex;align-items:flex-start;justify-content:space-between;gap:1rem;margin-bottom:.5rem;flex-wrap:wrap;">'
          + '<div style="display:flex;align-items:center;gap:.6rem;flex-wrap:wrap;">'
          + '<span style="font-weight:800;font-size:.95rem;color:var(--ink);">'+g.term+'</span>'
          + (g.abbr ? '<span style="font-family:\'DM Mono\',monospace;font-size:.72rem;font-weight:600;color:var(--ink-light);background:var(--cream);padding:.1rem .4rem;border-radius:5px;">'+g.abbr+'</span>' : '')
          + '</div>'
          + '<span style="font-size:.62rem;font-weight:800;letter-spacing:.06em;text-transform:uppercase;color:'+catColor+';background:'+catColor+'18;padding:.18rem .55rem;border-radius:5px;white-space:nowrap;">'+g.category+'</span>'
          + '</div>'
          + '<p style="font-size:.85rem;color:var(--ink-light);line-height:1.7;margin:0;">'+g.definition+'</p>'
          + '</div>';
      }).join('')
      + '</div>';
  });

  if (!filtered.length) listHtml = '<div style="text-align:center;padding:3rem;color:var(--ink-light);">No glossary terms found.</div>';

  container.innerHTML = letterNavHtml + listHtml;
}

