var currentTrackId = null;

function showImprovementTracksPage() {
  navHistory = [];
  document.querySelectorAll('.page').forEach(function(p) { p.classList.remove('active'); });
  document.getElementById('improvement-tracks-page').classList.add('active');
  document.getElementById('navBackBtn').style.display = 'none';
  hideFloatingBack();
  currentCapId = null;
  currentSubCapIdx = null;
  currentTrackId = null;
  renderTracksGrid();
  window.scrollTo(0, 0);
}

function renderTracksGrid() {
  var grid = document.getElementById('tracksListGrid');
  if (!grid) return;
  grid.innerHTML = IMPROVEMENT_TRACKS.map(function(t) {
    var capsHtml = t.capLabels.map(function(lbl, i) {
      return '<span style="display:inline-flex;align-items:center;gap:.3rem;background:white;border:1px solid var(--border);border-radius:20px;padding:.22rem .65rem;font-size:.72rem;font-weight:600;color:var(--ink-mid);">' + t.capIcons[i] + ' ' + lbl + '</span>';
    }).join('');

    return '<div style="background:white;border:1.5px solid var(--border);border-radius:16px;overflow:hidden;cursor:pointer;transition:all .22s;display:flex;flex-direction:column;" onmouseover="this.style.borderColor=\'' + t.accentColor + '\';this.style.boxShadow=\'0 8px 32px rgba(0,0,0,.09)\';this.style.transform=\'translateY(-2px)\';" onmouseout="this.style.borderColor=\'var(--border)\';this.style.boxShadow=\'\';this.style.transform=\'\'" onclick="openTrack(\'' + t.id + '\')">'
      + '<div style="height:4px;background:' + t.accentColor + ';"></div>'
      + '<div style="padding:1.5rem 1.75rem;flex:1;display:flex;flex-direction:column;">'
      + '<div style="display:flex;align-items:flex-start;justify-content:space-between;margin-bottom:1rem;">'
      + '<div>'
      + '<div style="font-size:.65rem;font-weight:800;letter-spacing:.12em;text-transform:uppercase;color:' + t.accentColor + ';margin-bottom:.35rem;">Track ' + t.number + '</div>'
      + '<h3 style="font-family:\'Cormorant Garamond\',serif;font-size:1.35rem;font-weight:600;color:var(--ink);line-height:1.25;margin:0;">' + t.title + '</h3>'
      + '</div>'
      + '<div style="width:46px;height:46px;border-radius:12px;background:' + t.accentColor + '15;border:1.5px solid ' + t.accentColor + '30;display:flex;align-items:center;justify-content:center;font-size:1.5rem;flex-shrink:0;">' + t.icon + '</div>'
      + '</div>'
      + '<p style="font-size:.84rem;color:var(--ink-light);line-height:1.7;margin:0 0 1.1rem;flex:1;">' + t.tagline + '</p>'
      + '<div style="display:flex;gap:.4rem;flex-wrap:wrap;margin-bottom:1.25rem;">' + capsHtml + '</div>'
      + '<div style="display:flex;align-items:center;gap:1.25rem;margin-bottom:1.25rem;padding-top:.75rem;border-top:1px solid var(--border);">'
      + '<span style="font-size:.76rem;color:var(--ink-light);">⏱ <strong style="color:var(--ink);">' + t.duration + '</strong></span>'
      + '<span style="font-size:.76rem;color:var(--ink-light);">📦 <strong style="color:var(--ink);">' + t.deliverables.length + ' deliverables</strong></span>'
      + '</div>'
      + '<div style="display:flex;gap:.5rem;flex-wrap:wrap;">'
      + '<button onclick="event.stopPropagation();openTrack(\'' + t.id + '\')" style="flex:1;min-width:120px;background:' + t.accentColor + ';color:white;border:none;border-radius:9px;padding:.6rem 1rem;font-size:.8rem;font-weight:700;cursor:pointer;font-family:inherit;transition:opacity .15s;" onmouseover="this.style.opacity=\'.85\'" onmouseout="this.style.opacity=\'1\'">Start Track ' + t.number + ' →</button>'
      + '<button onclick="event.stopPropagation();openTrackAssessModal(\'' + t.id + '\')" style="background:white;color:#e85d04;border:1.5px solid #e85d0440;border-radius:9px;padding:.6rem .85rem;font-size:.78rem;font-weight:700;cursor:pointer;font-family:inherit;transition:all .15s;" onmouseover="this.style.background=\'#fff3ee\';this.style.borderColor=\'#e85d04\'" onmouseout="this.style.background=\'white\';this.style.borderColor=\'#e85d0440\'">Assess</button>'
      + '<button onclick="event.stopPropagation();openTrackLearnPage(\'' + t.id + '\')" style="background:white;color:#0369a1;border:1.5px solid #0369a140;border-radius:9px;padding:.6rem .85rem;font-size:.78rem;font-weight:700;cursor:pointer;font-family:inherit;transition:all .15s;" onmouseover="this.style.background=\'#eff6ff\';this.style.borderColor=\'#0369a1\'" onmouseout="this.style.background=\'white\';this.style.borderColor=\'#0369a140\'">' + (trackAssessResults[t.id] ? 'Learn (Personalised)' : 'Learn') + '</button>'
      + '<button onclick="event.stopPropagation();openTrackImprovePage(\'' + t.id + '\')" style="background:white;color:#6d28d9;border:1.5px solid #6d28d940;border-radius:9px;padding:.6rem .85rem;font-size:.78rem;font-weight:700;cursor:pointer;font-family:inherit;transition:all .15s;" onmouseover="this.style.background=\'#f5f3ff\';this.style.borderColor=\'#6d28d9\'" onmouseout="this.style.background=\'white\';this.style.borderColor=\'#6d28d940\'">' + (trackAssessResults[t.id] ? 'Improve (Personalised)' : 'Improve') + '</button>'
      + '</div>'
      + '</div></div>';
  }).join('');
}


// ─────────────────────────────────────────────────────────────────────────────
// TRACK ASSESS / LEARN / IMPROVE FUNCTIONALITY
// ─────────────────────────────────────────────────────────────────────────────

var trackAssessResults = {}; // { trackId: { answers: [0-4,...], level: 'beginner|intermediate|advanced', avg: n } }

var TRACK_ASSESS_QUESTIONS = {
  foundation: [
    { q: 'How clearly documented is your organization\'s current strategic plan?', opts: ['No written plan','Partially written','Documented but outdated','Clear and current','Fully aligned and reviewed regularly'] },
    { q: 'How strong is your board governance (defined roles, regular meetings, accountability)?', opts: ['No formal governance','Minimal structure','Some structure in place','Well-defined structure','Exemplary governance'] },
    { q: 'How well are your core operational systems (HR, finance, programs) documented?', opts: ['Not documented','1–2 systems only','Key systems documented','Most systems documented','All systems fully documented'] },
    { q: 'How regularly do you track KPIs and review organizational performance?', opts: ['Never','Occasionally','Quarterly','Monthly','Weekly with full team'] },
    { q: 'How confident are you in presenting your governance structure to a new funder?', opts: ['Not at all confident','Low confidence','Somewhat confident','Confident','Very confident'] }
  ],
  value: [
    { q: 'How clearly can you articulate your Theory of Change to an external stakeholder?', opts: ['Cannot explain it','Vague understanding','Some clarity','Clear explanation','Compelling and evidenced'] },
    { q: 'How well-packaged are your programs (budget, outcomes, funder-ready brief)?', opts: ['No packaged programs','Basic descriptions only','1 program packaged','2 programs packaged','Full portfolio packaged'] },
    { q: 'How effective is your one-page case for support in securing meetings?', opts: ['Don\'t have one','Very weak','Somewhat effective','Effective','Highly effective'] },
    { q: 'How well does your communications messaging resonate with funders and donors?', opts: ['No tailored messaging','Weak resonance','Some resonance','Good resonance','Consistently compelling'] },
    { q: 'How often do funders request more information after first contact?', opts: ['Never','Rarely','Sometimes','Often','Almost always'] }
  ],
  financial: [
    { q: 'How diversified is your current funding mix (across grant types, corporate, earned income)?', opts: ['Single source','2 sources','3 sources','4–5 sources','6+ diverse sources'] },
    { q: 'How strong is your grant proposal writing capability?', opts: ['No proposals written','1–2 weak proposals','Competent proposals','Strong proposals','Consistently funded proposals'] },
    { q: 'How active and well-managed is your funder pipeline (prospect list, tracking)?', opts: ['No pipeline','Informal list only','Basic tracker','Active pipeline of 10+','Pipeline of 20+ actively managed'] },
    { q: 'How reliable are your monthly financial reports (P&L, budget vs actual)?', opts: ['No reporting','Annual only','Quarterly','Monthly','Monthly with board review'] },
    { q: 'How confident are funders in your financial management based on feedback?', opts: ['Major concerns raised','Some concerns','Neutral feedback','Positive feedback','Consistently praised'] }
  ],
  story: [
    { q: 'How compelling and current is your organization\'s impact report?', opts: ['No impact report','Outdated report','Basic current report','Strong visual report','Award-worthy storytelling'] },
    { q: 'How well-developed is your donor stewardship system (touchpoints, follow-ups)?', opts: ['No system','Ad hoc follow-ups','Basic touchpoints','30/60/90-day plan','Automated + personal system'] },
    { q: 'How consistent and strategic is your communications calendar?', opts: ['No calendar','Reactive posting only','Occasional planning','12-week calendar','Full year planned'] },
    { q: 'How effectively does your team collect and share beneficiary stories?', opts: ['Never collected','Rarely and informally','Sometimes collected','Regularly collected','Systematic ethical collection'] },
    { q: 'How well does your donor communications retain existing donors year-over-year?', opts: ['No retention focus','<40% retention','40–60% retention','60–80% retention','>80% retention'] }
  ],
  _default: [
    { q: 'How would you rate your organization\'s current capability in this track\'s focus areas?', opts: ['Very low','Low','Moderate','High','Very high'] },
    { q: 'How often do you apply best practices in this capability area?', opts: ['Never','Rarely','Sometimes','Often','Always'] },
    { q: 'How confident is your team when executing this track\'s core activities?', opts: ['Not at all','Low confidence','Somewhat confident','Confident','Very confident'] },
    { q: 'How well does your organization document and review this capability area?', opts: ['Not at all','Minimal documentation','Some documentation','Well documented','Fully documented and reviewed'] },
    { q: 'How prepared are you to present this capability area to external stakeholders (funders, partners)?', opts: ['Not prepared','Low readiness','Somewhat prepared','Well prepared','Fully prepared'] }
  ]
};

function openTrackAssessModal(trackId) {
  var track = IMPROVEMENT_TRACKS.find(function(t) { return t.id === trackId; });
  if (!track) return;
  var qs = TRACK_ASSESS_QUESTIONS[trackId] || TRACK_ASSESS_QUESTIONS._default;
  var answers = (trackAssessResults[trackId] && trackAssessResults[trackId].answers) || [];

  var questionsHtml = qs.map(function(q, qi) {
    var optsHtml = q.opts.map(function(opt, oi) {
      var selected = answers[qi] === oi;
      var selStyle = selected ? 'background:' + track.accentColor + ';color:white;border-color:' + track.accentColor + ';' : 'background:white;color:#374151;border-color:#d1d5db;';
      return '<button onclick="updateTrackAssessOpt(\'' + trackId + '\',' + qi + ',' + oi + ',this)" data-qi="' + qi + '" data-oi="' + oi + '" style="display:block;width:100%;text-align:left;padding:.6rem .9rem;margin:.25rem 0;border-radius:8px;border:1.5px solid #d1d5db;cursor:pointer;font-family:inherit;font-size:.82rem;font-weight:500;transition:all .15s;' + selStyle + '">' + (oi+1) + '. ' + opt + '</button>';
    }).join('');
    return '<div style="margin-bottom:1.5rem;"><p style="font-weight:700;color:#111827;font-size:.9rem;margin:0 0 .6rem;">' + (qi+1) + '. ' + q.q + '</p>' + optsHtml + '</div>';
  }).join('');

  var overlay = document.createElement('div');
  overlay.id = 'trackAssessOverlay';
  overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.55);z-index:9999;display:flex;align-items:center;justify-content:center;padding:1rem;';
  overlay.innerHTML = '<div style="background:white;border-radius:18px;max-width:600px;width:100%;max-height:90vh;overflow-y:auto;box-shadow:0 24px 60px rgba(0,0,0,.25);">'
    + '<div style="background:linear-gradient(135deg,' + track.accentColor + ',#0d3d26);padding:1.75rem 2rem;border-radius:18px 18px 0 0;">'
    + '<div style="display:flex;align-items:center;justify-content:space-between;">'
    + '<div><div style="font-size:.65rem;font-weight:800;letter-spacing:.12em;text-transform:uppercase;color:rgba(255,255,255,.65);margin-bottom:.3rem;">Track ' + track.number + ' — Self-Assessment</div>'
    + '<div style="font-family:\'Cormorant Garamond\',serif;font-size:1.45rem;font-weight:700;color:white;">' + track.title + '</div></div>'
    + '<button onclick="closeTrackAssessModal()" style="background:rgba(255,255,255,.15);border:1.5px solid rgba(255,255,255,.3);color:white;border-radius:10px;padding:.5rem .9rem;cursor:pointer;font-family:inherit;font-size:.85rem;font-weight:700;">✕ Close</button>'
    + '</div>'
    + '<p style="color:rgba(255,255,255,.78);font-size:.84rem;margin:.75rem 0 0;line-height:1.6;">Answer all 5 questions honestly to receive personalised learning and improvement recommendations.</p>'
    + '</div>'
    + '<div style="padding:1.75rem 2rem;" id="trackAssessQuestions_' + trackId + '">' + questionsHtml + '</div>'
    + '<div style="padding:0 2rem 1.75rem;">'
    + '<button onclick="submitTrackAssess(\'' + trackId + '\')" style="width:100%;background:' + track.accentColor + ';color:white;border:none;border-radius:12px;padding:.85rem;font-size:.95rem;font-weight:700;cursor:pointer;font-family:inherit;">Submit Assessment →</button>'
    + '</div></div>';
  document.body.appendChild(overlay);
}

function updateTrackAssessOpt(trackId, qi, oi, btn) {
  var track = IMPROVEMENT_TRACKS.find(function(t) { return t.id === trackId; });
  if (!trackAssessResults[trackId]) trackAssessResults[trackId] = { answers: [] };
  trackAssessResults[trackId].answers[qi] = oi;
  // Update button styles in this question group
  var container = document.getElementById('trackAssessQuestions_' + trackId);
  if (!container) return;
  var allBtns = container.querySelectorAll('button[data-qi="' + qi + '"]');
  allBtns.forEach(function(b) {
    var isSelected = parseInt(b.getAttribute('data-oi')) === oi;
    b.style.background = isSelected ? track.accentColor : 'white';
    b.style.color = isSelected ? 'white' : '#374151';
    b.style.borderColor = isSelected ? track.accentColor : '#d1d5db';
  });
}

function closeTrackAssessModal() {
  var el = document.getElementById('trackAssessOverlay');
  if (el) el.remove();
}

function submitTrackAssess(trackId) {
  var qs = TRACK_ASSESS_QUESTIONS[trackId] || TRACK_ASSESS_QUESTIONS._default;
  if (!trackAssessResults[trackId]) trackAssessResults[trackId] = { answers: [] };
  var answers = trackAssessResults[trackId].answers;
  // Validate all answered
  for (var i = 0; i < qs.length; i++) {
    if (answers[i] === undefined || answers[i] === null) {
      alert('Please answer all ' + qs.length + ' questions before submitting.');
      return;
    }
  }
  var total = answers.reduce(function(s, v) { return s + v; }, 0);
  var avg = total / qs.length;
  var level = avg < 1 ? 'beginner' : avg < 2.5 ? 'intermediate' : 'advanced';
  trackAssessResults[trackId].avg = avg;
  trackAssessResults[trackId].level = level;
  closeTrackAssessModal();
  // Show toast
  var levelLabel = level === 'beginner' ? '🌱 Beginner' : level === 'intermediate' ? '🔥 Intermediate' : '🚀 Advanced';
  var toast = document.createElement('div');
  toast.style.cssText = 'position:fixed;bottom:2rem;right:2rem;background:#111827;color:white;padding:1rem 1.4rem;border-radius:14px;font-size:.88rem;font-weight:700;z-index:9999;box-shadow:0 8px 28px rgba(0,0,0,.25);max-width:320px;';
  toast.innerHTML = 'Assessment complete! Your level: <strong>' + levelLabel + '</strong><br><span style="font-weight:400;opacity:.8;font-size:.82rem;">Click Learn or Improve to see personalised content.</span>';
  document.body.appendChild(toast);
  setTimeout(function() { if (toast.parentNode) toast.parentNode.removeChild(toast); }, 4500);
}

function openTrackLearnPage(trackId) {
  var track = IMPROVEMENT_TRACKS.find(function(t) { return t.id === trackId; });
  if (!track) return;

  // Ensure _mlRegistry is populated
  window._mlRegistry = window._mlRegistry || {};
  Object.keys(CAPABILITIES).forEach(function(key) {
    var cap = CAPABILITIES[key];
    (cap.microLessons || []).forEach(function(ml, i) {
      var rk = 'ml_' + key + '_' + i;
      if (!window._mlRegistry[rk]) {
        window._mlRegistry[rk] = { icon: cap.icon, capTitle: cap.title, capId: key, lessonIdx: i, title: ml.title, objective: ml.objective, content: ml.content, activity: ml.activity };
      }
    });
  });

  // Ensure _tplRegistry is populated
  window._tplRegistry = window._tplRegistry || {};
  var categoryMap = { strategy:'Strategy', programs:'Programs', leadership:'HR', team:'HR', systems:'Operations', funding:'Fundraising', comms:'Communications', finance:'Finance' };
  Object.keys(CAPABILITIES).forEach(function(key) {
    var cap = CAPABILITIES[key];
    (cap.templates || []).forEach(function(t) {
      var tplKey = 'tt_' + t.name.replace(/[^a-zA-Z0-9]/g,'_');
      if (!window._tplRegistry[tplKey]) {
        window._tplRegistry[tplKey] = { name:t.name, type:t.type, icon:t.icon||'📄', desc:t.desc||'', howTo:t.howTo||'', category:categoryMap[key]||'Strategy', capId:key, capTitle:cap.title };
      }
    });
  });

  // Set navigation history
  var tracksPageActive = document.getElementById('improvement-tracks-page') && document.getElementById('improvement-tracks-page').classList.contains('active');
  var trackDetailActive = document.getElementById('track-detail-page') && document.getElementById('track-detail-page').classList.contains('active');

  if (trackDetailActive) {
    navHistory = [
      { pageId: 'improvement-tracks-page', label: '← Improvement Tracks', capId: null, subIdx: null },
      { pageId: 'track-detail-page', label: '← ' + track.title, capId: null, subIdx: null }
    ];
  } else {
    navHistory = [{ pageId: 'improvement-tracks-page', label: '← Improvement Tracks', capId: null, subIdx: null }];
  }

  currentTrackId = trackId;
  document.querySelectorAll('.page').forEach(function(p) { p.classList.remove('active'); });
  document.getElementById('track-learn-page').classList.add('active');
  document.getElementById('navBackBtn').style.display = 'flex';
  var backLabel = navHistory[navHistory.length - 1].label;
  document.getElementById('navBackLabel').textContent = backLabel;
  setFloatingBack(backLabel);
  currentCapId = null;
  currentSubCapIdx = null;

  // Update breadcrumb
  var bc = document.getElementById('trackLearnBreadcrumb');
  if (bc) { bc.textContent = track.title; bc.onclick = function() { openTrack(trackId); }; }

  renderTrackLearnContent(track);
  window.scrollTo(0, 0);
}

function renderTrackLearnContent(track) {
  var assessed = trackAssessResults[track.id] && trackAssessResults[track.id].level;
  var level = assessed ? trackAssessResults[track.id].level : null;
  var avg = assessed ? trackAssessResults[track.id].avg : null;
  var capColors = { strategy:'#16a34a', programs:'#2563eb', leadership:'#d97706', team:'#7c3aed', systems:'#0891b2', funding:'#dc2626', comms:'#db2777', finance:'#065f46' };

  // Collect micro lessons
  var microLessons = [];
  track.capabilities.forEach(function(capId) {
    var cap = CAPABILITIES[capId];
    if (!cap || !cap.microLessons) return;
    cap.microLessons.forEach(function(ml, idx) {
      microLessons.push({ regKey: 'ml_' + capId + '_' + idx, capId: capId, capTitle: cap.title, capIcon: cap.icon, capColor: capColors[capId] || '#1A6B4A', idx: idx, title: ml.title, objective: ml.objective });
    });
  });
  if (level === 'advanced') microLessons = microLessons.slice().reverse();
  // For assess-based ordering: label lessons as priority or standard
  var priorityLessonKeys = [];
  if (assessed && trackAssessResults[track.id].answers) {
    var answers = trackAssessResults[track.id].answers;
    var capIds = track.capabilities;
    answers.forEach(function(ans, i) {
      if (ans <= 1 && capIds[i]) {
        var cap = CAPABILITIES[capIds[i]];
        if (cap && cap.microLessons) {
          cap.microLessons.forEach(function(ml, idx) {
            priorityLessonKeys.push('ml_' + capIds[i] + '_' + idx);
          });
        }
      }
    });
  }

  // Collect webinars
  var webinars = WEBINARS.filter(function(w) { return track.capabilities.indexOf(w.capId) >= 0; });

  // Collect learning paths
  var paths = LEARNING_PATHS.filter(function(p) {
    return p.caps && track.capabilities.some(function(c) { return p.caps.indexOf(c) >= 0; });
  });

  var html = '';

  // Hero banner
  html += '<div style="background:linear-gradient(135deg,' + track.accentColor + ',#0d3d26);border-radius:20px;padding:2rem 2.25rem;margin-bottom:1.75rem;">';
  html += '<div style="font-size:.62rem;font-weight:800;letter-spacing:.14em;text-transform:uppercase;color:rgba(255,255,255,.65);margin-bottom:.4rem;">Track ' + track.number + ' · Learn</div>';
  html += '<div style="font-family:\'Cormorant Garamond\',serif;font-size:1.8rem;font-weight:700;color:white;margin-bottom:.5rem;">' + track.title + '</div>';
  html += '<p style="font-size:.88rem;color:rgba(255,255,255,.8);line-height:1.65;margin:0 0 1.25rem;">' + track.tagline + '</p>';
  // Tab nav inside hero
  html += '<div style="display:flex;gap:.5rem;flex-wrap:wrap;">';
  html += '<span style="background:rgba(255,255,255,.95);color:' + track.accentColor + ';border-radius:8px;padding:.4rem .9rem;font-size:.78rem;font-weight:800;">Learn</span>';
  html += '<span onclick="openTrackImprovePage(\'' + track.id + '\')" style="background:rgba(255,255,255,.18);color:white;border-radius:8px;padding:.4rem .9rem;font-size:.78rem;font-weight:700;cursor:pointer;">Improve</span>';
  html += '<span onclick="openTrackAssessModal(\'' + track.id + '\')" style="background:rgba(255,255,255,.18);color:white;border-radius:8px;padding:.4rem .9rem;font-size:.78rem;font-weight:700;cursor:pointer;">' + (assessed ? 'Re-Assess' : 'Assess') + '</span>';
  html += '<span onclick="openTrack(\'' + track.id + '\')" style="background:rgba(255,255,255,.18);color:white;border-radius:8px;padding:.4rem .9rem;font-size:.78rem;font-weight:700;cursor:pointer;">Track Overview</span>';
  html += '</div></div>';

  // Assessment banner
  if (!assessed) {
    html += '<div style="background:#fef9c3;border:1.5px solid #fde047;border-radius:12px;padding:1rem 1.25rem;margin-bottom:1.5rem;display:flex;align-items:center;gap:.9rem;">';
    html += '<span style="font-size:1.5rem;">📋</span>';
    html += '<div><strong style="color:#854d0e;display:block;margin-bottom:.2rem;">Take the assessment for personalised recommendations</strong>';
    html += '<span style="font-size:.83rem;color:#713f12;">Your skill level determines which lessons to prioritise. It only takes 2 minutes.</span></div>';
    html += '<button onclick="openTrackAssessModal(\'' + track.id + '\')" style="margin-left:auto;background:#e85d04;color:white;border:none;border-radius:9px;padding:.5rem 1rem;font-size:.8rem;font-weight:700;cursor:pointer;font-family:inherit;white-space:nowrap;flex-shrink:0;">Assess Now →</button>';
    html += '</div>';
  } else {
    var levelLabel = level === 'beginner' ? '🌱 Beginner' : level === 'intermediate' ? '🔥 Intermediate' : '🚀 Advanced';
    var levelColor = level === 'beginner' ? '#16a34a' : level === 'intermediate' ? '#d97706' : '#6d28d9';
    var levelNote = level === 'beginner' ? 'Start with foundational lessons in order for best results.' : level === 'intermediate' ? 'You have a solid base. Focus on mid-level lessons first.' : 'Advanced level — lessons shown hardest-first for maximum growth.';
    html += '<div style="background:linear-gradient(135deg,' + levelColor + '15,' + levelColor + '08);border:1.5px solid ' + levelColor + '40;border-radius:12px;padding:1rem 1.25rem;margin-bottom:1.5rem;display:flex;align-items:center;gap:.9rem;">';
    html += '<div style="width:44px;height:44px;border-radius:12px;background:' + levelColor + ';display:flex;align-items:center;justify-content:center;font-size:1.2rem;flex-shrink:0;">' + (level === 'beginner' ? '🌱' : level === 'intermediate' ? '🔥' : '🚀') + '</div>';
    html += '<div><div style="font-weight:800;color:' + levelColor + ';font-size:.92rem;margin-bottom:.15rem;">' + levelLabel + ' — Score: ' + (avg * 25).toFixed(0) + '/100</div>';
    html += '<div style="font-size:.82rem;color:var(--ink-light);">' + levelNote + '</div></div>';
    html += '<button onclick="openTrackAssessModal(\'' + track.id + '\')" style="margin-left:auto;background:white;color:' + levelColor + ';border:1.5px solid ' + levelColor + '50;border-radius:9px;padding:.4rem .85rem;font-size:.76rem;font-weight:700;cursor:pointer;font-family:inherit;white-space:nowrap;flex-shrink:0;">Re-Assess</button>';
    html += '</div>';
  }

  // ── MICRO LESSONS ──
  html += '<div style="margin-bottom:2rem;">';
  html += '<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:1rem;flex-wrap:wrap;gap:.5rem;">';
  html += '<h2 style="font-size:1.05rem;font-weight:800;color:var(--ink);">📚 Micro Lessons <span style="font-weight:500;font-size:.82rem;color:var(--ink-light);margin-left:.4rem;">(' + microLessons.length + ')</span></h2>';
  html += '<button onclick="showMicroLessonsPage()" style="background:white;color:var(--emerald);border:1.5px solid rgba(26,107,74,.3);border-radius:8px;padding:.4rem .85rem;font-size:.78rem;font-weight:700;cursor:pointer;font-family:inherit;">View All Lessons →</button>';
  html += '</div>';
  if (microLessons.length === 0) {
    html += '<p style="color:var(--ink-light);font-size:.85rem;font-style:italic;">No lessons found for this track.</p>';
  } else {
    microLessons.forEach(function(ml, i) {
      html += '<div onclick="openMicroLesson(\'' + ml.regKey + '\', false)" style="background:white;border:1.5px solid ' + (priorityLessonKeys.indexOf(ml.regKey) >= 0 ? 'rgba(220,38,38,.4)' : 'var(--border)') + ';border-radius:12px;padding:1rem 1.15rem;margin-bottom:.75rem;cursor:pointer;transition:all .2s;" onmouseover="this.style.borderColor=\'' + ml.capColor + '\';this.style.boxShadow=\'0 4px 16px rgba(0,0,0,.08)\'" onmouseout="this.style.borderColor=\'' + (priorityLessonKeys.indexOf(ml.regKey) >= 0 ? 'rgba(220,38,38,.4)' : 'var(--border)') + '\';this.style.boxShadow=\'none\'">';
      html += '<div style="display:flex;align-items:flex-start;gap:.85rem;">';
      html += '<div style="width:38px;height:38px;border-radius:10px;background:' + ml.capColor + '15;border:1.5px solid ' + ml.capColor + '30;display:flex;align-items:center;justify-content:center;font-size:1.05rem;flex-shrink:0;">' + ml.capIcon + '</div>';
      html += '<div style="flex:1;min-width:0;">';
      html += '<div style="display:flex;align-items:center;gap:.4rem;margin-bottom:.2rem;">';
      html += '<div style="font-size:.65rem;font-weight:700;letter-spacing:.1em;text-transform:uppercase;color:var(--ink-light);">' + ml.capTitle + ' · Lesson ' + (ml.idx + 1) + '</div>';
      if (priorityLessonKeys.indexOf(ml.regKey) >= 0) {
        html += '<span style="background:#fef2f2;color:#dc2626;border-radius:6px;padding:.1rem .4rem;font-size:.62rem;font-weight:800;letter-spacing:.05em;">PRIORITY</span>';
      }
      html += '</div>';
      html += '<div style="font-weight:700;color:var(--ink);font-size:.92rem;margin-bottom:.25rem;">' + ml.title + '</div>';
      html += '<div style="font-size:.82rem;color:var(--ink-light);line-height:1.55;">' + ml.objective + '</div>';
      html += '</div>';
      html += '<div style="color:' + ml.capColor + ';font-size:.8rem;font-weight:700;white-space:nowrap;flex-shrink:0;">Open →</div>';
      html += '</div></div>';
    });
  }
  html += '</div>';

  // ── WEBINARS ──
  html += '<div style="margin-bottom:2rem;">';
  html += '<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:1rem;flex-wrap:wrap;gap:.5rem;">';
  html += '<h2 style="font-size:1.05rem;font-weight:800;color:var(--ink);">🎙️ Webinars <span style="font-weight:500;font-size:.82rem;color:var(--ink-light);margin-left:.4rem;">(' + webinars.length + ')</span></h2>';
  html += '<button onclick="showWebinarsPage()" style="background:white;color:var(--emerald);border:1.5px solid rgba(26,107,74,.3);border-radius:8px;padding:.4rem .85rem;font-size:.78rem;font-weight:700;cursor:pointer;font-family:inherit;">All Webinars →</button>';
  html += '</div>';
  if (webinars.length === 0) {
    html += '<p style="color:var(--ink-light);font-size:.85rem;font-style:italic;">No webinars found for this track\'s capabilities.</p>';
  } else {
    webinars.forEach(function(w) {
      var statusBadge = w.status === 'recorded'
        ? '<span style="background:#dcfce7;color:#16a34a;padding:.2rem .55rem;border-radius:20px;font-size:.68rem;font-weight:700;">● Recorded</span>'
        : '<span style="background:#fff7ed;color:#c2410c;padding:.2rem .55rem;border-radius:20px;font-size:.68rem;font-weight:700;">⏰ Upcoming</span>';
      html += '<div onclick="openWebinar(\'' + w.id + '\')" style="background:white;border:1.5px solid var(--border);border-radius:12px;padding:1rem 1.15rem;margin-bottom:.75rem;cursor:pointer;transition:all .2s;" onmouseover="this.style.borderColor=\'#0369a1\';this.style.boxShadow=\'0 4px 16px rgba(0,0,0,.08)\'" onmouseout="this.style.borderColor=\'var(--border)\';this.style.boxShadow=\'none\'">';
      html += '<div style="display:flex;align-items:flex-start;gap:.85rem;">';
      html += '<div style="font-size:1.8rem;flex-shrink:0;">' + w.icon + '</div>';
      html += '<div style="flex:1;min-width:0;">';
      html += '<div style="display:flex;align-items:center;gap:.5rem;margin-bottom:.3rem;flex-wrap:wrap;">' + statusBadge + '<span style="font-size:.72rem;color:var(--ink-light);">' + w.duration + '</span></div>';
      html += '<div style="font-weight:700;color:var(--ink);font-size:.92rem;margin-bottom:.2rem;">' + w.title + '</div>';
      html += '<div style="font-size:.82rem;color:var(--ink-light);">' + w.speaker + ' · ' + w.role + '</div>';
      html += '</div>';
      html += '<div style="color:#0369a1;font-size:.8rem;font-weight:700;white-space:nowrap;flex-shrink:0;">Watch →</div>';
      html += '</div></div>';
    });
  }
  html += '</div>';

  // ── LEARNING PATHS ──
  html += '<div style="margin-bottom:2rem;">';
  html += '<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:1rem;flex-wrap:wrap;gap:.5rem;">';
  html += '<h2 style="font-size:1.05rem;font-weight:800;color:var(--ink);">🛤️ Learning Paths <span style="font-weight:500;font-size:.82rem;color:var(--ink-light);margin-left:.4rem;">(' + paths.length + ')</span></h2>';
  html += '<button onclick="showLearningPathsPage()" style="background:white;color:var(--emerald);border:1.5px solid rgba(26,107,74,.3);border-radius:8px;padding:.4rem .85rem;font-size:.78rem;font-weight:700;cursor:pointer;font-family:inherit;">All Paths →</button>';
  html += '</div>';
  if (paths.length === 0) {
    html += '<p style="color:var(--ink-light);font-size:.85rem;font-style:italic;">No learning paths matched for this track.</p>';
  } else {
    paths.forEach(function(p) {
      var levelBadge = p.level === 'Foundation' ? '<span style="background:#dcfce7;color:#16a34a;padding:.2rem .55rem;border-radius:20px;font-size:.68rem;font-weight:700;">' + p.level + '</span>'
        : p.level === 'Intermediate' ? '<span style="background:#fff7ed;color:#c2410c;padding:.2rem .55rem;border-radius:20px;font-size:.68rem;font-weight:700;">' + p.level + '</span>'
        : '<span style="background:#f3e8ff;color:#7c3aed;padding:.2rem .55rem;border-radius:20px;font-size:.68rem;font-weight:700;">' + p.level + '</span>';
      html += '<div onclick="openLearningPath(\'' + p.id + '\')" style="background:white;border:1.5px solid var(--border);border-radius:12px;padding:1rem 1.15rem;margin-bottom:.75rem;cursor:pointer;transition:all .2s;" onmouseover="this.style.borderColor=\'' + p.color + '\';this.style.boxShadow=\'0 4px 16px rgba(0,0,0,.08)\'" onmouseout="this.style.borderColor=\'var(--border)\';this.style.boxShadow=\'none\'">';
      html += '<div style="display:flex;align-items:center;gap:.85rem;">';
      html += '<div style="font-size:1.8rem;flex-shrink:0;">' + p.icon + '</div>';
      html += '<div style="flex:1;min-width:0;">';
      html += '<div style="display:flex;align-items:center;gap:.5rem;margin-bottom:.3rem;flex-wrap:wrap;">' + levelBadge + '<span style="font-size:.72rem;color:var(--ink-light);">' + p.duration + ' · ' + p.totalTime + '</span></div>';
      html += '<div style="font-weight:700;color:var(--ink);font-size:.92rem;margin-bottom:.2rem;">' + p.title + '</div>';
      html += '<div style="font-size:.82rem;color:var(--ink-light);">' + p.tagline + '</div>';
      html += '</div>';
      html += '<div style="color:' + p.color + ';font-size:.8rem;font-weight:700;white-space:nowrap;flex-shrink:0;">Start →</div>';
      html += '</div></div>';
    });
  }
  html += '</div>';

  var container = document.getElementById('trackLearnContent');
  if (container) container.innerHTML = html;
}

function openTrackImprovePage(trackId) {
  var track = IMPROVEMENT_TRACKS.find(function(t) { return t.id === trackId; });
  if (!track) return;

  // Ensure _tplRegistry is populated
  window._tplRegistry = window._tplRegistry || {};
  var categoryMap = { strategy:'Strategy', programs:'Programs', leadership:'HR', team:'HR', systems:'Operations', funding:'Fundraising', comms:'Communications', finance:'Finance' };
  Object.keys(CAPABILITIES).forEach(function(key) {
    var cap = CAPABILITIES[key];
    (cap.templates || []).forEach(function(t) {
      var tplKey = 'tt_' + t.name.replace(/[^a-zA-Z0-9]/g,'_');
      if (!window._tplRegistry[tplKey]) {
        window._tplRegistry[tplKey] = { name:t.name, type:t.type, icon:t.icon||'📄', desc:t.desc||'', howTo:t.howTo||'', category:categoryMap[key]||'Strategy', capId:key, capTitle:cap.title };
      }
    });
  });

  // Set navigation history
  var trackDetailActive = document.getElementById('track-detail-page') && document.getElementById('track-detail-page').classList.contains('active');
  var trackLearnActive = document.getElementById('track-learn-page') && document.getElementById('track-learn-page').classList.contains('active');

  if (trackLearnActive) {
    navHistory.push({ pageId: 'track-learn-page', label: '← ' + track.title + ' (Learn)', capId: null, subIdx: null });
  } else if (trackDetailActive) {
    navHistory = [
      { pageId: 'improvement-tracks-page', label: '← Improvement Tracks', capId: null, subIdx: null },
      { pageId: 'track-detail-page', label: '← ' + track.title, capId: null, subIdx: null }
    ];
  } else {
    navHistory = [{ pageId: 'improvement-tracks-page', label: '← Improvement Tracks', capId: null, subIdx: null }];
  }

  currentTrackId = trackId;
  document.querySelectorAll('.page').forEach(function(p) { p.classList.remove('active'); });
  document.getElementById('track-improve-page').classList.add('active');
  document.getElementById('navBackBtn').style.display = 'flex';
  var backLabel = navHistory[navHistory.length - 1].label;
  document.getElementById('navBackLabel').textContent = backLabel;
  setFloatingBack(backLabel);
  currentCapId = null;
  currentSubCapIdx = null;

  // Update breadcrumb
  var bc = document.getElementById('trackImproveBreadcrumb');
  if (bc) { bc.textContent = track.title; bc.onclick = function() { openTrack(trackId); }; }

  renderTrackImproveContent(track);
  window.scrollTo(0, 0);
}

function renderTrackImproveContent(track) {
  var assessed = trackAssessResults[track.id] && trackAssessResults[track.id].level;
  var level = assessed ? trackAssessResults[track.id].level : null;
  var avg = assessed ? trackAssessResults[track.id].avg : null;
  var _tplTypeColors = { DOCX:'#2563eb', XLSX:'#16a34a', PDF:'#dc2626', PPTX:'#d97706' };
  var _tplTypeBg = { DOCX:'rgba(37,99,235,.08)', XLSX:'rgba(22,163,74,.08)', PDF:'rgba(220,38,38,.08)', PPTX:'rgba(217,119,6,.08)' };

  // Collect templates from capabilities
  var templates = [];
  track.capabilities.forEach(function(capId) {
    var cap = CAPABILITIES[capId];
    if (!cap || !cap.templates) return;
    cap.templates.forEach(function(t) {
      var key = 'tt_' + t.name.replace(/[^a-zA-Z0-9]/g,'_');
      templates.push({ key: key, capId: capId, capTitle: cap.title, capIcon: cap.icon, name: t.name, type: t.type, icon: t.icon || '📄', desc: t.desc || '' });
    });
  });

  // Collect workbooks from subCapabilities
  var workbooks = [];
  track.capabilities.forEach(function(capId) {
    var cap = CAPABILITIES[capId];
    if (!cap || !cap.subCapabilities) return;
    cap.subCapabilities.forEach(function(sub, subIdx) {
      if (sub.workbook) {
        workbooks.push({ capId: capId, subIdx: subIdx, capTitle: cap.title, capIcon: cap.icon, title: sub.workbook.title || sub.title, subtitle: sub.workbook.subtitle || '', intro: sub.workbook.intro || '' });
      }
    });
  });

  var weeks = track.weeks || [];
  var deliverables = track.deliverables || [];

  var html = '';

  // Hero banner
  html += '<div style="background:linear-gradient(135deg,#6d28d9,#0d3d26);border-radius:20px;padding:2rem 2.25rem;margin-bottom:1.75rem;">';
  html += '<div style="font-size:.62rem;font-weight:800;letter-spacing:.14em;text-transform:uppercase;color:rgba(255,255,255,.65);margin-bottom:.4rem;">Track ' + track.number + ' · Improve</div>';
  html += '<div style="font-family:\'Cormorant Garamond\',serif;font-size:1.8rem;font-weight:700;color:white;margin-bottom:.5rem;">' + track.title + '</div>';
  html += '<p style="font-size:.88rem;color:rgba(255,255,255,.8);line-height:1.65;margin:0 0 1.25rem;">Your practical improvement plan, workbooks, and tools for this track.</p>';
  // Tab nav inside hero
  html += '<div style="display:flex;gap:.5rem;flex-wrap:wrap;">';
  html += '<span onclick="openTrackLearnPage(\'' + track.id + '\')" style="background:rgba(255,255,255,.18);color:white;border-radius:8px;padding:.4rem .9rem;font-size:.78rem;font-weight:700;cursor:pointer;">Learn</span>';
  html += '<span style="background:rgba(255,255,255,.95);color:#6d28d9;border-radius:8px;padding:.4rem .9rem;font-size:.78rem;font-weight:800;">Improve</span>';
  html += '<span onclick="openTrackAssessModal(\'' + track.id + '\')" style="background:rgba(255,255,255,.18);color:white;border-radius:8px;padding:.4rem .9rem;font-size:.78rem;font-weight:700;cursor:pointer;">' + (assessed ? 'Re-Assess' : 'Assess') + '</span>';
  html += '<span onclick="openTrack(\'' + track.id + '\')" style="background:rgba(255,255,255,.18);color:white;border-radius:8px;padding:.4rem .9rem;font-size:.78rem;font-weight:700;cursor:pointer;">Track Overview</span>';
  html += '</div></div>';

  // Assessment banner
  if (!assessed) {
    html += '<div style="background:#fef9c3;border:1.5px solid #fde047;border-radius:12px;padding:1rem 1.25rem;margin-bottom:1.5rem;display:flex;align-items:center;gap:.9rem;">';
    html += '<span style="font-size:1.5rem;">📋</span>';
    html += '<div><strong style="color:#854d0e;display:block;margin-bottom:.2rem;">Take the assessment for a personalised action plan</strong>';
    html += '<span style="font-size:.83rem;color:#713f12;">Know your level so you focus on the right phase of the roadmap.</span></div>';
    html += '<button onclick="openTrackAssessModal(\'' + track.id + '\')" style="margin-left:auto;background:#e85d04;color:white;border:none;border-radius:9px;padding:.5rem 1rem;font-size:.8rem;font-weight:700;cursor:pointer;font-family:inherit;white-space:nowrap;flex-shrink:0;">Assess Now →</button>';
    html += '</div>';
  } else {
    var levelLabel = level === 'beginner' ? '🌱 Beginner' : level === 'intermediate' ? '🔥 Intermediate' : '🚀 Advanced';
    var levelColor = level === 'beginner' ? '#16a34a' : level === 'intermediate' ? '#d97706' : '#6d28d9';
    var levelFocus = level === 'beginner' ? 'Start with Week 1–2. Complete the foundational workbooks first.'
      : level === 'intermediate' ? 'Focus on Week 3–4 (Build & Apply). Use templates that fill your identified gaps.'
      : 'Jump to Week 5+ (Implement & Prove). Use advanced tools to optimise your systems.';
    html += '<div style="background:linear-gradient(135deg,' + levelColor + '15,' + levelColor + '08);border:1.5px solid ' + levelColor + '40;border-radius:12px;padding:1rem 1.25rem;margin-bottom:1.5rem;display:flex;align-items:center;gap:.9rem;">';
    html += '<div style="width:44px;height:44px;border-radius:12px;background:' + levelColor + ';display:flex;align-items:center;justify-content:center;font-size:1.2rem;flex-shrink:0;">' + (level === 'beginner' ? '🌱' : level === 'intermediate' ? '🔥' : '🚀') + '</div>';
    html += '<div><div style="font-weight:800;color:' + levelColor + ';font-size:.92rem;margin-bottom:.15rem;">' + levelLabel + ' — Score: ' + (avg * 25).toFixed(0) + '/100</div>';
    html += '<div style="font-size:.82rem;color:var(--ink-light);">' + levelFocus + '</div></div>';
    html += '<button onclick="openTrackAssessModal(\'' + track.id + '\')" style="margin-left:auto;background:white;color:' + levelColor + ';border:1.5px solid ' + levelColor + '50;border-radius:9px;padding:.4rem .85rem;font-size:.76rem;font-weight:700;cursor:pointer;font-family:inherit;white-space:nowrap;flex-shrink:0;">Re-Assess</button>';
    html += '</div>';
  }

  // ── 90-DAY ROADMAP ──
  html += '<div style="margin-bottom:2rem;">';
  html += '<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:1rem;flex-wrap:wrap;gap:.5rem;">';
  html += '<h2 style="font-size:1.05rem;font-weight:800;color:var(--ink);">🗺️ 90-Day Roadmap <span style="font-weight:500;font-size:.82rem;color:var(--ink-light);margin-left:.4rem;">(' + weeks.length + ' phases)</span></h2>';
  html += '<button onclick="showRoadmapPage()" style="background:white;color:var(--emerald);border:1.5px solid rgba(26,107,74,.3);border-radius:8px;padding:.4rem .85rem;font-size:.78rem;font-weight:700;cursor:pointer;font-family:inherit;">Full Roadmap →</button>';
  html += '</div>';
  var phaseColors = { 'Assess & Learn': '#0369a1', 'Build & Apply': '#d97706', 'Implement & Prove': '#16a34a' };
  weeks.forEach(function(w, i) {
    var pc = phaseColors[w.phase] || track.accentColor;
    // Highlight the recommended phase based on level
    var isRecommended = (level === 'beginner' && i === 0) || (level === 'intermediate' && i === 1) || (level === 'advanced' && i === weeks.length - 1);
    var cardBorder = isRecommended ? pc : 'var(--border)';
    var cardBg = isRecommended ? pc + '08' : 'white';
    html += '<div style="background:' + cardBg + ';border:1.5px solid ' + cardBorder + ';border-radius:12px;padding:1.1rem 1.25rem;margin-bottom:.75rem;">';
    if (isRecommended) {
      html += '<div style="font-size:.65rem;font-weight:800;letter-spacing:.1em;text-transform:uppercase;color:' + pc + ';margin-bottom:.4rem;">★ Recommended for your level</div>';
    }
    html += '<div style="display:flex;align-items:center;gap:.75rem;margin-bottom:.75rem;">';
    html += '<div style="background:' + pc + ';color:white;border-radius:8px;padding:.3rem .7rem;font-size:.72rem;font-weight:800;white-space:nowrap;">Week ' + w.week + '</div>';
    html += '<div style="font-weight:700;color:var(--ink);font-size:.9rem;">' + w.phase + '</div>';
    html += '</div>';
    html += '<ul style="padding-left:1.25rem;list-style:disc;">';
    w.tasks.forEach(function(task) {
      html += '<li style="padding:.28rem 0;font-size:.84rem;color:var(--ink-mid);">' + task + '</li>';
    });
    html += '</ul></div>';
  });
  html += '</div>';

  // ── DELIVERABLES ──
  html += '<div style="margin-bottom:2rem;">';
  html += '<h2 style="font-size:1.05rem;font-weight:800;color:var(--ink);margin-bottom:1rem;">📦 Track Deliverables <span style="font-weight:500;font-size:.82rem;color:var(--ink-light);margin-left:.4rem;">(' + deliverables.length + ')</span></h2>';
  deliverables.forEach(function(d) {
    var hasAction = !!d.action;
    html += '<div style="background:white;border:1.5px solid var(--border);border-radius:12px;padding:1rem 1.1rem;margin-bottom:.75rem;display:flex;align-items:flex-start;gap:.85rem;' + (hasAction ? 'cursor:pointer;transition:all .2s;' : '') + '"'
      + (hasAction ? ' onclick="' + d.action + '" onmouseover="this.style.borderColor=\'' + track.accentColor + '\';this.style.boxShadow=\'0 4px 16px rgba(0,0,0,.08)\';this.style.transform=\'translateY(-1px)\';" onmouseout="this.style.borderColor=\'var(--border)\';this.style.boxShadow=\'none\';this.style.transform=\'\';"' : '')
      + '>';
    html += '<div style="width:44px;height:44px;border-radius:12px;background:' + track.accentColor + '15;border:1.5px solid ' + track.accentColor + '30;display:flex;align-items:center;justify-content:center;font-size:1.3rem;flex-shrink:0;">' + d.icon + '</div>';
    html += '<div style="flex:1;min-width:0;"><div style="font-weight:700;color:var(--ink);font-size:.92rem;margin-bottom:.25rem;">' + d.title + '</div>';
    html += '<div style="font-size:.83rem;color:var(--ink-light);line-height:1.55;">' + d.desc + '</div></div>';
    if (hasAction) {
      html += '<div style="font-size:.78rem;font-weight:700;color:' + track.accentColor + ';white-space:nowrap;flex-shrink:0;align-self:center;">Open →</div>';
    }
    html += '</div>';
  });
  html += '</div>';

  // ── TOOLS & TEMPLATES ──
  html += '<div style="margin-bottom:2rem;">';
  html += '<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:1rem;flex-wrap:wrap;gap:.5rem;">';
  html += '<h2 style="font-size:1.05rem;font-weight:800;color:var(--ink);">🛠️ Tools & Templates <span style="font-weight:500;font-size:.82rem;color:var(--ink-light);margin-left:.4rem;">(' + templates.length + ')</span></h2>';
  html += '<button onclick="showToolsTemplatesPage()" style="background:white;color:var(--emerald);border:1.5px solid rgba(26,107,74,.3);border-radius:8px;padding:.4rem .85rem;font-size:.78rem;font-weight:700;cursor:pointer;font-family:inherit;">All Templates →</button>';
  html += '</div>';
  if (templates.length === 0) {
    html += '<p style="color:var(--ink-light);font-size:.85rem;font-style:italic;">No templates found for this track.</p>';
  } else {
    templates.forEach(function(item) {
      var tc = _tplTypeColors[item.type] || '#6b7280';
      var tb = _tplTypeBg[item.type] || 'rgba(107,114,128,.08)';
      html += '<div style="background:white;border:1.5px solid var(--border);border-radius:12px;padding:1rem 1.15rem;margin-bottom:.75rem;transition:all .2s;" onmouseover="this.style.borderColor=\'' + tc + '\';this.style.boxShadow=\'0 4px 16px rgba(0,0,0,.08)\'" onmouseout="this.style.borderColor=\'var(--border)\';this.style.boxShadow=\'none\'">';
      html += '<div style="display:flex;align-items:flex-start;gap:.85rem;">';
      html += '<div style="width:40px;height:40px;border-radius:10px;background:' + tb + ';border:1.5px solid ' + tc + '33;display:flex;align-items:center;justify-content:center;font-size:1.1rem;flex-shrink:0;">' + item.icon + '</div>';
      html += '<div style="flex:1;min-width:0;">';
      html += '<div style="font-size:.65rem;font-weight:700;letter-spacing:.1em;text-transform:uppercase;color:var(--ink-light);margin-bottom:.2rem;">' + item.capTitle + '</div>';
      html += '<div style="font-weight:700;color:var(--ink);font-size:.9rem;margin-bottom:.25rem;">' + item.name + '</div>';
      html += '<div style="font-size:.82rem;color:var(--ink-light);line-height:1.55;margin-bottom:.6rem;">' + (item.desc.length > 120 ? item.desc.substring(0, 120) + '…' : item.desc) + '</div>';
      html += '<div style="display:flex;gap:.5rem;">';
      html += '<button onclick="event.stopPropagation();openTemplateDetail(\'' + item.key + '\')" style="background:var(--cream);color:var(--emerald-dark);border:1.5px solid var(--border);border-radius:8px;padding:.4rem .85rem;font-size:.76rem;font-weight:700;cursor:pointer;font-family:inherit;">View</button>';
      html += '<button onclick="event.stopPropagation();downloadTemplatePDF(\'' + item.key + '\')" style="background:#dc2626;color:white;border:none;border-radius:8px;padding:.4rem .85rem;font-size:.76rem;font-weight:700;cursor:pointer;font-family:inherit;">PDF</button>';
      html += '<span style="display:inline-flex;align-items:center;padding:.4rem .75rem;background:' + tb + ';color:' + tc + ';border-radius:8px;font-size:.72rem;font-weight:800;">' + item.type + '</span>';
      html += '</div></div></div></div>';
    });
  }
  html += '</div>';

  // ── WORKBOOKS ──
  html += '<div style="margin-bottom:2rem;">';
  html += '<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:1rem;flex-wrap:wrap;gap:.5rem;">';
  html += '<h2 style="font-size:1.05rem;font-weight:800;color:var(--ink);">📓 Workbooks <span style="font-weight:500;font-size:.82rem;color:var(--ink-light);margin-left:.4rem;">(' + workbooks.length + ')</span></h2>';
  html += '<button onclick="showWorkbooksPage()" style="background:white;color:var(--emerald);border:1.5px solid rgba(26,107,74,.3);border-radius:8px;padding:.4rem .85rem;font-size:.78rem;font-weight:700;cursor:pointer;font-family:inherit;">All Workbooks →</button>';
  html += '</div>';
  if (workbooks.length === 0) {
    html += '<p style="color:var(--ink-light);font-size:.85rem;font-style:italic;">No workbooks found for this track.</p>';
  } else {
    workbooks.forEach(function(wb) {
      html += '<div style="background:white;border:1.5px solid var(--border);border-radius:12px;padding:1.1rem 1.25rem;margin-bottom:.75rem;transition:all .2s;" onmouseover="this.style.borderColor=\'var(--emerald)\';this.style.boxShadow=\'0 4px 16px rgba(0,0,0,.08)\'" onmouseout="this.style.borderColor=\'var(--border)\';this.style.boxShadow=\'none\'">';
      html += '<div style="display:flex;align-items:center;gap:.85rem;margin-bottom:.75rem;">';
      html += '<div style="font-size:1.5rem;">' + wb.capIcon + '</div>';
      html += '<div><div style="font-size:.65rem;font-weight:700;letter-spacing:.1em;text-transform:uppercase;color:var(--ink-light);margin-bottom:.2rem;">' + wb.capTitle + '</div>';
      html += '<div style="font-weight:700;color:var(--ink);font-size:.92rem;">' + wb.title + '</div></div>';
      html += '</div>';
      if (wb.subtitle) html += '<div style="font-size:.78rem;font-weight:700;color:var(--gold);margin-bottom:.45rem;">' + wb.subtitle + '</div>';
      html += '<p style="font-size:.82rem;color:var(--ink-light);line-height:1.6;margin-bottom:.85rem;">' + (wb.intro ? wb.intro.substring(0, 130) + '…' : '') + '</p>';
      html += '<div style="display:flex;gap:.5rem;flex-wrap:wrap;">';
      html += '<button onclick="downloadWorkbook(\'' + wb.capId + '\',' + wb.subIdx + ',\'PDF\')" style="background:var(--emerald);color:white;border:none;border-radius:8px;padding:.5rem .9rem;font-size:.78rem;font-weight:700;cursor:pointer;font-family:inherit;">PDF</button>';
      html += '<button onclick="downloadWorkbook(\'' + wb.capId + '\',' + wb.subIdx + ',\'Word\')" style="background:white;color:var(--emerald);border:1.5px solid rgba(26,107,74,.35);border-radius:8px;padding:.5rem .9rem;font-size:.78rem;font-weight:700;cursor:pointer;font-family:inherit;">Word</button>';
      html += '<button onclick="openSubCapability(\'' + wb.capId + '\',' + wb.subIdx + ')" style="background:var(--cream);color:var(--ink-mid);border:1.5px solid var(--border);border-radius:8px;padding:.5rem .9rem;font-size:.78rem;font-weight:700;cursor:pointer;font-family:inherit;">Open Workbook →</button>';
      html += '</div></div>';
    });
  }
  html += '</div>';

  var container = document.getElementById('trackImproveContent');
  if (container) container.innerHTML = html;
}


// ─────────────────────────────────────────────────────────────────────────────

function openTrack(trackId) {
  var track = IMPROVEMENT_TRACKS.find(function(t) { return t.id === trackId; });
  if (!track) return;

  // Set history — preserve if coming from the Improve page
  var capImproveActiveTrack = document.getElementById('cap-improve-page') && document.getElementById('cap-improve-page').classList.contains('active');
  var tracksPageActive = document.getElementById('improvement-tracks-page') && document.getElementById('improvement-tracks-page').classList.contains('active');

  if (capImproveActiveTrack) {
    navHistory.push({ pageId: 'cap-improve-page', label: '← Improve', capId: null, subIdx: null });
  } else {
    navHistory = [{ pageId: 'improvement-tracks-page', label: '← Improvement Tracks', capId: null, subIdx: null }];
  }

  currentTrackId = trackId;
  var _trackBackLabel = navHistory.length > 0 ? navHistory[navHistory.length - 1].label : '← Improvement Tracks';
  document.querySelectorAll('.page').forEach(function(p) { p.classList.remove('active'); });
  document.getElementById('track-detail-page').classList.add('active');
  document.getElementById('navBackBtn').style.display = 'flex';
  document.getElementById('navBackLabel').textContent = _trackBackLabel;
  setFloatingBack(_trackBackLabel);

  // Set breadcrumb
  var bc = document.getElementById('trackDetailBreadcrumb');
  if (bc) bc.textContent = track.title;

  renderTrackDetail(track);
  window.scrollTo(0, 0);
}

function renderTrackDetail(track) {
  var el = document.getElementById('trackDetailContent');
  if (!el) return;

  // Deliverables
  var delivHtml = track.deliverables.map(function(d) {
    var clickable = d.action ? 'cursor:pointer;' : '';
    var hoverAttrs = d.action
      ? ' onmouseover="this.style.borderColor=\'' + track.accentColor + '\';this.style.boxShadow=\'0 4px 16px rgba(0,0,0,.08)\';this.querySelector(\'.deliv-cta\').style.opacity=\'1\';" onmouseout="this.style.borderColor=\'var(--border)\';this.style.boxShadow=\'\';this.querySelector(\'.deliv-cta\').style.opacity=\'0\';"'
      : '';
    var onClickAttr = d.action ? ' onclick="' + d.action + '"' : '';
    var ctaBtn = d.action
      ? '<span class="deliv-cta" style="opacity:0;transition:opacity .15s;font-size:.75rem;font-weight:700;color:' + track.accentColor + ';white-space:nowrap;flex-shrink:0;">Open →</span>'
      : '';
    return '<div style="display:flex;gap:.85rem;align-items:flex-start;padding:.85rem 0;border-bottom:1px solid var(--border);' + clickable + 'transition:all .2s;"' + hoverAttrs + onClickAttr + '>'
      + '<div style="font-size:1.4rem;line-height:1;flex-shrink:0;">' + d.icon + '</div>'
      + '<div style="flex:1;min-width:0;"><div style="font-weight:700;font-size:.88rem;color:var(--ink);margin-bottom:.2rem;">' + d.title + '</div>'
      + '<div style="font-size:.8rem;color:var(--ink-light);line-height:1.6;">' + d.desc + '</div></div>'
      + ctaBtn
      + '</div>';
  }).join('');

  // Week plan
  var weeksHtml = track.weeks.map(function(w, i) {
    var taskItems = w.tasks.map(function(t) {
      return '<li style="font-size:.84rem;color:var(--ink-mid);line-height:1.65;margin-bottom:.35rem;padding-left:.25rem;">' + t + '</li>';
    }).join('');
    var phaseColors = {'Assess & Learn':'#0369a1','Build & Apply':'#d97706','Implement & Prove':'#16a34a'};
    var pc = phaseColors[w.phase] || track.accentColor;
    return '<div style="display:flex;gap:1.25rem;align-items:flex-start;">'
      + '<div style="display:flex;flex-direction:column;align-items:center;flex-shrink:0;">'
      + '<div style="width:38px;height:38px;border-radius:50%;background:' + pc + ';color:white;font-size:.68rem;font-weight:800;display:flex;align-items:center;justify-content:center;text-align:center;line-height:1.15;">Wk<br>' + w.week + '</div>'
      + (i < track.weeks.length - 1 ? '<div style="width:2px;flex:1;min-height:36px;background:var(--border);margin-top:4px;"></div>' : '')
      + '</div>'
      + '<div style="padding-bottom:' + (i < track.weeks.length - 1 ? '1.5rem' : '0') + ';flex:1;">'
      + '<div style="font-weight:700;font-size:.88rem;color:var(--ink);margin-bottom:.5rem;">' + w.phase + '</div>'
      + '<ul style="list-style:disc;padding-left:1.1rem;margin:0;">' + taskItems + '</ul>'
      + '</div></div>';
  }).join('');

  // Capabilities list
  var capLinksHtml = track.capLabels.map(function(lbl, i) {
    var capId = track.capabilities[i];
    return '<div onclick="loadCapability(\'' + capId + '\')" style="background:white;border:1.5px solid var(--border);border-radius:12px;padding:.85rem 1.1rem;cursor:pointer;transition:all .2s;display:flex;gap:.75rem;align-items:center;" onmouseover="this.style.borderColor=\'' + track.accentColor + '\';this.style.background=\'#fafaf9\';" onmouseout="this.style.borderColor=\'var(--border)\';this.style.background=\'white\';">'
      + '<div style="font-size:1.4rem;flex-shrink:0;">' + track.capIcons[i] + '</div>'
      + '<div style="flex:1;min-width:0;"><div style="font-weight:700;font-size:.87rem;color:var(--ink);margin-bottom:.15rem;">' + lbl + '</div>'
      + '<div style="font-size:.75rem;color:var(--ink-light);">Explore modules →</div></div>'
      + '</div>';
  }).join('');

  // Next track
  var nextTrack = IMPROVEMENT_TRACKS.find(function(t) { return t.id === track.nextTrack; });
  var nextHtml = nextTrack
    ? '<div style="background:linear-gradient(135deg,' + nextTrack.accentColor + ' 0%,#0d3d26 100%);border-radius:16px;padding:1.75rem 2rem;display:flex;align-items:center;gap:1.5rem;flex-wrap:wrap;margin-top:2rem;">'
      + '<div style="font-size:2.2rem;">' + nextTrack.icon + '</div>'
      + '<div style="flex:1;min-width:0;"><div style="font-size:.65rem;font-weight:800;letter-spacing:.14em;text-transform:uppercase;color:rgba(255,255,255,.55);margin-bottom:.3rem;">Up Next — Track ' + nextTrack.number + '</div>'
      + '<div style="font-family:\'Cormorant Garamond\',serif;font-size:1.25rem;font-weight:600;color:white;margin-bottom:.3rem;">' + nextTrack.title + '</div>'
      + '<div style="font-size:.82rem;color:rgba(255,255,255,.72);">' + nextTrack.tagline + '</div></div>'
      + '<button onclick="openTrack(\'' + nextTrack.id + '\')" style="background:rgba(255,255,255,.15);border:1.5px solid rgba(255,255,255,.35);color:white;border-radius:10px;padding:.65rem 1.3rem;font-size:.83rem;font-weight:700;cursor:pointer;font-family:inherit;white-space:nowrap;">Start Next Track →</button>'
      + '</div>'
    : '';

  el.innerHTML = ''
    // ── HERO ──
    + '<div style="background:linear-gradient(135deg,' + track.accentColor + ' 0%,#0d3d26 100%);border-radius:20px;padding:2.5rem 2.25rem;margin-bottom:2rem;position:relative;overflow:hidden;">'
    + '<div style="position:absolute;top:-20px;right:-20px;font-size:7rem;opacity:.07;">' + track.icon + '</div>'
    + '<div style="position:relative;">'
    + '<div style="display:flex;align-items:center;gap:.6rem;flex-wrap:wrap;margin-bottom:.9rem;">'
    + '<span style="background:rgba(255,255,255,.18);border:1px solid rgba(255,255,255,.25);border-radius:20px;padding:.25rem .8rem;font-size:.65rem;font-weight:800;letter-spacing:.12em;text-transform:uppercase;color:white;">Track ' + track.number + ' of 4</span>'
    + '<span style="background:rgba(255,255,255,.12);border:1px solid rgba(255,255,255,.2);border-radius:20px;padding:.25rem .8rem;font-size:.65rem;font-weight:700;color:rgba(255,255,255,.85);">⏱ ' + track.duration + '</span>'
    + '</div>'
    + '<h1 style="font-family:\'Cormorant Garamond\',serif;font-size:clamp(1.8rem,5vw,2.75rem);font-weight:300;line-height:1.2;margin-bottom:.85rem;color:white;">' + track.icon + ' ' + track.title + '</h1>'
    + '<p style="font-size:.93rem;color:rgba(255,255,255,.82);line-height:1.75;max-width:600px;margin-bottom:1.5rem;">' + track.tagline + '</p>'
    + '<div style="background:rgba(255,255,255,.1);border:1px solid rgba(255,255,255,.18);border-radius:12px;padding:.9rem 1.15rem;">'
    + '<div style="font-size:.63rem;font-weight:800;letter-spacing:.1em;text-transform:uppercase;color:rgba(255,255,255,.55);margin-bottom:.35rem;">Outcome</div>'
    + '<div style="font-size:.87rem;line-height:1.65;color:rgba(255,255,255,.88);">' + track.outcome + '</div>'
    + '</div>'
    // Hero action buttons
    + '<div style="display:flex;gap:.65rem;flex-wrap:wrap;margin-top:1.25rem;">'
    + '<button onclick="openTrackAssessModal(\'' + track.id + '\')" style="background:white;color:' + track.accentColor + ';border:none;border-radius:9px;padding:.6rem 1.2rem;font-size:.82rem;font-weight:700;cursor:pointer;font-family:inherit;">Assess My Level</button>'
    + '<button onclick="openTrackLearnPage(\'' + track.id + '\')" style="background:rgba(255,255,255,.18);border:1.5px solid rgba(255,255,255,.35);color:white;border-radius:9px;padding:.6rem 1.2rem;font-size:.82rem;font-weight:700;cursor:pointer;font-family:inherit;">Learn</button>'
    + '<button onclick="openTrackImprovePage(\'' + track.id + '\')" style="background:rgba(255,255,255,.18);border:1.5px solid rgba(255,255,255,.35);color:white;border-radius:9px;padding:.6rem 1.2rem;font-size:.82rem;font-weight:700;cursor:pointer;font-family:inherit;">Improve</button>'
    + '</div>'
    + '</div></div>'

    // ── MAIN CONTENT GRID ──
    + '<div style="display:grid;grid-template-columns:1fr 1fr;gap:1.75rem;margin-bottom:1.75rem;" class="track-detail-grid">'

    // Left column
    + '<div style="display:flex;flex-direction:column;gap:1.5rem;">'
    // About
    + '<div style="background:white;border:1.5px solid var(--border);border-radius:16px;padding:1.5rem 1.75rem;">'
    + '<h2 style="font-size:.68rem;font-weight:800;letter-spacing:.12em;text-transform:uppercase;color:var(--gold);margin-bottom:.9rem;">About This Track</h2>'
    + '<div style="font-size:.87rem;color:var(--ink-mid);line-height:1.8;white-space:pre-line;margin-bottom:1.25rem;">' + track.description + '</div>'
    + '<div style="background:var(--cream);border-radius:10px;padding:.9rem 1.1rem;">'
    + '<div style="font-size:.65rem;font-weight:800;letter-spacing:.1em;text-transform:uppercase;color:var(--emerald);margin-bottom:.45rem;">Who is this for?</div>'
    + '<div style="font-size:.83rem;color:var(--ink-mid);line-height:1.7;">' + track.whoFor + '</div>'
    + '</div></div>'
    // Capabilities
    + '<div style="background:white;border:1.5px solid var(--border);border-radius:16px;padding:1.5rem 1.75rem;">'
    + '<h2 style="font-size:.68rem;font-weight:800;letter-spacing:.12em;text-transform:uppercase;color:var(--emerald);margin-bottom:.9rem;">Capabilities in This Track</h2>'
    + '<div style="display:flex;flex-direction:column;gap:.6rem;">' + capLinksHtml + '</div>'
    + '</div>'
    + '</div>'

    // Right column
    + '<div style="display:flex;flex-direction:column;gap:1.5rem;">'
    // Deliverables
    + '<div style="background:white;border:1.5px solid var(--border);border-radius:16px;padding:1.5rem 1.75rem;">'
    + '<h2 style="font-size:.68rem;font-weight:800;letter-spacing:.12em;text-transform:uppercase;color:var(--gold);margin-bottom:.9rem;">What You Will Build</h2>'
    + '<div>' + delivHtml + '</div>'
    + '</div>'
    // Week plan
    + '<div style="background:white;border:1.5px solid var(--border);border-radius:16px;padding:1.5rem 1.75rem;">'
    + '<h2 style="font-size:.68rem;font-weight:800;letter-spacing:.12em;text-transform:uppercase;color:var(--emerald);margin-bottom:1.1rem;">Week-by-Week Plan</h2>'
    + weeksHtml
    + '</div>'
    + '</div>'

    + '</div>'

    // ── BOTTOM CTA ──
    + '<div style="background:white;border:1.5px solid var(--border);border-radius:16px;padding:1.4rem 1.75rem;display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:1rem;">'
    + '<div><div style="font-weight:700;font-size:.95rem;color:var(--ink);margin-bottom:.2rem;">Ready to start Track ' + track.number + '?</div>'
    + '<div style="font-size:.82rem;color:var(--ink-light);">Take the assessment first to get your baseline score, then follow the plan.</div></div>'
    + '<div style="display:flex;gap:.65rem;flex-wrap:wrap;">'
    + '<button onclick="showAssessmentPage()" style="background:white;border:1.5px solid var(--border);color:var(--ink-mid);border-radius:10px;padding:.6rem 1.2rem;font-size:.83rem;font-weight:700;cursor:pointer;font-family:inherit;transition:border-color .15s;" onmouseover="this.style.borderColor=\'var(--emerald)\'" onmouseout="this.style.borderColor=\'var(--border)\'">Take Assessment</button>'
    + '<button onclick="showCategoriesPage()" style="background:' + track.accentColor + ';color:white;border:none;border-radius:10px;padding:.6rem 1.35rem;font-size:.83rem;font-weight:700;cursor:pointer;font-family:inherit;transition:opacity .15s;" onmouseover="this.style.opacity=\'.85\'" onmouseout="this.style.opacity=\'1\'">Go to Capabilities →</button>'
    + '</div></div>'

    + nextHtml;

  // Responsive fix
  var style = document.getElementById('trackDetailGridStyle');
  if (!style) {
    style = document.createElement('style');
    style.id = 'trackDetailGridStyle';
    style.textContent = '@media(max-width:700px){.track-detail-grid{grid-template-columns:1fr!important;}}';
    document.head.appendChild(style);
  }
}

function renderVideoGuideFilters() {
  var container = document.getElementById('videoGuideFilterBtns');
  if (!container) return;
  container.innerHTML = videoCategories.map(function(f) {
    var isActive = f === currentVideoFilter;
    return '<button onclick="filterVideoGuides(\'' + f + '\')" style="padding:.45rem 1.1rem;border-radius:20px;font-size:.82rem;font-weight:700;cursor:pointer;font-family:inherit;border:1.5px solid ' + (isActive ? 'var(--emerald)' : 'var(--border)') + ';background:' + (isActive ? 'var(--emerald)' : 'white') + ';color:' + (isActive ? 'white' : 'var(--ink-light)') + ';transition:all .18s;">' + f + '</button>';
  }).join('');
}

function filterVideoGuides(f) {
  currentVideoFilter = f;
  renderVideoGuideFilters();
  renderVideoGuides();
}

function renderVideoGuides() {
  var grid = document.getElementById('videoGuidesGrid');
  if (!grid) return;
  grid.style.cssText = 'display:grid;grid-template-columns:repeat(auto-fill,minmax(300px,1fr));gap:1.5rem;';

  var filtered = currentVideoFilter === 'All'
    ? VG_LIBRARY
    : VG_LIBRARY.filter(function(v) { return v.category === currentVideoFilter; });

  var countEl = document.getElementById('vgStatCount');
  if (countEl) countEl.textContent = filtered.length;

  // Update runtime stat
  var rtEl = document.getElementById('vgStatRuntime');
  if (rtEl) {
    var totalMins = filtered.reduce(function(sum, v) {
      var parts = v.duration.split(':');
      return sum + parseInt(parts[0]) + parseInt(parts[1]) / 60;
    }, 0);
    var h = Math.floor(totalMins / 60), m = Math.round(totalMins % 60);
    rtEl.textContent = h + 'h ' + m + 'm';
  }

  if (!filtered.length) {
    grid.innerHTML = '<div style="grid-column:1/-1;text-align:center;padding:3rem;color:var(--ink-light);">No video guides in this category.</div>';
    return;
  }

  grid.innerHTML = filtered.map(function(v) {
    var shortDesc = v.desc.substring(0, 110).replace(/\s\S*$/, '') + '\u2026';
    return '<div style="background:#fff;border:1px solid #e8e4dc;border-radius:14px;overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,.05);transition:box-shadow .2s,transform .2s;cursor:pointer;" onclick="openVGDetail(\'' + v.id + '\')" onmouseover="this.style.boxShadow=\'0 8px 28px rgba(0,0,0,.13)\';this.style.transform=\'translateY(-2px)\'" onmouseout="this.style.boxShadow=\'0 2px 8px rgba(0,0,0,.05)\';this.style.transform=\'\'">'
      + '<div style="position:relative;aspect-ratio:16/9;background:' + v.thumb + ';overflow:hidden;">'
      + (v.imgSrc ? '<img src="'+v.imgSrc+'" alt="'+v.title+'" style="width:100%;height:100%;object-fit:cover;display:block;position:absolute;inset:0;" onerror="this.style.display=\'none\'">' : '')
      + '<div style="position:absolute;inset:0;background:linear-gradient(to bottom,rgba(0,0,0,.15) 0%,rgba(0,0,0,.5) 100%);"></div>'
      + '<div style="position:absolute;inset:0;display:flex;align-items:center;justify-content:center;">'
      + '<div style="width:54px;height:54px;border-radius:50%;background:rgba(255,255,255,.18);border:2px solid rgba(255,255,255,.55);display:flex;align-items:center;justify-content:center;font-size:1.45rem;backdrop-filter:blur(4px);">\u25b6</div>'
      + '</div>'
      + '<div style="position:absolute;top:.7rem;left:.7rem;background:' + v.badge.bg + ';color:' + v.badge.text + ';font-size:.58rem;font-weight:800;letter-spacing:.07em;text-transform:uppercase;padding:.22rem .6rem;border-radius:5px;">' + v.category + '</div>'
      + '<div style="position:absolute;bottom:.65rem;right:.65rem;background:rgba(0,0,0,.72);color:white;font-size:.72rem;font-weight:700;padding:.18rem .52rem;border-radius:5px;font-family:\'DM Mono\',monospace;">' + v.duration + '</div>'
      + '<div style="position:absolute;top:.65rem;right:.7rem;background:rgba(0,0,0,.45);color:rgba(255,255,255,.8);font-size:.58rem;font-weight:700;padding:.18rem .5rem;border-radius:4px;">Lesson ' + v.lessonNum + '</div>'
      + '</div>'
      + '<div style="padding:1.1rem 1.2rem 1rem;">'
      + '<div style="font-size:.65rem;font-weight:700;letter-spacing:.07em;text-transform:uppercase;color:' + v.badge.bg + ';margin-bottom:.3rem;">' + v.capTitle + '</div>'
      + '<div style="font-weight:800;font-size:.92rem;color:#111;line-height:1.3;margin-bottom:.4rem;">' + v.title + '</div>'
      + '<p style="font-size:.78rem;color:#6b7280;line-height:1.55;margin-bottom:.8rem;">' + shortDesc + '</p>'
      + '<div style="display:flex;align-items:center;justify-content:space-between;">'
      + '<span style="font-size:.72rem;color:#9ca3af;font-family:\'DM Mono\',monospace;">' + v.lessons.length + ' topics · ' + v.duration + '</span>'
      + '<span style="color:var(--emerald);font-weight:700;font-size:.8rem;">Watch \u2192</span>'
      + '</div></div></div>';
  }).join('');
}

function openVGDetail(vgId) {
  var v = null;
  for (var i = 0; i < VG_LIBRARY.length; i++) { if (VG_LIBRARY[i].id === vgId) { v = VG_LIBRARY[i]; break; } }
  if (!v) return;

  var modal = document.getElementById('vgDetailModal');
  if (!modal) {
    modal = document.createElement('div');
    modal.id = 'vgDetailModal';
    modal.style.cssText = 'display:none;position:fixed;inset:0;z-index:3000;background:rgba(4,12,8,.92);backdrop-filter:blur(8px);overflow-y:auto;';
    modal.addEventListener('click', function(e) { if (e.target === modal) closeVGDetail(); });
    document.body.appendChild(modal);
  }

  var topicsHtml = v.lessons.map(function(l, i) {
    return '<div style="display:flex;gap:.85rem;padding:.75rem 1rem;background:' + (i % 2 === 0 ? 'var(--cream)' : 'white') + ';border-radius:10px;border:1px solid var(--border);align-items:flex-start;">'
      + '<div style="min-width:22px;height:22px;border-radius:50%;background:' + v.badge.bg + ';color:#fff;font-size:.65rem;font-weight:800;display:flex;align-items:center;justify-content:center;flex-shrink:0;">' + (i + 1) + '</div>'
      + '<span style="font-size:.84rem;color:var(--ink-mid);line-height:1.6;">' + l + '</span>'
      + '</div>';
  }).join('');

  var instrHtml = v.instrs.map(function(s, i) {
    return '<div style="display:flex;gap:.75rem;padding:.65rem .9rem;background:var(--cream);border-radius:9px;border:1px solid var(--border);align-items:flex-start;">'
      + '<div style="min-width:20px;height:20px;border-radius:50%;background:#6366f1;color:#fff;font-size:.62rem;font-weight:800;display:flex;align-items:center;justify-content:center;flex-shrink:0;">' + (i + 1) + '</div>'
      + '<span style="font-size:.82rem;color:var(--ink-mid);line-height:1.55;">' + s + '</span>'
      + '</div>';
  }).join('');

  modal.innerHTML =
    '<div style="max-width:840px;margin:1.5rem auto;padding:0 1rem 4rem;">'
    + '<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:1rem;padding:.5rem 0;">'
    + '<div style="display:flex;align-items:center;gap:.5rem;font-size:.8rem;color:rgba(255,255,255,.5);">'
    + '<span onclick="closeVGDetail()" style="color:rgba(255,255,255,.8);cursor:pointer;font-weight:700;">\u2190 Video Guides</span>'
    + '<span style="opacity:.35;">\u203a</span><span style="color:rgba(255,255,255,.9);">' + v.capTitle + '</span>'
    + '</div>'
    + '<button onclick="closeVGDetail()" style="background:rgba(255,255,255,.1);border:1px solid rgba(255,255,255,.2);color:rgba(255,255,255,.8);width:34px;height:34px;border-radius:50%;font-size:1rem;cursor:pointer;line-height:1;">\u2715</button>'
    + '</div>'
    + '<div style="background:#000;border-radius:16px;overflow:hidden;box-shadow:0 20px 60px rgba(0,0,0,.7);margin-bottom:1.5rem;">'
    + '<video id="vgDetailVid" controls autoplay playsinline style="width:100%;display:block;max-height:440px;background:#000;" src="' + v.src + '">Your browser does not support HTML5 video.</video>'
    + '<div style="background:#06160d;padding:.6rem 1.1rem;display:flex;align-items:center;gap:.85rem;flex-wrap:wrap;">'
    + '<div style="background:' + v.badge.bg + ';color:#fff;font-size:.6rem;font-weight:800;letter-spacing:.06em;text-transform:uppercase;padding:.18rem .55rem;border-radius:5px;">' + v.category + '</div>'
    + '<span style="color:rgba(255,255,255,.5);font-size:.72rem;">' + v.capTitle + ' \u00b7 Lesson ' + v.lessonNum + ' of 6</span>'
    + '<span style="color:rgba(255,255,255,.3);margin-left:auto;font-size:.65rem;">Demo video — content is illustrative</span>'
    + '</div></div>'
    + '<div style="background:#fff;border-radius:16px;padding:1.75rem;margin-bottom:1.25rem;">'
    + '<div style="font-size:.6rem;font-weight:700;letter-spacing:.14em;text-transform:uppercase;color:' + v.badge.bg + ';margin-bottom:.35rem;">' + v.capTitle + ' \u00b7 Micro Lesson ' + v.lessonNum + '</div>'
    + '<h2 style="font-family:\'Cormorant Garamond\',serif;font-size:1.65rem;font-weight:600;color:var(--emerald-dark);line-height:1.25;margin-bottom:.75rem;">' + v.title + '</h2>'
    + '<p style="font-size:.88rem;color:var(--ink-mid);line-height:1.8;margin-bottom:1.1rem;">' + v.desc + '</p>'
    + '<div style="background:var(--emerald-glow);border:1px solid rgba(26,107,74,.15);border-radius:10px;padding:1rem 1.25rem;">'
    + '<div style="font-size:.65rem;font-weight:800;text-transform:uppercase;letter-spacing:.1em;color:var(--emerald);margin-bottom:.4rem;">Learning Objective</div>'
    + '<p style="font-size:.87rem;color:var(--ink-mid);line-height:1.65;margin:0;">' + v.obj + '</p>'
    + '</div></div>'
    + '<div style="background:#fff;border-radius:16px;padding:1.5rem;margin-bottom:1.25rem;">'
    + '<div style="font-size:.65rem;font-weight:800;text-transform:uppercase;letter-spacing:.1em;color:var(--ink-pale);margin-bottom:.75rem;">Topics Covered in This Video</div>'
    + '<div style="display:flex;flex-direction:column;gap:.5rem;">' + topicsHtml + '</div>'
    + '</div>'
    + '<div style="background:#fff;border-radius:16px;padding:1.5rem;margin-bottom:1.25rem;">'
    + '<div style="font-size:.65rem;font-weight:800;text-transform:uppercase;letter-spacing:.1em;color:var(--ink-pale);margin-bottom:.75rem;">How to Watch This Guide</div>'
    + '<div style="display:flex;flex-direction:column;gap:.5rem;">' + instrHtml + '</div>'
    + '</div>'
    + '<div style="background:linear-gradient(135deg,var(--emerald-dark),var(--emerald));border-radius:14px;padding:1.4rem 1.75rem;display:flex;align-items:center;justify-content:space-between;gap:1rem;flex-wrap:wrap;">'
    + '<div style="color:#fff;"><div style="font-weight:800;font-size:.95rem;">Ready to go deeper?</div><div style="font-size:.8rem;opacity:.8;margin-top:.15rem;">Open the full ' + v.capTitle + ' capability module with workbook, templates, and all 6 micro lessons.</div></div>'
    + '<button onclick="closeVGDetail();loadCapability(\'' + v.capId + '\')" style="background:#fff;color:var(--emerald-dark);font-weight:800;padding:.7rem 1.4rem;border-radius:10px;border:none;cursor:pointer;font-family:inherit;white-space:nowrap;font-size:.88rem;">Open Full Module \u2192</button>'
    + '</div>'
    + '</div>';

  modal.style.display = 'block';
  document.body.style.overflow = 'hidden';
}

function closeVGDetail() {
  var modal = document.getElementById('vgDetailModal');
  if (modal) {
    var vid = document.getElementById('vgDetailVid');
    if (vid) { vid.pause(); vid.removeAttribute('src'); vid.load(); }
    modal.style.display = 'none';
  }
  document.body.style.overflow = '';
}

function openVideoGuidePlayer(capId, subIdx) {
  var cap = CAPABILITIES[capId];
  if (!cap || !cap.subCapabilities || !cap.subCapabilities[subIdx]) return;
  var sub = cap.subCapabilities[subIdx];
  var v = sub.video;
  if (!v) return;
  var vSrc = _VG_VIDEOS[_vgVideoIdx % _VG_VIDEOS.length].src;
  _vgVideoIdx++;

  // Build or reuse modal
  var modal = document.getElementById('vgPlayerModal');
  if (!modal) {
    modal = document.createElement('div');
    modal.id = 'vgPlayerModal';
    modal.style.cssText = 'display:none;position:fixed;inset:0;z-index:3000;background:rgba(4,12,8,.93);backdrop-filter:blur(8px);overflow-y:auto;';
    modal.addEventListener('click', function(e){ if(e.target===modal) closeVGModal(); });
    document.body.appendChild(modal);
  }

  var objItems = (v.objectives||'').split(';').map(function(o){return o.trim();}).filter(Boolean).map(function(o){
    return '<li style="font-size:.85rem;color:var(--ink-mid);line-height:1.65;margin-bottom:.3rem;">'+o+'</li>';
  }).join('');

  var instrItems = (v.instructions||[]).map(function(s,i){
    return '<div style="display:flex;gap:.75rem;padding:.7rem .85rem;background:var(--cream);border-radius:9px;border:1px solid var(--border);align-items:flex-start;">'
      +'<div style="min-width:22px;height:22px;border-radius:50%;background:var(--emerald);color:#fff;font-size:.68rem;font-weight:800;display:flex;align-items:center;justify-content:center;">'+(i+1)+'</div>'
      +'<span style="font-size:.83rem;color:var(--ink-mid);line-height:1.55;">'+s+'</span></div>';
  }).join('');

  modal.innerHTML =
    '<div style="max-width:880px;margin:1.5rem auto;padding:0 1rem 4rem;">'
    // top bar
    +'<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:1rem;padding:.5rem 0;">'
    +'<div style="display:flex;align-items:center;gap:.5rem;font-size:.8rem;color:rgba(255,255,255,.55);">'
    +'<span onclick="closeVGModal()" style="color:rgba(255,255,255,.8);cursor:pointer;font-weight:700;font-size:.85rem;">← Video Guides</span>'
    +'<span style="opacity:.35;font-size:.9rem;">›</span>'
    +'<span style="color:rgba(255,255,255,.9);">'+v.title+'</span>'
    +'</div>'
    +'<button onclick="closeVGModal()" style="background:rgba(255,255,255,.1);border:1px solid rgba(255,255,255,.2);color:rgba(255,255,255,.8);width:34px;height:34px;border-radius:50%;font-size:1rem;cursor:pointer;line-height:1;">✕</button>'
    +'</div>'
    // video player
    +'<div style="background:#000;border-radius:16px;overflow:hidden;box-shadow:0 20px 60px rgba(0,0,0,.7);margin-bottom:1.5rem;">'
    +'<video id="vgVid" controls autoplay playsinline style="width:100%;display:block;max-height:490px;background:#000;" src="'+vSrc+'">Your browser does not support HTML5 video.</video>'
    +'<div style="background:#06160d;padding:.6rem 1.1rem;display:flex;align-items:center;gap:.85rem;flex-wrap:wrap;">'
    +'<span style="font-size:.72rem;font-weight:700;padding:.22rem .65rem;border-radius:20px;background:rgba(99,102,241,.18);color:#a5b4fc;border:1px solid rgba(99,102,241,.3);">📹 '+cap.title+'</span>'
    +'<span style="font-size:.72rem;color:rgba(255,255,255,.45);">⏱ '+v.duration+'</span>'
    +'<span style="font-size:.68rem;color:rgba(255,255,255,.25);margin-left:auto;">Demo video — content is illustrative</span>'
    +'</div></div>'
    // info card
    +'<div style="background:#fff;border-radius:16px;padding:1.75rem;margin-bottom:1.25rem;">'
    +'<div style="font-family:\'DM Mono\',monospace;font-size:.62rem;font-weight:600;letter-spacing:.14em;text-transform:uppercase;color:var(--gold);margin-bottom:.45rem;">'+cap.title+'</div>'
    +'<h2 style="font-family:\'Cormorant Garamond\',serif;font-size:1.65rem;font-weight:600;color:var(--emerald-dark);line-height:1.25;margin-bottom:.85rem;">'+v.title+'</h2>'
    +'<p style="font-size:.88rem;color:var(--ink-mid);line-height:1.8;margin-bottom:'+(objItems?'1.25rem':'0')+'">'+(v.description||'')+'</p>'
    +(objItems ? '<div style="margin-top:.5rem;"><div style="font-size:.7rem;font-weight:800;text-transform:uppercase;letter-spacing:.1em;color:var(--emerald);margin-bottom:.5rem;">Learning Objectives</div><ul style="margin:0;padding-left:1.1rem;">'+objItems+'</ul></div>' : '')
    +'</div>'
    // instructions
    +(instrItems ? '<div style="background:#fff;border-radius:16px;padding:1.5rem;margin-bottom:1.25rem;">'
    +'<div style="font-family:\'DM Mono\',monospace;font-size:.62rem;font-weight:600;letter-spacing:.14em;text-transform:uppercase;color:var(--ink-pale);margin-bottom:.85rem;">How to Watch This Guide</div>'
    +'<div style="display:flex;flex-direction:column;gap:.5rem;">'+instrItems+'</div></div>' : '')
    // CTA
    +'<div style="background:linear-gradient(135deg,var(--emerald-dark),var(--emerald));border-radius:14px;padding:1.4rem 1.75rem;display:flex;align-items:center;justify-content:space-between;gap:1rem;flex-wrap:wrap;">'
    +'<div style="color:#fff;"><div style="font-weight:800;font-size:.95rem;">Ready to go deeper?</div><div style="font-size:.8rem;opacity:.8;margin-top:.2rem;">Explore the full '+sub.title+' capability with workbook, templates and more.</div></div>'
    +'<button onclick="closeVGModal();openSubCapability(\''+capId+'\','+subIdx+')" style="background:#fff;color:var(--emerald-dark);font-weight:800;padding:.7rem 1.4rem;border-radius:10px;border:none;cursor:pointer;font-family:inherit;white-space:nowrap;font-size:.88rem;">Open Full Module →</button>'
    +'</div>'
    +'</div>';

  modal.style.display = 'block';
  document.body.style.overflow = 'hidden';
}

function closeVGModal() {
  var modal = document.getElementById('vgPlayerModal');
  if (modal) {
    var vid = document.getElementById('vgVid');
    if (vid) { vid.pause(); vid.removeAttribute('src'); vid.load(); }
    modal.style.display = 'none';
  }
  document.body.style.overflow = '';
}





function closeFooterModal(id) {
  var el = document.getElementById(id);
  if (el) el.style.display = 'none';
  document.body.style.overflow = '';
}
function showQuickGuideModal() {
  document.getElementById('quickGuideModal').style.display = 'block';
  document.body.style.overflow = 'hidden';
}
function showPrivacyModal() {
  document.getElementById('privacyModal').style.display = 'block';
  document.body.style.overflow = 'hidden';
}



