// Close all open tool menus when clicking outside
document.addEventListener('click', function(e) {
  if (!e.target.closest('[id^="wrap-lp-tool-"]')) {
    document.querySelectorAll('[id^="lp-tool-"]').forEach(function(el) {
      if (!el.id.startsWith('wrap-')) el.style.display = 'none';
    });
  }
});

function toggleToolMenu(toolId) {
  var menu = document.getElementById(toolId);
  if (!menu) return;
  var isOpen = menu.style.display === 'block';
  // Close all other open menus first
  document.querySelectorAll('[id^="lp-tool-"]').forEach(function(el) {
    if (!el.id.startsWith('wrap-')) el.style.display = 'none';
  });
  menu.style.display = isOpen ? 'none' : 'block';
}

