function downloadTool(toolName, format) {
  var data = getToolContent(toolName);
  if (format === 'pdf') {
    downloadToolAsPDF(toolName, data);
  } else {
    downloadToolAsDocx(toolName, data);
  }
}

function downloadToolAsPDF(toolName, data) {
  try {
    var jsPDF = window.jspdf ? window.jspdf.jsPDF : window.jsPDF;
    if (!jsPDF) { showToast('PDF library loading… please try again in a moment.'); return; }

    var doc = new jsPDF({ unit: 'mm', format: 'a4' });
    var pageW = 210, margin = 18, contentW = pageW - margin * 2;
    var y = 20;
    var emerald = [26, 107, 74];
    var inkDark  = [26, 26, 26];
    var inkLight = [107, 107, 107];

    function checkPage(needed) {
      if (y + needed > 275) { doc.addPage(); y = 20; }
    }

    // Header bar with logo
    doc.setFillColor(26, 107, 74);
    doc.rect(0, 0, 210, 22, 'F');
    // Add logo image to header
    try {
      var _logoB64 = '';
      doc.addImage('data:image/png;base64,' + _logoB64, 'PNG', margin, 2, 40, 18);
    } catch(imgErr) {
      doc.setTextColor(255, 255, 255);
      doc.setFontSize(8); doc.setFont('helvetica', 'bold');
      doc.text('ALJUDE ACADEMY  ·  CAPACITY BUILDING PLATFORM', margin, 11);
    }
    doc.setTextColor(255, 255, 255);
    doc.setFontSize(7);
    doc.setFont('helvetica', 'normal');
    doc.text('CAPACITY BUILDING PLATFORM', 210 - margin, 14, { align: 'right' });

    y = 34;
    // Title
    doc.setTextColor(...inkDark);
    doc.setFontSize(19);
    doc.setFont('helvetica', 'bold');
    var titleLines = doc.splitTextToSize(toolName, contentW);
    doc.text(titleLines, margin, y);
    y += titleLines.length * 8 + 3;

    // Subtitle
    doc.setFontSize(9.5);
    doc.setFont('helvetica', 'normal');
    doc.setTextColor(...inkLight);
    var subLines = doc.splitTextToSize(data.subtitle, contentW);
    doc.text(subLines, margin, y);
    y += subLines.length * 5 + 6;

    // Divider
    doc.setDrawColor(...emerald);
    doc.setLineWidth(0.6);
    doc.line(margin, y, pageW - margin, y);
    y += 8;

    // Sections
    data.sections.forEach(function(section) {
      checkPage(20);
      // Section header
      doc.setFillColor(235, 248, 241);
      doc.roundedRect(margin - 2, y - 4, contentW + 4, 10, 2, 2, 'F');
      doc.setFontSize(10.5);
      doc.setFont('helvetica', 'bold');
      doc.setTextColor(...emerald);
      doc.text(section.title, margin + 2, y + 2.5);
      y += 12;

      // Section content
      doc.setFontSize(9);
      doc.setFont('helvetica', 'normal');
      doc.setTextColor(...inkDark);
      var lines = section.content.split('\n');
      lines.forEach(function(line) {
        checkPage(6);
        if (line.trim() === '') { y += 3; return; }
        var wrapped = doc.splitTextToSize(line, contentW - 4);
        wrapped.forEach(function(wl) {
          checkPage(5.5);
          doc.text(wl, margin + 4, y);
          y += 5.5;
        });
      });
      y += 6;
    });

    // Footer
    var pageCount = doc.internal.getNumberOfPages();
    for (var p = 1; p <= pageCount; p++) {
      doc.setPage(p);
      doc.setFillColor(245, 245, 245);
      doc.rect(0, 285, 210, 12, 'F');
      doc.setFontSize(7);
      doc.setFont('helvetica', 'normal');
      doc.setTextColor(...inkLight);
      doc.text('ALJUDE Academy  ·  aljude.org', margin, 291);
      doc.text('Page ' + p + ' of ' + pageCount, pageW - margin, 291, { align: 'right' });
    }

    doc.save(toolName + '.pdf');
    showToast(toolName + ' downloaded as PDF!');
  } catch(e) {
    console.error(e);
    showToast('Could not generate PDF. Please try again.');
  }
}

function downloadToolAsDocx(toolName, data) {
  // Build a simple .docx-like RTF file since we can't run Node.js in the browser.
  // We use a well-structured HTML blob saved as .doc (opens in Word).
  var html = '<!DOCTYPE html><html><head><meta charset="UTF-8">';
  html += '</head><body>';
  html += '<div class="header" style="background:#1a6b4a;color:white;padding:14px 20px;margin:-2.5cm -2.5cm 24px;display:flex;align-items:center;justify-content:space-between;">' + '<img src="data:image/png;base64," style="height:48px;width:auto;" />' + '<span style="color:rgba(255,255,255,.8);font-size:7.5pt;font-weight:600;letter-spacing:.1em;text-transform:uppercase;">Capacity Building Platform</span>' + '</div>';
  html += '<h1>' + toolName + '</h1>';
  html += '<div class="subtitle">' + data.subtitle + '</div>';
  html += '<hr>';

  data.sections.forEach(function(sec) {
    html += '<div class="section-title">' + sec.title + '</div>';
    html += '<div class="section-content">' + sec.content.replace(/</g,'&lt;').replace(/>/g,'&gt;') + '</div>';
  });

  html += '<div class="footer"><span>ALJUDE Academy &nbsp;·&nbsp; aljude.org</span><span>' + toolName + '</span></div>';
  html += '</body></html>';

  var blob = new Blob([html], { type: 'application/msword' });
  var url  = URL.createObjectURL(blob);
  var a    = document.createElement('a');
  a.href  = url;
  a.download = toolName + '.doc';
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
  showToast(toolName + ' downloaded as Word!');
}

