function downloadWebinarResource(resourceName, webinarTitle, format) {
  var data = _webinarResourceTemplates[resourceName];
  if (!data) {
    // Fallback generic template
    data = {
      subtitle: 'A professional resource from the "' + webinarTitle + '" session on ALJUDE Academy.',
      sections: [
        { title: '1. Overview', content: 'Purpose of this resource:\n_______________________________________________\n\nHow to use it:\n_______________________________________________' },
        { title: '2. Key Information', content: 'Section A: _______________________________________________\n_______________________________________________\n\nSection B: _______________________________________________\n_______________________________________________' },
        { title: '3. Action Steps', content: 'Step 1: _______________________________________________\nOwner: _______________  Deadline: _______________\n\nStep 2: _______________________________________________\nOwner: _______________  Deadline: _______________\n\nStep 3: _______________________________________________\nOwner: _______________  Deadline: _______________' },
        { title: '4. Notes & Follow-Up', content: 'Notes: _______________________________________________\nFollow-up date: _______________' }
      ]
    };
  }
  if (format === 'pdf') {
    downloadToolAsPDF(resourceName, data);
  } else {
    downloadToolAsDocx(resourceName, data);
  }
  showToast(resourceName + ' downloading as ' + (format === 'pdf' ? 'PDF' : 'Word') + '…');
}


// ── MISSING FUNCTIONS (added for full online compatibility) ──────────────────

/**
 * scrollToHowItWorks — Footer "How It Works" link
 * Navigates to home page and scrolls to the capability grid section.
 */
function scrollToHowItWorks() {
  goHome();
  setTimeout(function() {
    var target = document.getElementById('homeCapGrid');
    if (!target) target = document.querySelector('.capability-grid');
    if (target) {
      target.scrollIntoView({ behavior: 'smooth', block: 'start' });
    } else {
      window.scrollTo({ top: 400, behavior: 'smooth' });
    }
  }, 150);
}

/**
 * showTermsModal — Footer "Terms of Use" link
 */
function showTermsModal() {
  var el = document.getElementById('termsModal');
  if (el) {
    el.style.display = 'block';
    document.body.style.overflow = 'hidden';
  }
}

/**
 * handleSignIn — Sign-in page "Sign In" button
 * Validates inputs then opens auth modal (or shows a toast for demo).
 */
function handleSignIn() {
  var email = document.getElementById('signinEmail');
  var password = document.getElementById('signinPassword');
  var emailVal = email ? email.value.trim() : '';
  var passVal  = password ? password.value : '';

  if (!emailVal || !emailVal.includes('@')) {
    showToast('Please enter a valid email address.');
    if (email) email.focus();
    return;
  }
  if (!passVal || passVal.length < 4) {
    showToast('Please enter your password.');
    if (password) password.focus();
    return;
  }
  // Demo behaviour — show welcome toast and navigate home
  showToast('Welcome back! Signing you in…');
  setTimeout(function() { goHome(); }, 900);
}

/**
 * handleSignUp — Sign-up page "Create Free Account" button
 * Validates inputs then shows confirmation toast.
 */
function handleSignUp() {
  showToast('Account created! Welcome to ALJUDE Academy.');
  setTimeout(function() { goHome(); }, 900);
}
